import { useState, useEffect } from 'react';
import {
  Plus,
  Phone,
  Mail,
  Calendar,
  CheckSquare,
  FileText,
  Clock,
  CheckCircle2,
  MoreHorizontal,
  Edit,
  Trash2,
  Activity,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/hooks/useAuth';
import { format, formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import type { Database } from '@/integrations/supabase/types';

type ActivityType = Database['public']['Enums']['activity_type'];

interface ActivityRecord {
  id: string;
  type: ActivityType;
  subject: string;
  description: string | null;
  status: string | null;
  priority: string | null;
  due_date: string | null;
  completed_at: string | null;
  duration_minutes: number | null;
  outcome: string | null;
  call_result: string | null;
  meeting_location: string | null;
  created_at: string;
  owner?: {
    first_name: string | null;
    last_name: string | null;
    email: string;
  };
}

interface ActivitiesWidgetProps {
  accountId?: string;
  contactId?: string;
  leadId?: string;
  opportunityId?: string;
  className?: string;
  compact?: boolean;
}

const activityTypeIcons: Record<ActivityType, typeof Phone> = {
  call: Phone,
  email: Mail,
  meeting: Calendar,
  task: CheckSquare,
  note: FileText,
};

const activityTypeLabels: Record<ActivityType, string> = {
  call: 'Ligação',
  email: 'Email',
  meeting: 'Reunião',
  task: 'Tarefa',
  note: 'Anotação',
};

const activityTypeColors: Record<ActivityType, string> = {
  call: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
  email: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400',
  meeting: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400',
  task: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400',
  note: 'bg-gray-100 text-gray-700 dark:bg-gray-900/30 dark:text-gray-400',
};

const priorityLabels: Record<string, string> = {
  low: 'Baixa',
  normal: 'Normal',
  high: 'Alta',
  urgent: 'Urgente',
};

const priorityColors: Record<string, string> = {
  low: 'bg-muted text-muted-foreground',
  normal: 'bg-info/10 text-info',
  high: 'bg-warning/10 text-warning',
  urgent: 'bg-destructive/10 text-destructive',
};

const callResultLabels: Record<string, string> = {
  connected: 'Conectado',
  voicemail: 'Caixa Postal',
  no_answer: 'Sem Resposta',
  busy: 'Ocupado',
  wrong_number: 'Número Errado',
};

export function ActivitiesWidget({
  accountId,
  contactId,
  leadId,
  opportunityId,
  className = '',
  compact = false,
}: ActivitiesWidgetProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const [activities, setActivities] = useState<ActivityRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [showDialog, setShowDialog] = useState(false);
  const [editingActivity, setEditingActivity] = useState<ActivityRecord | null>(null);
  const [saving, setSaving] = useState(false);

  // Form state
  const [formData, setFormData] = useState({
    type: 'call' as ActivityType,
    subject: '',
    description: '',
    priority: 'normal',
    due_date: '',
    duration_minutes: '',
    meeting_location: '',
    outcome: '',
    call_result: '',
  });

  useEffect(() => {
    fetchActivities();
  }, [accountId, contactId, leadId, opportunityId]);

  const fetchActivities = async () => {
    setLoading(true);
    let query = supabase
      .from('activities')
      .select(`
        *,
        owner:profiles!activities_owner_id_fkey(first_name, last_name, email)
      `)
      .order('due_date', { ascending: true, nullsFirst: false })
      .order('created_at', { ascending: false });

    if (accountId) query = query.eq('account_id', accountId);
    if (contactId) query = query.eq('contact_id', contactId);
    if (leadId) query = query.eq('lead_id', leadId);
    if (opportunityId) query = query.eq('opportunity_id', opportunityId);

    const { data, error } = await query;

    if (error) {
      console.error('Error fetching activities:', error);
    } else {
      setActivities(data || []);
    }
    setLoading(false);
  };

  const resetForm = () => {
    setFormData({
      type: 'call',
      subject: '',
      description: '',
      priority: 'normal',
      due_date: '',
      duration_minutes: '',
      meeting_location: '',
      outcome: '',
      call_result: '',
    });
  };

  const handleSave = async () => {
    if (!formData.subject.trim()) {
      toast({ variant: 'destructive', title: 'Erro', description: 'O assunto é obrigatório' });
      return;
    }

    setSaving(true);

    // Get user's profile for organization_id
    const { data: profile } = await supabase
      .from('profiles')
      .select('organization_id')
      .eq('id', user?.id)
      .single();

    if (!profile?.organization_id) {
      toast({ variant: 'destructive', title: 'Erro', description: 'Organização não encontrada' });
      setSaving(false);
      return;
    }

    const activityData = {
      type: formData.type,
      subject: formData.subject.trim(),
      description: formData.description.trim() || null,
      priority: formData.priority,
      due_date: formData.due_date || null,
      duration_minutes: formData.duration_minutes ? parseInt(formData.duration_minutes) : null,
      meeting_location: formData.meeting_location.trim() || null,
      outcome: formData.outcome.trim() || null,
      call_result: formData.call_result.trim() || null,
      organization_id: profile.organization_id,
      owner_id: user?.id || '',
      status: 'open',
      account_id: accountId || null,
      contact_id: contactId || null,
      lead_id: leadId || null,
      opportunity_id: opportunityId || null,
    };

    if (editingActivity) {
      const { error } = await supabase
        .from('activities')
        .update({
          type: activityData.type,
          subject: activityData.subject,
          description: activityData.description,
          priority: activityData.priority,
          due_date: activityData.due_date,
          duration_minutes: activityData.duration_minutes,
          meeting_location: activityData.meeting_location,
          outcome: activityData.outcome,
          call_result: activityData.call_result,
        })
        .eq('id', editingActivity.id);

      if (error) {
        toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao atualizar atividade' });
      } else {
        toast({ title: 'Atividade atualizada' });
        closeDialog();
        fetchActivities();
      }
    } else {
      const { error } = await supabase.from('activities').insert(activityData);

      if (error) {
        toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao criar atividade' });
      } else {
        toast({ title: 'Atividade criada' });
        closeDialog();
        fetchActivities();
      }
    }

    setSaving(false);
  };

  const completeActivity = async (activity: ActivityRecord) => {
    const { error } = await supabase
      .from('activities')
      .update({
        status: 'completed',
        completed_at: new Date().toISOString(),
      })
      .eq('id', activity.id);

    if (error) {
      toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao concluir atividade' });
    } else {
      toast({ title: 'Atividade concluída' });
      fetchActivities();
    }
  };

  const deleteActivity = async (activityId: string) => {
    const { error } = await supabase.from('activities').delete().eq('id', activityId);

    if (error) {
      toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao excluir atividade' });
    } else {
      toast({ title: 'Atividade excluída' });
      fetchActivities();
    }
  };

  const openEditDialog = (activity: ActivityRecord) => {
    setEditingActivity(activity);
    setFormData({
      type: activity.type,
      subject: activity.subject,
      description: activity.description || '',
      priority: activity.priority || 'normal',
      due_date: activity.due_date ? activity.due_date.split('T')[0] : '',
      duration_minutes: activity.duration_minutes?.toString() || '',
      meeting_location: activity.meeting_location || '',
      outcome: activity.outcome || '',
      call_result: activity.call_result || '',
    });
    setShowDialog(true);
  };

  const closeDialog = () => {
    setShowDialog(false);
    setEditingActivity(null);
    resetForm();
  };

  const getOwnerName = (activity: ActivityRecord) => {
    if (activity.owner) {
      if (activity.owner.first_name || activity.owner.last_name) {
        return `${activity.owner.first_name || ''} ${activity.owner.last_name || ''}`.trim();
      }
      return activity.owner.email;
    }
    return 'Desconhecido';
  };

  const openActivities = activities.filter((a) => a.status !== 'completed');
  const completedActivities = activities.filter((a) => a.status === 'completed');

  if (compact) {
    return (
      <div className={className}>
        <div className="flex items-center justify-between mb-3">
          <h4 className="text-sm font-medium">Atividades ({openActivities.length} em aberto)</h4>
          <Button size="sm" variant="ghost" onClick={() => setShowDialog(true)}>
            <Plus className="h-4 w-4" />
          </Button>
        </div>

        {loading ? (
          <p className="text-sm text-muted-foreground">Carregando...</p>
        ) : openActivities.length === 0 ? (
          <p className="text-sm text-muted-foreground">Nenhuma atividade em aberto</p>
        ) : (
          <div className="space-y-2 max-h-40 overflow-y-auto">
            {openActivities.slice(0, 3).map((activity) => {
              const Icon = activityTypeIcons[activity.type];
              return (
                <div key={activity.id} className="flex items-center gap-2 text-sm">
                  <Icon className="h-4 w-4 text-muted-foreground shrink-0" />
                  <span className="truncate flex-1">{activity.subject}</span>
                  {activity.due_date && (
                    <span className="text-xs text-muted-foreground shrink-0">
                      {format(new Date(activity.due_date), "d 'de' MMM", { locale: ptBR })}
                    </span>
                  )}
                </div>
              );
            })}
            {openActivities.length > 3 && (
              <p className="text-xs text-muted-foreground">+{openActivities.length - 3} mais</p>
            )}
          </div>
        )}

        <Dialog open={showDialog} onOpenChange={setShowDialog}>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>{editingActivity ? 'Editar Atividade' : 'Registrar Atividade'}</DialogTitle>
              <DialogDescription>
                Registre uma ligação, email, reunião ou tarefa.
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Tipo</Label>
                  <Select
                    value={formData.type}
                    onValueChange={(v) => setFormData({ ...formData, type: v as ActivityType })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="call">Ligação</SelectItem>
                      <SelectItem value="email">Email</SelectItem>
                      <SelectItem value="meeting">Reunião</SelectItem>
                      <SelectItem value="task">Tarefa</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Prioridade</Label>
                  <Select
                    value={formData.priority}
                    onValueChange={(v) => setFormData({ ...formData, priority: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixa</SelectItem>
                      <SelectItem value="normal">Normal</SelectItem>
                      <SelectItem value="high">Alta</SelectItem>
                      <SelectItem value="urgent">Urgente</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-2">
                <Label>Assunto *</Label>
                <Input
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  placeholder="Assunto da atividade"
                />
              </div>
              <div className="space-y-2">
                <Label>Data de Vencimento</Label>
                <Input
                  type="date"
                  value={formData.due_date}
                  onChange={(e) => setFormData({ ...formData, due_date: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  rows={3}
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={closeDialog}>Cancelar</Button>
              <Button onClick={handleSave} disabled={saving || !formData.subject.trim()}>
                {saving ? 'Salvando...' : editingActivity ? 'Atualizar' : 'Salvar'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    );
  }

  return (
    <Card className={className}>
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>Atividades</CardTitle>
          <CardDescription>Ligações, reuniões, emails e tarefas</CardDescription>
        </div>
        <Button size="sm" onClick={() => setShowDialog(true)}>
          <Plus className="mr-2 h-4 w-4" />
          Registrar Atividade
        </Button>
      </CardHeader>
      <CardContent>
        {loading ? (
          <div className="flex items-center justify-center h-32 text-muted-foreground">
            <p>Carregando atividades...</p>
          </div>
        ) : activities.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-32 text-muted-foreground">
            <Activity className="h-8 w-8 mb-2" />
            <p>Nenhuma atividade registrada</p>
          </div>
        ) : (
          <div className="space-y-6">
            {/* Open Activities */}
            {openActivities.length > 0 && (
              <div>
                <h4 className="text-sm font-medium text-muted-foreground mb-3">
                  Em Aberto ({openActivities.length})
                </h4>
                <div className="space-y-3">
                  {openActivities.map((activity) => {
                    const Icon = activityTypeIcons[activity.type];
                    const isOverdue = activity.due_date && new Date(activity.due_date) < new Date();
                    return (
                      <div
                        key={activity.id}
                        className={`flex items-start gap-3 p-3 rounded-lg border ${
                          isOverdue ? 'border-destructive/50 bg-destructive/5' : 'bg-card'
                        }`}
                      >
                        <div className={`p-2 rounded-md ${activityTypeColors[activity.type]}`}>
                          <Icon className="h-4 w-4" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <span className="font-medium">{activity.subject}</span>
                            <Badge variant="outline" className={priorityColors[activity.priority || 'normal']}>
                              {priorityLabels[activity.priority || 'normal']}
                            </Badge>
                          </div>
                          {activity.description && (
                            <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                              {activity.description}
                            </p>
                          )}
                          <div className="flex items-center gap-4 mt-2 text-xs text-muted-foreground">
                            <span>{getOwnerName(activity)}</span>
                            {activity.due_date && (
                              <span className={`flex items-center gap-1 ${isOverdue ? 'text-destructive' : ''}`}>
                                <Clock className="h-3 w-3" />
                                {isOverdue ? 'Atrasado: ' : 'Vence em: '}
                                {format(new Date(activity.due_date), "d 'de' MMM yyyy", { locale: ptBR })}
                              </span>
                            )}
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8"
                            onClick={() => completeActivity(activity)}
                          >
                            <CheckCircle2 className="h-4 w-4 text-success" />
                          </Button>
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" size="icon" className="h-8 w-8">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => openEditDialog(activity)}>
                                <Edit className="mr-2 h-4 w-4" />
                                Editar
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem
                                className="text-destructive"
                                onClick={() => deleteActivity(activity.id)}
                              >
                                <Trash2 className="mr-2 h-4 w-4" />
                                Excluir
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Completed Activities */}
            {completedActivities.length > 0 && (
              <div>
                <h4 className="text-sm font-medium text-muted-foreground mb-3">
                  Concluídas ({completedActivities.length})
                </h4>
                <div className="space-y-3">
                  {completedActivities.slice(0, 5).map((activity) => {
                    const Icon = activityTypeIcons[activity.type];
                    return (
                      <div
                        key={activity.id}
                        className="flex items-start gap-3 p-3 rounded-lg border bg-muted/30 opacity-75"
                      >
                        <div className={`p-2 rounded-md bg-muted`}>
                          <Icon className="h-4 w-4 text-muted-foreground" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <span className="font-medium line-through">{activity.subject}</span>
                          <div className="flex items-center gap-4 mt-1 text-xs text-muted-foreground">
                            <span>Concluída {activity.completed_at && formatDistanceToNow(new Date(activity.completed_at), { addSuffix: true, locale: ptBR })}</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        )}

        <Dialog open={showDialog} onOpenChange={setShowDialog}>
          <DialogContent className="max-w-lg">
            <DialogHeader>
              <DialogTitle>{editingActivity ? 'Editar Atividade' : 'Registrar Atividade'}</DialogTitle>
              <DialogDescription>
                Registre uma ligação, email, reunião ou tarefa.
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Tipo</Label>
                  <Select
                    value={formData.type}
                    onValueChange={(v) => setFormData({ ...formData, type: v as ActivityType })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="call">Ligação</SelectItem>
                      <SelectItem value="email">Email</SelectItem>
                      <SelectItem value="meeting">Reunião</SelectItem>
                      <SelectItem value="task">Tarefa</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Prioridade</Label>
                  <Select
                    value={formData.priority}
                    onValueChange={(v) => setFormData({ ...formData, priority: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixa</SelectItem>
                      <SelectItem value="normal">Normal</SelectItem>
                      <SelectItem value="high">Alta</SelectItem>
                      <SelectItem value="urgent">Urgente</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-2">
                <Label>Assunto *</Label>
                <Input
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  placeholder="Assunto da atividade"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Data de Vencimento</Label>
                  <Input
                    type="date"
                    value={formData.due_date}
                    onChange={(e) => setFormData({ ...formData, due_date: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Duração (minutos)</Label>
                  <Input
                    type="number"
                    value={formData.duration_minutes}
                    onChange={(e) => setFormData({ ...formData, duration_minutes: e.target.value })}
                    placeholder="30"
                  />
                </div>
              </div>
              {formData.type === 'meeting' && (
                <div className="space-y-2">
                  <Label>Local</Label>
                  <Input
                    value={formData.meeting_location}
                    onChange={(e) => setFormData({ ...formData, meeting_location: e.target.value })}
                    placeholder="Local da reunião ou link"
                  />
                </div>
              )}
              {formData.type === 'call' && (
                <div className="space-y-2">
                  <Label>Resultado da Ligação</Label>
                  <Select
                    value={formData.call_result}
                    onValueChange={(v) => setFormData({ ...formData, call_result: v })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione o resultado" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="connected">Conectado</SelectItem>
                      <SelectItem value="voicemail">Caixa Postal</SelectItem>
                      <SelectItem value="no_answer">Sem Resposta</SelectItem>
                      <SelectItem value="busy">Ocupado</SelectItem>
                      <SelectItem value="wrong_number">Número Errado</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              )}
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  rows={3}
                  placeholder="Detalhes da atividade..."
                />
              </div>
              <div className="space-y-2">
                <Label>Resultado</Label>
                <Input
                  value={formData.outcome}
                  onChange={(e) => setFormData({ ...formData, outcome: e.target.value })}
                  placeholder="Resultado ou próximos passos"
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={closeDialog}>Cancelar</Button>
              <Button onClick={handleSave} disabled={saving || !formData.subject.trim()}>
                {saving ? 'Salvando...' : editingActivity ? 'Atualizar' : 'Salvar'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import {
  CheckCircle,
  XCircle,
  Clock,
  AlertTriangle,
  User,
  DollarSign,
  FileText,
  RefreshCw,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

type ApprovalType = 'discount' | 'special_terms' | 'contract' | 'price_override' | 'credit_limit' | 'exception';

interface ApprovalRequestDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  entityType: string;
  entityId: string;
  entityName: string;
  approvalType: ApprovalType;
  requestedValue: Record<string, unknown>;
  originalValue: Record<string, unknown>;
  onSuccess?: () => void;
}

interface Approver {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string;
  role: string;
}

const approvalTypeConfig: Record<ApprovalType, { label: string; icon: React.ReactNode; description: string }> = {
  discount: {
    label: 'Discount Approval',
    icon: <DollarSign className="h-5 w-5" />,
    description: 'Request approval for discount exceeding threshold',
  },
  special_terms: {
    label: 'Special Terms',
    icon: <FileText className="h-5 w-5" />,
    description: 'Request approval for special contract terms',
  },
  contract: {
    label: 'Contract Approval',
    icon: <FileText className="h-5 w-5" />,
    description: 'Request approval for contract execution',
  },
  price_override: {
    label: 'Price Override',
    icon: <DollarSign className="h-5 w-5" />,
    description: 'Request approval for price override',
  },
  credit_limit: {
    label: 'Credit Limit',
    icon: <AlertTriangle className="h-5 w-5" />,
    description: 'Request approval for credit limit exception',
  },
  exception: {
    label: 'Exception Request',
    icon: <AlertTriangle className="h-5 w-5" />,
    description: 'Request approval for general exception',
  },
};

export function ApprovalRequestDialog({
  open,
  onOpenChange,
  entityType,
  entityId,
  entityName,
  approvalType,
  requestedValue,
  originalValue,
  onSuccess,
}: ApprovalRequestDialogProps) {
  const { profile } = useAuth();
  const { toast } = useToast();
  const [approvers, setApprovers] = useState<Approver[]>([]);
  const [selectedApprover, setSelectedApprover] = useState('');
  const [reason, setReason] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (open) {
      fetchApprovers();
    }
  }, [open]);

  const fetchApprovers = async () => {
    const { data } = await supabase
      .from('profiles')
      .select('id, first_name, last_name, email, role')
      .in('role', ['manager', 'admin'])
      .neq('id', profile?.id);

    if (data) {
      setApprovers(data);
      if (data.length === 1) {
        setSelectedApprover(data[0].id);
      }
    }
  };

  const handleSubmit = async () => {
    if (!profile?.organization_id || !selectedApprover) return;

    setSubmitting(true);

    const config = approvalTypeConfig[approvalType];

    const { error } = await supabase.from('approval_requests').insert([{
      organization_id: profile.organization_id,
      entity_type: entityType,
      entity_id: entityId,
      entity_name: entityName,
      approval_type: approvalType,
      title: `${config.label} for ${entityName}`,
      description: config.description,
      reason: reason,
      requested_value: JSON.parse(JSON.stringify(requestedValue)),
      original_value: JSON.parse(JSON.stringify(originalValue)),
      requested_by: profile.id,
      assigned_to: selectedApprover,
      status: 'pending',
    }]);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Error',
        description: 'Failed to submit approval request',
      });
    } else {
      // Create notification for approver
      await supabase.from('notifications').insert([{
        organization_id: profile.organization_id,
        user_id: selectedApprover,
        title: `New Approval Request: ${config.label}`,
        message: `${profile.first_name} ${profile.last_name} has requested approval for ${entityName}`,
        type: 'approval',
        entity_type: entityType,
        entity_id: entityId,
        priority: 'high',
      }]);

      toast({
        title: 'Approval requested',
        description: 'Your request has been submitted for approval.',
      });
      onOpenChange(false);
      setReason('');
      setSelectedApprover('');
      onSuccess?.();
    }

    setSubmitting(false);
  };

  const config = approvalTypeConfig[approvalType];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {config.icon}
            {config.label}
          </DialogTitle>
          <DialogDescription>
            {config.description}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* Entity Info */}
          <div className="p-3 bg-muted rounded-lg">
            <div className="flex items-center gap-2 text-sm">
              <FileText className="h-4 w-4 text-muted-foreground" />
              <span className="font-medium">{entityName}</span>
              <Badge variant="secondary">{entityType}</Badge>
            </div>
          </div>

          {/* Value Comparison */}
          {(requestedValue.discount_percent !== undefined || requestedValue.total !== undefined) && (
            <div className="grid grid-cols-2 gap-4">
              <div className="p-3 bg-muted rounded-lg">
                <p className="text-xs text-muted-foreground mb-1">Original Value</p>
                <p className="font-medium">
                  {originalValue.discount_percent !== undefined
                    ? `${originalValue.discount_percent}% discount`
                    : typeof originalValue.total === 'number'
                    ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(originalValue.total)
                    : JSON.stringify(originalValue)
                  }
                </p>
              </div>
              <div className="p-3 bg-primary/10 rounded-lg border border-primary/20">
                <p className="text-xs text-muted-foreground mb-1">Requested Value</p>
                <p className="font-medium text-primary">
                  {requestedValue.discount_percent !== undefined
                    ? `${requestedValue.discount_percent}% discount`
                    : typeof requestedValue.total === 'number'
                    ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(requestedValue.total)
                    : JSON.stringify(requestedValue)
                  }
                </p>
              </div>
            </div>
          )}

          {/* Approver Selection */}
          <div className="space-y-2">
            <Label>Assign to Approver *</Label>
            <Select value={selectedApprover} onValueChange={setSelectedApprover}>
              <SelectTrigger>
                <SelectValue placeholder="Select approver" />
              </SelectTrigger>
              <SelectContent>
                {approvers.map((approver) => (
                  <SelectItem key={approver.id} value={approver.id}>
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4" />
                      <span>{approver.first_name} {approver.last_name}</span>
                      <Badge variant="secondary" className="ml-auto">
                        {approver.role}
                      </Badge>
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Reason */}
          <div className="space-y-2">
            <Label>Reason for Request *</Label>
            <Textarea
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Explain why this approval is needed..."
              rows={4}
            />
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={!selectedApprover || !reason || submitting}
          >
            {submitting ? (
              <RefreshCw className="mr-2 h-4 w-4 animate-spin" />
            ) : (
              <Clock className="mr-2 h-4 w-4" />
            )}
            Submit Request
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

// Pending Approvals Widget for Dashboard
export function PendingApprovalsWidget() {
  const { profile } = useAuth();
  const [approvals, setApprovals] = useState<Array<{
    id: string;
    title: string;
    entity_name: string;
    approval_type: ApprovalType;
    status: string;
    created_at: string;
    requester: {
      first_name: string | null;
      last_name: string | null;
    } | null;
  }>>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPendingApprovals();
  }, [profile]);

  const fetchPendingApprovals = async () => {
    if (!profile?.id) return;

    const { data, error } = await supabase
      .from('approval_requests')
      .select(`
        id,
        title,
        entity_name,
        approval_type,
        status,
        created_at,
        requester:profiles!approval_requests_requested_by_fkey(first_name, last_name)
      `)
      .eq('assigned_to', profile.id)
      .eq('status', 'pending')
      .order('created_at', { ascending: false })
      .limit(5);

    if (!error && data) {
      setApprovals(data as typeof approvals);
    }
    setLoading(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-8">
        <RefreshCw className="h-6 w-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (approvals.length === 0) {
    return (
      <div className="text-center py-8 text-muted-foreground">
        <CheckCircle className="h-8 w-8 mx-auto mb-2 opacity-50" />
        <p>No pending approvals</p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {approvals.map((approval) => {
        const config = approvalTypeConfig[approval.approval_type];
        return (
          <div
            key={approval.id}
            className="flex items-center gap-3 p-3 rounded-lg border bg-card hover:bg-muted/50 cursor-pointer"
          >
            <div className="p-2 bg-warning/10 rounded-lg">
              {config.icon}
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-medium truncate">{approval.title}</p>
              <p className="text-sm text-muted-foreground">
                From {approval.requester?.first_name} {approval.requester?.last_name}
              </p>
            </div>
            <Badge variant="secondary">
              <Clock className="mr-1 h-3 w-3" />
              Pending
            </Badge>
          </div>
        );
      })}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import {
  Upload,
  File,
  FileText,
  Image,
  Trash2,
  Download,
  Eye,
  MoreHorizontal,
  RefreshCw,
  X,
  Paperclip,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Attachment {
  id: string;
  file_name: string;
  file_path: string;
  file_size: number | null;
  file_type: string | null;
  mime_type: string | null;
  category: string | null;
  description: string | null;
  created_at: string;
  uploaded_by: string;
  uploader?: {
    first_name: string | null;
    last_name: string | null;
  } | null;
}

interface AttachmentsWidgetProps {
  entityType: string;
  entityId: string;
  accountId?: string;
  contactId?: string;
  leadId?: string;
  opportunityId?: string;
  quoteId?: string;
  contractId?: string;
}

const getFileIcon = (mimeType: string | null) => {
  if (!mimeType) return <File className="h-4 w-4" />;
  if (mimeType.startsWith('image/')) return <Image className="h-4 w-4" />;
  if (mimeType.includes('pdf') || mimeType.includes('document')) return <FileText className="h-4 w-4" />;
  return <File className="h-4 w-4" />;
};

const formatFileSize = (bytes: number | null) => {
  if (!bytes) return '-';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
};

export function AttachmentsWidget({
  entityType,
  entityId,
  accountId,
  contactId,
  leadId,
  opportunityId,
  quoteId,
  contractId,
}: AttachmentsWidgetProps) {
  const { profile } = useAuth();
  const { toast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [attachments, setAttachments] = useState<Attachment[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [previewAttachment, setPreviewAttachment] = useState<Attachment | null>(null);
  const [deleteAttachmentId, setDeleteAttachmentId] = useState<string | null>(null);
  const [dragActive, setDragActive] = useState(false);

  useEffect(() => {
    fetchAttachments();
  }, [entityType, entityId]);

  const fetchAttachments = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('attachments')
      .select(`
        *,
        uploader:profiles!attachments_uploaded_by_fkey(first_name, last_name)
      `)
      .eq('entity_type', entityType)
      .eq('entity_id', entityId)
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching attachments:', error);
    } else {
      setAttachments(data || []);
    }
    setLoading(false);
  };

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      await uploadFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      await uploadFiles(Array.from(e.target.files));
      e.target.value = '';
    }
  };

  const uploadFiles = async (files: File[]) => {
    if (!profile?.organization_id) return;

    setUploading(true);
    let successCount = 0;

    for (const file of files) {
      try {
        // Generate unique file path
        const fileExt = file.name.split('.').pop();
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const filePath = `${profile.organization_id}/${entityType}/${entityId}/${fileName}`;

        // Upload to storage
        const { error: uploadError } = await supabase.storage
          .from('attachments')
          .upload(filePath, file);

        if (uploadError) {
          console.error('Upload error:', uploadError);
          continue;
        }

        // Create attachment record
        const { error: dbError } = await supabase.from('attachments').insert([{
          organization_id: profile.organization_id,
          file_name: file.name,
          file_path: filePath,
          file_size: file.size,
          file_type: fileExt,
          mime_type: file.type,
          entity_type: entityType,
          entity_id: entityId,
          account_id: accountId,
          contact_id: contactId,
          lead_id: leadId,
          opportunity_id: opportunityId,
          quote_id: quoteId,
          contract_id: contractId,
          uploaded_by: profile.id,
        }]);

        if (dbError) {
          console.error('DB error:', dbError);
          // Try to clean up the uploaded file
          await supabase.storage.from('attachments').remove([filePath]);
        } else {
          successCount++;
        }
      } catch (err) {
        console.error('Error uploading file:', err);
      }
    }

    setUploading(false);

    if (successCount > 0) {
      toast({
        title: 'Arquivos enviados',
        description: `${successCount} arquivo(s) enviado(s) com sucesso.`,
      });
      fetchAttachments();
    } else {
      toast({
        variant: 'destructive',
        title: 'Falha no envio',
        description: 'Não foi possível enviar os arquivos. Tente novamente.',
      });
    }
  };

  const deleteAttachment = async (id: string) => {
    const attachment = attachments.find(a => a.id === id);
    if (!attachment) return;

    // Delete from storage
    await supabase.storage.from('attachments').remove([attachment.file_path]);

    // Delete from database
    const { error } = await supabase.from('attachments').delete().eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao excluir anexo',
      });
    } else {
      toast({
        title: 'Anexo excluído',
        description: 'O arquivo foi excluído com sucesso.',
      });
      fetchAttachments();
    }
    setDeleteAttachmentId(null);
  };

  const downloadAttachment = async (attachment: Attachment) => {
    const { data, error } = await supabase.storage
      .from('attachments')
      .download(attachment.file_path);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao baixar arquivo',
      });
      return;
    }

    // Create download link
    const url = URL.createObjectURL(data);
    const a = document.createElement('a');
    a.href = url;
    a.download = attachment.file_name;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const previewAttachmentFile = async (attachment: Attachment) => {
    const { data, error } = await supabase.storage
      .from('attachments')
      .createSignedUrl(attachment.file_path, 3600);

    if (error || !data) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao visualizar arquivo',
      });
      return;
    }

    setPreviewUrl(data.signedUrl);
    setPreviewAttachment(attachment);
  };

  const isPreviewable = (mimeType: string | null) => {
    if (!mimeType) return false;
    return mimeType.startsWith('image/') || mimeType === 'application/pdf';
  };

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Paperclip className="h-5 w-5" />
                Anexos
              </CardTitle>
              <CardDescription>
                {attachments.length} arquivo{attachments.length !== 1 ? 's' : ''} anexado{attachments.length !== 1 ? 's' : ''}
              </CardDescription>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => fileInputRef.current?.click()}
              disabled={uploading}
            >
              {uploading ? (
                <RefreshCw className="mr-2 h-4 w-4 animate-spin" />
              ) : (
                <Upload className="mr-2 h-4 w-4" />
              )}
              Enviar
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          <input
            ref={fileInputRef}
            type="file"
            multiple
            className="hidden"
            onChange={handleFileSelect}
            accept=".pdf,.doc,.docx,.xls,.xlsx,.jpg,.jpeg,.png,.gif,.webp,.txt,.csv"
          />

          {/* Drop Zone */}
          <div
            className={`border-2 border-dashed rounded-lg p-6 mb-4 transition-colors ${
              dragActive ? 'border-primary bg-primary/5' : 'border-muted'
            }`}
            onDragEnter={handleDrag}
            onDragLeave={handleDrag}
            onDragOver={handleDrag}
            onDrop={handleDrop}
          >
            <div className="flex flex-col items-center justify-center text-center">
              <Upload className="h-8 w-8 text-muted-foreground mb-2" />
              <p className="text-sm text-muted-foreground">
                Arraste e solte arquivos aqui, ou{' '}
                <button
                  type="button"
                  className="text-primary hover:underline"
                  onClick={() => fileInputRef.current?.click()}
                >
                  procure
                </button>
              </p>
              <p className="text-xs text-muted-foreground mt-1">
                PDF, Word, Excel, Imagens (máx. 50MB)
              </p>
            </div>
          </div>

          {/* Attachments List */}
          {loading ? (
            <div className="flex items-center justify-center py-8">
              <RefreshCw className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : attachments.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <Paperclip className="h-8 w-8 mx-auto mb-2 opacity-50" />
              <p>Nenhum anexo ainda</p>
            </div>
          ) : (
            <div className="space-y-2">
              {attachments.map((attachment) => (
                <div
                  key={attachment.id}
                  className="flex items-center gap-3 p-3 rounded-lg border bg-card hover:bg-muted/50 transition-colors"
                >
                  <div className="p-2 bg-muted rounded-lg">
                    {getFileIcon(attachment.mime_type)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">{attachment.file_name}</p>
                    <div className="flex items-center gap-2 text-xs text-muted-foreground">
                      <span>{formatFileSize(attachment.file_size)}</span>
                      <span>•</span>
                      <span>{format(new Date(attachment.created_at), "d 'de' MMM yyyy", { locale: ptBR })}</span>
                      {attachment.uploader && (
                        <>
                          <span>•</span>
                          <span>
                            {attachment.uploader.first_name} {attachment.uploader.last_name}
                          </span>
                        </>
                      )}
                    </div>
                  </div>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button variant="ghost" size="icon">
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      {isPreviewable(attachment.mime_type) && (
                        <DropdownMenuItem onClick={() => previewAttachmentFile(attachment)}>
                          <Eye className="mr-2 h-4 w-4" />
                          Visualizar
                        </DropdownMenuItem>
                      )}
                      <DropdownMenuItem onClick={() => downloadAttachment(attachment)}>
                        <Download className="mr-2 h-4 w-4" />
                        Baixar
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        className="text-destructive focus:text-destructive"
                        onClick={() => setDeleteAttachmentId(attachment.id)}
                      >
                        <Trash2 className="mr-2 h-4 w-4" />
                        Excluir
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Preview Dialog */}
      <Dialog open={!!previewUrl} onOpenChange={() => { setPreviewUrl(null); setPreviewAttachment(null); }}>
        <DialogContent className="max-w-4xl max-h-[90vh]">
          <DialogHeader>
            <DialogTitle>{previewAttachment?.file_name}</DialogTitle>
            <DialogDescription>
              {formatFileSize(previewAttachment?.file_size ?? null)} • {previewAttachment?.mime_type}
            </DialogDescription>
          </DialogHeader>
          <div className="flex-1 overflow-auto">
            {previewAttachment?.mime_type?.startsWith('image/') ? (
              <img
                src={previewUrl!}
                alt={previewAttachment.file_name}
                className="max-w-full h-auto mx-auto"
              />
            ) : previewAttachment?.mime_type === 'application/pdf' ? (
              <iframe
                src={previewUrl!}
                className="w-full h-[70vh]"
                title={previewAttachment.file_name}
              />
            ) : null}
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <AlertDialog open={!!deleteAttachmentId} onOpenChange={() => setDeleteAttachmentId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Excluir Anexo</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza de que deseja excluir este anexo? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deleteAttachmentId && deleteAttachment(deleteAttachmentId)}
            >
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

