    icon: Trash2,
    label: 'Exclusão',
    color: 'text-destructive',
    bgColor: 'bg-destructive/10',
    borderColor: 'border-destructive/30',
  },
};

const PAGE_SIZE = 15;

export function ChangeHistory({ entityType, entityId, className, maxHeight }: ChangeHistoryProps) {
  const { profile } = useAuth();
  const [page, setPage] = useState(0);
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
  const [filterUser, setFilterUser] = useState<string>('all');
  const [filterField, setFilterField] = useState<string>('all');

  const { data, isLoading, isFetching } = useQuery({
    queryKey: ['entity-change-history', entityType, entityId, page, filterUser, filterField],
    queryFn: async () => {
      const { data, error } = await supabase.rpc('get_entity_change_history', {
        p_entity_type: entityType,
        p_entity_id: entityId,
        p_limit: PAGE_SIZE,
        p_offset: page * PAGE_SIZE,
        p_changed_by: filterUser !== 'all' ? filterUser : null,
        p_field_filter: filterField !== 'all' ? filterField : null,
      });

      if (error) throw error;
      return (data || []) as ChangeRecord[];
    },
    enabled: !!entityId && !!profile?.organization_id,
    staleTime: STALE_TIMES.dynamic,
  });

  const records = data || [];
  const totalCount = records.length > 0 ? Number(records[0].total_count) : 0;
  const hasMore = (page + 1) * PAGE_SIZE < totalCount;

  // Collect unique users and fields for filters
  const uniqueUsers = Array.from(
    new Map(
      records
        .filter((r) => r.changed_by)
        .map((r) => [r.changed_by, { id: r.changed_by!, name: r.changed_by_name }])
    ).values()
  );

  const uniqueFields = Array.from(
    new Set(
      records.flatMap((r) => r.changes?.map((c) => c.field) || [])
    )
  );

  const toggleExpand = useCallback((id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  if (isLoading) {
    return (
      <div className={cn('space-y-4', className)}>
        {[...Array(3)].map((_, i) => (
          <div key={i} className="flex gap-4">
            <Skeleton className="h-10 w-10 rounded-full" />
            <div className="flex-1 space-y-2">
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-3 w-32" />
              <Skeleton className="h-16 w-full" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (records.length === 0 && page === 0) {
    return (
      <div className={cn('flex flex-col items-center justify-center py-8 text-muted-foreground', className)}>
        <Clock className="h-8 w-8 mb-2" />
        <p className="text-sm">Nenhuma alteração registrada</p>
      </div>
    );
  }

  return (
    <div className={cn('space-y-4', className)}>
      {/* Filters */}
      <div className="flex gap-2 flex-wrap">
        {uniqueUsers.length > 1 && (
          <Select value={filterUser} onValueChange={(v) => { setFilterUser(v); setPage(0); }}>
            <SelectTrigger className="w-[180px] h-8 text-xs">
              <User className="h-3 w-3 mr-1" />
              <SelectValue placeholder="Filtrar por usuário" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os usuários</SelectItem>
              {uniqueUsers.map((u) => (
                <SelectItem key={u.id} value={u.id}>{u.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        )}
        {uniqueFields.length > 1 && (
          <Select value={filterField} onValueChange={(v) => { setFilterField(v); setPage(0); }}>
            <SelectTrigger className="w-[180px] h-8 text-xs">
              <Filter className="h-3 w-3 mr-1" />
              <SelectValue placeholder="Filtrar por campo" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os campos</SelectItem>
              {uniqueFields.map((f) => (
                <SelectItem key={f} value={f}>{f.replace(/_/g, ' ')}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        )}
      </div>

      {/* Timeline */}
      <div className={cn('space-y-0', maxHeight && 'overflow-y-auto')} style={maxHeight ? { maxHeight } : undefined}>
        {records.map((record, index) => {
          const config = ACTION_CONFIG[record.action];
          const ActionIcon = config.icon;
          const isExpanded = expandedIds.has(record.id);
          const changesCount = record.changes?.length || 0;

          return (
            <div key={record.id} className="relative flex gap-4 pb-6">
              {/* Timeline line */}
              {index < records.length - 1 && (
                <div className="absolute left-5 top-12 bottom-0 w-px bg-border" />
              )}

              {/* Avatar */}
              <div className="relative z-10 shrink-0">
                <Avatar className="h-10 w-10 border-2 border-background">
                  <AvatarImage src={record.changed_by_avatar || ''} />
                  <AvatarFallback className={cn(config.bgColor, config.color, 'text-xs')}>
                    {record.changed_by_name
                      ? record.changed_by_name.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase()
                      : 'SYS'}
                  </AvatarFallback>
                </Avatar>
                <div className={cn(
                  'absolute -bottom-1 -right-1 h-5 w-5 rounded-full flex items-center justify-center border-2 border-background',
                  config.bgColor
                )}>
                  <ActionIcon className={cn('h-3 w-3', config.color)} />
                </div>
              </div>

              {/* Content */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="text-sm font-medium">{record.changed_by_name}</span>
                  <Badge variant="outline" className={cn('text-xs', config.borderColor, config.color)}>
                    {config.label}
                  </Badge>
                  {changesCount > 0 && record.action === 'update' && (
                    <span className="text-xs text-muted-foreground">
                      {changesCount} {changesCount === 1 ? 'campo' : 'campos'}
                    </span>
                  )}
                </div>
                <p className="text-xs text-muted-foreground mt-0.5">
                  {format(new Date(record.changed_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                  {' · '}
                  {formatDistanceToNow(new Date(record.changed_at), { addSuffix: true, locale: ptBR })}
                </p>

                {/* Changes */}
                {changesCount > 0 && (
                  <div className="mt-2">
                    {record.action === 'update' ? (
                      <div>
                        <button
                          onClick={() => toggleExpand(record.id)}
                          className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
                        >
                          <ChevronDown className={cn('h-3 w-3 transition-transform', isExpanded && 'rotate-180')} />
                          {isExpanded ? 'Ocultar detalhes' : 'Ver detalhes'}
                        </button>
                        {isExpanded && (
                          <div className="mt-2 space-y-2">
                            {record.changes.map((change, ci) => (
                              <DiffRow key={ci} change={change} />
                            ))}
                          </div>
                        )}
                      </div>
                    ) : record.action === 'create' ? (
                      <div>
                        <button
                          onClick={() => toggleExpand(record.id)}
                          className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
                        >
                          <ChevronDown className={cn('h-3 w-3 transition-transform', isExpanded && 'rotate-180')} />
                          {isExpanded ? 'Ocultar valores iniciais' : `Ver ${changesCount} valores iniciais`}
                        </button>
                        {isExpanded && (
                          <div className="mt-2 space-y-1">
                            {record.changes.slice(0, 20).map((change, ci) => (
                              <div key={ci} className="flex items-baseline gap-2 text-xs">
                                <span className="text-muted-foreground font-medium min-w-[120px]">
                                  {change.field_label}:
                                </span>
                                <span className="text-success">{truncate(change.new_value, 80)}</span>
                              </div>
                            ))}
                            {record.changes.length > 20 && (
                              <p className="text-xs text-muted-foreground">
                                ...e mais {record.changes.length - 20} campos
                              </p>
                            )}
                          </div>
                        )}
                      </div>
                    ) : (
                      <p className="text-xs text-destructive/80 mt-1">
                        Registro excluído com {changesCount} campos
                      </p>
                    )}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between text-xs text-muted-foreground">
        <span>
          {totalCount > 0
            ? `Mostrando ${page * PAGE_SIZE + 1}–${Math.min((page + 1) * PAGE_SIZE, totalCount)} de ${totalCount}`
            : ''}
        </span>
        <div className="flex gap-2">
          {page > 0 && (
            <Button variant="outline" size="sm" onClick={() => setPage(p => p - 1)} disabled={isFetching}>
              Anterior
            </Button>
          )}
          {hasMore && (
            <Button variant="outline" size="sm" onClick={() => setPage(p => p + 1)} disabled={isFetching}>
              Carregar Mais
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}

function DiffRow({ change }: { change: { field: string; old_value: string | null; new_value: string | null; field_label: string } }) {
  return (
    <div className="rounded-md border p-2.5 bg-muted/30">
      <p className="text-xs font-medium text-muted-foreground mb-1.5">
        {change.field_label}
      </p>
      <div className="flex flex-col gap-1">
        {change.old_value !== null && (
          <div className="flex items-start gap-2">
            <Minus className="h-3 w-3 mt-0.5 text-destructive shrink-0" />
            <span className="text-xs bg-destructive/10 text-destructive rounded px-1.5 py-0.5 break-all">
              {truncate(change.old_value, 200)}
            </span>
          </div>
        )}
        {change.new_value !== null && (
          <div className="flex items-start gap-2">
            <Plus className="h-3 w-3 mt-0.5 text-success shrink-0" />
            <span className="text-xs bg-success/10 text-success rounded px-1.5 py-0.5 break-all">
              {truncate(change.new_value, 200)}
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

function truncate(value: string | null, max: number): string {
  if (!value) return '(vazio)';
  return value.length > max ? value.slice(0, max) + '…' : value;
}

import { useState, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion';
import { Calendar } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { CalendarIcon, Save, Loader2 } from '@/components/icons';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { cn } from '@/lib/utils';
import {
  useCustomFieldDefinitions,
  useCustomFieldValues,
  useSaveCustomFieldValues,
  getFieldValue,
  validateFieldValue,
  type CustomFieldDefinition,
  type CustomFieldEntityType,
} from '@/hooks/useCustomFields';

// Autonomous mode: fetches its own data and manages save internally
interface AutonomousProps {
  entityType: CustomFieldEntityType;
  entityId?: string;
  readOnly?: boolean;
  compact?: boolean;
  className?: string;
  // Discriminator: controlled props absent
  definitions?: undefined;
  values?: undefined;
  onChange?: undefined;
}

// Controlled mode: receives data from parent, parent handles save
interface ControlledProps {
  entityType: CustomFieldEntityType;
  definitions: CustomFieldDefinition[];
  values: Record<string, any>;
  onChange: (values: Record<string, any>) => void;
  readOnly?: boolean;
  compact?: boolean;
  className?: string;
  // Not used in controlled mode
  entityId?: undefined;
}

type CustomFieldsRendererProps = AutonomousProps | ControlledProps;

function isControlledMode(props: CustomFieldsRendererProps): props is ControlledProps {
  return props.definitions !== undefined && props.onChange !== undefined;
}

export function CustomFieldsRenderer(props: CustomFieldsRendererProps) {
  const {
    entityType,
    readOnly = false,
    compact = false,
    className,
  } = props;

  const controlled = isControlledMode(props);

  // --- Autonomous mode hooks (always called for hooks consistency) ---
  const { data: autoDefs = [], isLoading: defsLoading } = useCustomFieldDefinitions(entityType);
  const { data: autoValues = [], isLoading: valsLoading } = useCustomFieldValues(
    entityType,
    controlled ? undefined : props.entityId
  );
  const saveMutation = useSaveCustomFieldValues();

  // Resolve which definitions/values to use
  const definitions: CustomFieldDefinition[] = controlled ? props.definitions : autoDefs;
  const entityId = controlled ? undefined : props.entityId;

  const [fieldValues, setFieldValues] = useState<Record<string, any>>({});
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isDirty, setIsDirty] = useState(false);

  // Initialize values for autonomous mode
  useEffect(() => {
    if (controlled) return;
    if (autoDefs.length > 0) {
      const initial: Record<string, any> = {};
      autoDefs.forEach((def) => {
        const fieldValue = autoValues.find((v) => v.field_definition_id === def.id);
        initial[def.id] = getFieldValue(def, fieldValue);
      });
      setFieldValues(initial);
      setIsDirty(false);
    }
  }, [controlled, autoDefs, autoValues]);

  // Sync controlled values
  useEffect(() => {
    if (controlled) {
      setFieldValues(props.values);
    }
  }, [controlled, controlled ? props.values : null]);

  const updateValue = (fieldId: string, value: any) => {
    if (controlled) {
      props.onChange({ ...props.values, [fieldId]: value });
    } else {
      setFieldValues((prev) => ({ ...prev, [fieldId]: value }));
      setIsDirty(true);
    }

    // Clear error on change
    setErrors((prev) => {
      const next = { ...prev };
      delete next[fieldId];
      return next;
    });
  };

  const handleSave = () => {
    if (controlled || !entityId) return;

    // Validate all fields
    const newErrors: Record<string, string> = {};
    definitions.forEach((def) => {
      const error = validateFieldValue(def, fieldValues[def.id]);
      if (error) newErrors[def.id] = error;
    });

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    saveMutation.mutate({
      entityType,
      entityId,
      values: fieldValues,
      definitions,
    });
    setIsDirty(false);
  };

  // Loading only applies to autonomous mode
  if (!controlled && (defsLoading || (entityId && valsLoading))) {
    return (
      <div className={cn('space-y-4', className)}>
        <Skeleton className="h-6 w-48" />
        <div className="grid gap-4 sm:grid-cols-2">
          <Skeleton className="h-10" />
          <Skeleton className="h-10" />
          <Skeleton className="h-10" />
        </div>
      </div>
    );
  }

  if (definitions.length === 0) return null;

  // Group by section_name
  const sections = definitions.reduce<Record<string, CustomFieldDefinition[]>>((acc, def) => {
    const section = def.section_name || 'Campos Personalizados';
    if (!acc[section]) acc[section] = [];
    acc[section].push(def);
    return acc;
  }, {});

  const sectionKeys = Object.keys(sections);

  const renderField = (def: CustomFieldDefinition) => {
    const value = fieldValues[def.id];
    const error = errors[def.id];

    if (readOnly) {
      return (
        <div key={def.id} className="space-y-1">
          <Label className="text-xs text-muted-foreground">{def.field_label}</Label>
          <p className="text-sm">{formatDisplayValue(def, value)}</p>
        </div>
      );
    }

    return (
      <div key={def.id} className="space-y-1.5">
        <Label htmlFor={def.id} className="text-sm font-medium">
          {def.field_label}
          {def.is_required && <span className="text-destructive ml-1">*</span>}
        </Label>
        {def.description && (
          <p className="text-xs text-muted-foreground">{def.description}</p>
        )}
        {renderFieldInput(def, value, (v: any) => updateValue(def.id, v))}
        {error && <p className="text-xs text-destructive">{error}</p>}
      </div>
    );
  };

  return (
    <div className={cn('space-y-4', className)}>
      {sectionKeys.length === 1 ? (
        <div>
          <h4 className="text-sm font-medium text-muted-foreground mb-3">
            {sectionKeys[0]}
          </h4>
          <div className={cn('grid gap-4', compact ? 'sm:grid-cols-1' : 'sm:grid-cols-2')}>
            {sections[sectionKeys[0]].map(renderField)}
          </div>
        </div>
      ) : (
        <Accordion type="multiple" defaultValue={sectionKeys} className="w-full">
          {sectionKeys.map((section) => (
            <AccordionItem key={section} value={section}>
              <AccordionTrigger className="text-sm font-medium">
                {section}
                <Badge variant="secondary" className="ml-2 text-xs">
                  {sections[section].length}
                </Badge>
              </AccordionTrigger>
              <AccordionContent>
                <div className={cn('grid gap-4 pt-2', compact ? 'sm:grid-cols-1' : 'sm:grid-cols-2')}>
                  {sections[section].map(renderField)}
                </div>
              </AccordionContent>
            </AccordionItem>
          ))}
        </Accordion>
      )}

      {!readOnly && !controlled && entityId && isDirty && (
        <div className="flex justify-end pt-2">
          <Button
            size="sm"
            onClick={handleSave}
            disabled={saveMutation.isPending}
          >
            {saveMutation.isPending ? (
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            ) : (
              <Save className="mr-2 h-4 w-4" />
            )}
            Salvar Campos Personalizados
          </Button>
        </div>
      )}
    </div>
  );
}

function renderFieldInput(
  def: CustomFieldDefinition,
  value: any,
  onChange: (value: any) => void
) {
  switch (def.field_type) {
    case 'text':
    case 'email':
    case 'phone':
    case 'url':
      return (
        <Input
          id={def.id}
          type={def.field_type === 'email' ? 'email' : def.field_type === 'url' ? 'url' : 'text'}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          placeholder={def.placeholder || ''}
        />
      );

    case 'number':
    case 'decimal':
      return (
        <Input
          id={def.id}
          type="number"
          step={def.field_type === 'decimal' ? '0.01' : '1'}
          value={value ?? ''}
          onChange={(e) => onChange(e.target.value ? Number(e.target.value) : null)}
          placeholder={def.placeholder || ''}
        />
      );

    case 'textarea':
      return (
        <Textarea
          id={def.id}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          placeholder={def.placeholder || ''}
          rows={3}
        />
      );

    case 'boolean':
      return (
        <div className="flex items-center gap-2 pt-1">
          <Checkbox
            id={def.id}
            checked={!!value}
            onCheckedChange={(checked) => onChange(!!checked)}
          />
          <Label htmlFor={def.id} className="text-sm cursor-pointer">
            {def.placeholder || 'Sim'}
          </Label>
        </div>
      );

    case 'select':
      return (
        <Select value={value || ''} onValueChange={onChange}>
          <SelectTrigger>
            <SelectValue placeholder={def.placeholder || 'Selecione...'} />
          </SelectTrigger>
          <SelectContent>
            {def.options.map((opt: any) => (
              <SelectItem key={opt.value} value={opt.value}>
                {opt.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      );

    case 'multiselect': {
      const selected: string[] = Array.isArray(value) ? value : [];
      return (
        <div className="flex flex-wrap gap-2">
          {def.options.map((opt: any) => {
            const isSelected = selected.includes(opt.value);
            return (
              <Badge
                key={opt.value}
                variant={isSelected ? 'default' : 'outline'}
                className="cursor-pointer select-none"
                onClick={() => {
                  if (isSelected) {
                    onChange(selected.filter((v: string) => v !== opt.value));
                  } else {
                    onChange([...selected, opt.value]);
                  }
                }}
              >
                {opt.label}
              </Badge>
            );
          })}
        </div>
      );
    }

    case 'date':
    case 'datetime':
      return (
        <Popover>
          <PopoverTrigger asChild>
            <Button
              variant="outline"
              className={cn(
                'w-full justify-start text-left font-normal',
                !value && 'text-muted-foreground'
              )}
            >
              <CalendarIcon className="mr-2 h-4 w-4" />
              {value
                ? format(new Date(value), def.field_type === 'datetime' ? 'dd/MM/yyyy HH:mm' : 'dd/MM/yyyy', { locale: ptBR })
                : def.placeholder || 'Selecionar data'}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar
              mode="single"
              selected={value ? new Date(value) : undefined}
              onSelect={(date) => onChange(date?.toISOString() || null)}
              locale={ptBR}
            />
          </PopoverContent>
        </Popover>
      );

    default:
      return (
        <Input
          id={def.id}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          placeholder={def.placeholder || ''}
        />
      );
  }
}

function formatDisplayValue(def: CustomFieldDefinition, value: any): string {
  if (value === null || value === undefined || value === '') return '—';

  switch (def.field_type) {
    case 'boolean':
      return value ? 'Sim' : 'Não';
    case 'date':
      return format(new Date(value), 'dd/MM/yyyy', { locale: ptBR });
    case 'datetime':
      return format(new Date(value), 'dd/MM/yyyy HH:mm', { locale: ptBR });
    case 'number':
      return Number(value).toLocaleString('pt-BR');
    case 'decimal':
      return Number(value).toLocaleString('pt-BR', { minimumFractionDigits: 2 });
    case 'select': {
      const opt = def.options.find((o: any) => o.value === value);
      return opt?.label || value;
    }
    case 'multiselect': {
      if (!Array.isArray(value)) return '—';
      return value
        .map((v: string) => {
          const opt = def.options.find((o: any) => o.value === v);
          return opt?.label || v;
        })
        .join(', ');
    }
    default:
      return String(value);
  }
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import {
  Loader2,
  ArrowRight,
  Building2,
  User,
  Target,
  CheckCircle,
  AlertTriangle,
  Search,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/hooks/useAuth';

interface Lead {
  id: string;
  first_name: string;
  last_name: string;
  email: string | null;
  phone: string | null;
  mobile: string | null;
  company: string | null;
  job_title: string | null;
  industry: string | null;
  website: string | null;
  address_street: string | null;
  address_city: string | null;
  address_state: string | null;
  address_postal_code: string | null;
  address_country: string | null;
  description: string | null;
  source: string | null;
}

interface LeadConversionWizardProps {
  lead: Lead;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onConverted: () => void;
}

interface DuplicateAccount {
  id: string;
  name: string;
  website: string | null;
  email: string | null;
}

const conversionSchema = z.object({
  // Account
  createAccount: z.boolean().default(true),
  accountName: z.string().min(1, 'Nome da conta é obrigatório'),
  accountIndustry: z.string().optional(),
  accountWebsite: z.string().optional(),
  useExistingAccount: z.boolean().default(false),
  existingAccountId: z.string().optional(),

  // Contact
  createContact: z.boolean().default(true),
  contactFirstName: z.string().min(1, 'Nome é obrigatório'),
  contactLastName: z.string().min(1, 'Sobrenome é obrigatório'),
  contactEmail: z.string().optional(),
  contactPhone: z.string().optional(),
  contactJobTitle: z.string().optional(),

  // Opportunity
  createOpportunity: z.boolean().default(true),
  opportunityName: z.string().min(1, 'Nome da oportunidade é obrigatório'),
  opportunityAmount: z.coerce.number().min(0).optional(),
  opportunityDescription: z.string().optional(),
});

type ConversionFormData = z.infer<typeof conversionSchema>;

export function LeadConversionWizard({ 
  lead, 
  open, 
  onOpenChange, 
  onConverted 
}: LeadConversionWizardProps) {
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [loading, setLoading] = useState(false);
  const [duplicateAccounts, setDuplicateAccounts] = useState<DuplicateAccount[]>([]);
  const [checkingDuplicates, setCheckingDuplicates] = useState(false);
  const [conversionResult, setConversionResult] = useState<{
    accountId: string;
    contactId: string;
    opportunityId?: string;
  } | null>(null);

  const form = useForm<ConversionFormData>({
    resolver: zodResolver(conversionSchema),
    defaultValues: {
      createAccount: true,
      accountName: lead.company || `${lead.first_name} ${lead.last_name}`,
      accountIndustry: lead.industry || '',
      accountWebsite: lead.website || '',
      useExistingAccount: false,
      existingAccountId: '',

      createContact: true,
      contactFirstName: lead.first_name,
      contactLastName: lead.last_name,
      contactEmail: lead.email || '',
      contactPhone: lead.phone || lead.mobile || '',
      contactJobTitle: lead.job_title || '',

      createOpportunity: true,
      opportunityName: `${lead.company || lead.first_name} - Nova Oportunidade`,
      opportunityAmount: 0,
      opportunityDescription: lead.description || '',
    },
  });

  const useExistingAccount = form.watch('useExistingAccount');
  const createOpportunity = form.watch('createOpportunity');

  const checkForDuplicates = async () => {
    setCheckingDuplicates(true);

    const searchTerms = [
      lead.company,
      lead.email,
      lead.website,
    ].filter(Boolean);

    if (searchTerms.length === 0) {
      setCheckingDuplicates(false);
      return;
    }

    // Search for potential duplicate accounts
    let query = supabase
      .from('accounts')
      .select('id, name, website, email');

    if (lead.company) {
      query = query.or(`name.ilike.%${lead.company}%`);
    }
    if (lead.email) {
      query = query.or(`email.ilike.%${lead.email}%`);
    }
    if (lead.website) {
      query = query.or(`website.ilike.%${lead.website}%`);
    }

    const { data } = await query.limit(5);

    if (data && data.length > 0) {
      setDuplicateAccounts(data);
    }

    setCheckingDuplicates(false);
  };

  const handleNext = () => {
    if (step === 1) {
      checkForDuplicates();
      setStep(2);
    } else if (step === 2) {
      setStep(3);
    }
  };

  const handleBack = () => {
    if (step === 2) setStep(1);
    else if (step === 3) setStep(2);
  };

  const onSubmit = async (data: ConversionFormData) => {
    if (!profile?.organization_id) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Você deve fazer parte de uma organização para converter leads.',
      });
      return;
    }

    setLoading(true);

    try {
      let accountId: string;

      // Step 1: Create or use existing Account
      if (data.useExistingAccount && data.existingAccountId) {
        accountId = data.existingAccountId;
      } else {
        const { data: accountData, error: accountError } = await supabase
          .from('accounts')
          .insert([{
            name: data.accountName,
            industry: data.accountIndustry || null,
            website: data.accountWebsite || null,
            email: lead.email,
            phone: lead.phone,
            address_street: lead.address_street,
            address_city: lead.address_city,
            address_state: lead.address_state,
            address_postal_code: lead.address_postal_code,
            address_country: lead.address_country,
            source: lead.source,
            organization_id: profile.organization_id,
            owner_id: profile.id,
          }])
          .select()
          .single();

        if (accountError) throw accountError;
        accountId = accountData.id;
      }

      // Step 2: Create Contact
      const { data: contactData, error: contactError } = await supabase
        .from('contacts')
        .insert([{
          first_name: data.contactFirstName,
          last_name: data.contactLastName,
          email: data.contactEmail || null,
          phone: data.contactPhone || null,
          job_title: data.contactJobTitle || null,
          account_id: accountId,
          organization_id: profile.organization_id,
          owner_id: profile.id,
        }])
        .select()
        .single();

      if (contactError) throw contactError;
      const contactId = contactData.id;

      // Step 3: Create Opportunity (optional)
      let opportunityId: string | undefined;
      if (data.createOpportunity) {
        const { data: oppData, error: oppError } = await supabase
          .from('opportunities')
          .insert([{
            name: data.opportunityName,
            amount: data.opportunityAmount || 0,
            description: data.opportunityDescription || null,
            account_id: accountId,
            stage: 'prospecting',
            source: lead.source,
            organization_id: profile.organization_id,
            owner_id: profile.id,
          }])
          .select()
          .single();

        if (oppError) throw oppError;
        opportunityId = oppData.id;

        // Link contact to opportunity
        await supabase
          .from('opportunity_contacts')
          .insert([{
            opportunity_id: opportunityId,
            contact_id: contactId,
            is_primary: true,
            role: 'decision_maker',
          }]);
      }

      // Step 4: Update Lead status to converted
      const { error: leadError } = await supabase
        .from('leads')
        .update({
          status: 'converted',
          converted_at: new Date().toISOString(),
          converted_account_id: accountId,
          converted_contact_id: contactId,
          converted_opportunity_id: opportunityId || null,
        })
        .eq('id', lead.id);

      if (leadError) throw leadError;

      // Step 5: Create timeline event
      await supabase
        .from('timeline_events')
        .insert([{
          organization_id: profile.organization_id,
          event_type: 'lead_converted',
          title: 'Lead converted',
          description: `Lead "${lead.first_name} ${lead.last_name}" was converted to Account, Contact${opportunityId ? ', and Opportunity' : ''}.`,
          lead_id: lead.id,
          account_id: accountId,
          contact_id: contactId,
          opportunity_id: opportunityId || null,
          created_by: profile.id,
          metadata: {
            lead_name: `${lead.first_name} ${lead.last_name}`,
            account_name: data.accountName,
            opportunity_name: data.createOpportunity ? data.opportunityName : null,
          },
        }]);

      // Transfer notes from lead to account/contact
      const { data: notes } = await supabase
        .from('notes')
        .select('*')
        .eq('lead_id', lead.id);

      if (notes && notes.length > 0) {
        const updatedNotes = notes.map(note => ({
          ...note,
          id: undefined, // Let Supabase generate new IDs
          account_id: accountId,
          contact_id: contactId,
          lead_id: null,
        }));
        await supabase.from('notes').insert(updatedNotes);
      }

      setConversionResult({
        accountId,
        contactId,
        opportunityId,
      });

      toast({
        title: 'Lead convertido com sucesso!',
        description: `Conta${opportunityId ? ', Contato e Oportunidade criados' : ' e Contato criados'}.`,
      });

      setStep(3);
      onConverted();

    } catch (error: any) {
      console.error('Error converting lead:', error);
      toast({
        variant: 'destructive',
        title: 'Falha na conversão',
        description: error.message || 'Falha ao converter lead. Tente novamente.',
      });
    } finally {
      setLoading(false);
    }
  };

  const renderStep1 = () => (
    <div className="space-y-6">
      <div className="flex items-center gap-4 p-4 bg-muted/50 rounded-lg">
        <div className="p-2 bg-primary/10 rounded-full">
          <User className="h-6 w-6 text-primary" />
        </div>
        <div>
          <p className="font-medium">{lead.first_name} {lead.last_name}</p>
          <p className="text-sm text-muted-foreground">
            {lead.job_title && lead.company 
              ? `${lead.job_title} na ${lead.company}`
              : lead.company || lead.job_title || 'Sem empresa'}
          </p>
        </div>
      </div>

      <Separator />

      {/* Account Section */}
      <div className="space-y-4">
        <div className="flex items-center gap-2">
          <Building2 className="h-5 w-5 text-muted-foreground" />
          <h3 className="font-medium">Conta</h3>
        </div>

        <FormField
          control={form.control}
          name="useExistingAccount"
          render={({ field }) => (
            <FormItem className="flex items-center space-x-2 space-y-0">
              <FormControl>
                <Checkbox
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
              <FormLabel className="font-normal">
                Vincular a conta existente
              </FormLabel>
            </FormItem>
          )}
        />

        {useExistingAccount ? (
          <FormField
            control={form.control}
            name="existingAccountId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Selecionar Conta</FormLabel>
                <Select
                  value={field.value}
                  onValueChange={field.onChange}
                >
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Buscar e selecionar conta..." />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    {duplicateAccounts.map((acc) => (
                      <SelectItem key={acc.id} value={acc.id}>
                        {acc.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />
        ) : (
          <>
            <FormField
              control={form.control}
              name="accountName"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Nome da Conta *</FormLabel>
                  <FormControl>
                    <Input {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <div className="grid gap-4 md:grid-cols-2">
              <FormField
                control={form.control}
                name="accountIndustry"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Indústria</FormLabel>
                    <FormControl>
                      <Input {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="accountWebsite"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Website</FormLabel>
                    <FormControl>
                      <Input {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
          </>
        )}
      </div>

      <Separator />

      {/* Contact Section */}
      <div className="space-y-4">
        <div className="flex items-center gap-2">
          <User className="h-5 w-5 text-muted-foreground" />
          <h3 className="font-medium">Contato</h3>
        </div>

        <div className="grid gap-4 md:grid-cols-2">
          <FormField
            control={form.control}
            name="contactFirstName"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Nome *</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="contactLastName"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Sobrenome *</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
        </div>

        <div className="grid gap-4 md:grid-cols-2">
          <FormField
            control={form.control}
            name="contactEmail"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Email</FormLabel>
                <FormControl>
                  <Input type="email" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
          <FormField
            control={form.control}
            name="contactPhone"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Telefone</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
        </div>

        <FormField
          control={form.control}
          name="contactJobTitle"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Cargo</FormLabel>
              <FormControl>
                <Input {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
      </div>
    </div>
  );

  const renderStep2 = () => (
    <div className="space-y-6">
      {/* Duplicate Warning */}
      {duplicateAccounts.length > 0 && !useExistingAccount && (
        <Card className="border-warning">
          <CardHeader className="pb-3">
            <CardTitle className="flex items-center gap-2 text-warning">
              <AlertTriangle className="h-5 w-5" />
              Possíveis Duplicatas Encontradas
            </CardTitle>
            <CardDescription>
              Encontramos {duplicateAccounts.length} conta(s) que podem ser duplicadas.
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-2">
            {duplicateAccounts.map((acc) => (
              <div 
                key={acc.id}
                className="flex items-center justify-between p-3 border rounded-lg"
              >
                <div>
                  <p className="font-medium">{acc.name}</p>
                  <p className="text-sm text-muted-foreground">{acc.email || acc.website}</p>
                </div>
                <Button 
                  variant="outline" 
                  size="sm"
                  onClick={() => {
                    form.setValue('useExistingAccount', true);
                    form.setValue('existingAccountId', acc.id);
                    setStep(1);
                  }}
                >
                  Usar esta conta
                </Button>
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      {/* Opportunity Section */}
      <div className="space-y-4">
        <div className="flex items-center gap-2">
          <Target className="h-5 w-5 text-muted-foreground" />
          <h3 className="font-medium">Oportunidade</h3>
        </div>

        <FormField
          control={form.control}
          name="createOpportunity"
          render={({ field }) => (
            <FormItem className="flex items-center space-x-2 space-y-0">
              <FormControl>
                <Checkbox
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
              <FormLabel className="font-normal">
                Criar uma oportunidade para esta conversão
              </FormLabel>
            </FormItem>
          )}
        />

        {createOpportunity && (
          <div className="space-y-4 pl-6 border-l-2 border-muted">
            <FormField
              control={form.control}
              name="opportunityName"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Nome da Oportunidade *</FormLabel>
                  <FormControl>
                    <Input {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="opportunityAmount"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Valor</FormLabel>
                  <FormControl>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                        R$
                      </span>
                      <Input 
                        type="number" 
                        step="0.01"
                        min="0"
                        className="pl-9"
                        {...field}
                        value={field.value || ''} 
                      />
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="opportunityDescription"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Descrição</FormLabel>
                  <FormControl>
                    <Textarea 
                      {...field} 
                      className="min-h-[80px]"
                      placeholder="Detalhes adicionais sobre esta oportunidade..."
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>
        )}
      </div>

      {/* Summary */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">Resumo da Conversão</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          <div className="flex items-center gap-2">
            <CheckCircle className="h-4 w-4 text-success" />
            <span className="text-sm">
              {useExistingAccount ? 'Vincular a conta existente' : 'Criar nova conta'}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <CheckCircle className="h-4 w-4 text-success" />
            <span className="text-sm">Criar novo contato</span>
          </div>
          {createOpportunity && (
            <div className="flex items-center gap-2">
              <CheckCircle className="h-4 w-4 text-success" />
              <span className="text-sm">Criar nova oportunidade</span>
            </div>
          )}
          <div className="flex items-center gap-2">
            <CheckCircle className="h-4 w-4 text-success" />
            <span className="text-sm">Marcar lead como convertido</span>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const renderStep3 = () => (
    <div className="space-y-6 text-center">
      <div className="flex justify-center">
        <div className="p-4 bg-success/10 rounded-full">
          <CheckCircle className="h-12 w-12 text-success" />
        </div>
      </div>

      <div>
        <h3 className="text-xl font-semibold">Conversão Concluída!</h3>
        <p className="text-muted-foreground mt-2">
          O lead foi convertido com sucesso.
        </p>
      </div>

      {conversionResult && (
        <div className="space-y-3">
          <Button
            variant="outline"
            className="w-full justify-start"
            onClick={() => navigate(`/accounts/${conversionResult.accountId}`)}
          >
            <Building2 className="mr-2 h-4 w-4" />
            Ver Conta
          </Button>
          <Button
            variant="outline"
            className="w-full justify-start"
            onClick={() => navigate(`/contacts/${conversionResult.contactId}`)}
          >
            <User className="mr-2 h-4 w-4" />
            Ver Contato
          </Button>
          {conversionResult.opportunityId && (
            <Button
              variant="outline"
              className="w-full justify-start"
              onClick={() => navigate(`/opportunities/${conversionResult.opportunityId}`)}
            >
              <Target className="mr-2 h-4 w-4" />
              Ver Oportunidade
            </Button>
          )}
        </div>
      )}

      <Button onClick={() => onOpenChange(false)} className="w-full">
        Fechar
      </Button>
    </div>
  );

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Converter Lead</DialogTitle>
          <DialogDescription>
            Converta este lead em Conta, Contato e, opcionalmente, uma Oportunidade.
          </DialogDescription>
        </DialogHeader>

        {/* Progress Steps */}
        <div className="flex items-center justify-center gap-2 py-4">
          <Badge variant={step >= 1 ? 'default' : 'outline'}>1. Detalhes</Badge>
          <ArrowRight className="h-4 w-4 text-muted-foreground" />
          <Badge variant={step >= 2 ? 'default' : 'outline'}>2. Revisão</Badge>
          <ArrowRight className="h-4 w-4 text-muted-foreground" />
          <Badge variant={step >= 3 ? 'default' : 'outline'}>3. Concluído</Badge>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)}>
            {step === 1 && renderStep1()}
            {step === 2 && renderStep2()}
            {step === 3 && renderStep3()}

            {step < 3 && (
              <div className="flex justify-between pt-6">
                <Button
                  type="button"
                  variant="outline"
                  onClick={step === 1 ? () => onOpenChange(false) : handleBack}
                >
                  {step === 1 ? 'Cancelar' : 'Voltar'}
                </Button>

                {step === 1 ? (
                  <Button type="button" onClick={handleNext}>
                    Próximo
                    <ArrowRight className="ml-2 h-4 w-4" />
                  </Button>
                ) : (
                  <Button type="submit" disabled={loading}>
                    {loading ? (
                      <>
                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                        Convertendo...
                      </>
                    ) : (
                      <>
                        <CheckCircle className="mr-2 h-4 w-4" />
                        Converter Lead
                      </>
                    )}
                  </Button>
                )}
              </div>
            )}
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import {
  Plus,
  Trash2,
  Edit,
  Save,
  X,
  RefreshCw,
  Settings,
  Zap,
  Users,
  MapPin,
  Target,
  RotateCcw,
  GripVertical,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

type RuleType = 'round_robin' | 'territory' | 'segment' | 'load_balance' | 'skill_based' | 'priority';

interface RoutingRule {
  id: string;
  name: string;
  description: string | null;
  rule_type: RuleType;
  entity_type: string;
  conditions: unknown[];
  actions: Record<string, unknown>;
  target_user_ids: string[] | null;
  target_team_id: string | null;
  target_territory_id: string | null;
  priority: number;
  is_active: boolean;
  is_default: boolean;
  created_at: string;
}

interface User {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string;
}

interface Team {
  id: string;
  name: string;
}

interface Territory {
  id: string;
  name: string;
  region: string | null;
}

interface RuleForm {
  name: string;
  description: string;
  rule_type: RuleType;
  entity_type: string;
  target_user_ids: string[];
  target_team_id: string;
  target_territory_id: string;
  priority: string;
  is_active: boolean;
  is_default: boolean;
  conditions: Array<{
    field: string;
    operator: string;
    value: string;
  }>;
}

const initialForm: RuleForm = {
  name: '',
  description: '',
  rule_type: 'round_robin',
  entity_type: 'lead',
  target_user_ids: [],
  target_team_id: '',
  target_territory_id: '',
  priority: '100',
  is_active: true,
  is_default: false,
  conditions: [],
};

const ruleTypeConfig: Record<RuleType, { label: string; icon: React.ReactNode; description: string }> = {
  round_robin: {
    label: 'Round Robin',
    icon: <RotateCcw className="h-4 w-4" />,
    description: 'Distribui leads igualmente entre usuários selecionados',
  },
  territory: {
    label: 'Por Território',
    icon: <MapPin className="h-4 w-4" />,
    description: 'Direciona baseado na localização geográfica',
  },
  segment: {
    label: 'Por Segmento',
    icon: <Target className="h-4 w-4" />,
    description: 'Direciona baseado nas características do lead',
  },
  load_balance: {
    label: 'Balanceamento de Carga',
    icon: <Zap className="h-4 w-4" />,
    description: 'Distribui baseado na carga de trabalho atual',
  },
  skill_based: {
    label: 'Por Habilidade',
    icon: <Users className="h-4 w-4" />,
    description: 'Direciona para usuários com habilidades compatíveis',
  },
  priority: {
    label: 'Prioridade',
    icon: <Target className="h-4 w-4" />,
    description: 'Direciona leads de alto valor para top performers',
  },
};

const conditionFields = [
  { value: 'source', label: 'Origem do Lead' },
  { value: 'industry', label: 'Segmento' },
  { value: 'company', label: 'Empresa' },
  { value: 'score', label: 'Pontuação do Lead' },
  { value: 'address_state', label: 'Estado' },
  { value: 'address_country', label: 'País' },
];

const conditionOperators = [
  { value: 'equals', label: 'Igual a' },
  { value: 'not_equals', label: 'Diferente de' },
  { value: 'contains', label: 'Contém' },
  { value: 'greater_than', label: 'Maior que' },
  { value: 'less_than', label: 'Menor que' },
];

const entityTypeLabels: Record<string, string> = {
  lead: 'Lead',
  opportunity: 'Oportunidade',
  ticket: 'Ticket',
  account: 'Conta',
};

export function LeadRoutingRules() {
  const { profile } = useAuth();
  const { toast } = useToast();
  const [rules, setRules] = useState<RoutingRule[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [teams, setTeams] = useState<Team[]>([]);
  const [territories, setTerritories] = useState<Territory[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingRule, setEditingRule] = useState<RoutingRule | null>(null);
  const [deleteRuleId, setDeleteRuleId] = useState<string | null>(null);
  const [form, setForm] = useState<RuleForm>(initialForm);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchRules();
    fetchUsers();
    fetchTeams();
    fetchTerritories();
  }, [profile?.organization_id]);

  const fetchRules = async () => {
    if (!profile?.organization_id) return;

    setLoading(true);
    const { data, error } = await supabase
      .from('routing_rules')
      .select('*')
      .eq('organization_id', profile.organization_id)
      .order('priority');

    if (!error && data) {
      setRules(data as unknown as RoutingRule[]);
    }
    setLoading(false);
  };

  const fetchUsers = async () => {
    const { data } = await supabase
      .from('profiles')
      .select('id, first_name, last_name, email')
      .order('first_name');
    if (data) setUsers(data);
  };

  const fetchTeams = async () => {
    const { data } = await supabase
      .from('teams')
      .select('id, name')
      .order('name');
    if (data) setTeams(data);
  };

  const fetchTerritories = async () => {
    const { data } = await supabase
      .from('territories')
      .select('id, name, region')
      .order('name');
    if (data) setTerritories(data);
  };

  const openDialog = (rule?: RoutingRule) => {
    if (rule) {
      setEditingRule(rule);
      setForm({
        name: rule.name,
        description: rule.description || '',
        rule_type: rule.rule_type,
        entity_type: rule.entity_type,
        target_user_ids: rule.target_user_ids || [],
        target_team_id: rule.target_team_id || '',
        target_territory_id: rule.target_territory_id || '',
        priority: rule.priority.toString(),
        is_active: rule.is_active,
        is_default: rule.is_default,
        conditions: (rule.conditions as Array<{ field: string; operator: string; value: string }>) || [],
      });
    } else {
      setEditingRule(null);
      setForm(initialForm);
    }
    setDialogOpen(true);
  };

  const addCondition = () => {
    setForm(prev => ({
      ...prev,
      conditions: [...prev.conditions, { field: '', operator: 'equals', value: '' }],
    }));
  };

  const removeCondition = (index: number) => {
    setForm(prev => ({
      ...prev,
      conditions: prev.conditions.filter((_, i) => i !== index),
    }));
  };

  const updateCondition = (index: number, field: keyof typeof form.conditions[0], value: string) => {
    setForm(prev => ({
      ...prev,
      conditions: prev.conditions.map((c, i) => i === index ? { ...c, [field]: value } : c),
    }));
  };

  const handleSave = async () => {
    if (!profile?.organization_id || !form.name) return;

    setSaving(true);

    const ruleData = {
      name: form.name,
      description: form.description || null,
      rule_type: form.rule_type,
      entity_type: form.entity_type,
      conditions: form.conditions,
      target_user_ids: form.target_user_ids.length > 0 ? form.target_user_ids : null,
      target_team_id: form.target_team_id || null,
      target_territory_id: form.target_territory_id || null,
      priority: parseInt(form.priority) || 100,
      is_active: form.is_active,
      is_default: form.is_default,
      organization_id: profile.organization_id,
    };

    let error;
    if (editingRule) {
      const result = await supabase
        .from('routing_rules')
        .update(ruleData)
        .eq('id', editingRule.id);
      error = result.error;
    } else {
      const result = await supabase.from('routing_rules').insert([ruleData]);
      error = result.error;
    }

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao salvar regra de roteamento.',
      });
    } else {
      toast({
        title: editingRule ? 'Regra atualizada' : 'Regra criada',
        description: `A regra de roteamento "${form.name}" foi salva com sucesso.`,
      });
      setDialogOpen(false);
      fetchRules();
    }

    setSaving(false);
  };

  const deleteRule = async (id: string) => {
    const { error } = await supabase.from('routing_rules').delete().eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao excluir regra de roteamento.',
      });
    } else {
      toast({
        title: 'Regra excluída',
        description: 'A regra de roteamento foi excluída com sucesso.',
      });
      fetchRules();
    }
    setDeleteRuleId(null);
  };

  const toggleRuleActive = async (rule: RoutingRule) => {
    const { error } = await supabase
      .from('routing_rules')
      .update({ is_active: !rule.is_active })
      .eq('id', rule.id);

    if (!error) {
      fetchRules();
    }
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="flex items-center gap-2">
              <Zap className="h-5 w-5" />
              Regras de Roteamento de Leads
            </CardTitle>
            <CardDescription>
              Configure a atribuição automática de leads baseada em regras
            </CardDescription>
          </div>
          <Button onClick={() => openDialog()}>
            <Plus className="mr-2 h-4 w-4" />
            Nova Regra
          </Button>
        </div>
      </CardHeader>
      <CardContent>
        {loading ? (
          <div className="flex items-center justify-center py-8">
            <RefreshCw className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : rules.length === 0 ? (
          <div className="text-center py-8">
            <Settings className="h-8 w-8 mx-auto mb-2 text-muted-foreground opacity-50" />
            <p className="text-muted-foreground">Nenhuma regra de roteamento configurada</p>
            <p className="text-sm text-muted-foreground mb-4">
              Crie regras para atribuir leads automaticamente à sua equipe.
            </p>
            <Button variant="outline" onClick={() => openDialog()}>
              <Plus className="mr-2 h-4 w-4" />
              Criar Primeira Regra
            </Button>
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Nome</TableHead>
                <TableHead>Tipo</TableHead>
                <TableHead>Entidade</TableHead>
                <TableHead>Prioridade</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="w-[100px]"></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {rules.map((rule) => {
                const config = ruleTypeConfig[rule.rule_type];
                return (
                  <TableRow key={rule.id}>
                    <TableCell>
                      <div>
                        <p className="font-medium">{rule.name}</p>
                        {rule.description && (
                          <p className="text-sm text-muted-foreground truncate max-w-[200px]">
                            {rule.description}
                          </p>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        {config.icon}
                        <span>{config.label}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline">{entityTypeLabels[rule.entity_type] || rule.entity_type}</Badge>
                    </TableCell>
                    <TableCell>{rule.priority}</TableCell>
                    <TableCell>
                      <Switch
                        checked={rule.is_active}
                        onCheckedChange={() => toggleRuleActive(rule)}
                      />
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-1">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => openDialog(rule)}
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setDeleteRuleId(rule.id)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        )}

        {/* Rule Dialog */}
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>
                {editingRule ? 'Editar Regra de Roteamento' : 'Criar Regra de Roteamento'}
              </DialogTitle>
              <DialogDescription>
                Configure como os leads devem ser atribuídos automaticamente.
              </DialogDescription>
            </DialogHeader>

            <div className="space-y-6 py-4">
              {/* Basic Info */}
              <div className="grid gap-4">
                <div className="space-y-2">
                  <Label>Nome da Regra *</Label>
                  <Input
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    placeholder="Ex.: Leads Enterprise para Reps Seniores"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Descrição</Label>
                  <Textarea
                    value={form.description}
                    onChange={(e) => setForm({ ...form, description: e.target.value })}
                    placeholder="Descreva quando esta regra se aplica..."
                    rows={2}
                  />
                </div>
              </div>

              {/* Rule Type */}
              <div className="space-y-2">
                <Label>Tipo de Regra</Label>
                <Select
                  value={form.rule_type}
                  onValueChange={(value) => setForm({ ...form, rule_type: value as RuleType })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(ruleTypeConfig).map(([key, config]) => (
                      <SelectItem key={key} value={key}>
                        <div className="flex items-center gap-2">
                          {config.icon}
                          <div>
                            <span>{config.label}</span>
                            <p className="text-xs text-muted-foreground">
                              {config.description}
                            </p>
                          </div>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Conditions */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label>Condições (Quando aplicar esta regra)</Label>
                  <Button variant="outline" size="sm" onClick={addCondition}>
                    <Plus className="mr-2 h-4 w-4" />
                    Adicionar Condição
                  </Button>
                </div>

                {form.conditions.length === 0 ? (
                  <div className="text-center py-4 border border-dashed rounded-lg">
                    <p className="text-sm text-muted-foreground">
                      Sem condições - a regra se aplica a todos os leads
                    </p>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {form.conditions.map((condition, index) => (
                      <div key={index} className="flex items-center gap-2">
                        <Select
                          value={condition.field}
                          onValueChange={(v) => updateCondition(index, 'field', v)}
                        >
                          <SelectTrigger className="w-[150px]">
                            <SelectValue placeholder="Campo" />
                          </SelectTrigger>
                          <SelectContent>
                            {conditionFields.map((f) => (
                              <SelectItem key={f.value} value={f.value}>{f.label}</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Select
                          value={condition.operator}
                          onValueChange={(v) => updateCondition(index, 'operator', v)}
                        >
                          <SelectTrigger className="w-[150px]">
                            <SelectValue placeholder="Operador" />
                          </SelectTrigger>
                          <SelectContent>
                            {conditionOperators.map((o) => (
                              <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Input
                          value={condition.value}
                          onChange={(e) => updateCondition(index, 'value', e.target.value)}
                          placeholder="Valor"
                          className="flex-1"
                        />
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeCondition(index)}
                        >
