// Stale indicator badge for opportunity cards
export function StaleIndicator({ 
  opportunityId, 
  thresholdDays = 14 
}: { 
  opportunityId: string; 
  thresholdDays?: number;
}) {
  const [daysSinceActivity, setDaysSinceActivity] = useState<number | null>(null);

  useEffect(() => {
    checkStaleness();
  }, [opportunityId]);

  const checkStaleness = async () => {
    const [activitiesResult, oppResult] = await Promise.all([
      supabase
        .from('activities')
        .select('created_at')
        .eq('opportunity_id', opportunityId)
        .order('created_at', { ascending: false })
        .limit(1),
      supabase
        .from('opportunities')
        .select('updated_at')
        .eq('id', opportunityId)
        .maybeSingle(),
    ]);

    const lastDate = activitiesResult.data?.[0]?.created_at || oppResult.data?.updated_at;
    if (lastDate) {
      const days = differenceInDays(new Date(), new Date(lastDate));
      if (days >= thresholdDays) {
        setDaysSinceActivity(days);
      }
    }
  };

  if (daysSinceActivity === null) return null;

  const severity = daysSinceActivity >= 30 
    ? 'destructive' 
    : daysSinceActivity >= 21 
      ? 'default' 
      : 'secondary';

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <Badge variant={severity} className="gap-1">
            <AlertTriangle className="h-3 w-3" />
            {daysSinceActivity}d
          </Badge>
        </TooltipTrigger>
        <TooltipContent>
          Sem atividade há {daysSinceActivity} dias
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

import { useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { FileSignature, Calendar, DollarSign, AlertTriangle } from '@/components/icons';

interface Customer360ContractsProps {
  entityType: string;
  entityId: string;
}

export function Customer360Contracts({ entityType, entityId }: Customer360ContractsProps) {
  const navigate = useNavigate();

  const { data: contracts = [] } = useQuery({
    queryKey: ['c360-contracts', entityId],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'account_id';
      const { data, error } = await supabase
        .from('contracts')
        .select('*')
        .eq(column, entityId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!entityId,
  });

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  const getStatusVariant = (status: string) => {
    switch (status) {
      case 'active': return 'default';
      case 'expired': return 'destructive';
      case 'draft': return 'secondary';
      case 'pending_approval': return 'outline';
      case 'cancelled': return 'destructive';
      default: return 'secondary';
    }
  };

  const getStatusLabel = (status: string) => {
    const map: Record<string, string> = {
      draft: 'Rascunho', pending_approval: 'Pendente', active: 'Ativo',
      expired: 'Expirado', cancelled: 'Cancelado', renewed: 'Renovado',
      terminated: 'Encerrado',
    };
    return map[status] || status;
  };

  const isExpiringSoon = (endDate: string) => {
    const end = new Date(endDate);
    const now = new Date();
    const daysUntilExpiry = Math.ceil((end.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    return daysUntilExpiry > 0 && daysUntilExpiry <= 30;
  };

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <CardTitle className="flex items-center gap-2">
          <FileSignature className="h-5 w-5" />
          Contratos ({contracts.length})
        </CardTitle>
