import { createContext, useContext, useMemo, useCallback, type ReactNode } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { APP_DEFINITIONS, getAppBySlug, LAST_APP_KEY, RECENT_APPS_KEY, type AppSlug, type AppDefinition } from '@/config/apps';
import { useModuleAccess } from '@/hooks/useModuleAccess';

interface AppContextValue {
  /** Currently active app derived from URL, or null if on /apps or non-app route */
  currentApp: AppDefinition | null;
  /** All apps the user's org has access to */
  availableApps: AppDefinition[];
  /** Loading state of module access */
  isLoading: boolean;
  /** Navigate to a specific app */
  switchApp: (slug: AppSlug) => void;
  /** Check if an app is enabled */
  isAppEnabled: (slug: AppSlug) => boolean;
  /** Get the route prefix for the current app */
  prefix: string;
}

const AppContext = createContext<AppContextValue | null>(null);

export function AppProvider({ children }: { children: ReactNode }) {
  const location = useLocation();
  const navigate = useNavigate();
  const { isModuleEnabled, isLoading } = useModuleAccess();

  // Derive current app from URL: /app/{slug}/...
  const currentApp = useMemo(() => {
    const match = location.pathname.match(/^\/app\/([^/]+)/);
    if (!match) return null;
    return getAppBySlug(match[1]) || null;
  }, [location.pathname]);

  const prefix = currentApp ? `/app/${currentApp.slug}` : '';

  const availableApps = useMemo(() => {
    if (isLoading) return APP_DEFINITIONS; // Show all while loading
    return APP_DEFINITIONS.filter((app) => isModuleEnabled(app.moduleKey));
  }, [isModuleEnabled, isLoading]);

  const isAppEnabled = useCallback(
    (slug: AppSlug) => {
      const app = getAppBySlug(slug);
      if (!app) return false;
      if (isLoading) return true;
      return isModuleEnabled(app.moduleKey);
    },
    [isModuleEnabled, isLoading]
  );

  const switchApp = useCallback(
    (slug: AppSlug) => {
      const app = getAppBySlug(slug);
      if (!app) return;
      // Save to localStorage
      localStorage.setItem(LAST_APP_KEY, slug);
      // Update recent apps
      try {
        const recent: string[] = JSON.parse(localStorage.getItem(RECENT_APPS_KEY) || '[]');
        const updated = [slug, ...recent.filter((s) => s !== slug)].slice(0, 5);
        localStorage.setItem(RECENT_APPS_KEY, JSON.stringify(updated));
      } catch {}
      navigate(app.defaultRoute);
    },
    [navigate]
  );

  const value = useMemo<AppContextValue>(
    () => ({ currentApp, availableApps, isLoading, switchApp, isAppEnabled, prefix }),
    [currentApp, availableApps, isLoading, switchApp, isAppEnabled, prefix]
  );

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
}

export function useAppContext() {
  const ctx = useContext(AppContext);
  if (!ctx) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return ctx;
}

import { useState, useEffect, useCallback, createContext, useContext, ReactNode } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/integrations/supabase/client';

interface Profile {
  id: string;
  email: string;
  first_name: string | null;
  last_name: string | null;
  avatar_url: string | null;
  organization_id: string | null;
  team_id: string | null;
  role: 'user' | 'manager' | 'admin';
  is_active: boolean;
}

interface AuthContextType {
  user: User | null;
  session: Session | null;
  profile: Profile | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<{ error: Error | null }>;
  signUp: (email: string, password: string, firstName?: string, lastName?: string) => Promise<{ error: Error | null }>;
  signOut: () => Promise<void>;
  refreshProfile: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchProfile = useCallback(async (userId: string) => {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', userId)
      .single();

    if (error) {
      console.error('Error fetching profile:', error);
      return null;
    }

    return data as Profile;
  }, []);

  const refreshProfile = useCallback(async () => {
    if (user) {
      const profileData = await fetchProfile(user.id);
      setProfile(profileData);
    }
  }, [user, fetchProfile]);

  useEffect(() => {
    // Set up auth state listener FIRST
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, session) => {
        setSession(session);
        setUser(session?.user ?? null);

        // Defer profile fetch with setTimeout to avoid deadlock
        if (session?.user) {
          setTimeout(() => {
            fetchProfile(session.user.id).then(setProfile);
          }, 0);
        } else {
          setProfile(null);
        }

        setLoading(false);
      }
    );

    // THEN check for existing session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);

      if (session?.user) {
        fetchProfile(session.user.id).then(setProfile);
      }

      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, [fetchProfile]);

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    return { error: error as Error | null };
  };

  const signUp = async (email: string, password: string, firstName?: string, lastName?: string) => {
    const redirectUrl = `${window.location.origin}/`;

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: redirectUrl,
        data: {
          first_name: firstName,
          last_name: lastName,
        },
      },
    });

    // Update profile with name after signup
    if (!error && data.user) {
      await supabase
        .from('profiles')
        .update({
          first_name: firstName,
          last_name: lastName,
        })
        .eq('id', data.user.id);
    }

    return { error: error as Error | null };
  };

  const signOut = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setSession(null);
    setProfile(null);
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        session,
        profile,
        loading,
        signIn,
        signUp,
        signOut,
        refreshProfile,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useToast } from '@/hooks/use-toast';

export type ConversationChannel = 'email' | 'chat' | 'phone' | 'whatsapp' | 'sms' | 'social' | 'portal' | 'internal';
export type ConversationStatus = 'open' | 'waiting_customer' | 'waiting_agent' | 'bot_handling' | 'on_hold' | 'snoozed' | 'closed' | 'spam';
export type AgentStatus = 'available' | 'busy' | 'away' | 'offline' | 'in_meeting' | 'on_break' | 'after_call_work' | 'training';

export interface Conversation {
  id: string;
  organization_id: string;
  conversation_number: string;
  channel: ConversationChannel;
  status: ConversationStatus;
  priority: 'low' | 'medium' | 'high' | 'critical';
  subject: string | null;
  summary: string | null;
  tags: string[];
  account_id: string | null;
  contact_id: string | null;
  owner_id: string | null;
  queue_id: string | null;
  message_count: number;
  unread_count: number;
  first_message_at: string | null;
  last_message_at: string | null;
  sla_response_due_at: string | null;
  sla_response_breached: boolean;
  created_at: string;
  updated_at: string;
  contact?: {
    id: string;
    first_name: string | null;
    last_name: string | null;
    email: string | null;
    phone: string | null;
  } | null;
  account?: {
    id: string;
    name: string;
  } | null;
  owner?: {
    id: string;
    first_name: string | null;
    last_name: string | null;
    email: string;
  } | null;
}

export interface ConversationMessage {
  id: string;
  conversation_id: string;
  sender_type: 'agent' | 'customer' | 'bot' | 'system';
  sender_id: string | null;
  sender_name: string | null;
  sender_email: string | null;
  content: string | null;
  content_html: string | null;
  content_type: string;
  attachments: any[];
  delivery_status: string;
  is_internal: boolean;
  created_at: string;
}

interface UseConversationsOptions {
  status?: ConversationStatus | ConversationStatus[];
  channel?: ConversationChannel;
  ownerId?: string;
  queueId?: string;
}

export function useConversations(options: UseConversationsOptions = {}) {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const { profile } = useAuth();
  const { toast } = useToast();

  const fetchConversations = useCallback(async () => {
    if (!profile?.organization_id) return;

    try {
      setLoading(true);
      let query = supabase
        .from('conversations')
        .select(`
          *,
          contact:contacts(id, first_name, last_name, email, phone),
          account:accounts(id, name),
          owner:profiles!conversations_owner_id_fkey(id, first_name, last_name, email)
        `)
        .eq('organization_id', profile.organization_id)
        .order('last_message_at', { ascending: false, nullsFirst: false });

      if (options.status) {
        if (Array.isArray(options.status)) {
          query = query.in('status', options.status);
        } else {
          query = query.eq('status', options.status);
        }
      }

      if (options.channel) {
        query = query.eq('channel', options.channel);
      }

      if (options.ownerId) {
        query = query.eq('owner_id', options.ownerId);
      }

      if (options.queueId) {
        query = query.eq('queue_id', options.queueId);
      }

      const { data, error: fetchError } = await query.limit(100);

      if (fetchError) throw fetchError;
      setConversations((data || []) as unknown as Conversation[]);
    } catch (err) {
      console.error('Error fetching conversations:', err);
      setError(err as Error);
    } finally {
      setLoading(false);
    }
  }, [profile?.organization_id, options.status, options.channel, options.ownerId, options.queueId]);

  useEffect(() => {
    fetchConversations();
  }, [fetchConversations]);

  // Real-time subscription
  useEffect(() => {
    if (!profile?.organization_id) return;

    const channel = supabase
      .channel('conversations-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'conversations',
          filter: `organization_id=eq.${profile.organization_id}`,
        },
        () => {
          fetchConversations();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [profile?.organization_id, fetchConversations]);

  const assignToMe = async (conversationId: string) => {
    if (!profile?.id) return false;

    try {
      const { error } = await supabase.rpc('assign_conversation_to_agent', {
        p_conversation_id: conversationId,
        p_agent_id: profile.id,
        p_method: 'manual'
      });

      if (error) throw error;

      toast({ title: 'Conversação atribuída', description: 'A conversação foi atribuída a você.' });
      fetchConversations();
      return true;
    } catch (err) {
      console.error('Error assigning conversation:', err);
      toast({ title: 'Erro', description: 'Não foi possível atribuir a conversação.', variant: 'destructive' });
      return false;
    }
  };

  const closeConversation = async (conversationId: string) => {
    try {
      const { error } = await supabase
        .from('conversations')
        .update({ 
          status: 'closed' as ConversationStatus, 
          closed_at: new Date().toISOString(),
          closed_by: profile?.id 
        })
        .eq('id', conversationId);

      if (error) throw error;

      toast({ title: 'Conversação fechada' });
      fetchConversations();
      return true;
    } catch (err) {
      console.error('Error closing conversation:', err);
      toast({ title: 'Erro', description: 'Não foi possível fechar a conversação.', variant: 'destructive' });
      return false;
    }
  };

  return {
    conversations,
    loading,
    error,
    refetch: fetchConversations,
    assignToMe,
    closeConversation,
  };
}

export function useConversationMessages(conversationId: string | null) {
  const [messages, setMessages] = useState<ConversationMessage[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchMessages = useCallback(async () => {
    if (!conversationId) {
      setMessages([]);
      return;
    }

    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('conversation_messages')
        .select('*')
        .eq('conversation_id', conversationId)
        .eq('is_deleted', false)
        .order('created_at', { ascending: true });

      if (error) throw error;
      setMessages((data || []) as ConversationMessage[]);
    } catch (err) {
      console.error('Error fetching messages:', err);
    } finally {
      setLoading(false);
    }
  }, [conversationId]);

  useEffect(() => {
    fetchMessages();
  }, [fetchMessages]);

  // Real-time subscription for messages
  useEffect(() => {
    if (!conversationId) return;

    const channel = supabase
      .channel(`messages-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'conversation_messages',
          filter: `conversation_id=eq.${conversationId}`,
        },
        (payload) => {
          setMessages(prev => [...prev, payload.new as ConversationMessage]);
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [conversationId]);

  return { messages, loading, refetch: fetchMessages };
}

export function useAgentStatus() {
  const { profile } = useAuth();
  const [status, setStatus] = useState<AgentStatus>('offline');
  const { toast } = useToast();

  useEffect(() => {
    if (!profile?.id) return;

    const fetchStatus = async () => {
      const { data } = await supabase
        .from('agent_status')
        .select('status')
        .eq('user_id', profile.id)
        .single();

      if (data) {
        setStatus(data.status as AgentStatus);
      }
    };

    fetchStatus();
  }, [profile?.id]);

  const updateStatus = async (newStatus: AgentStatus, reason?: string) => {
    if (!profile?.id) return false;

    try {
      const { error } = await supabase.rpc('update_agent_availability', {
        p_user_id: profile.id,
        p_status: newStatus,
        p_reason: reason || null
      });

      if (error) throw error;

      setStatus(newStatus);
      toast({ title: 'Status atualizado', description: `Seu status agora é: ${newStatus}` });
      return true;
    } catch (err) {
      console.error('Error updating status:', err);
      toast({ title: 'Erro', description: 'Não foi possível atualizar o status.', variant: 'destructive' });
      return false;
    }
  };

  return { status, updateStatus };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { STALE_TIMES, GC_TIMES } from '@/lib/queryConfig';
import { useToast } from '@/hooks/use-toast';

export type CustomFieldType =
  | 'text' | 'number' | 'decimal' | 'date' | 'datetime' | 'boolean'
  | 'select' | 'multiselect' | 'url' | 'email' | 'phone' | 'textarea' | 'lookup';

export type CustomFieldEntityType = 'lead' | 'contact' | 'account' | 'opportunity' | 'ticket' | 'order';

export interface CustomFieldDefinition {
  id: string;
  organization_id: string;
  entity_type: CustomFieldEntityType;
  field_name: string;
  field_label: string;
  field_type: CustomFieldType;
  is_required: boolean;
  default_value: string | null;
  options: { label: string; value: string; color?: string }[];
  validation_rules: {
    min?: number;
    max?: number;
    min_length?: number;
    max_length?: number;
    pattern?: string;
    pattern_message?: string;
  };
  display_order: number;
  section_name: string;
  is_active: boolean;
  description: string | null;
  placeholder: string | null;
  lookup_entity: string | null;
  created_by: string | null;
  created_at: string;
  updated_at: string;
}

export interface CustomFieldValue {
  id: string;
  organization_id: string;
  field_definition_id: string;
  entity_type: CustomFieldEntityType;
  entity_id: string;
  value_text: string | null;
  value_number: number | null;
  value_date: string | null;
  value_boolean: boolean | null;
  value_json: any | null;
  created_at: string;
  updated_at: string;
}

// Get the raw value from a custom field value record based on field type
export function getFieldValue(fieldDef: CustomFieldDefinition, fieldValue?: CustomFieldValue): any {
  if (!fieldValue) return fieldDef.default_value ?? null;

  switch (fieldDef.field_type) {
    case 'number':
    case 'decimal':
      return fieldValue.value_number;
    case 'boolean':
      return fieldValue.value_boolean;
    case 'date':
    case 'datetime':
      return fieldValue.value_date;
    case 'multiselect':
    case 'lookup':
      return fieldValue.value_json;
    default:
      return fieldValue.value_text;
  }
}

// Prepare value for saving based on field type
function prepareValueForSave(fieldDef: CustomFieldDefinition, value: any) {
  const base = {
    value_text: null as string | null,
    value_number: null as number | null,
    value_date: null as string | null,
    value_boolean: null as boolean | null,
    value_json: null as any,
  };

  if (value === null || value === undefined || value === '') return base;

  switch (fieldDef.field_type) {
    case 'number':
    case 'decimal':
      base.value_number = typeof value === 'number' ? value : parseFloat(value);
      break;
    case 'boolean':
      base.value_boolean = Boolean(value);
      break;
    case 'date':
    case 'datetime':
      base.value_date = value;
      break;
    case 'multiselect':
    case 'lookup':
      base.value_json = value;
      break;
    default:
      base.value_text = String(value);
      break;
  }

  return base;
}

// Validate a field value based on definition rules
export function validateFieldValue(
  fieldDef: CustomFieldDefinition,
  value: any
): string | null {
  if (fieldDef.is_required && (value === null || value === undefined || value === '')) {
    return `${fieldDef.field_label} é obrigatório`;
  }

  if (value === null || value === undefined || value === '') return null;

  const rules = fieldDef.validation_rules;

  if (rules.min !== undefined && typeof value === 'number' && value < rules.min) {
    return `${fieldDef.field_label} deve ser no mínimo ${rules.min}`;
  }
  if (rules.max !== undefined && typeof value === 'number' && value > rules.max) {
    return `${fieldDef.field_label} deve ser no máximo ${rules.max}`;
  }
  if (rules.min_length !== undefined && typeof value === 'string' && value.length < rules.min_length) {
    return `${fieldDef.field_label} deve ter no mínimo ${rules.min_length} caracteres`;
  }
  if (rules.max_length !== undefined && typeof value === 'string' && value.length > rules.max_length) {
    return `${fieldDef.field_label} deve ter no máximo ${rules.max_length} caracteres`;
  }
  if (rules.pattern && typeof value === 'string') {
    const regex = new RegExp(rules.pattern);
    if (!regex.test(value)) {
      return rules.pattern_message || `${fieldDef.field_label} formato inválido`;
    }
  }

  // Type-specific validation
  if (fieldDef.field_type === 'email' && typeof value === 'string') {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(value)) return 'Email inválido';
  }
  if (fieldDef.field_type === 'url' && typeof value === 'string') {
    try {
      new URL(value);
    } catch {
      return 'URL inválida';
    }
  }

  return null;
}

