import { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ArrowLeft, Loader2, X } from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { CustomFieldsRenderer } from '@/components/CustomFieldsRenderer';
import { useCustomFieldDefinitions, useCustomFieldValues, useSaveCustomFieldValues, getFieldValue } from '@/hooks/useCustomFields';

const accountSchema = z.object({
  name: z.string().min(1, 'Nome da empresa é obrigatório').max(255),
  industry: z.string().optional(),
  website: z.string().url('Deve ser uma URL válida').optional().or(z.literal('')),
  phone: z.string().optional(),
  email: z.string().email('Deve ser um e-mail válido').optional().or(z.literal('')),
  address_street: z.string().optional(),
  address_city: z.string().optional(),
  address_state: z.string().optional(),
  address_postal_code: z.string().optional(),
  address_country: z.string().optional(),
  description: z.string().optional(),
  source: z.string().optional(),
  annual_revenue: z.coerce.number().min(0).optional().or(z.literal('')),
  employee_count: z.coerce.number().int().min(0).optional().or(z.literal('')),
  parent_account_id: z.string().optional(),
  territory_id: z.string().optional(),
  owner_id: z.string().optional(),
});

type AccountFormData = z.infer<typeof accountSchema>;

interface Account {
  id: string;
  name: string;
}

interface Territory {
  id: string;
  name: string;
}

interface User {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string;
}

const industries = [
  'Tecnologia',
  'Saúde',
  'Finanças',
  'Manufatura',
  'Varejo',
  'Educação',
  'Imobiliário',
  'Consultoria',
  'Mídia',
  'Transporte',
  'Energia',
  'Agronegócio',
  'Construção',
  'Hotelaria',
  'Outro',
];

const sources = [
  'Website',
  'Indicação',
  'Feira/Evento',
  'Ligação Fria',
  'Redes Sociais',
  'Publicidade',
  'Parceiro',
  'Outro',
];

export default function AccountForm() {
  const { id } = useParams<{ id: string }>();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [territories, setTerritories] = useState<Territory[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [tags, setTags] = useState<string[]>([]);
  const [tagInput, setTagInput] = useState('');
  const { data: customFieldDefs = [] } = useCustomFieldDefinitions('account');
  const { data: customFieldValuesData = [] } = useCustomFieldValues('account', id);
  const saveCustomFields = useSaveCustomFieldValues();
  const [customFieldValues, setCustomFieldValues] = useState<Record<string, any>>({});

  useEffect(() => {
    if (customFieldDefs.length > 0) {
      const values: Record<string, any> = {};
      customFieldDefs.forEach(def => {
        const fieldValue = customFieldValuesData.find(v => v.field_definition_id === def.id);
        values[def.id] = getFieldValue(def, fieldValue);
      });
      setCustomFieldValues(values);
    }
  }, [customFieldDefs, customFieldValuesData]);

  const isEditing = Boolean(id);

  const form = useForm<AccountFormData>({
    resolver: zodResolver(accountSchema),
    defaultValues: {
      name: '',
      industry: '',
      website: '',
      phone: '',
      email: '',
      address_street: '',
      address_city: '',
      address_state: '',
      address_postal_code: '',
      address_country: '',
      description: '',
      source: '',
      annual_revenue: '',
      employee_count: '',
      parent_account_id: '',
      territory_id: '',
      owner_id: '',
    },
  });


  useEffect(() => {
    if (user) {
      fetchReferenceData();
      if (isEditing) {
        fetchAccount();
      }
    }
  }, [user, id]);

  const fetchReferenceData = async () => {
    // Fetch accounts for parent selection (excluding current if editing)
    const accountsQuery = supabase.from('accounts').select('id, name').order('name');
    if (id) {
      accountsQuery.neq('id', id);
    }
    const { data: accountsData } = await accountsQuery;
    setAccounts(accountsData || []);

    // Fetch territories
    const { data: territoriesData } = await supabase
      .from('territories')
      .select('id, name')
      .order('name');
    setTerritories(territoriesData || []);

    // Fetch users
    const { data: usersData } = await supabase
      .from('profiles')
      .select('id, first_name, last_name, email')
      .eq('is_active', true)
      .order('first_name');
    setUsers(usersData || []);
  };

  const fetchAccount = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('accounts')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar conta',
      });
      navigate('/accounts');
    } else if (data) {
      form.reset({
        name: data.name,
        industry: data.industry || '',
        website: data.website || '',
        phone: data.phone || '',
        email: data.email || '',
        address_street: data.address_street || '',
        address_city: data.address_city || '',
        address_state: data.address_state || '',
        address_postal_code: data.address_postal_code || '',
        address_country: data.address_country || '',
        description: data.description || '',
        source: data.source || '',
        annual_revenue: data.annual_revenue || '',
        employee_count: data.employee_count || '',
        parent_account_id: data.parent_account_id || '',
        territory_id: data.territory_id || '',
        owner_id: data.owner_id || '',
      });
      setTags(data.tags || []);
    }
    setLoading(false);
  };

  const onSubmit = async (data: AccountFormData) => {
    setSaving(true);

    // Get user's profile for organization_id
    const { data: profile } = await supabase
      .from('profiles')
      .select('organization_id')
      .eq('id', user?.id)
      .single();

    if (!profile?.organization_id) {
      toast({ variant: 'destructive', title: 'Erro', description: 'Organização não encontrada' });
      setSaving(false);
      return;
    }

    const accountData = {
      name: data.name,
      industry: data.industry || null,
      website: data.website || null,
      phone: data.phone || null,
      email: data.email || null,
      address_street: data.address_street || null,
      address_city: data.address_city || null,
      address_state: data.address_state || null,
      address_postal_code: data.address_postal_code || null,
      address_country: data.address_country || null,
      description: data.description || null,
      source: data.source || null,
      annual_revenue: data.annual_revenue ? Number(data.annual_revenue) : null,
      employee_count: data.employee_count ? Number(data.employee_count) : null,
      parent_account_id: data.parent_account_id || null,
      territory_id: data.territory_id || null,
      owner_id: data.owner_id || null,
      tags: tags.length > 0 ? tags : null,
      organization_id: profile.organization_id,
    };

    if (isEditing) {
      const { error } = await supabase
        .from('accounts')
        .update(accountData)
        .eq('id', id);

      if (error) {
        toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao atualizar conta' });
      } else {
        toast({ title: 'Conta atualizada' });
        if (customFieldDefs.length > 0 && id) {
          saveCustomFields.mutate({ entityType: 'account', entityId: id, values: customFieldValues, definitions: customFieldDefs });
        }
        navigate(`/accounts/${id}`);
      }
    } else {
      const { data: newAccount, error } = await supabase
        .from('accounts')
        .insert(accountData)
        .select()
        .single();

      if (error) {
        toast({ variant: 'destructive', title: 'Erro', description: 'Falha ao criar conta' });
