type ArticleStatus = 'draft' | 'in_review' | 'published' | 'archived';

const statusConfig: Record<ArticleStatus, { label: string; className: string }> = {
  draft: { label: 'Rascunho', className: 'bg-slate-100 text-slate-700' },
  in_review: { label: 'Em Revisão', className: 'bg-yellow-100 text-yellow-700' },
  published: { label: 'Publicado', className: 'bg-green-100 text-green-700' },
  archived: { label: 'Arquivado', className: 'bg-gray-100 text-gray-700' },
};

export default function ArticleDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch article
  const { data: article, isLoading } = useQuery({
    queryKey: ['knowledge-article', id],
    queryFn: async () => {
      if (!id) return null;

      const { data, error } = await supabase
        .from('knowledge_articles')
        .select(`
          *,
          category:category_id(id, name, slug)
        `)
        .eq('id', id)
        .single();

      if (error) throw error;

      // Fetch author
      let author = null;
      if (data.author_id) {
        const { data: authorData } = await supabase
          .from('profiles')
          .select('id, first_name, last_name, email, avatar_url')
          .eq('id', data.author_id)
          .single();
        author = authorData;
      }

      // Increment view count
      await supabase
        .from('knowledge_articles')
        .update({ view_count: (data.view_count || 0) + 1 })
        .eq('id', id);

      return { ...data, author };
    },
    enabled: !!id,
  });

  // Fetch related articles
  const { data: relatedArticles = [] } = useQuery({
    queryKey: ['related-articles', article?.category_id, id],
    queryFn: async () => {
      if (!article?.category_id || !id) return [];

      const { data, error } = await supabase
        .from('knowledge_articles')
        .select('id, title, slug, summary')
        .eq('category_id', article.category_id)
        .eq('status', 'published')
        .neq('id', id)
        .limit(5);

      if (error) throw error;
      return data || [];
    },
    enabled: !!article?.category_id,
  });

  // Update article status
  const updateStatusMutation = useMutation({
    mutationFn: async (newStatus: ArticleStatus) => {
      const updates: any = { status: newStatus };

      if (newStatus === 'published' && !article?.published_at) {
        updates.published_at = new Date().toISOString();
        updates.published_by = profile?.id;
      }

      const { error } = await supabase
        .from('knowledge_articles')
        .update(updates)
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['knowledge-article', id] });
      toast({
        title: 'Status atualizado',
        description: 'O artigo foi atualizado com sucesso.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.message,
        variant: 'destructive',
      });
    },
  });

  // Submit feedback
  const submitFeedbackMutation = useMutation({
    mutationFn: async (isHelpful: boolean) => {
      const { error } = await supabase
        .from('article_feedback')
        .insert({
          article_id: id,
          is_helpful: isHelpful,
          user_id: profile?.id,
        });

      if (error) throw error;
    },
    onSuccess: (_, isHelpful) => {
      queryClient.invalidateQueries({ queryKey: ['knowledge-article', id] });
      toast({
        title: 'Obrigado pelo feedback!',
        description: isHelpful 
          ? 'Ficamos felizes que o artigo foi útil.'
          : 'Vamos trabalhar para melhorar este conteúdo.',
      });
    },
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <RefreshCcw className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!article) {
    return (
      <div className="flex flex-col items-center justify-center py-12">
        <h2 className="text-xl font-semibold">Artigo não encontrado</h2>
        <Button className="mt-4" onClick={() => navigate('/knowledge')}>
          Voltar para Base de Conhecimento
        </Button>
      </div>
    );
  }

  return (
    <>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
          <div className="flex items-start gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate('/knowledge')}>
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <div className="flex items-center gap-2 flex-wrap mb-2">
                <Badge className={statusConfig[article.status as ArticleStatus].className}>
                  {statusConfig[article.status as ArticleStatus].label}
                </Badge>
                {article.is_public ? (
                  <Badge variant="outline" className="text-green-600">
                    <Globe className="h-3 w-3 mr-1" />
                    Público
                  </Badge>
                ) : (
                  <Badge variant="outline" className="text-slate-600">
                    <Lock className="h-3 w-3 mr-1" />
                    Interno
                  </Badge>
                )}
                {article.is_featured && (
                  <Badge variant="outline" className="text-yellow-600">
                    <Star className="h-3 w-3 mr-1 fill-yellow-500" />
                    Destaque
                  </Badge>
                )}
              </div>
              <h1 className="text-2xl font-bold tracking-tight">
                {article.title}
              </h1>
              {article.summary && (
                <p className="text-muted-foreground mt-1">{article.summary}</p>
              )}
            </div>
          </div>

          <div className="flex gap-2">
            <Button variant="outline" onClick={() => navigate(`/knowledge/${id}/edit`)}>
              <Edit className="mr-2 h-4 w-4" />
              Editar
            </Button>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="icon">
                  <MoreHorizontal className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                {article.status === 'draft' && (
                  <DropdownMenuItem onClick={() => updateStatusMutation.mutate('in_review')}>
                    <Send className="mr-2 h-4 w-4" />
                    Enviar para Revisão
                  </DropdownMenuItem>
                )}
                {article.status === 'in_review' && (
                  <DropdownMenuItem onClick={() => updateStatusMutation.mutate('published')}>
                    <Globe className="mr-2 h-4 w-4" />
                    Publicar
                  </DropdownMenuItem>
                )}
                {article.status === 'published' && (
                  <DropdownMenuItem onClick={() => updateStatusMutation.mutate('archived')}>
                    <Archive className="mr-2 h-4 w-4" />
                    Arquivar
                  </DropdownMenuItem>
                )}
                {article.status === 'archived' && (
                  <DropdownMenuItem onClick={() => updateStatusMutation.mutate('draft')}>
                    <RefreshCcw className="mr-2 h-4 w-4" />
                    Reativar como Rascunho
                  </DropdownMenuItem>
                )}
                <DropdownMenuSeparator />
                <DropdownMenuItem className="text-destructive">
                  <Trash2 className="mr-2 h-4 w-4" />
                  Excluir
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-6">
            {/* Article Content */}
            <Card>
              <CardContent className="pt-6">
                <div className="prose prose-slate max-w-none dark:prose-invert">
                  {article.content_html ? (
                    <div dangerouslySetInnerHTML={{ __html: article.content_html }} />
                  ) : (
                    <div className="whitespace-pre-wrap">{article.content}</div>
                  )}
                </div>
              </CardContent>
            </Card>

            {/* Feedback */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Este artigo foi útil?</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="flex gap-4">
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => submitFeedbackMutation.mutate(true)}
                    disabled={submitFeedbackMutation.isPending}
                  >
                    <ThumbsUp className="mr-2 h-4 w-4" />
                    Sim, ajudou!
                  </Button>
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => submitFeedbackMutation.mutate(false)}
                    disabled={submitFeedbackMutation.isPending}
                  >
                    <ThumbsDown className="mr-2 h-4 w-4" />
                    Precisa melhorar
                  </Button>
                </div>
                <div className="flex items-center justify-center gap-6 mt-4 text-sm text-muted-foreground">
                  <span className="flex items-center gap-1">
                    <ThumbsUp className="h-4 w-4 text-green-500" />
                    {article.helpful_count} acharam útil
                  </span>
                  <span className="flex items-center gap-1">
                    <ThumbsDown className="h-4 w-4 text-red-500" />
                    {article.not_helpful_count} não acharam
                  </span>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Metadata */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium">Informações</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4 text-sm">
                {article.category && (
                  <div className="flex items-center gap-2">
                    <Folder className="h-4 w-4 text-muted-foreground" />
                    <span>{article.category.name}</span>
                  </div>
                )}

                <div className="flex items-center gap-2">
                  <Eye className="h-4 w-4 text-muted-foreground" />
                  <span>{article.view_count} visualizações</span>
                </div>

                <Separator />

                {article.author && (
                  <div>
                    <p className="text-xs text-muted-foreground mb-2">Autor</p>
                    <div className="flex items-center gap-2">
                      <Avatar className="h-6 w-6">
                        <AvatarImage src={article.author.avatar_url || ''} />
                        <AvatarFallback className="text-xs">
                          {article.author.first_name?.[0]}{article.author.last_name?.[0]}
                        </AvatarFallback>
                      </Avatar>
                      <span>{article.author.first_name} {article.author.last_name}</span>
                    </div>
                  </div>
                )}

                <div>
                  <p className="text-xs text-muted-foreground mb-1">Criado em</p>
                  <p>{format(new Date(article.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</p>
                </div>

                <div>
                  <p className="text-xs text-muted-foreground mb-1">Última atualização</p>
                  <p>{formatDistanceToNow(new Date(article.updated_at), { addSuffix: true, locale: ptBR })}</p>
                </div>

                {article.published_at && (
                  <div>
                    <p className="text-xs text-muted-foreground mb-1">Publicado em</p>
                    <p>{format(new Date(article.published_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</p>
                  </div>
                )}

                {article.tags && article.tags.length > 0 && (
                  <div>
                    <p className="text-xs text-muted-foreground mb-2">Tags</p>
                    <div className="flex flex-wrap gap-1">
                      {article.tags.map((tag: string) => (
                        <Badge key={tag} variant="secondary" className="text-xs">
                          {tag}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Related Articles */}
            {relatedArticles.length > 0 && (
              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-sm font-medium">Artigos Relacionados</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  {relatedArticles.map((related) => (
                    <Link
                      key={related.id}
                      to={`/knowledge/${related.id}`}
                      className="block p-2 rounded-lg hover:bg-muted transition-colors"
                    >
                      <p className="font-medium text-sm line-clamp-2">{related.title}</p>
                      {related.summary && (
                        <p className="text-xs text-muted-foreground line-clamp-1 mt-1">
                          {related.summary}
                        </p>
                      )}
                    </Link>
                  ))}
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { ArrowLeft, Save, Loader2, Eye, Globe, Lock, Star, Send, X } from '@/components/icons';
import { useToast } from '@/hooks/use-toast';

const articleSchema = z.object({
  title: z.string().min(5, 'O título deve ter pelo menos 5 caracteres').max(200),
  slug: z.string().min(3, 'O slug deve ter pelo menos 3 caracteres').max(100)
    .regex(/^[a-z0-9-]+$/, 'O slug deve conter apenas letras minúsculas, números e hífens'),
  summary: z.string().max(500).optional().nullable(),
  content: z.string().min(50, 'O conteúdo deve ter pelo menos 50 caracteres'),
  category_id: z.string().optional().nullable(),
  tags: z.array(z.string()).optional(),
  is_public: z.boolean().default(true),
  is_internal: z.boolean().default(false),
  is_featured: z.boolean().default(false),
  meta_title: z.string().max(60).optional().nullable(),
  meta_description: z.string().max(160).optional().nullable(),
});

type ArticleFormData = z.infer<typeof articleSchema>;

export default function ArticleForm() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const isEditing = !!id;

  const [tagInput, setTagInput] = useState('');

  const form = useForm<ArticleFormData>({
    resolver: zodResolver(articleSchema),
    defaultValues: {
      title: '',
      slug: '',
      summary: '',
      content: '',
      category_id: null,
      tags: [],
      is_public: true,
      is_internal: false,
      is_featured: false,
      meta_title: '',
      meta_description: '',
    },
  });

  // Auto-generate slug from title
  const watchTitle = form.watch('title');
  useEffect(() => {
    if (!isEditing && watchTitle) {
      const slug = watchTitle
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/[^a-z0-9\s-]/g, '')
        .replace(/\s+/g, '-')
        .replace(/-+/g, '-')
        .substring(0, 100);
      form.setValue('slug', slug);
    }
  }, [watchTitle, isEditing, form]);

  // Fetch existing article for edit mode
  const { data: article, isLoading: isLoadingArticle } = useQuery({
    queryKey: ['knowledge-article', id],
    queryFn: async () => {
      if (!id) return null;
      const { data, error } = await supabase
        .from('knowledge_articles')
        .select('*')
        .eq('id', id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: isEditing,
  });

  // Fetch categories
  const { data: categories = [] } = useQuery({
    queryKey: ['knowledge-categories', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('knowledge_categories')
        .select('id, name')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('name');
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Populate form when editing
  useEffect(() => {
    if (article) {
      form.reset({
        title: article.title,
        slug: article.slug,
        summary: article.summary || '',
        content: article.content,
        category_id: article.category_id,
        tags: article.tags || [],
        is_public: article.is_public,
        is_internal: article.is_internal,
        is_featured: article.is_featured,
        meta_title: article.meta_title || '',
        meta_description: article.meta_description || '',
      });
    }
  }, [article, form]);

  // Create/Update mutation
  const mutation = useMutation({
    mutationFn: async (data: ArticleFormData) => {
      if (!profile?.organization_id) throw new Error('Organização não encontrada');

      const articleData = {
        title: data.title,
        slug: data.slug,
        summary: data.summary || null,
        content: data.content,
        category_id: data.category_id || null,
        tags: data.tags || [],
        is_public: data.is_public,
        is_internal: data.is_internal,
        is_featured: data.is_featured,
        meta_title: data.meta_title || null,
        meta_description: data.meta_description || null,
        last_edited_by: profile.id,
      };

      if (isEditing) {
        // Increment version on edit
        const newVersion = (article?.version || 0) + 1;

        // Save version history
        await supabase.from('article_versions').insert({
          article_id: id,
          version: article?.version || 1,
          title: article?.title || '',
          content: article?.content || '',
          changed_by: profile.id,
          change_summary: 'Versão anterior salva antes da edição',
        });

        const { error } = await supabase
          .from('knowledge_articles')
          .update({ ...articleData, version: newVersion })
          .eq('id', id);
        if (error) throw error;
        return id;
      } else {
        const { data: newArticle, error } = await supabase
          .from('knowledge_articles')
          .insert({
            ...articleData,
            organization_id: profile.organization_id,
            author_id: profile.id,
            status: 'draft',
            version: 1,
          })
          .select('id')
          .single();
        if (error) throw error;
        return newArticle.id;
      }
    },
    onSuccess: (articleId) => {
      queryClient.invalidateQueries({ queryKey: ['knowledge-articles'] });
      queryClient.invalidateQueries({ queryKey: ['knowledge-article', articleId] });
      toast({
        title: isEditing ? 'Artigo atualizado' : 'Artigo criado',
        description: isEditing 
          ? 'As alterações foram salvas com sucesso.'
          : 'O artigo foi criado como rascunho.',
      });
      navigate(`/knowledge/${articleId}`);
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao salvar',
        description: error.message,
        variant: 'destructive',
      });
    },
  });

  const onSubmit = (data: ArticleFormData) => {
    mutation.mutate(data);
  };

  const handleAddTag = () => {
    const tag = tagInput.trim().toLowerCase();
    if (tag && !form.getValues('tags')?.includes(tag)) {
      form.setValue('tags', [...(form.getValues('tags') || []), tag]);
    }
    setTagInput('');
  };

  const handleRemoveTag = (tagToRemove: string) => {
    form.setValue('tags', form.getValues('tags')?.filter(tag => tag !== tagToRemove) || []);
  };

  if (isEditing && isLoadingArticle) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate(-1)}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">
              {isEditing ? 'Editar Artigo' : 'Novo Artigo'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing 
                ? 'Atualize o conteúdo do artigo'
                : 'Crie um novo artigo para a base de conhecimento'
              }
            </p>
          </div>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            {/* Main Content */}
            <Card>
              <CardHeader>
                <CardTitle>Conteúdo do Artigo</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Título *</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Ex: Como configurar sua conta" 
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="slug"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>URL Slug *</FormLabel>
                      <FormControl>
                        <div className="flex items-center gap-2">
                          <span className="text-muted-foreground text-sm">/artigos/</span>
                          <Input 
                            placeholder="como-configurar-sua-conta" 
                            {...field} 
                          />
                        </div>
                      </FormControl>
                      <FormDescription>
                        URL amigável para o artigo (gerado automaticamente do título)
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="summary"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Resumo</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Breve descrição do artigo..."
                          className="min-h-[80px]"
                          {...field} 
                          value={field.value || ''}
                        />
                      </FormControl>
                      <FormDescription>
                        Aparece nos resultados de busca e listagens
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="content"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Conteúdo *</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Escreva o conteúdo do artigo aqui...

Você pode usar:
- **Negrito** para destaque
- *Itálico* para ênfase
- # Títulos de seção
- ## Subtítulos
- Listas com - ou 1. 2. 3."
                          className="min-h-[400px] font-mono text-sm"
                          {...field} 
                        />
                      </FormControl>
                      <FormDescription>
                        Suporta formatação Markdown para estruturar o conteúdo
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* Classification */}
            <Card>
              <CardHeader>
                <CardTitle>Classificação</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="category_id"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Categoria</FormLabel>
                      <Select 
                        onValueChange={field.onChange} 
                        value={field.value || ''}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Selecione uma categoria" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="">Nenhuma</SelectItem>
                          {categories.map((cat) => (
                            <SelectItem key={cat.id} value={cat.id}>
                              {cat.name}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div>
                  <FormLabel>Tags</FormLabel>
                  <div className="flex gap-2 mt-2">
                    <Input 
                      placeholder="Adicionar tag..."
                      value={tagInput}
                      onChange={(e) => setTagInput(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          e.preventDefault();
                          handleAddTag();
                        }
                      }}
                    />
                    <Button type="button" variant="outline" onClick={handleAddTag}>
                      Adicionar
                    </Button>
                  </div>
                  {form.watch('tags')?.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-3">
                      {form.watch('tags')?.map((tag) => (
                        <Badge 
                          key={tag} 
                          variant="secondary"
                          className="gap-1 cursor-pointer"
                          onClick={() => handleRemoveTag(tag)}
                        >
                          {tag}
                          <X className="h-3 w-3" />
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>

            {/* Visibility Settings */}
            <Card>
              <CardHeader>
                <CardTitle>Visibilidade</CardTitle>
                <CardDescription>
                  Configure quem pode ver este artigo
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                <FormField
                  control={form.control}
                  name="is_public"
                  render={({ field }) => (
                    <FormItem className="flex items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <div className="flex items-center gap-2">
                          <Globe className="h-4 w-4 text-primary" />
                          <FormLabel className="text-base font-medium">Público</FormLabel>
                        </div>
                        <FormDescription>
                          Visível para clientes no portal de autoatendimento
                        </FormDescription>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="is_internal"
                  render={({ field }) => (
                    <FormItem className="flex items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <div className="flex items-center gap-2">
                          <Lock className="h-4 w-4 text-muted-foreground" />
                          <FormLabel className="text-base font-medium">Interno</FormLabel>
                        </div>
                        <FormDescription>
                          Visível apenas para agentes e funcionários
                        </FormDescription>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="is_featured"
                  render={({ field }) => (
                    <FormItem className="flex items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <div className="flex items-center gap-2">
                          <Star className="h-4 w-4 text-primary" />
                          <FormLabel className="text-base font-medium">Destaque</FormLabel>
                        </div>
                        <FormDescription>
                          Aparece em posição de destaque na base de conhecimento
                        </FormDescription>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* SEO Settings */}
            <Card>
              <CardHeader>
                <CardTitle>SEO</CardTitle>
                <CardDescription>
                  Otimização para mecanismos de busca
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="meta_title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Meta Título</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Título para SEO (deixe em branco para usar o título do artigo)"
                          maxLength={60}
                          {...field} 
                          value={field.value || ''}
                        />
                      </FormControl>
                      <FormDescription>
                        Máximo 60 caracteres ({60 - (field.value?.length || 0)} restantes)
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="meta_description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Meta Descrição</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Descrição para resultados de busca..."
                          maxLength={160}
                          className="min-h-[80px]"
                          {...field} 
                          value={field.value || ''}
                        />
                      </FormControl>
                      <FormDescription>
                        Máximo 160 caracteres ({160 - (field.value?.length || 0)} restantes)
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* Actions */}
            <div className="flex justify-end gap-4">
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => navigate(-1)}
              >
                Cancelar
              </Button>
              <Button type="submit" disabled={mutation.isPending}>
                {mutation.isPending && (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                )}
                <Save className="mr-2 h-4 w-4" />
                {isEditing ? 'Salvar Alterações' : 'Criar Rascunho'}
              </Button>
            </div>
          </form>
        </Form>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate } from 'react-router-dom';
import {
  Search,
  Filter,
  Download,
  RefreshCw,
  Eye,
  Edit,
  Trash2,
  Upload,
  LogIn,
  LogOut,
  FileText,
  User,
  Calendar,
  Clock,
  ChevronDown,
  ChevronRight,
  ExternalLink,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { useDebounce } from '@/hooks/useDebounce';
import { format, subDays, startOfDay, endOfDay } from 'date-fns';
import { exportToCSV } from '@/components/CSVImportDialog';

interface AuditLog {
  id: string;
  user_id: string | null;
  user_email: string | null;
  action: string;
  entity_type: string;
  entity_id: string | null;
  entity_name: string | null;
  changes: Record<string, unknown> | null;
  old_values: Record<string, unknown> | null;
  new_values: Record<string, unknown> | null;
  ip_address: string | null;
  user_agent: string | null;
  session_id: string | null;
  metadata: Record<string, unknown> | null;
  created_at: string;
  [key: string]: unknown;
}

const actionIcons: Record<string, typeof Eye> = {
  create: Edit,
  update: Edit,
  delete: Trash2,
  view: Eye,
  export: Download,
  import: Upload,
  login: LogIn,
  logout: LogOut,
};

const actionColors: Record<string, string> = {
  create: 'bg-success/10 text-success border-success/20',
  update: 'bg-info/10 text-info border-info/20',
  delete: 'bg-destructive/10 text-destructive border-destructive/20',
  view: 'bg-muted text-muted-foreground border-muted',
  export: 'bg-warning/10 text-warning border-warning/20',
  import: 'bg-primary/10 text-primary border-primary/20',
  login: 'bg-success/10 text-success border-success/20',
  logout: 'bg-muted text-muted-foreground border-muted',
};

const entityTypes = [
  { value: 'all', label: 'All Entities' },
  { value: 'lead', label: 'Leads' },
  { value: 'account', label: 'Accounts' },
  { value: 'contact', label: 'Contacts' },
  { value: 'opportunity', label: 'Opportunities' },
  { value: 'quote', label: 'Quotes' },
  { value: 'product', label: 'Products' },
  { value: 'activity', label: 'Activities' },
  { value: 'territory', label: 'Territories' },
  { value: 'cadence', label: 'Cadences' },
  { value: 'forecast', label: 'Forecasts' },
];

const actionTypes = [
  { value: 'all', label: 'All Actions' },
  { value: 'create', label: 'Create' },
  { value: 'update', label: 'Update' },
  { value: 'delete', label: 'Delete' },
  { value: 'view', label: 'View' },
  { value: 'export', label: 'Export' },
  { value: 'import', label: 'Import' },
  { value: 'login', label: 'Login' },
  { value: 'logout', label: 'Logout' },
];

const dateRanges = [
  { value: '1', label: 'Last 24 hours' },
  { value: '7', label: 'Last 7 days' },
  { value: '30', label: 'Last 30 days' },
  { value: '90', label: 'Last 90 days' },
  { value: 'custom', label: 'Custom range' },
];

export default function AuditLogs() {
  const { user, profile, loading: authLoading } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();

  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [entityFilter, setEntityFilter] = useState('all');
  const [actionFilter, setActionFilter] = useState('all');
  const [dateRange, setDateRange] = useState('7');
  const [customDateFrom, setCustomDateFrom] = useState<Date | undefined>();
  const [customDateTo, setCustomDateTo] = useState<Date | undefined>();
  const [selectedLog, setSelectedLog] = useState<AuditLog | null>(null);
  const [totalCount, setTotalCount] = useState(0);
  const [page, setPage] = useState(1);
  const pageSize = 50;

  const debouncedSearch = useDebounce(searchQuery, 300);

  useEffect(() => {
    if (!authLoading && !user) {
      navigate('/auth');
    }
  }, [user, authLoading, navigate]);

  useEffect(() => {
    if (user && profile) {
      fetchLogs();
    }
  }, [user, profile, debouncedSearch, entityFilter, actionFilter, dateRange, customDateFrom, customDateTo, page]);

  const fetchLogs = async () => {
    if (!profile?.organization_id) return;

    // Check if user has permission (admin or manager)
    if (profile.role !== 'admin' && profile.role !== 'manager') {
      toast({
        variant: 'destructive',
        title: 'Access Denied',
        description: 'You do not have permission to view audit logs',
      });
      navigate('/dashboard');
      return;
    }

    setLoading(true);

    let query = supabase
      .from('audit_logs')
      .select('*', { count: 'exact' })
      .eq('organization_id', profile.organization_id)
      .order('created_at', { ascending: false });

    // Apply date filter
    let fromDate: Date;
    let toDate = new Date();

    if (dateRange === 'custom' && customDateFrom && customDateTo) {
      fromDate = startOfDay(customDateFrom);
      toDate = endOfDay(customDateTo);
    } else {
      const days = parseInt(dateRange) || 7;
      fromDate = subDays(new Date(), days);
    }

    query = query
      .gte('created_at', fromDate.toISOString())
      .lte('created_at', toDate.toISOString());

    // Apply entity filter
    if (entityFilter !== 'all') {
      query = query.eq('entity_type', entityFilter);
    }

    // Apply action filter
    if (actionFilter !== 'all') {
      query = query.eq('action', actionFilter);
    }

    // Apply search filter
    if (debouncedSearch) {
      query = query.or(`user_email.ilike.%${debouncedSearch}%,entity_name.ilike.%${debouncedSearch}%`);
    }

    // Pagination
    const from = (page - 1) * pageSize;
    const to = from + pageSize - 1;
    query = query.range(from, to);

    const { data, error, count } = await query;

    if (error) {
      console.error('Error fetching audit logs:', error);
      toast({
        variant: 'destructive',
        title: 'Error',
        description: 'Failed to load audit logs',
      });
    } else {
      const mappedData: AuditLog[] = (data || []).map((item) => ({
        ...item,
        changes: (typeof item.changes === 'object' ? item.changes : {}) as Record<string, unknown> | null,
        old_values: (typeof item.old_values === 'object' ? item.old_values : {}) as Record<string, unknown> | null,
        new_values: (typeof item.new_values === 'object' ? item.new_values : {}) as Record<string, unknown> | null,
        metadata: (typeof item.metadata === 'object' ? item.metadata : {}) as Record<string, unknown> | null,
      }));
      setLogs(mappedData);
      setTotalCount(count || 0);
    }
    setLoading(false);
  };

  const handleExport = async () => {
    if (logs.length === 0) {
      toast({
        title: 'No data to export',
        description: 'Apply filters to find audit logs first',
      });
      return;
    }

    const columns = [
      { key: 'created_at', label: 'Timestamp' },
      { key: 'user_email', label: 'User' },
      { key: 'action', label: 'Action' },
      { key: 'entity_type', label: 'Entity Type' },
      { key: 'entity_name', label: 'Entity Name' },
      { key: 'ip_address', label: 'IP Address' },
    ];

    await exportToCSV(logs as unknown as Record<string, unknown>[], 'audit_logs', columns);

    toast({
      title: 'Export complete',
      description: `Exported ${logs.length} audit log entries`,
    });
  };

  const renderChanges = (log: AuditLog) => {
    if (!log.old_values || !log.new_values) return null;

    const oldKeys = Object.keys(log.old_values);
    const newKeys = Object.keys(log.new_values);
    const allKeys = [...new Set([...oldKeys, ...newKeys])];

    if (allKeys.length === 0) return null;

    return (
      <div className="space-y-2">
        <p className="text-sm font-medium">Field Changes:</p>
        <div className="space-y-1">
          {allKeys.map((key) => {
            const oldVal = log.old_values[key];
            const newVal = log.new_values[key];
            if (oldVal === newVal) return null;

            return (
              <div key={key} className="text-sm">
                <span className="font-medium text-muted-foreground">{key}:</span>
                <div className="flex items-center gap-2 ml-4">
                  <span className="text-destructive line-through">
                    {oldVal !== undefined ? String(oldVal) : '(empty)'}
                  </span>
                  <ChevronRight className="h-3 w-3" />
                  <span className="text-success">
                    {newVal !== undefined ? String(newVal) : '(empty)'}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  if (authLoading || !user) {
    return null;
  }

  const totalPages = Math.ceil(totalCount / pageSize);

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="governance"
          title="Audit Logs"
          subtitle="Rastreie todas as ações e alterações na organização"
          compact
          actions={
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={fetchLogs} className="gap-2 bg-white/10 text-white border-white/20 hover:bg-white/20">
                <RefreshCw className="h-4 w-4" /> Atualizar
              </Button>
              <Button variant="outline" size="sm" onClick={handleExport} className="gap-2 bg-white text-foreground hover:bg-white/90">
                <Download className="h-4 w-4" /> Exportar
              </Button>
            </div>
          }
        />

        {/* Filters */}
        <div className="flex flex-col gap-4 md:flex-row md:items-center">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Search by user or entity..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
            />
          </div>

          <Select value={entityFilter} onValueChange={setEntityFilter}>
            <SelectTrigger className="w-[160px]">
              <SelectValue placeholder="Entity type" />
            </SelectTrigger>
            <SelectContent>
              {entityTypes.map((type) => (
                <SelectItem key={type.value} value={type.value}>
                  {type.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Select value={actionFilter} onValueChange={setActionFilter}>
            <SelectTrigger className="w-[140px]">
              <SelectValue placeholder="Action" />
            </SelectTrigger>
            <SelectContent>
              {actionTypes.map((type) => (
                <SelectItem key={type.value} value={type.value}>
                  {type.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Select value={dateRange} onValueChange={setDateRange}>
            <SelectTrigger className="w-[160px]">
              <SelectValue placeholder="Date range" />
            </SelectTrigger>
            <SelectContent>
              {dateRanges.map((range) => (
                <SelectItem key={range.value} value={range.value}>
                  {range.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          {dateRange === 'custom' && (
            <div className="flex items-center gap-2">
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" size="sm">
                    <Calendar className="mr-2 h-4 w-4" />
                    {customDateFrom ? format(customDateFrom, 'PP') : 'From'}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0">
                  <CalendarComponent
                    mode="single"
                    selected={customDateFrom}
                    onSelect={setCustomDateFrom}
                    initialFocus
                  />
                </PopoverContent>
              </Popover>
              <span className="text-muted-foreground">to</span>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" size="sm">
                    <Calendar className="mr-2 h-4 w-4" />
                    {customDateTo ? format(customDateTo, 'PP') : 'To'}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0">
                  <CalendarComponent
                    mode="single"
                    selected={customDateTo}
                    onSelect={setCustomDateTo}
                    initialFocus
                  />
                </PopoverContent>
              </Popover>
            </div>
          )}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="p-4 bg-card rounded-lg border">
            <p className="text-sm text-muted-foreground">Total Events</p>
            <p className="text-2xl font-bold">{totalCount.toLocaleString()}</p>
          </div>
          <div className="p-4 bg-card rounded-lg border">
            <p className="text-sm text-muted-foreground">Creates</p>
            <p className="text-2xl font-bold text-success">
              {logs.filter(l => l.action === 'create').length}
            </p>
          </div>
          <div className="p-4 bg-card rounded-lg border">
            <p className="text-sm text-muted-foreground">Updates</p>
            <p className="text-2xl font-bold text-info">
              {logs.filter(l => l.action === 'update').length}
            </p>
          </div>
          <div className="p-4 bg-card rounded-lg border">
            <p className="text-sm text-muted-foreground">Deletes</p>
            <p className="text-2xl font-bold text-destructive">
              {logs.filter(l => l.action === 'delete').length}
            </p>
          </div>
        </div>

        {/* Table */}
        <div className="rounded-lg border bg-card">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[180px]">Timestamp</TableHead>
                <TableHead className="w-[200px]">User</TableHead>
                <TableHead className="w-[100px]">Action</TableHead>
                <TableHead className="w-[120px]">Entity</TableHead>
                <TableHead>Details</TableHead>
                <TableHead className="w-[80px]"></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {loading ? (
                <TableRow>
                  <TableCell colSpan={6} className="h-24 text-center">
                    Loading audit logs...
                  </TableCell>
                </TableRow>
              ) : logs.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} className="h-24 text-center">
                    <div className="flex flex-col items-center gap-2">
                      <FileText className="h-8 w-8 text-muted-foreground" />
                      <p className="text-muted-foreground">No audit logs found</p>
                      <p className="text-sm text-muted-foreground">
                        Try adjusting your filters
                      </p>
                    </div>
                  </TableCell>
                </TableRow>
              ) : (
                logs.map((log) => {
                  const ActionIcon = actionIcons[log.action] || FileText;

                  return (
                    <TableRow key={log.id}>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          <Clock className="h-4 w-4 text-muted-foreground" />
                          <div>
                            <p className="font-medium">
                              {format(new Date(log.created_at), 'PP')}
                            </p>
                            <p className="text-xs text-muted-foreground">
                              {format(new Date(log.created_at), 'p')}
                            </p>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          <div className="h-8 w-8 rounded-full bg-muted flex items-center justify-center">
                            <User className="h-4 w-4" />
                          </div>
                          <div>
                            <p className="font-medium truncate max-w-[150px]">
                              {log.user_email || 'System'}
                            </p>
                            {log.ip_address && (
                              <p className="text-xs text-muted-foreground">
                                {log.ip_address}
                              </p>
                            )}
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Badge variant="outline" className={actionColors[log.action]}>
                          <ActionIcon className="mr-1 h-3 w-3" />
                          {log.action.charAt(0).toUpperCase() + log.action.slice(1)}
                        </Badge>
                      </TableCell>
                      <TableCell>
                        <div>
                          <p className="font-medium capitalize">{log.entity_type}</p>
                          {log.entity_id && (
                            <p className="text-xs text-muted-foreground font-mono">
                              {log.entity_id.slice(0, 8)}...
                            </p>
                          )}
                        </div>
                      </TableCell>
                      <TableCell>
                        <p className="truncate max-w-[300px]">
                          {log.entity_name || '-'}
                        </p>
                        {Object.keys(log.new_values || {}).length > 0 && (
                          <p className="text-xs text-muted-foreground">
                            {Object.keys(log.new_values).length} field(s) changed
                          </p>
                        )}
                      </TableCell>
                      <TableCell>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setSelectedLog(log)}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              Showing {((page - 1) * pageSize) + 1} to {Math.min(page * pageSize, totalCount)} of {totalCount} entries
            </p>
            <div className="flex items-center gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page === 1}
                onClick={() => setPage(p => p - 1)}
              >
                Previous
              </Button>
              <span className="text-sm text-muted-foreground">
                Page {page} of {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page === totalPages}
                onClick={() => setPage(p => p + 1)}
              >
                Next
              </Button>
            </div>
          </div>
        )}

        {/* Detail Dialog */}
        <Dialog open={!!selectedLog} onOpenChange={() => setSelectedLog(null)}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <FileText className="h-5 w-5" />
                Audit Log Details
              </DialogTitle>
              <DialogDescription>
                Complete information about this audit event
              </DialogDescription>
            </DialogHeader>

            {selectedLog && (
              <ScrollArea className="max-h-[60vh]">
                <div className="space-y-6">
                  {/* Basic Info */}
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm text-muted-foreground">Timestamp</p>
                      <p className="font-medium">
                        {format(new Date(selectedLog.created_at), 'PPpp')}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">User</p>
                      <p className="font-medium">{selectedLog.user_email || 'System'}</p>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Action</p>
                      <Badge variant="outline" className={actionColors[selectedLog.action]}>
                        {selectedLog.action.charAt(0).toUpperCase() + selectedLog.action.slice(1)}
                      </Badge>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Entity Type</p>
                      <p className="font-medium capitalize">{selectedLog.entity_type}</p>
                    </div>
                  </div>

                  <Separator />

                  {/* Entity Info */}
                  <div>
                    <p className="text-sm font-medium mb-2">Entity Information</p>
                    <div className="p-3 bg-muted/50 rounded-lg space-y-2">
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">Name</span>
                        <span className="font-medium">{selectedLog.entity_name || '-'}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">ID</span>
                        <span className="font-mono text-sm">{selectedLog.entity_id || '-'}</span>
                      </div>
                    </div>
                  </div>

                  {/* Changes */}
                  {(selectedLog.action === 'update' || selectedLog.action === 'create') && (
                    <>
                      <Separator />
                      <div>
                        {renderChanges(selectedLog)}
                      </div>
                    </>
                  )}

                  {/* Technical Info */}
                  <Separator />
                  <div>
                    <p className="text-sm font-medium mb-2">Technical Details</p>
                    <div className="p-3 bg-muted/50 rounded-lg space-y-2 text-sm">
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">IP Address</span>
                        <span className="font-mono">{selectedLog.ip_address || '-'}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">User Agent</span>
                        <span className="truncate max-w-[300px]">{selectedLog.user_agent || '-'}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">Session ID</span>
                        <span className="font-mono">{selectedLog.session_id || '-'}</span>
                      </div>
                    </div>
                  </div>

                  {/* Metadata */}
                  {selectedLog.metadata && Object.keys(selectedLog.metadata).length > 0 && (
                    <>
                      <Separator />
                      <div>
                        <p className="text-sm font-medium mb-2">Additional Metadata</p>
                        <pre className="p-3 bg-muted/50 rounded-lg text-xs overflow-auto">
                          {JSON.stringify(selectedLog.metadata, null, 2)}
                        </pre>
                      </div>
                    </>
                  )}
                </div>
              </ScrollArea>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate } from 'react-router-dom';
import {
  Plus,
  Search,
  Play,
  Pause,
  Settings,
  Trash2,
  Copy,
  MoreHorizontal,
  Zap,
  GitBranch,
  Clock,
  CheckCircle,
  XCircle,
  AlertTriangle,
  RefreshCw,
  Filter,
  History,
  FileText,
  Target,
  Mail,
  Bell,
  Users,
  ArrowRight,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Workflow {
  id: string;
  name: string;
  description: string | null;
  trigger_type: string;
  trigger_entity: string;
  status: string;
  run_count: number;
  success_count: number;
  failure_count: number;
  last_run_at: string | null;
  created_at: string;
}

interface WorkflowRun {
  id: string;
  workflow_id: string;
  trigger_record_type: string | null;
  status: string;
  started_at: string;
  completed_at: string | null;
  duration_ms: number | null;
  error_message: string | null;
  workflow?: { name: string };
}

const triggerTypeLabels: Record<string, { label: string; icon: React.ReactNode }> = {
  record_created: { label: 'Registro Criado', icon: <Plus className="h-4 w-4" /> },
  record_updated: { label: 'Registro Atualizado', icon: <RefreshCw className="h-4 w-4" /> },
  field_changed: { label: 'Campo Alterado', icon: <FileText className="h-4 w-4" /> },
  scheduled: { label: 'Agendado', icon: <Clock className="h-4 w-4" /> },
  manual: { label: 'Manual', icon: <Play className="h-4 w-4" /> },
  approval_completed: { label: 'Aprovação Concluída', icon: <CheckCircle className="h-4 w-4" /> },
  sla_breach: { label: 'SLA Violado', icon: <AlertTriangle className="h-4 w-4" /> },
  stage_changed: { label: 'Estágio Alterado', icon: <ArrowRight className="h-4 w-4" /> },
  score_changed: { label: 'Score Alterado', icon: <Target className="h-4 w-4" /> },
};

const entityLabels: Record<string, string> = {
  lead: 'Leads',
  opportunity: 'Oportunidades',
  account: 'Contas',
  contact: 'Contatos',
  ticket: 'Tickets',
  quote: 'Cotações',
  contract: 'Contratos',
};

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  draft: { label: 'Rascunho', variant: 'secondary' },
  active: { label: 'Ativo', variant: 'default' },
  paused: { label: 'Pausado', variant: 'outline' },
  archived: { label: 'Arquivado', variant: 'destructive' },
};

const runStatusConfig: Record<string, { label: string; icon: React.ReactNode; color: string }> = {
  pending: { label: 'Pendente', icon: <Clock className="h-4 w-4" />, color: 'text-muted-foreground' },
  running: { label: 'Executando', icon: <RefreshCw className="h-4 w-4 animate-spin" />, color: 'text-blue-500' },
  completed: { label: 'Concluído', icon: <CheckCircle className="h-4 w-4" />, color: 'text-green-500' },
  failed: { label: 'Falhou', icon: <XCircle className="h-4 w-4" />, color: 'text-destructive' },
  cancelled: { label: 'Cancelado', icon: <XCircle className="h-4 w-4" />, color: 'text-muted-foreground' },
  paused: { label: 'Pausado', icon: <Pause className="h-4 w-4" />, color: 'text-yellow-500' },
  waiting_approval: { label: 'Aguardando', icon: <Clock className="h-4 w-4" />, color: 'text-yellow-500' },
};

export default function Automations() {
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const [workflows, setWorkflows] = useState<Workflow[]>([]);
  const [runs, setRuns] = useState<WorkflowRun[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [entityFilter, setEntityFilter] = useState<string>('all');
  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [newWorkflow, setNewWorkflow] = useState({
    name: '',
    description: '',
    trigger_type: 'record_created',
    trigger_entity: 'lead',
  });

  useEffect(() => {
    if (profile?.organization_id) {
      fetchWorkflows();
      fetchRuns();
    }
  }, [profile?.organization_id]);

  const fetchWorkflows = async () => {
    if (!profile?.organization_id) return;

    const { data, error } = await supabase
      .from('workflows')
      .select('*')
      .eq('organization_id', profile.organization_id)
      .order('created_at', { ascending: false });

    if (!error && data) {
      setWorkflows(data as Workflow[]);
    }
    setLoading(false);
  };

  const fetchRuns = async () => {
    if (!profile?.organization_id) return;

    const { data, error } = await supabase
      .from('workflow_runs')
      .select(`
        *,
        workflow:workflows(name)
      `)
      .eq('organization_id', profile.organization_id)
      .order('started_at', { ascending: false })
      .limit(50);

    if (!error && data) {
      setRuns(data as unknown as WorkflowRun[]);
    }
  };

  const handleCreateWorkflow = async () => {
    if (!profile?.organization_id || !newWorkflow.name) return;

    const { data, error } = await supabase
      .from('workflows')
      .insert([{
        name: newWorkflow.name,
        description: newWorkflow.description || null,
        trigger_type: newWorkflow.trigger_type as any,
        trigger_entity: newWorkflow.trigger_entity,
        organization_id: profile.organization_id,
        created_by: profile.id,
      }])
      .select()
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao criar workflow',
      });
    } else {
      toast({
        title: 'Workflow criado',
        description: `"${newWorkflow.name}" foi criado com sucesso.`,
      });
      setCreateDialogOpen(false);
      setNewWorkflow({ name: '', description: '', trigger_type: 'record_created', trigger_entity: 'lead' });
      navigate(`/automations/${data.id}`);
    }
  };

  const toggleWorkflowStatus = async (workflow: Workflow) => {
    const newStatus = workflow.status === 'active' ? 'paused' : 'active';

    const { error } = await supabase
      .from('workflows')
      .update({ status: newStatus })
      .eq('id', workflow.id);

    if (!error) {
      toast({
        title: newStatus === 'active' ? 'Workflow ativado' : 'Workflow pausado',
        description: `"${workflow.name}" foi ${newStatus === 'active' ? 'ativado' : 'pausado'}.`,
      });
      fetchWorkflows();
    }
  };

  const deleteWorkflow = async (workflow: Workflow) => {
    const { error } = await supabase
      .from('workflows')
      .delete()
      .eq('id', workflow.id);

    if (!error) {
      toast({
        title: 'Workflow excluído',
        description: `"${workflow.name}" foi excluído.`,
      });
      fetchWorkflows();
    }
  };

  const duplicateWorkflow = async (workflow: Workflow) => {
    if (!profile?.organization_id) return;

    const { error } = await supabase
      .from('workflows')
      .insert([{
        name: `${workflow.name} (Cópia)`,
        description: workflow.description,
        trigger_type: workflow.trigger_type as any,
        trigger_entity: workflow.trigger_entity,
        organization_id: profile.organization_id,
        created_by: profile.id,
        status: 'draft',
      }]);

    if (!error) {
      toast({
        title: 'Workflow duplicado',
        description: `Cópia de "${workflow.name}" foi criada.`,
      });
      fetchWorkflows();
    }
  };

  const filteredWorkflows = workflows.filter(w => {
    const matchesSearch = w.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         w.description?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'all' || w.status === statusFilter;
    const matchesEntity = entityFilter === 'all' || w.trigger_entity === entityFilter;
    return matchesSearch && matchesStatus && matchesEntity;
  });

  // Stats
  const activeWorkflows = workflows.filter(w => w.status === 'active').length;
  const totalRuns = workflows.reduce((sum, w) => sum + w.run_count, 0);
  const successRate = totalRuns > 0 
    ? Math.round((workflows.reduce((sum, w) => sum + w.success_count, 0) / totalRuns) * 100)
    : 0;

  return (
    <div className="space-y-6">
      <ModuleHeroBanner
        module="admin"
        title="Automações"
        subtitle="Gerencie workflows e automações do sistema"
        compact
        actions={
          <Button onClick={() => setCreateDialogOpen(true)} className="gap-2 bg-white text-foreground hover:bg-white/90">
            <Plus className="h-4 w-4" /> Novo Workflow
          </Button>
        }
      />

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Workflows</CardTitle>
            <GitBranch className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{workflows.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Ativos</CardTitle>
            <Play className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{activeWorkflows}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Execuções Totais</CardTitle>
            <History className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{totalRuns}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Taxa de Sucesso</CardTitle>
            <CheckCircle className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{successRate}%</div>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="workflows" className="space-y-4">
        <TabsList>
          <TabsTrigger value="workflows">Workflows</TabsTrigger>
          <TabsTrigger value="runs">Execuções Recentes</TabsTrigger>
          <TabsTrigger value="templates">Templates</TabsTrigger>
        </TabsList>

        <TabsContent value="workflows" className="space-y-4">
          {/* Filters */}
          <div className="flex items-center gap-4">
            <div className="relative flex-1 max-w-sm">
              <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar workflows..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-8"
              />
            </div>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-[150px]">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos Status</SelectItem>
                <SelectItem value="active">Ativo</SelectItem>
                <SelectItem value="paused">Pausado</SelectItem>
                <SelectItem value="draft">Rascunho</SelectItem>
                <SelectItem value="archived">Arquivado</SelectItem>
              </SelectContent>
            </Select>
            <Select value={entityFilter} onValueChange={setEntityFilter}>
              <SelectTrigger className="w-[150px]">
                <SelectValue placeholder="Entidade" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todas Entidades</SelectItem>
                {Object.entries(entityLabels).map(([key, label]) => (
                  <SelectItem key={key} value={key}>{label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Workflows Table */}
          {loading ? (
            <div className="flex items-center justify-center py-8">
              <RefreshCw className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : filteredWorkflows.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Zap className="h-12 w-12 text-muted-foreground opacity-50 mb-4" />
                <p className="text-muted-foreground mb-4">Nenhum workflow encontrado</p>
                <Button onClick={() => setCreateDialogOpen(true)}>
                  <Plus className="mr-2 h-4 w-4" />
                  Criar Primeiro Workflow
                </Button>
              </CardContent>
            </Card>
          ) : (
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Nome</TableHead>
                    <TableHead>Trigger</TableHead>
                    <TableHead>Entidade</TableHead>
                    <TableHead>Execuções</TableHead>
                    <TableHead>Última Execução</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="w-[100px]"></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredWorkflows.map((workflow) => {
                    const triggerConfig = triggerTypeLabels[workflow.trigger_type] || { label: workflow.trigger_type, icon: <Zap className="h-4 w-4" /> };
                    const status = statusConfig[workflow.status] || statusConfig.draft;

                    return (
                      <TableRow 
                        key={workflow.id}
                        className="cursor-pointer"
                        onClick={() => navigate(`/automations/${workflow.id}`)}
                      >
                        <TableCell>
                          <div>
                            <p className="font-medium">{workflow.name}</p>
                            {workflow.description && (
                              <p className="text-sm text-muted-foreground truncate max-w-[250px]">
                                {workflow.description}
                              </p>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            {triggerConfig.icon}
                            <span className="text-sm">{triggerConfig.label}</span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge variant="outline">
                            {entityLabels[workflow.trigger_entity] || workflow.trigger_entity}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <span>{workflow.run_count}</span>
                            {workflow.run_count > 0 && (
                              <span className="text-xs text-muted-foreground">
                                ({Math.round((workflow.success_count / workflow.run_count) * 100)}% sucesso)
                              </span>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          {workflow.last_run_at ? (
                            <span className="text-sm text-muted-foreground">
                              {format(new Date(workflow.last_run_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                            </span>
                          ) : (
                            <span className="text-sm text-muted-foreground">Nunca</span>
                          )}
                        </TableCell>
                        <TableCell>
                          <Badge variant={status.variant}>{status.label}</Badge>
                        </TableCell>
                        <TableCell onClick={(e) => e.stopPropagation()}>
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" size="icon">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => navigate(`/automations/${workflow.id}`)}>
                                <Settings className="mr-2 h-4 w-4" />
                                Editar
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => toggleWorkflowStatus(workflow)}>
                                {workflow.status === 'active' ? (
                                  <>
                                    <Pause className="mr-2 h-4 w-4" />
                                    Pausar
                                  </>
                                ) : (
                                  <>
                                    <Play className="mr-2 h-4 w-4" />
                                    Ativar
                                  </>
                                )}
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => duplicateWorkflow(workflow)}>
                                <Copy className="mr-2 h-4 w-4" />
                                Duplicar
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem 
                                onClick={() => deleteWorkflow(workflow)}
                                className="text-destructive"
                              >
                                <Trash2 className="mr-2 h-4 w-4" />
                                Excluir
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          )}
        </TabsContent>

        <TabsContent value="runs" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Execuções Recentes</CardTitle>
              <CardDescription>Últimas 50 execuções de workflows</CardDescription>
            </CardHeader>
            <CardContent>
              {runs.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  Nenhuma execução encontrada
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Workflow</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Iniciado</TableHead>
                      <TableHead>Duração</TableHead>
                      <TableHead>Erro</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {runs.map((run) => {
                      const statusCfg = runStatusConfig[run.status] || runStatusConfig.pending;
                      return (
                        <TableRow key={run.id}>
                          <TableCell className="font-medium">
                            {run.workflow?.name || 'Workflow Desconhecido'}
                          </TableCell>
                          <TableCell>
                            <div className={`flex items-center gap-2 ${statusCfg.color}`}>
                              {statusCfg.icon}
                              <span>{statusCfg.label}</span>
                            </div>
                          </TableCell>
                          <TableCell>
                            {format(new Date(run.started_at), "dd/MM/yyyy HH:mm:ss", { locale: ptBR })}
                          </TableCell>
                          <TableCell>
                            {run.duration_ms ? `${run.duration_ms}ms` : '-'}
                          </TableCell>
                          <TableCell>
                            {run.error_message ? (
                              <span className="text-sm text-destructive truncate max-w-[200px] block">
                                {run.error_message}
                              </span>
                            ) : '-'}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="templates" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Templates de Workflow</CardTitle>
              <CardDescription>
                Use templates pré-configurados para criar workflows rapidamente
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="grid gap-4 md:grid-cols-3">
                {[
                  {
                    name: 'Lead Nurturing',
                    description: 'Sequência automática de follow-up para novos leads',
                    icon: <Users className="h-8 w-8" />,
                    category: 'Sales',
                  },
                  {
                    name: 'Notificação de SLA',
                    description: 'Alerta quando um ticket está próximo de violar o SLA',
                    icon: <Bell className="h-8 w-8" />,
                    category: 'Service',
                  },
                  {
                    name: 'Boas-vindas',
                    description: 'Email automático de boas-vindas para novos contatos',
                    icon: <Mail className="h-8 w-8" />,
                    category: 'Marketing',
                  },
                  {
                    name: 'Aprovação de Desconto',
                    description: 'Fluxo de aprovação para descontos acima de 20%',
                    icon: <CheckCircle className="h-8 w-8" />,
                    category: 'Sales',
                  },
                  {
                    name: 'Escalonamento',
                    description: 'Escalonamento automático de tickets de alta prioridade',
                    icon: <AlertTriangle className="h-8 w-8" />,
                    category: 'Service',
                  },
                  {
                    name: 'Atualização de Score',
                    description: 'Recalcula score do lead baseado em atividades',
                    icon: <Target className="h-8 w-8" />,
                    category: 'Sales',
                  },
                ].map((template, index) => (
                  <Card key={index} className="cursor-pointer hover:border-primary transition-colors">
                    <CardContent className="pt-6">
                      <div className="flex items-start gap-4">
                        <div className="p-2 rounded-lg bg-primary/10 text-primary">
                          {template.icon}
                        </div>
                        <div className="flex-1">
                          <h3 className="font-semibold">{template.name}</h3>
                          <p className="text-sm text-muted-foreground mb-2">
                            {template.description}
                          </p>
                          <Badge variant="secondary">{template.category}</Badge>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Create Dialog */}
      <Dialog open={createDialogOpen} onOpenChange={setCreateDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Novo Workflow</DialogTitle>
            <DialogDescription>
              Crie uma nova automação para seu sistema
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Nome *</Label>
              <Input
                value={newWorkflow.name}
                onChange={(e) => setNewWorkflow({ ...newWorkflow, name: e.target.value })}
                placeholder="Ex: Notificar equipe de vendas"
              />
            </div>
            <div className="space-y-2">
              <Label>Descrição</Label>
              <Textarea
                value={newWorkflow.description}
                onChange={(e) => setNewWorkflow({ ...newWorkflow, description: e.target.value })}
                placeholder="Descreva o que este workflow faz..."
                rows={2}
              />
            </div>
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label>Trigger</Label>
                <Select
                  value={newWorkflow.trigger_type}
                  onValueChange={(v) => setNewWorkflow({ ...newWorkflow, trigger_type: v })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(triggerTypeLabels).map(([key, config]) => (
                      <SelectItem key={key} value={key}>
                        <div className="flex items-center gap-2">
                          {config.icon}
                          <span>{config.label}</span>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Entidade</Label>
                <Select
                  value={newWorkflow.trigger_entity}
                  onValueChange={(v) => setNewWorkflow({ ...newWorkflow, trigger_entity: v })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(entityLabels).map(([key, label]) => (
                      <SelectItem key={key} value={key}>{label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCreateDialogOpen(false)}>
              Cancelar
            </Button>
            <Button onClick={handleCreateWorkflow} disabled={!newWorkflow.name}>
              Criar Workflow
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from 'react';
