                        rows={10}
                      />
                      <p className="text-sm text-muted-foreground">
                        Use {"{{nome}}"}, {"{{empresa}}"} para personalização
                      </p>
                    </div>
                  </CardContent>
                </Card>
              )}

              {form.type === 'sms' && (
                <Card>
                  <CardHeader>
                    <CardTitle>Conteúdo do SMS</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="space-y-2">
                      <Label>Mensagem</Label>
                      <Textarea
                        value={form.content}
