import { Switch } from '@/components/ui/switch';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

type ContractStatus = 'draft' | 'pending_approval' | 'sent' | 'negotiating' | 'signed' | 'active' | 'expired' | 'terminated' | 'renewed';

interface Account {
  id: string;
  name: string;
}

interface Contact {
  id: string;
  first_name: string;
  last_name: string;
  account_id: string | null;
}

interface Opportunity {
  id: string;
  name: string;
  account_id: string;
}

interface Quote {
  id: string;
  quote_number: string;
  name: string;
  account_id: string;
  total: number | null;
}

interface ContractForm {
  name: string;
  description: string;
  account_id: string;
  contact_id: string;
  opportunity_id: string;
  quote_id: string;
  status: ContractStatus;
  total_value: string;
  recurring_value: string;
  billing_frequency: string;
  payment_terms: string;
  start_date: string;
  end_date: string;
  auto_renewal: boolean;
  renewal_notice_days: string;
  terms_and_conditions: string;
  special_conditions: string;
}

const initialForm: ContractForm = {
  name: '',
  description: '',
  account_id: '',
  contact_id: '',
  opportunity_id: '',
  quote_id: '',
  status: 'draft',
  total_value: '',
  recurring_value: '',
  billing_frequency: 'monthly',
  payment_terms: 'Net 30',
  start_date: '',
  end_date: '',
  auto_renewal: false,
  renewal_notice_days: '30',
  terms_and_conditions: '',
  special_conditions: '',
};

export default function ContractForm() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, profile, loading: authLoading } = useAuth();
  const { toast } = useToast();
  const [form, setForm] = useState<ContractForm>(initialForm);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [opportunities, setOpportunities] = useState<Opportunity[]>([]);
  const [quotes, setQuotes] = useState<Quote[]>([]);

  const isEditing = !!id;

  useEffect(() => {
    if (user) {
      fetchAccounts();
      fetchOpportunities();
      fetchQuotes();
      if (id) {
        fetchContract();
      }
    }
  }, [user, id]);

  useEffect(() => {
    if (form.account_id) {
      fetchContacts(form.account_id);
    }
  }, [form.account_id]);

  const fetchAccounts = async () => {
    const { data } = await supabase
      .from('accounts')
      .select('id, name')
      .order('name');
    if (data) setAccounts(data);
  };

  const fetchContacts = async (accountId: string) => {
    const { data } = await supabase
      .from('contacts')
      .select('id, first_name, last_name, account_id')
      .eq('account_id', accountId)
      .order('first_name');
    if (data) setContacts(data);
  };

  const fetchOpportunities = async () => {
    const { data } = await supabase
      .from('opportunities')
      .select('id, name, account_id')
      .order('name');
    if (data) setOpportunities(data);
  };

  const fetchQuotes = async () => {
    const { data } = await supabase
      .from('quotes')
      .select('id, quote_number, name, account_id, total')
      .eq('status', 'accepted')
      .order('created_at', { ascending: false });
    if (data) setQuotes(data);
  };

  const fetchContract = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('contracts')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar contrato',
      });
      navigate('/contracts');
    } else if (data) {
      setForm({
        name: data.name || '',
        description: data.description || '',
        account_id: data.account_id || '',
        contact_id: data.contact_id || '',
        opportunity_id: data.opportunity_id || '',
        quote_id: data.quote_id || '',
        status: data.status || 'draft',
        total_value: data.total_value?.toString() || '',
        recurring_value: data.recurring_value?.toString() || '',
        billing_frequency: data.billing_frequency || 'monthly',
        payment_terms: data.payment_terms || '',
        start_date: data.start_date || '',
        end_date: data.end_date || '',
        auto_renewal: data.auto_renewal || false,
        renewal_notice_days: data.renewal_notice_days?.toString() || '30',
        terms_and_conditions: data.terms_and_conditions || '',
        special_conditions: data.special_conditions || '',
      });
    }
    setLoading(false);
  };

  const handleQuoteSelect = (quoteId: string) => {
    const quote = quotes.find(q => q.id === quoteId);
    if (quote) {
      setForm(prev => ({
        ...prev,
        quote_id: quoteId,
        account_id: quote.account_id,
        total_value: quote.total?.toString() || prev.total_value,
        name: prev.name || `Contract for ${quote.name}`,
      }));
    }
  };

  const handleOpportunitySelect = (opportunityId: string) => {
    const opportunity = opportunities.find(o => o.id === opportunityId);
    if (opportunity) {
      setForm(prev => ({
        ...prev,
        opportunity_id: opportunityId,
        account_id: opportunity.account_id,
      }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!profile?.organization_id) return;

    if (!form.name || !form.account_id) {
      toast({
        variant: 'destructive',
        title: 'Erro de Validação',
        description: 'Por favor, preencha todos os campos obrigatórios',
      });
      return;
    }

    setSaving(true);

    const contractData = {
      name: form.name,
      description: form.description || null,
      account_id: form.account_id,
      contact_id: form.contact_id || null,
      opportunity_id: form.opportunity_id || null,
      quote_id: form.quote_id || null,
      status: form.status,
      total_value: form.total_value ? parseFloat(form.total_value) : null,
      recurring_value: form.recurring_value ? parseFloat(form.recurring_value) : null,
      billing_frequency: form.billing_frequency || null,
      payment_terms: form.payment_terms || null,
      start_date: form.start_date || null,
      end_date: form.end_date || null,
      auto_renewal: form.auto_renewal,
      renewal_notice_days: form.renewal_notice_days ? parseInt(form.renewal_notice_days) : 30,
      terms_and_conditions: form.terms_and_conditions || null,
      special_conditions: form.special_conditions || null,
      organization_id: profile.organization_id,
      owner_id: profile.id,
    };

    if (isEditing) {
      const { error } = await supabase
        .from('contracts')
        .update(contractData)
        .eq('id', id);

      if (error) {
        toast({
          variant: 'destructive',
          title: 'Erro',
          description: 'Falha ao atualizar contrato',
        });
      } else {
        toast({
          title: 'Contrato atualizado',
          description: 'O contrato foi atualizado com sucesso.',
        });
        navigate(`/contracts/${id}`);
      }
    } else {
      // Generate contract number
      const contractNumber = `CTR-${new Date().getFullYear()}-${Date.now().toString(36).toUpperCase()}`;

      const { data, error } = await supabase
        .from('contracts')
        .insert([{ ...contractData, contract_number: contractNumber }])
        .select()
        .single();

      if (error) {
        toast({
          variant: 'destructive',
          title: 'Erro',
          description: 'Falha ao criar contrato',
        });
      } else {
        // Create timeline event
        await supabase.from('timeline_events').insert([{
          organization_id: profile.organization_id,
          event_type: 'note_added',
          title: 'Contrato Criado',
          description: `Contrato "${form.name}" foi criado.`,
          account_id: form.account_id,
          opportunity_id: form.opportunity_id || null,
          created_by: profile.id,
        }]);

        toast({
          title: 'Contrato criado',
          description: 'O contrato foi criado com sucesso.',
        });
        navigate(`/contracts/${data.id}`);
      }
    }

    setSaving(false);
  };

  const filteredContacts = contacts.filter(c => 
    !form.account_id || c.account_id === form.account_id
  );

  const filteredOpportunities = opportunities.filter(o => 
    !form.account_id || o.account_id === form.account_id
  );

  const filteredQuotes = quotes.filter(q => 
    !form.account_id || q.account_id === form.account_id
  );

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <>
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button
            type="button"
            variant="ghost"
            size="icon"
            onClick={() => navigate('/contracts')}
          >
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div className="flex-1">
            <h1 className="text-2xl font-bold tracking-tight">
              {isEditing ? 'Editar Contrato' : 'Novo Contrato'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing ? 'Atualizar detalhes do contrato' : 'Criar um novo contrato de cliente'}
            </p>
          </div>
          <Button type="submit" disabled={saving}>
            {saving ? (
              <RefreshCw className="mr-2 h-4 w-4 animate-spin" />
            ) : (
              <Save className="mr-2 h-4 w-4" />
            )}
            {isEditing ? 'Atualizar Contrato' : 'Criar Contrato'}
          </Button>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Form */}
          <div className="lg:col-span-2 space-y-6">
            {/* Basic Info */}
            <Card>
              <CardHeader>
                <CardTitle>Informações Básicas</CardTitle>
                <CardDescription>Nome e descrição do contrato</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Nome do Contrato *</Label>
                  <Input
                    id="name"
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    placeholder="Acordo de Licenciamento Empresarial"
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="description">Descrição</Label>
                  <Textarea
                    id="description"
                    value={form.description}
                    onChange={(e) => setForm({ ...form, description: e.target.value })}
                    placeholder="Breve descrição do contrato..."
                    rows={3}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Relationships */}
            <Card>
              <CardHeader>
                <CardTitle>Relacionamentos</CardTitle>
                <CardDescription>Vincule a conta, contato, oportunidade e proposta</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="account">Conta *</Label>
                    <Select
                      value={form.account_id}
                      onValueChange={(value) => setForm({ ...form, account_id: value })}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione uma conta" />
                      </SelectTrigger>
                      <SelectContent>
                        {accounts.map((account) => (
                          <SelectItem key={account.id} value={account.id}>
                            {account.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="contact">Contato</Label>
                    <Select
                      value={form.contact_id}
                      onValueChange={(value) => setForm({ ...form, contact_id: value })}
                      disabled={!form.account_id}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione um contato" />
                      </SelectTrigger>
                      <SelectContent>
                        {filteredContacts.map((contact) => (
                          <SelectItem key={contact.id} value={contact.id}>
                            {contact.first_name} {contact.last_name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="opportunity">Oportunidade</Label>
                    <Select
                      value={form.opportunity_id}
                      onValueChange={handleOpportunitySelect}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione uma oportunidade" />
                      </SelectTrigger>
                      <SelectContent>
                        {filteredOpportunities.map((opp) => (
                          <SelectItem key={opp.id} value={opp.id}>
                            {opp.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="quote">Proposta (Aceita)</Label>
                    <Select
                      value={form.quote_id}
                      onValueChange={handleQuoteSelect}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione uma proposta" />
                      </SelectTrigger>
                      <SelectContent>
                        {filteredQuotes.map((quote) => (
                          <SelectItem key={quote.id} value={quote.id}>
                            {quote.quote_number} - {quote.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Financial */}
            <Card>
              <CardHeader>
                <CardTitle>Detalhes Financeiros</CardTitle>
                <CardDescription>Valor do contrato e informações de cobrança</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="total_value">Valor Total (R$)</Label>
                    <Input
                      id="total_value"
                      type="number"
                      step="0.01"
                      value={form.total_value}
                      onChange={(e) => setForm({ ...form, total_value: e.target.value })}
                      placeholder="0.00"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="recurring_value">Valor Recorrente (R$)</Label>
                    <Input
                      id="recurring_value"
                      type="number"
                      step="0.01"
                      value={form.recurring_value}
                      onChange={(e) => setForm({ ...form, recurring_value: e.target.value })}
                      placeholder="0.00"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="billing_frequency">Frequência de Cobrança</Label>
                    <Select
                      value={form.billing_frequency}
                      onValueChange={(value) => setForm({ ...form, billing_frequency: value })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="monthly">Mensal</SelectItem>
                        <SelectItem value="quarterly">Trimestral</SelectItem>
                        <SelectItem value="semi-annual">Semestral</SelectItem>
                        <SelectItem value="annual">Anual</SelectItem>
                        <SelectItem value="one-time">Única</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="payment_terms">Condições de Pagamento</Label>
                    <Select
                      value={form.payment_terms}
                      onValueChange={(value) => setForm({ ...form, payment_terms: value })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Net 15">15 dias</SelectItem>
                        <SelectItem value="Net 30">30 dias</SelectItem>
                        <SelectItem value="Net 45">45 dias</SelectItem>
                        <SelectItem value="Net 60">60 dias</SelectItem>
                        <SelectItem value="Due on Receipt">No Recebimento</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Terms */}
            <Card>
              <CardHeader>
                <CardTitle>Termos e Condições</CardTitle>
                <CardDescription>Termos padrão e condições especiais do contrato</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="terms">Termos Padrão</Label>
                  <Textarea
                    id="terms"
                    value={form.terms_and_conditions}
                    onChange={(e) => setForm({ ...form, terms_and_conditions: e.target.value })}
                    placeholder="Digite os termos e condições padrão..."
                    rows={6}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="special">Condições Especiais</Label>
                  <Textarea
                    id="special"
                    value={form.special_conditions}
                    onChange={(e) => setForm({ ...form, special_conditions: e.target.value })}
                    placeholder="Digite quaisquer condições ou exceções especiais..."
                    rows={4}
                  />
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Status */}
            <Card>
              <CardHeader>
                <CardTitle>Status</CardTitle>
              </CardHeader>
              <CardContent>
                <Select
                  value={form.status}
                  onValueChange={(value) => setForm({ ...form, status: value as ContractStatus })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="draft">Rascunho</SelectItem>
                    <SelectItem value="pending_approval">Aguardando Aprovação</SelectItem>
                    <SelectItem value="sent">Enviado</SelectItem>
                    <SelectItem value="negotiating">Em Negociação</SelectItem>
                    <SelectItem value="signed">Assinado</SelectItem>
                    <SelectItem value="active">Ativo</SelectItem>
                    <SelectItem value="expired">Expirado</SelectItem>
                    <SelectItem value="terminated">Rescindido</SelectItem>
                    <SelectItem value="renewed">Renovado</SelectItem>
                  </SelectContent>
                </Select>
              </CardContent>
            </Card>

            {/* Dates */}
            <Card>
              <CardHeader>
                <CardTitle>Período do Contrato</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="start_date">Data de Início</Label>
                  <Input
                    id="start_date"
                    type="date"
                    value={form.start_date}
                    onChange={(e) => setForm({ ...form, start_date: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="end_date">Data de Término</Label>
                  <Input
                    id="end_date"
                    type="date"
                    value={form.end_date}
                    onChange={(e) => setForm({ ...form, end_date: e.target.value })}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Renewal */}
            <Card>
              <CardHeader>
                <CardTitle>Configurações de Renovação</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label htmlFor="auto_renewal">Renovação Automática</Label>
                  <Switch
                    id="auto_renewal"
                    checked={form.auto_renewal}
                    onCheckedChange={(checked) => setForm({ ...form, auto_renewal: checked })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="renewal_notice">Período de Aviso (dias)</Label>
                  <Input
                    id="renewal_notice"
                    type="number"
                    value={form.renewal_notice_days}
                    onChange={(e) => setForm({ ...form, renewal_notice_days: e.target.value })}
                    placeholder="30"
                  />
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </form>
    </>
  );
}

import { useState, useEffect } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate, Link } from 'react-router-dom';
import {
  Plus,
  Search,
  MoreHorizontal,
  Eye,
  Edit,
  Trash2,
  ArrowUpDown,
  FileText,
  Calendar,
  Clock,
  CheckCircle,
  Send,
  RefreshCw,
  Download,
  Copy,
  AlertTriangle,
  Building2,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Card, CardContent } from '@/components/ui/card';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { format, differenceInDays, addDays } from 'date-fns';

type ContractStatus = 'draft' | 'pending_approval' | 'sent' | 'negotiating' | 'signed' | 'active' | 'expired' | 'terminated' | 'renewed';

interface Contract {
  id: string;
  contract_number: string;
  name: string;
  status: ContractStatus;
  total_value: number | null;
  recurring_value: number | null;
  start_date: string | null;
  end_date: string | null;
  signed_date: string | null;
  auto_renewal: boolean | null;
  created_at: string;
  account: {
    id: string;
    name: string;
  } | null;
  opportunity: {
    id: string;
    name: string;
  } | null;
  owner: {
    id: string;
    first_name: string | null;
    last_name: string | null;
  } | null;
}

const statusConfig: Record<ContractStatus, { label: string; className: string; icon: React.ReactNode }> = {
  draft: { 
    label: 'Rascunho', 
    className: 'bg-muted text-muted-foreground',
    icon: <FileText className="h-3 w-3" />
  },
  pending_approval: { 
    label: 'Aguard. Aprovação', 
    className: 'bg-warning/10 text-warning border-warning/20',
    icon: <Clock className="h-3 w-3" />
  },
  sent: { 
    label: 'Enviado', 
    className: 'bg-info/10 text-info border-info/20',
    icon: <Send className="h-3 w-3" />
  },
  negotiating: { 
    label: 'Negociando', 
    className: 'bg-purple-500/10 text-purple-500 border-purple-500/20',
    icon: <RefreshCw className="h-3 w-3" />
  },
  signed: { 
    label: 'Assinado', 
    className: 'bg-success/10 text-success border-success/20',
    icon: <CheckCircle className="h-3 w-3" />
  },
  active: { 
    label: 'Ativo', 
    className: 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
    icon: <CheckCircle className="h-3 w-3" />
  },
  expired: { 
    label: 'Expirado', 
    className: 'bg-destructive/10 text-destructive border-destructive/20',
    icon: <AlertTriangle className="h-3 w-3" />
  },
  terminated: { 
    label: 'Rescindido', 
    className: 'bg-destructive/10 text-destructive border-destructive/20',
    icon: <AlertTriangle className="h-3 w-3" />
  },
  renewed: { 
    label: 'Renovado', 
    className: 'bg-blue-500/10 text-blue-500 border-blue-500/20',
    icon: <RefreshCw className="h-3 w-3" />
  },
};

export default function Contracts() {
  const { user, loading: authLoading } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();
  const [contracts, setContracts] = useState<Contract[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [deleteContractId, setDeleteContractId] = useState<string | null>(null);

  useEffect(() => {
    if (user) {
      fetchContracts();
    }
  }, [user]);

  const fetchContracts = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('contracts')
      .select(`
        id,
        contract_number,
        name,
        status,
        total_value,
        recurring_value,
        start_date,
        end_date,
        signed_date,
        auto_renewal,
        created_at,
        account:accounts(id, name),
        opportunity:opportunities(id, name),
        owner:profiles!contracts_owner_id_fkey(id, first_name, last_name)
      `)
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching contracts:', error);
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar contratos',
      });
    } else {
      setContracts((data || []) as Contract[]);
    }
    setLoading(false);
  };

  const deleteContract = async (id: string) => {
    const { error } = await supabase.from('contracts').delete().eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao excluir contrato',
      });
    } else {
      toast({
        title: 'Contrato excluído',
        description: 'O contrato foi excluído com sucesso.',
      });
      fetchContracts();
    }
    setDeleteContractId(null);
  };

  const filteredContracts = contracts.filter((contract) => {
    const matchesSearch =
      searchQuery === '' ||
      contract.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      contract.contract_number.toLowerCase().includes(searchQuery.toLowerCase()) ||
      contract.account?.name.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesStatus = statusFilter === 'all' || contract.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  // Calculate stats
  const totalContracts = contracts.length;
  const activeContracts = contracts.filter(c => c.status === 'active').length;
  const expiringContracts = contracts.filter(c => {
    if (!c.end_date) return false;
    const daysUntilExpiry = differenceInDays(new Date(c.end_date), new Date());
    return daysUntilExpiry <= 30 && daysUntilExpiry > 0 && c.status === 'active';
  }).length;
  const totalValue = contracts.reduce((sum, c) => sum + (c.total_value || 0), 0);

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(value);
  };

  const getExpiryWarning = (endDate: string | null, status: ContractStatus) => {
    if (!endDate || status !== 'active') return null;
    const daysUntilExpiry = differenceInDays(new Date(endDate), new Date());
    if (daysUntilExpiry <= 0) return { label: 'Expirado', className: 'text-destructive' };
    if (daysUntilExpiry <= 30) return { label: `${daysUntilExpiry} dias`, className: 'text-warning' };
    return null;
  };

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="sales"
          title="Contratos"
          subtitle="Gerencie contratos de clientes e acompanhe renovações"
          compact
          actions={
            <div className="flex gap-2">
              <Button variant="outline" size="sm" className="gap-2 bg-white/10 text-white border-white/20 hover:bg-white/20">
                <Download className="h-4 w-4" /> Exportar
              </Button>
              <Button size="sm" onClick={() => navigate('/contracts/new')} className="gap-2 bg-white text-foreground hover:bg-white/90">
                <Plus className="h-4 w-4" /> Novo Contrato
              </Button>
            </div>
          }
        />

        {/* Stats Cards */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-primary/10 rounded-lg">
                  <FileText className="h-5 w-5 text-primary" />
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Total de Contratos</p>
                  <p className="text-2xl font-bold">{totalContracts}</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-success/10 rounded-lg">
                  <CheckCircle className="h-5 w-5 text-success" />
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Ativos</p>
                  <p className="text-2xl font-bold">{activeContracts}</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-warning/10 rounded-lg">
                  <AlertTriangle className="h-5 w-5 text-warning" />
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Expirando em Breve</p>
                  <p className="text-2xl font-bold">{expiringContracts}</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-info/10 rounded-lg">
                  <Building2 className="h-5 w-5 text-info" />
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Valor Total</p>
                  <p className="text-2xl font-bold">{formatCurrency(totalValue)}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <div className="flex flex-col gap-4 md:flex-row md:items-center">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Buscar contratos..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Filtrar por status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os Status</SelectItem>
              <SelectItem value="draft">Rascunho</SelectItem>
              <SelectItem value="pending_approval">Aguard. Aprovação</SelectItem>
              <SelectItem value="sent">Enviado</SelectItem>
              <SelectItem value="negotiating">Negociando</SelectItem>
              <SelectItem value="signed">Assinado</SelectItem>
              <SelectItem value="active">Ativo</SelectItem>
              <SelectItem value="expired">Expirado</SelectItem>
              <SelectItem value="terminated">Rescindido</SelectItem>
              <SelectItem value="renewed">Renovado</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Table */}
        <div className="rounded-lg border bg-card">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[120px]">Número</TableHead>
                <TableHead className="w-[250px]">Nome</TableHead>
                <TableHead>Conta</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Valor</TableHead>
                <TableHead>Data Final</TableHead>
                <TableHead>Renovação Auto</TableHead>
                <TableHead className="w-[50px]"></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {loading ? (
                <TableRow>
                  <TableCell colSpan={8} className="h-24 text-center">
                    <div className="flex items-center justify-center gap-2">
                      <RefreshCw className="h-4 w-4 animate-spin" />
                      Carregando contratos...
                    </div>
                  </TableCell>
                </TableRow>
              ) : filteredContracts.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={8} className="h-24 text-center">
                    <div className="flex flex-col items-center gap-2">
                      <FileText className="h-8 w-8 text-muted-foreground" />
                      <p className="text-muted-foreground">Nenhum contrato encontrado</p>
                      <Button variant="outline" size="sm" onClick={() => navigate('/contracts/new')}>
                        <Plus className="mr-2 h-4 w-4" />
                        Crie seu primeiro contrato
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ) : (
                filteredContracts.map((contract) => {
                  const config = statusConfig[contract.status];
                  const expiryWarning = getExpiryWarning(contract.end_date, contract.status);

                  return (
                    <TableRow key={contract.id} className="cursor-pointer hover:bg-muted/50">
                      <TableCell className="font-mono text-sm">
                        {contract.contract_number}
                      </TableCell>
                      <TableCell>
                        <Link to={`/contracts/${contract.id}`} className="font-medium hover:underline">
                          {contract.name}
                        </Link>
                        {contract.opportunity && (
                          <p className="text-sm text-muted-foreground">
                            {contract.opportunity.name}
                          </p>
                        )}
                      </TableCell>
                      <TableCell>
                        {contract.account ? (
                          <Link 
                            to={`/accounts/${contract.account.id}`}
                            className="hover:underline"
                          >
                            {contract.account.name}
                          </Link>
                        ) : '-'}
                      </TableCell>
                      <TableCell>
                        <Badge variant="outline" className={config.className}>
                          {config.icon}
                          <span className="ml-1">{config.label}</span>
                        </Badge>
                      </TableCell>
                      <TableCell>
                        {contract.total_value ? formatCurrency(contract.total_value) : '-'}
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          {contract.end_date ? (
                            <>
                              <span>{format(new Date(contract.end_date), 'MMM d, yyyy')}</span>
                              {expiryWarning && (
                                <span className={`text-xs font-medium ${expiryWarning.className}`}>
                                  ({expiryWarning.label})
                                </span>
                              )}
                            </>
                          ) : '-'}
                        </div>
                      </TableCell>
                      <TableCell>
                        {contract.auto_renewal ? (
                          <Badge variant="secondary">Auto</Badge>
                        ) : (
                          <span className="text-muted-foreground">-</span>
                        )}
                      </TableCell>
                      <TableCell>
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" size="icon">
                              <MoreHorizontal className="h-4 w-4" />
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => navigate(`/contracts/${contract.id}`)}>
                              <Eye className="mr-2 h-4 w-4" />
                              Ver Detalhes
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => navigate(`/contracts/${contract.id}/edit`)}>
                              <Edit className="mr-2 h-4 w-4" />
                              Editar
                            </DropdownMenuItem>
                            <DropdownMenuSeparator />
                            <DropdownMenuItem
                              className="text-destructive focus:text-destructive"
                              onClick={() => setDeleteContractId(contract.id)}
                            >
                              <Trash2 className="mr-2 h-4 w-4" />
                              Delete
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </div>

        {/* Delete Confirmation */}
        <AlertDialog open={!!deleteContractId} onOpenChange={() => setDeleteContractId(null)}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Delete Contract</AlertDialogTitle>
              <AlertDialogDescription>
                Are you sure you want to delete this contract? This action cannot be undone.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={() => deleteContractId && deleteContract(deleteContractId)}
              >
                Delete
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Activity, AlertTriangle, RefreshCw, Star, Zap,
  DollarSign, Target, TrendingUp, Ticket, ShoppingCart,
  Mail, Phone, FileSignature, MessageSquare, StickyNote,
} from '@/components/icons';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, PieChart as RechartsPie, Pie, Cell,
} from 'recharts';

// Subcomponents
import { Customer360Header } from '@/components/customer360/Customer360Header';
import { Customer360Stats } from '@/components/customer360/Customer360Stats';
import { Customer360Contracts } from '@/components/customer360/Customer360Contracts';
import { Customer360Conversations } from '@/components/customer360/Customer360Conversations';
import { Customer360Notes } from '@/components/customer360/Customer360Notes';
import { Customer360EngagementScore } from '@/components/customer360/Customer360EngagementScore';

const COLORS = ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6'];

export default function Customer360() {
  const { type, id } = useParams<{ type: string; id: string }>();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');

  const entityType = type || 'account';
  const tableName = entityType === 'contact' ? 'contacts' : 'accounts';

  // Fetch main entity
  const { data: entity, isLoading: loadingEntity } = useQuery({
    queryKey: ['customer-360-entity', entityType, id],
    queryFn: async () => {
      const { data, error } = await supabase.from(tableName).select('*').eq('id', id).single();
      if (error) throw error;
      return data as any;
    },
    enabled: !!id,
  });

  // Fetch related contacts (for accounts)
  const { data: contacts = [] } = useQuery({
    queryKey: ['customer-360-contacts', id],
    queryFn: async () => {
      if (entityType !== 'account') return [];
      const { data, error } = await supabase.from('contacts').select('*').eq('account_id', id).order('created_at', { ascending: false });
      if (error) throw error;
      return data as any[];
    },
    enabled: entityType === 'account' && !!id,
  });

  // Fetch opportunities
  const { data: opportunities = [] } = useQuery({
    queryKey: ['customer-360-opportunities', id],
    queryFn: async () => {
      const { data, error } = await supabase.from('opportunities').select('*').eq('account_id', id).order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch tickets
  const { data: tickets = [] } = useQuery({
    queryKey: ['customer-360-tickets', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('tickets').select('*').eq(column, id).order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch orders
  const { data: orders = [] } = useQuery({
    queryKey: ['customer-360-orders', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('orders').select('*').eq(column, id).order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch activities
  const { data: activities = [] } = useQuery({
    queryKey: ['customer-360-activities', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('activities').select('*').eq(column, id).order('created_at', { ascending: false }).limit(20);
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch contracts
  const { data: contracts = [] } = useQuery({
    queryKey: ['customer-360-contracts-count', id],
    queryFn: async () => {
      const { data, error } = await supabase.from('contracts').select('id, status').eq('account_id', id);
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch conversations count
  const { data: conversationsData = [] } = useQuery({
    queryKey: ['customer-360-conversations-count', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('conversations').select('id').eq(column, id);
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch timeline events
  const { data: timelineEvents = [] } = useQuery({
    queryKey: ['customer-360-timeline', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('timeline_events').select('*').eq(column, id).order('created_at', { ascending: false }).limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch health score
  const { data: healthScore } = useQuery({
    queryKey: ['customer-360-health', id],
    queryFn: async () => {
      if (entityType !== 'account') return null;
      const { data, error } = await supabase.from('customer_health_scores').select('*').eq('account_id', id).order('calculated_at', { ascending: false }).limit(1).single();
      if (error && error.code !== 'PGRST116') throw error;
      return data as any;
    },
    enabled: entityType === 'account' && !!id,
  });

  // Fetch behavioral events
  const { data: behavioralEvents = [] } = useQuery({
    queryKey: ['customer-360-behavioral', id],
    queryFn: async () => {
      const column = entityType === 'account' ? 'account_id' : 'contact_id';
      const { data, error } = await supabase.from('behavioral_events').select('*').eq(column, id).order('occurred_at', { ascending: false }).limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Calculate metrics
  const metrics = {
    totalRevenue: opportunities.filter((o: any) => o.stage === 'closed_won').reduce((sum: number, o: any) => sum + (o.amount || 0), 0),
    openPipeline: opportunities.filter((o: any) => !['closed_won', 'closed_lost'].includes(o.stage)).reduce((sum: number, o: any) => sum + (o.amount || 0), 0),
    totalOpportunities: opportunities.length,
    wonOpportunities: opportunities.filter((o: any) => o.stage === 'closed_won').length,
    openTickets: tickets.filter((t: any) => !['resolved', 'closed'].includes(t.status)).length,
    totalOrders: orders.length,
    orderValue: orders.reduce((sum: number, o: any) => sum + (o.grand_total || 0), 0),
    activities: activities.length,
    activeContracts: contracts.filter((c: any) => c.status === 'active').length,
    totalConversations: conversationsData.length,
    winRate: opportunities.length > 0
      ? ((opportunities.filter((o: any) => o.stage === 'closed_won').length / opportunities.length) * 100).toFixed(0)
      : '0',
  };

  // Chart data
  const revenueByMonth = opportunities
    .filter((o: any) => o.stage === 'closed_won' && o.close_date)
    .reduce((acc: Record<string, number>, o: any) => {
      const month = format(new Date(o.close_date!), 'MMM/yy', { locale: ptBR });
      acc[month] = (acc[month] || 0) + (o.amount || 0);
      return acc;
    }, {});

  const revenueChartData = Object.entries(revenueByMonth).map(([month, value]) => ({ month, value }));

  const opportunityStages = opportunities.reduce((acc: Record<string, number>, o: any) => {
    acc[o.stage] = (acc[o.stage] || 0) + 1;
    return acc;
  }, {});

  const stageChartData = Object.entries(opportunityStages).map(([name, value], index) => ({
    name,
    value,
    fill: COLORS[index % COLORS.length],
  }));

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', notation: 'compact' }).format(value);

  if (loadingEntity) {
    return (
      <>
        <div className="flex items-center justify-center h-64">
          <RefreshCw className="h-8 w-8 animate-spin" />
        </div>
      </>
    );
  }

  if (!entity) {
    return (
      <>
        <div className="text-center py-16">
          <AlertTriangle className="h-16 w-16 mx-auto text-muted-foreground mb-4" />
          <h2 className="text-xl font-semibold">Registro não encontrado</h2>
          <Button onClick={() => navigate(-1)} className="mt-4">Voltar</Button>
        </div>
      </>
    );
  }

  const entityName = entityType === 'account'
    ? entity.name
    : `${entity.first_name || ''} ${entity.last_name || ''}`.trim();

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <Customer360Header
          entityType={entityType}
          entityName={entityName}
          entity={entity}
          healthScore={healthScore}
        />

        {/* Quick Stats */}
        <Customer360Stats metrics={metrics} />

        {/* Main Content */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="flex-wrap h-auto">
            <TabsTrigger value="overview">Visão Geral</TabsTrigger>
            <TabsTrigger value="timeline">Timeline</TabsTrigger>
            <TabsTrigger value="opportunities">Oportunidades</TabsTrigger>
            <TabsTrigger value="tickets">Tickets</TabsTrigger>
            <TabsTrigger value="orders">Pedidos</TabsTrigger>
            <TabsTrigger value="contracts">Contratos</TabsTrigger>
            <TabsTrigger value="conversations">Conversas</TabsTrigger>
            <TabsTrigger value="notes">Notas</TabsTrigger>
            {entityType === 'account' && <TabsTrigger value="contacts">Contatos</TabsTrigger>}
            <TabsTrigger value="behavior">Comportamento</TabsTrigger>
          </TabsList>

          {/* ─── Overview ─── */}
          <TabsContent value="overview" className="mt-4 space-y-6">
            <div className="grid gap-6 lg:grid-cols-3">
              <div className="lg:col-span-2 space-y-6">
                {/* Revenue Chart */}
                <Card>
                  <CardHeader><CardTitle>Receita por Mês</CardTitle></CardHeader>
                  <CardContent>
                    <div className="h-[250px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={revenueChartData}>
                          <CartesianGrid strokeDasharray="3 3" />
                          <XAxis dataKey="month" />
                          <YAxis />
                          <Tooltip formatter={(value) => formatCurrency(Number(value))} />
                          <Area type="monotone" dataKey="value" stroke="hsl(var(--primary))" fill="hsl(var(--primary))" fillOpacity={0.3} />
                        </AreaChart>
                      </ResponsiveContainer>
                    </div>
                  </CardContent>
                </Card>

                {/* Stage Distribution */}
                <Card>
                  <CardHeader><CardTitle>Oportunidades por Estágio</CardTitle></CardHeader>
                  <CardContent>
                    <div className="h-[250px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <RechartsPie>
                          <Pie data={stageChartData} cx="50%" cy="50%" innerRadius={50} outerRadius={80} paddingAngle={5} dataKey="value">
                            {stageChartData.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.fill} />
                            ))}
                          </Pie>
                          <Tooltip />
                        </RechartsPie>
                      </ResponsiveContainer>
