                </ScrollArea>
              </CardContent>
            </Card>
          </TabsContent>

          {/* ─── Opportunities ─── */}
          <TabsContent value="opportunities" className="mt-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <CardTitle>Oportunidades ({opportunities.length})</CardTitle>
                <Button size="sm" onClick={() => navigate(`/opportunities/new?${entityType}_id=${id}`)}>Nova Oportunidade</Button>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {opportunities.map((opp: any) => (
                    <div key={opp.id} className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer" onClick={() => navigate(`/opportunities/${opp.id}`)}>
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="font-medium">{opp.name}</p>
                          <p className="text-sm text-muted-foreground">Criada em {format(new Date(opp.created_at), 'dd/MM/yyyy', { locale: ptBR })}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-bold">{formatCurrency(opp.amount || 0)}</p>
                          <Badge variant={opp.stage === 'closed_won' ? 'default' : opp.stage === 'closed_lost' ? 'destructive' : 'secondary'}>{opp.stage}</Badge>
                        </div>
                      </div>
                    </div>
                  ))}
                  {opportunities.length === 0 && <p className="text-center text-muted-foreground py-8">Nenhuma oportunidade encontrada</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* ─── Tickets ─── */}
          <TabsContent value="tickets" className="mt-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <CardTitle>Tickets ({tickets.length})</CardTitle>
                <Button size="sm" onClick={() => navigate(`/tickets/new?${entityType}_id=${id}`)}>Novo Ticket</Button>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {tickets.map((ticket: any) => (
                    <div key={ticket.id} className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer" onClick={() => navigate(`/tickets/${ticket.id}`)}>
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="font-medium">{ticket.subject}</p>
                          <p className="text-sm text-muted-foreground">{ticket.ticket_number} • {format(new Date(ticket.created_at), 'dd/MM/yyyy', { locale: ptBR })}</p>
                        </div>
                        <div className="flex gap-2">
                          <Badge variant={ticket.priority === 'critical' ? 'destructive' : 'secondary'}>{ticket.priority}</Badge>
                          <Badge variant="outline">{ticket.status}</Badge>
                        </div>
                      </div>
                    </div>
                  ))}
                  {tickets.length === 0 && <p className="text-center text-muted-foreground py-8">Nenhum ticket encontrado</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* ─── Orders ─── */}
          <TabsContent value="orders" className="mt-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <CardTitle>Pedidos ({orders.length})</CardTitle>
                <Button size="sm" onClick={() => navigate(`/orders/new?${entityType}_id=${id}`)}>Novo Pedido</Button>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {orders.map((order: any) => (
                    <div key={order.id} className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer" onClick={() => navigate(`/orders/${order.id}`)}>
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="font-medium">{order.order_number}</p>
                          <p className="text-sm text-muted-foreground">{format(new Date(order.created_at), 'dd/MM/yyyy', { locale: ptBR })}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-bold">{formatCurrency(order.grand_total || 0)}</p>
                          <Badge variant="outline">{order.status}</Badge>
                        </div>
                      </div>
                    </div>
                  ))}
                  {orders.length === 0 && <p className="text-center text-muted-foreground py-8">Nenhum pedido encontrado</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* ─── Contracts ─── */}
          <TabsContent value="contracts" className="mt-4">
            <Customer360Contracts entityType={entityType} entityId={id!} />
          </TabsContent>

          {/* ─── Conversations ─── */}
          <TabsContent value="conversations" className="mt-4">
            <Customer360Conversations entityType={entityType} entityId={id!} />
          </TabsContent>

          {/* ─── Notes ─── */}
          <TabsContent value="notes" className="mt-4">
            <Customer360Notes entityType={entityType} entityId={id!} />
          </TabsContent>

          {/* ─── Contacts ─── */}
          {entityType === 'account' && (
            <TabsContent value="contacts" className="mt-4">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <CardTitle>Contatos ({contacts.length})</CardTitle>
                  <Button size="sm" onClick={() => navigate(`/contacts/new?account_id=${id}`)}>Novo Contato</Button>
                </CardHeader>
                <CardContent>
                  <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {contacts.map((contact: any) => (
                      <div key={contact.id} className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer" onClick={() => navigate(`/contacts/${contact.id}`)}>
                        <div className="flex items-center gap-3">
                          <Avatar>
                            <AvatarFallback>{`${contact.first_name?.[0] || ''}${contact.last_name?.[0] || ''}`.toUpperCase()}</AvatarFallback>
                          </Avatar>
                          <div>
                            <p className="font-medium">{contact.first_name} {contact.last_name}</p>
                            <p className="text-sm text-muted-foreground">{contact.title}</p>
                            {contact.email && <p className="text-sm text-muted-foreground">{contact.email}</p>}
                          </div>
                        </div>
                        {contact.is_primary && (
                          <Badge className="mt-2" variant="default">
                            <Star className="h-3 w-3 mr-1" />
                            Principal
                          </Badge>
                        )}
                      </div>
                    ))}
                    {contacts.length === 0 && <p className="text-center text-muted-foreground py-8 col-span-full">Nenhum contato encontrado</p>}
                  </div>
                </CardContent>
              </Card>
            </TabsContent>
          )}

          {/* ─── Behavior ─── */}
          <TabsContent value="behavior" className="mt-4">
            <Card>
              <CardHeader>
                <CardTitle>Eventos Comportamentais</CardTitle>
                <CardDescription>Interações rastreadas do cliente</CardDescription>
              </CardHeader>
              <CardContent>
                <ScrollArea className="h-[400px]">
                  <div className="space-y-3">
                    {behavioralEvents.map((event: any) => (
                      <div key={event.id} className="flex items-start gap-3 p-3 border rounded-lg">
                        <div className="w-10 h-10 rounded-full bg-muted flex items-center justify-center">
                          <Zap className="h-5 w-5" />
                        </div>
                        <div className="flex-1">
                          <p className="font-medium">{event.event_name}</p>
                          <p className="text-sm text-muted-foreground">{event.page_url && `Página: ${event.page_url}`}</p>
                          <p className="text-xs text-muted-foreground">
                            {format(new Date(event.occurred_at), 'dd/MM/yyyy HH:mm:ss', { locale: ptBR })}
                          </p>
                        </div>
                        <Badge variant="secondary">{event.event_type}</Badge>
                      </div>
                    ))}
                    {behavioralEvents.length === 0 && (
                      <p className="text-center text-muted-foreground py-8">Nenhum evento comportamental rastreado</p>
                    )}
                  </div>
                </ScrollArea>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Heart,
  TrendingUp,
  TrendingDown,
  Minus,
  AlertTriangle,
  CheckCircle2,
  Users,
  PlayCircle,
  BarChart3,
  Target,
  Clock,
  ArrowRight,
  Plus,
} from '@/components/icons';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

export default function CustomerSuccess() {
  const { profile } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');

  // Fetch health scores
  const { data: healthScores = [] } = useQuery({
    queryKey: ['health-scores', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('customer_health_scores')
        .select(`
          *,
          account:accounts(id, name, industry)
        `)
        .eq('organization_id', profile.organization_id)
        .order('score', { ascending: true });
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch playbooks
  const { data: playbooks = [] } = useQuery({
    queryKey: ['playbooks', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('customer_playbooks')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch active enrollments
  const { data: enrollments = [] } = useQuery({
    queryKey: ['playbook-enrollments', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('playbook_enrollments')
        .select(`
          *,
          playbook:customer_playbooks(id, name, type),
          account:accounts(id, name)
        `)
        .eq('organization_id', profile.organization_id)
        .eq('status', 'active')
        .order('next_step_due', { ascending: true });
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Calculate metrics
  const metrics = {
    avgScore: healthScores.length > 0 
      ? Math.round(healthScores.reduce((sum, h: any) => sum + h.score, 0) / healthScores.length)
      : 0,
    atRisk: healthScores.filter((h: any) => h.risk_level === 'high' || h.risk_level === 'critical').length,
    healthy: healthScores.filter((h: any) => h.risk_level === 'low').length,
    activePlaybooks: enrollments.length,
  };

  const getTrendIcon = (trend: string) => {
    switch (trend) {
      case 'improving':
        return <TrendingUp className="h-4 w-4 text-green-600" />;
      case 'declining':
        return <TrendingDown className="h-4 w-4 text-red-600" />;
      default:
        return <Minus className="h-4 w-4 text-gray-400" />;
    }
  };

  const getRiskBadge = (riskLevel: string) => {
    const styles: Record<string, string> = {
      low: 'bg-green-100 text-green-800',
      medium: 'bg-yellow-100 text-yellow-800',
      high: 'bg-orange-100 text-orange-800',
      critical: 'bg-red-100 text-red-800',
    };
    const labels: Record<string, string> = {
      low: 'Saudável',
      medium: 'Atenção',
      high: 'Risco',
      critical: 'Crítico',
    };
    return (
      <Badge className={styles[riskLevel] || 'bg-gray-100 text-gray-800'}>
        {labels[riskLevel] || riskLevel}
      </Badge>
    );
  };

  const getPlaybookTypeBadge = (type: string) => {
    const styles: Record<string, string> = {
      onboarding: 'bg-blue-100 text-blue-800',
      adoption: 'bg-purple-100 text-purple-800',
      renewal: 'bg-green-100 text-green-800',
      expansion: 'bg-indigo-100 text-indigo-800',
      risk_mitigation: 'bg-red-100 text-red-800',
      reactivation: 'bg-orange-100 text-orange-800',
      offboarding: 'bg-gray-100 text-gray-800',
    };
    const labels: Record<string, string> = {
      onboarding: 'Onboarding',
      adoption: 'Adoção',
      renewal: 'Renovação',
      expansion: 'Expansão',
      risk_mitigation: 'Mitigação de Risco',
      reactivation: 'Reativação',
      offboarding: 'Offboarding',
    };
    return (
      <Badge className={styles[type] || 'bg-gray-100 text-gray-800'}>
        {labels[type] || type}
      </Badge>
    );
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-yellow-600';
    if (score >= 40) return 'text-orange-600';
    return 'text-red-600';
  };

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="service"
          title="Customer Success"
          subtitle="Monitore a saúde dos clientes e gerencie playbooks de sucesso"
          compact
          actions={
            <Button variant="outline" asChild className="gap-2 bg-white text-foreground hover:bg-white/90">
              <Link to="/customer-success/playbooks/new">
                <Plus className="h-4 w-4" /> Novo Playbook
              </Link>
            </Button>
          }
        />

        {/* KPI Cards */}
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Health Score Médio</CardTitle>
              <Heart className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className={`text-2xl font-bold ${getScoreColor(metrics.avgScore)}`}>
                {metrics.avgScore}%
              </div>
              <Progress value={metrics.avgScore} className="mt-2 h-2" />
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Clientes em Risco</CardTitle>
              <AlertTriangle className="h-4 w-4 text-destructive" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-destructive">{metrics.atRisk}</div>
              <p className="text-xs text-muted-foreground">
                Requerem atenção imediata
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Clientes Saudáveis</CardTitle>
              <CheckCircle2 className="h-4 w-4 text-green-600" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-green-600">{metrics.healthy}</div>
              <p className="text-xs text-muted-foreground">
                Score acima de 80%
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Playbooks Ativos</CardTitle>
              <PlayCircle className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{metrics.activePlaybooks}</div>
              <p className="text-xs text-muted-foreground">
                Clientes em jornadas
              </p>
            </CardContent>
          </Card>
        </div>

        {/* Main Content */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="overview">Visão Geral</TabsTrigger>
            <TabsTrigger value="health">Health Scores</TabsTrigger>
            <TabsTrigger value="playbooks">Playbooks</TabsTrigger>
            <TabsTrigger value="enrollments">Jornadas Ativas</TabsTrigger>
          </TabsList>

          <TabsContent value="overview" className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              {/* At Risk Accounts */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <AlertTriangle className="h-5 w-5 text-destructive" />
                    Clientes em Risco
                  </CardTitle>
                  <CardDescription>Contas que precisam de atenção</CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    {healthScores
                      .filter((h: any) => h.risk_level === 'high' || h.risk_level === 'critical')
                      .slice(0, 5)
                      .map((health: any) => (
                        <div
                          key={health.id}
                          className="flex items-center justify-between rounded-lg border p-3"
                        >
                          <div className="flex items-center gap-3">
                            <div className={`text-lg font-bold ${getScoreColor(health.score)}`}>
                              {health.score}
                            </div>
                            <div>
                              <p className="font-medium">{health.account?.name}</p>
                              <p className="text-sm text-muted-foreground">
                                {health.account?.industry}
                              </p>
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            {getTrendIcon(health.trend)}
                            {getRiskBadge(health.risk_level)}
                          </div>
                        </div>
                      ))}
                    {healthScores.filter((h: any) => h.risk_level === 'high' || h.risk_level === 'critical').length === 0 && (
                      <p className="text-center text-sm text-muted-foreground py-4">
                        Nenhum cliente em risco 🎉
                      </p>
                    )}
                  </div>
                </CardContent>
              </Card>

              {/* Active Journeys */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <PlayCircle className="h-5 w-5" />
                    Jornadas em Andamento
                  </CardTitle>
                  <CardDescription>Próximas ações pendentes</CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    {enrollments.slice(0, 5).map((enrollment: any) => (
                      <div
                        key={enrollment.id}
                        className="flex items-center justify-between rounded-lg border p-3"
                      >
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            {getPlaybookTypeBadge(enrollment.playbook?.type)}
                          </div>
                          <p className="font-medium">{enrollment.account?.name}</p>
                          <p className="text-sm text-muted-foreground">
                            Step {enrollment.current_step} • {enrollment.progress_percent}% completo
                          </p>
                        </div>
                        {enrollment.next_step_due && (
                          <div className="text-right text-sm">
                            <p className="flex items-center gap-1 text-muted-foreground">
                              <Clock className="h-3 w-3" />
                              {format(new Date(enrollment.next_step_due), 'dd/MM', { locale: ptBR })}
                            </p>
                          </div>
                        )}
                      </div>
                    ))}
                    {enrollments.length === 0 && (
                      <p className="text-center text-sm text-muted-foreground py-4">
                        Nenhuma jornada ativa
                      </p>
                    )}
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Playbooks Summary */}
            <Card>
              <CardHeader>
                <CardTitle>Playbooks Disponíveis</CardTitle>
                <CardDescription>Modelos de jornada para Customer Success</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="grid gap-4 md:grid-cols-3 lg:grid-cols-4">
                  {playbooks.filter((p: any) => p.is_active).map((playbook: any) => (
                    <div key={playbook.id} className="rounded-lg border p-4 space-y-2">
                      <div className="flex items-center justify-between">
                        {getPlaybookTypeBadge(playbook.type)}
                      </div>
                      <h4 className="font-medium">{playbook.name}</h4>
                      <p className="text-sm text-muted-foreground line-clamp-2">
                        {playbook.description}
                      </p>
                      <div className="flex items-center justify-between text-sm">
                        <span className="text-muted-foreground">
                          {playbook.enrollment_count} inscrições
                        </span>
                        <Button variant="ghost" size="sm" asChild>
                          <Link to={`/customer-success/playbooks/${playbook.id}`}>
                            <ArrowRight className="h-4 w-4" />
                          </Link>
                        </Button>
                      </div>
                    </div>
                  ))}
                  {playbooks.length === 0 && (
                    <p className="col-span-full text-center text-sm text-muted-foreground py-4">
                      Nenhum playbook configurado
                    </p>
                  )}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="health" className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle>Health Scores por Cliente</CardTitle>
                <CardDescription>
                  Monitoramento da saúde de cada conta
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {healthScores.map((health: any) => (
                    <div
                      key={health.id}
                      className="flex items-center justify-between rounded-lg border p-4"
                    >
                      <div className="flex items-center gap-4">
