type DuplicateStatus = "detected" | "confirmed" | "false_positive" | "merged" | "ignored";

interface DetectedDuplicate {
  id: string;
  organization_id: string;
  entity_type: string;
  entity_ids: string[];
  match_reasons: { field: string; values?: string[]; confidence: number }[];
  similarity_score: number;
  status: DuplicateStatus;
  suggested_primary_id: string | null;
  decision_by: string | null;
  decision_at: string | null;
  decision_notes: string | null;
  merge_request_id: string | null;
  created_at: string;
  updated_at: string;
}

interface DuplicateRule {
  id: string;
  organization_id: string;
  entity_type: string;
  name: string;
  description: string | null;
  match_fields: { field: string; match_type: string; weight: number }[];
  threshold_score: number;
  auto_merge_threshold: number | null;
  is_active: boolean;
  priority: number;
  created_at: string;
}

const statusConfig: Record<DuplicateStatus, { label: string; color: string; icon: React.ElementType }> = {
  detected: { label: "Detectada", color: "bg-yellow-100 text-yellow-800", icon: AlertTriangle },
  confirmed: { label: "Confirmada", color: "bg-blue-100 text-blue-800", icon: CheckCircle },
  false_positive: { label: "Falso Positivo", color: "bg-gray-100 text-gray-800", icon: XCircle },
  merged: { label: "Mesclada", color: "bg-green-100 text-green-800", icon: GitMerge },
  ignored: { label: "Ignorada", color: "bg-gray-100 text-gray-600", icon: XCircle },
};

const entityTypeLabels: Record<string, { label: string; icon: React.ElementType }> = {
  contact: { label: "Contato", icon: UserCircle },
  account: { label: "Conta", icon: Building2 },
  lead: { label: "Lead", icon: Users },
};

export default function Duplicates() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [searchTerm, setSearchTerm] = useState("");
  const [entityFilter, setEntityFilter] = useState<string>("all");
  const [statusFilter, setStatusFilter] = useState<string>("detected");
  const [selectedDuplicate, setSelectedDuplicate] = useState<DetectedDuplicate | null>(null);
  const [decisionNotes, setDecisionNotes] = useState("");
  const [showRulesDialog, setShowRulesDialog] = useState(false);

  // Fetch duplicates
  const { data: duplicates = [], isLoading } = useQuery({
    queryKey: ["detected-duplicates", entityFilter, statusFilter],
    queryFn: async () => {
      let query = supabase
        .from("detected_duplicates")
        .select("*")
        .order("similarity_score", { ascending: false })
        .order("created_at", { ascending: false });

      if (entityFilter !== "all") {
        query = query.eq("entity_type", entityFilter);
      }

      if (statusFilter !== "all") {
        query = query.eq("status", statusFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return (data || []) as any[];
    },
  });

  // Fetch rules
  const { data: rules = [] } = useQuery({
    queryKey: ["duplicate-rules"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("duplicate_detection_rules")
        .select("*")
        .order("priority", { ascending: true });
      if (error) throw error;
      return (data || []) as any[];
    },
  });

  // Fetch entity details for display
  const { data: entityDetails = {} } = useQuery({
    queryKey: ["duplicate-entity-details", duplicates],
    queryFn: async () => {
      const details: Record<string, { name: string; email?: string }> = {};

      for (const dup of duplicates) {
        for (const entityId of dup.entity_ids) {
          if (!details[entityId]) {
            if (dup.entity_type === "contact") {
              const { data } = await supabase
                .from("contacts")
                .select("first_name, last_name, email")
                .eq("id", entityId)
                .single();
              if (data) {
                details[entityId] = {
                  name: `${data.first_name || ""} ${data.last_name || ""}`.trim(),
                  email: data.email || undefined,
                };
              }
            } else if (dup.entity_type === "account") {
              const { data } = await supabase
                .from("accounts")
                .select("name, email")
                .eq("id", entityId)
                .single();
              if (data) {
                details[entityId] = { name: data.name, email: data.email || undefined };
              }
            } else if (dup.entity_type === "lead") {
              const { data } = await supabase
                .from("leads")
                .select("first_name, last_name, email")
                .eq("id", entityId)
                .single();
              if (data) {
                details[entityId] = {
                  name: `${data.first_name || ""} ${data.last_name || ""}`.trim(),
                  email: data.email || undefined,
                };
              }
            }
          }
        }
      }

      return details;
    },
    enabled: duplicates.length > 0,
  });

  // Update duplicate status
  const updateStatusMutation = useMutation({
    mutationFn: async ({ id, status, notes }: { id: string; status: DuplicateStatus; notes?: string }) => {
      const { error } = await supabase
        .from("detected_duplicates")
        .update({
          status,
          decision_by: profile?.id,
          decision_at: new Date().toISOString(),
          decision_notes: notes || null,
        })
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["detected-duplicates"] });
      toast.success("Status atualizado com sucesso");
      setSelectedDuplicate(null);
      setDecisionNotes("");
    },
    onError: () => {
      toast.error("Erro ao atualizar status");
    },
  });

  // Create merge request
  const createMergeMutation = useMutation({
    mutationFn: async (duplicate: DetectedDuplicate) => {
      const targetId = duplicate.suggested_primary_id || duplicate.entity_ids[0];
      const sourceIds = duplicate.entity_ids.filter(id => id !== targetId);

      const { data, error } = await supabase
        .from("merge_requests")
        .insert({
          organization_id: duplicate.organization_id,
          entity_type: duplicate.entity_type,
          source_ids: sourceIds,
          target_id: targetId,
          status: "pending",
          requested_by: profile?.id,
        })
        .select()
        .single();

      if (error) throw error;

      // Update duplicate with merge request id
      await supabase
        .from("detected_duplicates")
        .update({ merge_request_id: data.id, status: "confirmed" })
        .eq("id", duplicate.id);

      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["detected-duplicates"] });
      queryClient.invalidateQueries({ queryKey: ["merge-requests"] });
      toast.success("Solicitação de merge criada");
    },
    onError: () => {
      toast.error("Erro ao criar solicitação de merge");
    },
  });

  // Stats
  const stats = {
    total: duplicates.length,
    detected: duplicates.filter(d => d.status === "detected").length,
    highConfidence: duplicates.filter(d => d.similarity_score >= 90).length,
    pending: duplicates.filter(d => d.status === "detected" || d.status === "confirmed").length,
  };

  const filteredDuplicates = duplicates.filter(dup => {
    if (!searchTerm) return true;
    const term = searchTerm.toLowerCase();
    return dup.entity_ids.some(id => {
      const details = entityDetails[id];
      return details?.name?.toLowerCase().includes(term) || 
             details?.email?.toLowerCase().includes(term);
    });
  });

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="admin"
          title="Duplicatas"
          subtitle="Detecte e gerencie registros duplicados no sistema"
          compact
          actions={
            <div className="flex gap-2">
              <Button variant="outline" onClick={() => setShowRulesDialog(true)} className="gap-2 bg-white/10 text-white border-white/20 hover:bg-white/20">
                <Settings className="h-4 w-4" /> Regras
              </Button>
              <Button className="gap-2 bg-white text-foreground hover:bg-white/90">
                <Zap className="h-4 w-4" /> Executar Detecção
              </Button>
            </div>
          }
        />

        {/* Stats Cards */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total Detectadas</CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.total}</div>
              <p className="text-xs text-muted-foreground">registros com potenciais duplicatas</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Aguardando Revisão</CardTitle>
              <AlertTriangle className="h-4 w-4 text-yellow-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.detected}</div>
              <p className="text-xs text-muted-foreground">precisam de análise</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Alta Confiança</CardTitle>
              <Percent className="h-4 w-4 text-green-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.highConfidence}</div>
              <p className="text-xs text-muted-foreground">similaridade ≥ 90%</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Regras Ativas</CardTitle>
              <Settings className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{rules.filter(r => r.is_active).length}</div>
              <p className="text-xs text-muted-foreground">de {rules.length} regras configuradas</p>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col md:flex-row gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Buscar por nome ou email..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <Select value={entityFilter} onValueChange={setEntityFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder="Tipo de entidade" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos os tipos</SelectItem>
                  <SelectItem value="contact">Contatos</SelectItem>
                  <SelectItem value="account">Contas</SelectItem>
                  <SelectItem value="lead">Leads</SelectItem>
                </SelectContent>
              </Select>
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos os status</SelectItem>
                  <SelectItem value="detected">Detectadas</SelectItem>
                  <SelectItem value="confirmed">Confirmadas</SelectItem>
                  <SelectItem value="false_positive">Falso Positivo</SelectItem>
                  <SelectItem value="merged">Mescladas</SelectItem>
                  <SelectItem value="ignored">Ignoradas</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </CardContent>
        </Card>

        {/* Duplicates Table */}
        <Card>
          <CardHeader>
            <CardTitle>Duplicatas Detectadas</CardTitle>
            <CardDescription>
              Revise e tome ações sobre os registros duplicados identificados
            </CardDescription>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <RefreshCw className="h-6 w-6 animate-spin text-muted-foreground" />
              </div>
            ) : filteredDuplicates.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <Users className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <p>Nenhuma duplicata encontrada</p>
              </div>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Registros</TableHead>
                    <TableHead>Razão do Match</TableHead>
                    <TableHead>Similaridade</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Detectado em</TableHead>
                    <TableHead className="text-right">Ações</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredDuplicates.map((dup) => {
                    const entityConfig = entityTypeLabels[dup.entity_type] || { label: dup.entity_type, icon: Users };
                    const EntityIcon = entityConfig.icon;
                    const statusInfo = statusConfig[dup.status];
                    const StatusIcon = statusInfo.icon;

                    return (
                      <TableRow key={dup.id}>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <EntityIcon className="h-4 w-4 text-muted-foreground" />
                            <span>{entityConfig.label}</span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="space-y-1">
                            {dup.entity_ids.map((id, index) => {
                              const details = entityDetails[id];
                              const isPrimary = id === dup.suggested_primary_id;
                              return (
                                <div key={id} className="flex items-center gap-2">
                                  {isPrimary && (
                                    <Badge variant="outline" className="text-xs">Principal</Badge>
                                  )}
                                  <span className={isPrimary ? "font-medium" : ""}>
                                    {details?.name || `ID: ${id.slice(0, 8)}...`}
                                  </span>
                                  {details?.email && (
                                    <span className="text-xs text-muted-foreground">
                                      ({details.email})
                                    </span>
                                  )}
                                </div>
                              );
                            })}
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex flex-wrap gap-1">
                            {dup.match_reasons.map((reason, index) => (
                              <Badge key={index} variant="secondary" className="text-xs">
                                {reason.field}: {reason.confidence}%
                              </Badge>
                            ))}
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <div className="w-16 h-2 bg-muted rounded-full overflow-hidden">
                              <div 
                                className={`h-full ${
                                  dup.similarity_score >= 90 ? 'bg-green-500' : 
                                  dup.similarity_score >= 70 ? 'bg-yellow-500' : 'bg-red-500'
                                }`}
                                style={{ width: `${dup.similarity_score}%` }}
                              />
                            </div>
                            <span className="text-sm font-medium">{dup.similarity_score}%</span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge className={statusInfo.color}>
                            <StatusIcon className="h-3 w-3 mr-1" />
                            {statusInfo.label}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          {format(new Date(dup.created_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                        </TableCell>
                        <TableCell className="text-right">
                          <div className="flex justify-end gap-2">
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => setSelectedDuplicate(dup)}
                            >
                              <Eye className="h-4 w-4" />
                            </Button>
                            {dup.status === "detected" && (
                              <>
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => createMergeMutation.mutate(dup)}
                                >
                                  <GitMerge className="h-4 w-4" />
                                </Button>
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => updateStatusMutation.mutate({ 
                                    id: dup.id, 
                                    status: "false_positive" 
                                  })}
                                >
                                  <XCircle className="h-4 w-4" />
                                </Button>
                              </>
                            )}
                          </div>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>

        {/* Duplicate Detail Dialog */}
        <Dialog open={!!selectedDuplicate} onOpenChange={() => setSelectedDuplicate(null)}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Detalhes da Duplicata</DialogTitle>
              <DialogDescription>
                Revise os registros e tome uma decisão
              </DialogDescription>
            </DialogHeader>
            {selectedDuplicate && (
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-sm font-medium">Tipo de Entidade</label>
                    <p className="text-muted-foreground capitalize">{selectedDuplicate.entity_type}</p>
                  </div>
                  <div>
                    <label className="text-sm font-medium">Similaridade</label>
                    <p className="text-muted-foreground">{selectedDuplicate.similarity_score}%</p>
                  </div>
                </div>

                <div>
                  <label className="text-sm font-medium">Registros Envolvidos</label>
                  <div className="mt-2 space-y-2">
                    {selectedDuplicate.entity_ids.map((id) => {
                      const details = entityDetails[id];
                      return (
                        <div key={id} className="p-3 border rounded-lg">
                          <p className="font-medium">{details?.name || id}</p>
                          {details?.email && (
                            <p className="text-sm text-muted-foreground">{details.email}</p>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>

                <div>
                  <label className="text-sm font-medium">Razões do Match</label>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {selectedDuplicate.match_reasons.map((reason, index) => (
                      <Badge key={index} variant="outline">
                        {reason.field}: {reason.confidence}%
                      </Badge>
                    ))}
                  </div>
                </div>

                {selectedDuplicate.status === "detected" && (
                  <div>
                    <label className="text-sm font-medium">Notas da Decisão</label>
                    <Textarea
                      value={decisionNotes}
                      onChange={(e) => setDecisionNotes(e.target.value)}
                      placeholder="Adicione notas sobre sua decisão..."
                      className="mt-2"
                    />
                  </div>
                )}
              </div>
            )}
            <DialogFooter>
              {selectedDuplicate?.status === "detected" && (
                <>
                  <Button
                    variant="outline"
                    onClick={() => updateStatusMutation.mutate({
                      id: selectedDuplicate.id,
                      status: "false_positive",
                      notes: decisionNotes,
                    })}
                  >
                    <XCircle className="h-4 w-4 mr-2" />
                    Falso Positivo
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => updateStatusMutation.mutate({
                      id: selectedDuplicate.id,
                      status: "ignored",
                      notes: decisionNotes,
                    })}
                  >
                    Ignorar
                  </Button>
                  <Button
                    onClick={() => createMergeMutation.mutate(selectedDuplicate)}
                  >
                    <GitMerge className="h-4 w-4 mr-2" />
                    Criar Merge
                  </Button>
                </>
              )}
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* Rules Dialog */}
        <Dialog open={showRulesDialog} onOpenChange={setShowRulesDialog}>
          <DialogContent className="max-w-3xl">
            <DialogHeader>
              <DialogTitle>Regras de Detecção de Duplicatas</DialogTitle>
              <DialogDescription>
                Configure as regras utilizadas para identificar registros duplicados
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              {rules.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <Settings className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>Nenhuma regra configurada</p>
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Nome</TableHead>
                      <TableHead>Entidade</TableHead>
                      <TableHead>Campos</TableHead>
                      <TableHead>Threshold</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {rules.map((rule) => (
                      <TableRow key={rule.id}>
                        <TableCell className="font-medium">{rule.name}</TableCell>
                        <TableCell className="capitalize">{rule.entity_type}</TableCell>
                        <TableCell>
                          <div className="flex flex-wrap gap-1">
                            {rule.match_fields.map((field, index) => (
                              <Badge key={index} variant="secondary" className="text-xs">
                                {field.field} ({field.weight}%)
                              </Badge>
                            ))}
                          </div>
                        </TableCell>
                        <TableCell>{rule.threshold_score}%</TableCell>
                        <TableCell>
                          <Badge variant={rule.is_active ? "default" : "secondary"}>
                            {rule.is_active ? "Ativa" : "Inativa"}
                          </Badge>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowRulesDialog(false)}>
                Fechar
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useAuth } from '@/hooks/useAuth';
import { BarChart3, Calendar, Target, TrendingUp, DollarSign, ChevronLeft, ChevronRight, Plus, Edit, Save, X } from '@/components/icons';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Progress } from '@/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts';
import { format, startOfMonth, endOfMonth, startOfQuarter, endOfQuarter, addMonths, addQuarters, subMonths, subQuarters } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Forecast {
  id: string;
  owner_id: string;
  organization_id: string;
  period_type: string;
  period_start: string;
  period_end: string;
  target_amount: number;
  commit_amount: number;
  best_case_amount: number;
  pipeline_amount: number;
  closed_amount: number;
  notes: string | null;
  owner?: { first_name: string | null; last_name: string | null; email: string } | null;
}

interface Opportunity {
  id: string;
  name: string;
  amount: number;
  close_date: string | null;
  stage: string;
  forecast_category: string | null;
  owner_id: string | null;
  account?: { name: string } | null;
}

const stageLabels: Record<string, string> = {
  'prospecting': 'Prospecção',
  'qualification': 'Qualificação',
  'proposal': 'Proposta',
  'negotiation': 'Negociação',
  'closed_won': 'Fechado Ganho',
  'closed_lost': 'Fechado Perdido',
};

const forecastCategoryLabels: Record<string, string> = {
  'commit': 'Commit',
  'best_case': 'Melhor Caso',
  'pipeline': 'Pipeline',
  'omitted': 'Omitido',
};

export default function Forecast() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [periodType, setPeriodType] = useState<'monthly' | 'quarterly'>('monthly');
  const [currentPeriod, setCurrentPeriod] = useState(new Date());
  const [editingForecast, setEditingForecast] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<{
    target_amount: number;
    commit_amount: number;
    best_case_amount: number;
  }>({ target_amount: 0, commit_amount: 0, best_case_amount: 0 });

  const getPeriodRange = () => {
    if (periodType === 'monthly') {
      return {
        start: startOfMonth(currentPeriod),
        end: endOfMonth(currentPeriod)
      };
    }
    return {
      start: startOfQuarter(currentPeriod),
      end: endOfQuarter(currentPeriod)
    };
  };

  const { start: periodStart, end: periodEnd } = getPeriodRange();

  // Fetch forecasts
  const { data: forecasts = [], isLoading: forecastsLoading } = useQuery({
    queryKey: ['forecasts', periodType, format(periodStart, 'yyyy-MM-dd')],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id, role')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('forecasts')
        .select(`
          *,
          owner:profiles!forecasts_owner_id_fkey(first_name, last_name, email)
        `)
        .eq('organization_id', profile.organization_id)
        .eq('period_type', periodType)
        .eq('period_start', format(periodStart, 'yyyy-MM-dd'));

      if (error) throw error;
      return data as Forecast[];
    },
    enabled: !!user
  });

  // Fetch opportunities for the period
  const { data: opportunities = [] } = useQuery({
    queryKey: ['forecast-opportunities', format(periodStart, 'yyyy-MM-dd'), format(periodEnd, 'yyyy-MM-dd')],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('opportunities')
        .select(`
          id, name, amount, close_date, stage, forecast_category, owner_id,
          account:accounts(name)
        `)
        .eq('organization_id', profile.organization_id)
        .gte('close_date', format(periodStart, 'yyyy-MM-dd'))
        .lte('close_date', format(periodEnd, 'yyyy-MM-dd'))
        .not('stage', 'eq', 'closed_lost');

      if (error) throw error;
      return data as Opportunity[];
    },
    enabled: !!user
  });

  // Fetch team members
  const { data: teamMembers = [] } = useQuery({
    queryKey: ['forecast-team'],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email, role')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true);

      if (error) throw error;
      return data;
    },
    enabled: !!user
  });

  // Fetch historical data for chart
  const { data: historicalData = [] } = useQuery({
    queryKey: ['forecast-history', periodType],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      // Get last 6 periods
      const periods = [];
      for (let i = 5; i >= 0; i--) {
        const date = periodType === 'monthly' 
          ? subMonths(currentPeriod, i)
          : subQuarters(currentPeriod, i);
        const start = periodType === 'monthly' ? startOfMonth(date) : startOfQuarter(date);
        periods.push(format(start, 'yyyy-MM-dd'));
      }

      const { data, error } = await supabase
        .from('forecasts')
        .select('period_start, target_amount, closed_amount')
        .eq('organization_id', profile.organization_id)
        .eq('period_type', periodType)
        .in('period_start', periods);

      if (error) throw error;

      // Aggregate by period
      const aggregated = periods.map(period => {
        const periodForecasts = data.filter(f => f.period_start === period);
        return {
          period: format(new Date(period), periodType === 'monthly' ? 'MMM yyyy' : 'QQQ yyyy', { locale: ptBR }),
          target: periodForecasts.reduce((sum, f) => sum + (f.target_amount || 0), 0),
          closed: periodForecasts.reduce((sum, f) => sum + (f.closed_amount || 0), 0)
        };
      });

      return aggregated;
    },
    enabled: !!user
  });

  // Save forecast mutation
  const saveForecastMutation = useMutation({
    mutationFn: async (data: { 
      owner_id: string;
      target_amount: number;
      commit_amount: number;
      best_case_amount: number;
    }) => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) throw new Error('Sem organização');

      // Calculate pipeline and closed from opportunities
      const ownerOpps = opportunities.filter(o => o.owner_id === data.owner_id);
      const pipeline_amount = ownerOpps
        .filter(o => o.stage !== 'closed_won')
        .reduce((sum, o) => sum + (o.amount || 0), 0);
      const closed_amount = ownerOpps
        .filter(o => o.stage === 'closed_won')
        .reduce((sum, o) => sum + (o.amount || 0), 0);

      const existingForecast = forecasts.find(f => f.owner_id === data.owner_id);

      const payload = {
        owner_id: data.owner_id,
        organization_id: profile.organization_id,
        period_type: periodType,
        period_start: format(periodStart, 'yyyy-MM-dd'),
        period_end: format(periodEnd, 'yyyy-MM-dd'),
        target_amount: data.target_amount,
        commit_amount: data.commit_amount,
        best_case_amount: data.best_case_amount,
        pipeline_amount,
        closed_amount
      };

      if (existingForecast) {
        const { error } = await supabase
          .from('forecasts')
          .update(payload)
          .eq('id', existingForecast.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('forecasts')
          .insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['forecasts'] });
      setEditingForecast(null);
      toast({
        title: 'Previsão salva',
        description: 'As alterações foram salvas com sucesso.'
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.message,
        variant: 'destructive'
      });
    }
  });

  const navigatePeriod = (direction: 'prev' | 'next') => {
    if (periodType === 'monthly') {
      setCurrentPeriod(direction === 'prev' ? subMonths(currentPeriod, 1) : addMonths(currentPeriod, 1));
    } else {
      setCurrentPeriod(direction === 'prev' ? subQuarters(currentPeriod, 1) : addQuarters(currentPeriod, 1));
    }
  };

  const startEditForecast = (memberId: string) => {
    const existing = forecasts.find(f => f.owner_id === memberId);
    setEditValues({
      target_amount: existing?.target_amount || 0,
      commit_amount: existing?.commit_amount || 0,
      best_case_amount: existing?.best_case_amount || 0
    });
    setEditingForecast(memberId);
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(amount);
  };

  // Calculate totals
  const totals = {
    target: forecasts.reduce((sum, f) => sum + (f.target_amount || 0), 0),
    commit: forecasts.reduce((sum, f) => sum + (f.commit_amount || 0), 0),
    bestCase: forecasts.reduce((sum, f) => sum + (f.best_case_amount || 0), 0),
    pipeline: forecasts.reduce((sum, f) => sum + (f.pipeline_amount || 0), 0),
    closed: forecasts.reduce((sum, f) => sum + (f.closed_amount || 0), 0)
  };

  // Calculate forecast by category from opportunities
  const byCategory = {
    commit: opportunities.filter(o => o.forecast_category === 'commit').reduce((sum, o) => sum + (o.amount || 0), 0),
    bestCase: opportunities.filter(o => o.forecast_category === 'best_case').reduce((sum, o) => sum + (o.amount || 0), 0),
    pipeline: opportunities.filter(o => o.forecast_category === 'pipeline').reduce((sum, o) => sum + (o.amount || 0), 0),
    omitted: opportunities.filter(o => o.forecast_category === 'omitted').reduce((sum, o) => sum + (o.amount || 0), 0),
    closed: opportunities.filter(o => o.stage === 'closed_won').reduce((sum, o) => sum + (o.amount || 0), 0)
  };

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="sales"
          title="Previsão de Vendas"
          subtitle="Metas e previsões de vendas da equipe"
          compact
        />
        {/* Header Controls */}
        <div className="flex items-center justify-end">
          <div className="hidden" />
          <div className="flex items-center gap-4">
            <Select value={periodType} onValueChange={(v: 'monthly' | 'quarterly') => setPeriodType(v)}>
              <SelectTrigger className="w-32">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="monthly">Mensal</SelectItem>
                <SelectItem value="quarterly">Trimestral</SelectItem>
              </SelectContent>
            </Select>
            <div className="flex items-center gap-2">
              <Button variant="outline" size="icon" onClick={() => navigatePeriod('prev')}>
                <ChevronLeft className="h-4 w-4" />
              </Button>
              <div className="w-36 text-center font-medium">
                {format(periodStart, periodType === 'monthly' ? "MMMM 'de' yyyy" : "QQQ 'de' yyyy", { locale: ptBR })}
              </div>
              <Button variant="outline" size="icon" onClick={() => navigatePeriod('next')}>
                <ChevronRight className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="grid grid-cols-5 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-2 text-muted-foreground mb-1">
                <Target className="h-4 w-4" />
                <span className="text-sm">Meta</span>
              </div>
              <div className="text-2xl font-bold">{formatCurrency(totals.target)}</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-2 text-muted-foreground mb-1">
                <TrendingUp className="h-4 w-4" />
                <span className="text-sm">Commit</span>
              </div>
              <div className="text-2xl font-bold">{formatCurrency(byCategory.commit)}</div>
              <div className="text-xs text-muted-foreground">
                {totals.target > 0 ? Math.round((byCategory.commit / totals.target) * 100) : 0}% da meta
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-2 text-muted-foreground mb-1">
                <BarChart3 className="h-4 w-4" />
                <span className="text-sm">Melhor Caso</span>
              </div>
              <div className="text-2xl font-bold">{formatCurrency(byCategory.bestCase)}</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-2 text-muted-foreground mb-1">
                <Calendar className="h-4 w-4" />
                <span className="text-sm">Pipeline</span>
              </div>
              <div className="text-2xl font-bold">{formatCurrency(byCategory.pipeline)}</div>
            </CardContent>
          </Card>
          <Card className="bg-primary/10">
            <CardContent className="p-4">
              <div className="flex items-center gap-2 text-muted-foreground mb-1">
                <DollarSign className="h-4 w-4" />
                <span className="text-sm">Fechado Ganho</span>
              </div>
              <div className="text-2xl font-bold text-primary">{formatCurrency(byCategory.closed)}</div>
              <div className="text-xs text-muted-foreground">
                {totals.target > 0 ? Math.round((byCategory.closed / totals.target) * 100) : 0}% da meta
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Progress Bar */}
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium">Progresso para Meta</span>
              <span className="text-sm text-muted-foreground">
                {formatCurrency(byCategory.closed)} / {formatCurrency(totals.target)}
              </span>
            </div>
            <Progress value={totals.target > 0 ? (byCategory.closed / totals.target) * 100 : 0} className="h-3" />
            <div className="flex justify-between mt-2 text-xs text-muted-foreground">
              <span>Fechado: {totals.target > 0 ? Math.round((byCategory.closed / totals.target) * 100) : 0}%</span>
              <span>Commit: +{formatCurrency(byCategory.commit)}</span>
              <span>Melhor Caso: +{formatCurrency(byCategory.bestCase)}</span>
            </div>
          </CardContent>
        </Card>

        <Tabs defaultValue="team" className="space-y-4">
          <TabsList>
            <TabsTrigger value="team">Previsão da Equipe</TabsTrigger>
            <TabsTrigger value="opportunities">Oportunidades ({opportunities.length})</TabsTrigger>
            <TabsTrigger value="trends">Tendências</TabsTrigger>
          </TabsList>

          <TabsContent value="team">
            <Card>
              <CardHeader>
                <CardTitle>Previsão da Equipe - {format(periodStart, periodType === 'monthly' ? "MMMM 'de' yyyy" : "QQQ 'de' yyyy", { locale: ptBR })}</CardTitle>
                <CardDescription>Metas individuais e desempenho</CardDescription>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Vendedor</TableHead>
                      <TableHead className="text-right">Meta</TableHead>
                      <TableHead className="text-right">Commit</TableHead>
                      <TableHead className="text-right">Melhor Caso</TableHead>
                      <TableHead className="text-right">Pipeline</TableHead>
                      <TableHead className="text-right">Fechado</TableHead>
                      <TableHead className="text-right">Atingimento</TableHead>
                      <TableHead></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {teamMembers.map(member => {
                      const forecast = forecasts.find(f => f.owner_id === member.id);
                      const memberOpps = opportunities.filter(o => o.owner_id === member.id);
                      const memberClosed = memberOpps.filter(o => o.stage === 'closed_won').reduce((sum, o) => sum + (o.amount || 0), 0);
                      const memberPipeline = memberOpps.filter(o => o.stage !== 'closed_won').reduce((sum, o) => sum + (o.amount || 0), 0);
                      const memberCommit = memberOpps.filter(o => o.forecast_category === 'commit').reduce((sum, o) => sum + (o.amount || 0), 0);
                      const memberBestCase = memberOpps.filter(o => o.forecast_category === 'best_case').reduce((sum, o) => sum + (o.amount || 0), 0);
                      const target = forecast?.target_amount || 0;
                      const attainment = target > 0 ? Math.round((memberClosed / target) * 100) : 0;

                      const isEditing = editingForecast === member.id;

                      return (
                        <TableRow key={member.id}>
                          <TableCell>
                            <div>
                              <div className="font-medium">
                                {member.first_name || member.email} {member.last_name || ''}
                              </div>
                              <div className="text-xs text-muted-foreground">{member.role}</div>
                            </div>
                          </TableCell>
                          <TableCell className="text-right">
                            {isEditing ? (
                              <Input
                                type="number"
                                value={editValues.target_amount}
                                onChange={(e) => setEditValues({ ...editValues, target_amount: parseFloat(e.target.value) || 0 })}
                                className="w-24 h-8 text-right"
                              />
                            ) : (
                              formatCurrency(target)
                            )}
                          </TableCell>
                          <TableCell className="text-right">
                            {isEditing ? (
                              <Input
                                type="number"
                                value={editValues.commit_amount}
                                onChange={(e) => setEditValues({ ...editValues, commit_amount: parseFloat(e.target.value) || 0 })}
                                className="w-24 h-8 text-right"
                              />
                            ) : (
                              formatCurrency(memberCommit)
                            )}
                          </TableCell>
                          <TableCell className="text-right">
                            {isEditing ? (
                              <Input
                                type="number"
                                value={editValues.best_case_amount}
                                onChange={(e) => setEditValues({ ...editValues, best_case_amount: parseFloat(e.target.value) || 0 })}
                                className="w-24 h-8 text-right"
                              />
                            ) : (
                              formatCurrency(memberBestCase)
                            )}
                          </TableCell>
                          <TableCell className="text-right">{formatCurrency(memberPipeline)}</TableCell>
                          <TableCell className="text-right font-medium">{formatCurrency(memberClosed)}</TableCell>
                          <TableCell className="text-right">
                            <Badge variant={attainment >= 100 ? 'default' : attainment >= 75 ? 'secondary' : 'outline'}>
                              {attainment}%
                            </Badge>
                          </TableCell>
                          <TableCell>
                            {isEditing ? (
                              <div className="flex gap-1">
                                <Button 
                                  size="sm" 
                                  variant="ghost"
                                  onClick={() => saveForecastMutation.mutate({
                                    owner_id: member.id,
                                    ...editValues
                                  })}
                                >
                                  <Save className="h-4 w-4" />
                                </Button>
                                <Button 
                                  size="sm" 
                                  variant="ghost"
                                  onClick={() => setEditingForecast(null)}
                                >
                                  <X className="h-4 w-4" />
                                </Button>
                              </div>
                            ) : (
                              <Button 
                                size="sm" 
                                variant="ghost"
                                onClick={() => startEditForecast(member.id)}
                              >
                                <Edit className="h-4 w-4" />
                              </Button>
                            )}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                    {/* Totals Row */}
                    <TableRow className="font-bold bg-muted/50">
                      <TableCell>Total</TableCell>
                      <TableCell className="text-right">{formatCurrency(totals.target)}</TableCell>
                      <TableCell className="text-right">{formatCurrency(byCategory.commit)}</TableCell>
                      <TableCell className="text-right">{formatCurrency(byCategory.bestCase)}</TableCell>
                      <TableCell className="text-right">{formatCurrency(byCategory.pipeline)}</TableCell>
                      <TableCell className="text-right">{formatCurrency(byCategory.closed)}</TableCell>
                      <TableCell className="text-right">
                        <Badge>{totals.target > 0 ? Math.round((byCategory.closed / totals.target) * 100) : 0}%</Badge>
                      </TableCell>
                      <TableCell></TableCell>
                    </TableRow>
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="opportunities">
            <Card>
              <CardHeader>
                <CardTitle>Oportunidades com Fechamento neste Período</CardTitle>
                <CardDescription>Negócios com data de fechamento em {format(periodStart, periodType === 'monthly' ? "MMMM 'de' yyyy" : "QQQ 'de' yyyy", { locale: ptBR })}</CardDescription>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Oportunidade</TableHead>
                      <TableHead>Conta</TableHead>
                      <TableHead>Estágio</TableHead>
                      <TableHead>Categoria</TableHead>
                      <TableHead>Data de Fechamento</TableHead>
                      <TableHead className="text-right">Valor</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {opportunities.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                          Nenhuma oportunidade com fechamento neste período
                        </TableCell>
                      </TableRow>
                    ) : (
                      opportunities.map(opp => (
                        <TableRow key={opp.id}>
                          <TableCell className="font-medium">{opp.name}</TableCell>
                          <TableCell>{opp.account?.name || '-'}</TableCell>
                          <TableCell>
                            <Badge variant={opp.stage === 'closed_won' ? 'default' : 'outline'}>
                              {stageLabels[opp.stage] || opp.stage.replace('_', ' ')}
                            </Badge>
                          </TableCell>
                          <TableCell>
                            <Badge variant="secondary">
                              {forecastCategoryLabels[opp.forecast_category || 'pipeline'] || opp.forecast_category?.replace('_', ' ') || 'Pipeline'}
                            </Badge>
                          </TableCell>
                          <TableCell>
                            {opp.close_date ? format(new Date(opp.close_date), "dd/MM/yyyy", { locale: ptBR }) : '-'}
                          </TableCell>
                          <TableCell className="text-right font-medium">
                            {formatCurrency(opp.amount || 0)}
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="trends">
            <Card>
              <CardHeader>
                <CardTitle>Desempenho Histórico</CardTitle>
                <CardDescription>Comparação de Meta vs Fechado ao longo do tempo</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="h-[400px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={historicalData}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="period" />
                      <YAxis tickFormatter={(value) => `R$${(value / 1000).toFixed(0)}k`} />
                      <Tooltip 
                        formatter={(value: number) => formatCurrency(value)}
                        labelStyle={{ color: 'var(--foreground)' }}
                      />
                      <Legend />
                      <Bar dataKey="target" name="Meta" fill="hsl(var(--muted-foreground))" />
                      <Bar dataKey="closed" name="Fechado" fill="hsl(var(--primary))" />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { format, differenceInDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Shield,
  FileText,
  Clock,
  AlertTriangle,
  CheckCircle2,
  XCircle,
  Users,
  Database,
  Lock,
  Eye,
  Download,
  Trash2,
  RefreshCw,
  TrendingUp,
  TrendingDown,
} from '@/components/icons';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Link } from 'react-router-dom';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';

export default function Governance() {
  const { profile } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');

  // Fetch LGPD requests
  const { data: lgpdRequests = [] } = useQuery({
    queryKey: ['lgpd-requests', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('lgpd_requests')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch retention policies
  const { data: retentionPolicies = [] } = useQuery({
    queryKey: ['retention-policies', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('data_retention_policies')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch audit logs summary
  const { data: auditStats } = useQuery({
    queryKey: ['audit-stats', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return null;
      const { data, error } = await supabase
        .from('audit_logs')
        .select('action, entity_type')
        .eq('organization_id', profile.organization_id)
        .gte('created_at', new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString());
      if (error) throw error;

      const stats = {
        total: data?.length || 0,
        creates: data?.filter(l => l.action === 'CREATE').length || 0,
        updates: data?.filter(l => l.action === 'UPDATE').length || 0,
        deletes: data?.filter(l => l.action === 'DELETE').length || 0,
        byEntity: {} as Record<string, number>,
      };

      data?.forEach(log => {
        stats.byEntity[log.entity_type] = (stats.byEntity[log.entity_type] || 0) + 1;
      });

      return stats;
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch consent logs
  const { data: consentStats } = useQuery({
    queryKey: ['consent-stats', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return null;
      const { data, error } = await supabase
        .from('consent_log')
        .select('action, consent_type')
        .eq('organization_id', profile.organization_id);
      if (error) throw error;

      return {
        total: data?.length || 0,
        granted: data?.filter(c => c.action === 'granted').length || 0,
        revoked: data?.filter(c => c.action === 'revoked').length || 0,
      };
    },
    enabled: !!profile?.organization_id,
  });

  // Calculate LGPD metrics
  const lgpdMetrics = {
    total: lgpdRequests.length,
    pending: lgpdRequests.filter((r: any) => ['received', 'verified', 'processing'].includes(r.status)).length,
    completed: lgpdRequests.filter((r: any) => r.status === 'completed').length,
    overdue: lgpdRequests.filter((r: any) => {
      if (['completed', 'denied'].includes(r.status)) return false;
      return new Date(r.deadline) < new Date();
    }).length,
  };

  const getStatusBadge = (status: string) => {
    const styles: Record<string, string> = {
      received: 'bg-blue-100 text-blue-800',
      verified: 'bg-purple-100 text-purple-800',
      processing: 'bg-yellow-100 text-yellow-800',
      completed: 'bg-green-100 text-green-800',
      denied: 'bg-red-100 text-red-800',
      expired: 'bg-gray-100 text-gray-800',
    };
    const labels: Record<string, string> = {
      received: 'Recebida',
      verified: 'Verificada',
      processing: 'Em Processamento',
      completed: 'Concluída',
      denied: 'Negada',
      expired: 'Expirada',
    };
    return (
      <Badge className={styles[status] || 'bg-gray-100 text-gray-800'}>
        {labels[status] || status}
      </Badge>
    );
