                <SelectItem value="license">Licença</SelectItem>
                <SelectItem value="subscription">Assinatura</SelectItem>
                <SelectItem value="virtual">Virtual</SelectItem>
                <SelectItem value="cloud_resource">Cloud</SelectItem>
              </SelectContent>
            </Select>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-full md:w-40">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos Status</SelectItem>
                <SelectItem value="available">Disponível</SelectItem>
                <SelectItem value="in_use">Em Uso</SelectItem>
                <SelectItem value="in_repair">Em Reparo</SelectItem>
                <SelectItem value="maintenance">Manutenção</SelectItem>
                <SelectItem value="retired">Aposentado</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Tag</TableHead>
                <TableHead>Nome</TableHead>
                <TableHead>Tipo</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Fabricante/Modelo</TableHead>
                <TableHead>Atribuído a</TableHead>
                <TableHead>Garantia</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8">
                    Carregando...
                  </TableCell>
                </TableRow>
              ) : filteredAssets && filteredAssets.length > 0 ? (
                filteredAssets.map((asset) => (
                  <TableRow key={asset.id}>
                    <TableCell>
                      <Link 
                        to={`/it/assets/${asset.id}`}
                        className="font-medium text-primary hover:underline"
                      >
                        {asset.asset_tag}
                      </Link>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        {getTypeIcon(asset.asset_type)}
                        <span>{asset.name}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <span className="capitalize text-sm">{asset.asset_type?.replace('_', ' ')}</span>
                    </TableCell>
                    <TableCell>{getStatusBadge(asset.status)}</TableCell>
                    <TableCell>
                      <div className="text-sm">
                        {asset.manufacturer && <div>{asset.manufacturer}</div>}
                        {asset.model && <div className="text-muted-foreground">{asset.model}</div>}
                      </div>
                    </TableCell>
                    <TableCell>
                      {asset.assigned_to_profile ? (
                        <div className="flex items-center gap-1">
                          <User className="h-3 w-3" />
                          <span className="text-sm">
                            {asset.assigned_to_profile.first_name} {asset.assigned_to_profile.last_name}
                          </span>
                        </div>
                      ) : (
                        <span className="text-muted-foreground text-sm">-</span>
                      )}
                    </TableCell>
                    <TableCell>
                      {getWarrantyStatus(asset.warranty_end_date)}
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8">
                    <Package className="mx-auto h-12 w-12 text-muted-foreground opacity-50" />
                    <p className="mt-2 text-muted-foreground">Nenhum ativo encontrado</p>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ArrowLeft, Save, Loader2 } from '@/components/icons';
import { toast } from 'sonner';

export default function ITChangeForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const isEdit = Boolean(id);

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    business_justification: '',
    category: '',
    change_type: 'normal' as 'standard' | 'normal' | 'emergency',
    risk_level: 'medium' as 'low' | 'medium' | 'high' | 'critical',
    implementation_plan: '',
    rollback_plan: '',
    test_plan: '',
    communication_plan: '',
    impact_analysis: '',
    downtime_required: false,
    downtime_duration_minutes: 0,
    cab_required: false,
    scheduled_start: '',
    scheduled_end: ''
  });

  const [assignedTo, setAssignedTo] = useState<string>('');

  // Fetch existing change for edit mode
  const { isLoading: isLoadingChange } = useQuery({
    queryKey: ['it-change', id],
    queryFn: async () => {
      if (!id) return null;
      const { data, error } = await supabase
        .from('it_changes')
        .select('*')
        .eq('id', id)
        .single();

      if (error) throw error;

      if (data) {
        setFormData({
          title: data.title || '',
          description: data.description || '',
          business_justification: data.business_justification || '',
          category: data.category || '',
          change_type: data.change_type || 'normal',
          risk_level: data.risk_level || 'medium',
          implementation_plan: data.implementation_plan || '',
          rollback_plan: data.rollback_plan || '',
          test_plan: data.test_plan || '',
          communication_plan: data.communication_plan || '',
          impact_analysis: data.impact_analysis || '',
          downtime_required: data.downtime_required || false,
          downtime_duration_minutes: data.downtime_duration_minutes || 0,
          cab_required: data.cab_required || false,
          scheduled_start: data.scheduled_start?.slice(0, 16) || '',
          scheduled_end: data.scheduled_end?.slice(0, 16) || ''
        });
        setAssignedTo(data.assigned_to || '');
      }

      return data;
    },
    enabled: isEdit
  });

  // Fetch users
  const { data: users } = useQuery({
    queryKey: ['users-list'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email')
        .order('first_name');

      if (error) throw error;
      return data;
    }
  });

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (!profile?.organization_id) {
        throw new Error('Organização não encontrada');
      }

      const changeData: any = {
        ...formData,
        organization_id: profile.organization_id,
        assigned_to: assignedTo || null,
        scheduled_start: formData.scheduled_start || null,
        scheduled_end: formData.scheduled_end || null
      };

      if (isEdit && id) {
        const { error } = await supabase
          .from('it_changes')
          .update(changeData)
          .eq('id', id);

        if (error) throw error;
      } else {
        // Generate change number
        const { data: numberData, error: numberError } = await supabase
          .rpc('generate_change_number', { org_id: profile.organization_id });

        if (numberError) throw numberError;

        changeData.change_number = numberData;
        changeData.requested_by = profile.id;

        const { error } = await supabase
          .from('it_changes')
          .insert(changeData);

        if (error) throw error;
      }
    },
    onSuccess: () => {
      toast.success(isEdit ? 'Mudança atualizada!' : 'Mudança criada!');
      queryClient.invalidateQueries({ queryKey: ['it-changes'] });
      navigate('/it/changes');
    },
    onError: (error) => {
      console.error('Error saving change:', error);
      toast.error('Erro ao salvar mudança');
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title.trim()) {
      toast.error('Título é obrigatório');
      return;
    }
    saveMutation.mutate();
  };

  const categories = [
    'Infraestrutura',
    'Aplicação',
    'Banco de Dados',
    'Rede',
    'Segurança',
    'Hardware',
    'Software',
    'Configuração',
    'Outro'
  ];

  if (isEdit && isLoadingChange) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button variant="ghost" size="icon" onClick={() => navigate('/it/changes')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div>
          <h1 className="text-3xl font-bold tracking-tight">
            {isEdit ? 'Editar Mudança' : 'Nova Mudança'}
          </h1>
          <p className="text-muted-foreground">
            {isEdit ? 'Atualize as informações da requisição de mudança' : 'Solicite uma nova mudança em TI'}
          </p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Info */}
          <div className="lg:col-span-2 space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Informações da Mudança</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="title">Título *</Label>
                  <Input
                    id="title"
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    placeholder="Descreva a mudança brevemente"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="description">Descrição</Label>
                  <Textarea
                    id="description"
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Descreva a mudança em detalhes..."
                    rows={4}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="business_justification">Justificativa de Negócio</Label>
                  <Textarea
                    id="business_justification"
                    value={formData.business_justification}
                    onChange={(e) => setFormData({ ...formData, business_justification: e.target.value })}
                    placeholder="Por que esta mudança é necessária?"
                    rows={3}
                  />
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="category">Categoria</Label>
                    <Select 
                      value={formData.category} 
                      onValueChange={(v) => setFormData({ ...formData, category: v })}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione..." />
                      </SelectTrigger>
                      <SelectContent>
                        {categories.map((cat) => (
                          <SelectItem key={cat} value={cat.toLowerCase()}>
                            {cat}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label>Atribuído a</Label>
                    <Select value={assignedTo} onValueChange={setAssignedTo}>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione..." />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="">Não atribuído</SelectItem>
                        {users?.map((user) => (
                          <SelectItem key={user.id} value={user.id}>
                            {user.first_name} {user.last_name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Planejamento</CardTitle>
                <CardDescription>Planos de implementação e contingência</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="implementation_plan">Plano de Implementação</Label>
                  <Textarea
                    id="implementation_plan"
                    value={formData.implementation_plan}
                    onChange={(e) => setFormData({ ...formData, implementation_plan: e.target.value })}
                    placeholder="Descreva os passos para implementar a mudança..."
                    rows={4}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="rollback_plan">Plano de Rollback</Label>
                  <Textarea
                    id="rollback_plan"
                    value={formData.rollback_plan}
                    onChange={(e) => setFormData({ ...formData, rollback_plan: e.target.value })}
                    placeholder="Descreva como reverter a mudança se necessário..."
                    rows={3}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="test_plan">Plano de Testes</Label>
                  <Textarea
                    id="test_plan"
                    value={formData.test_plan}
                    onChange={(e) => setFormData({ ...formData, test_plan: e.target.value })}
                    placeholder="Descreva como a mudança será testada..."
                    rows={3}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="communication_plan">Plano de Comunicação</Label>
                  <Textarea
                    id="communication_plan"
                    value={formData.communication_plan}
                    onChange={(e) => setFormData({ ...formData, communication_plan: e.target.value })}
                    placeholder="Quem precisa ser notificado e quando..."
                    rows={2}
                  />
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Análise de Impacto</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="impact_analysis">Análise de Impacto</Label>
                  <Textarea
                    id="impact_analysis"
                    value={formData.impact_analysis}
                    onChange={(e) => setFormData({ ...formData, impact_analysis: e.target.value })}
                    placeholder="Quais serviços, sistemas ou usuários serão afetados?"
                    rows={3}
                  />
                </div>

                <div className="flex items-center space-x-2">
                  <Switch
                    id="downtime_required"
                    checked={formData.downtime_required}
                    onCheckedChange={(checked) => setFormData({ ...formData, downtime_required: checked })}
                  />
                  <Label htmlFor="downtime_required">Requer Indisponibilidade (Downtime)</Label>
                </div>

                {formData.downtime_required && (
                  <div className="space-y-2">
                    <Label htmlFor="downtime_duration">Duração Estimada (minutos)</Label>
                    <Input
                      id="downtime_duration"
                      type="number"
                      value={formData.downtime_duration_minutes}
                      onChange={(e) => setFormData({ ...formData, downtime_duration_minutes: parseInt(e.target.value) || 0 })}
                    />
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Classificação</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Tipo de Mudança</Label>
                  <Select 
                    value={formData.change_type} 
                    onValueChange={(v: 'standard' | 'normal' | 'emergency') => 
                      setFormData({ ...formData, change_type: v })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="standard">Padrão (Pré-aprovada)</SelectItem>
                      <SelectItem value="normal">Normal</SelectItem>
                      <SelectItem value="emergency">Emergência</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Nível de Risco</Label>
                  <Select 
                    value={formData.risk_level} 
                    onValueChange={(v: 'low' | 'medium' | 'high' | 'critical') => 
                      setFormData({ ...formData, risk_level: v })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixo</SelectItem>
                      <SelectItem value="medium">Médio</SelectItem>
                      <SelectItem value="high">Alto</SelectItem>
                      <SelectItem value="critical">Crítico</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="flex items-center space-x-2">
                  <Switch
                    id="cab_required"
                    checked={formData.cab_required}
                    onCheckedChange={(checked) => setFormData({ ...formData, cab_required: checked })}
                  />
                  <Label htmlFor="cab_required">Requer CAB</Label>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Agendamento</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="scheduled_start">Início Previsto</Label>
                  <Input
                    id="scheduled_start"
                    type="datetime-local"
                    value={formData.scheduled_start}
                    onChange={(e) => setFormData({ ...formData, scheduled_start: e.target.value })}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="scheduled_end">Término Previsto</Label>
                  <Input
                    id="scheduled_end"
                    type="datetime-local"
                    value={formData.scheduled_end}
                    onChange={(e) => setFormData({ ...formData, scheduled_end: e.target.value })}
                  />
                </div>
              </CardContent>
            </Card>

            <div className="flex gap-2">
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => navigate('/it/changes')}
                className="flex-1"
              >
                Cancelar
              </Button>
              <Button type="submit" disabled={saveMutation.isPending} className="flex-1">
                {saveMutation.isPending ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : (
                  <Save className="mr-2 h-4 w-4" />
                )}
                Salvar
              </Button>
            </div>
          </div>
        </div>
      </form>
    </div>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Plus, Search, GitBranch, User, Calendar } from '@/components/icons';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

export default function ITChanges() {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [typeFilter, setTypeFilter] = useState<string>('all');

  const { data: changes, isLoading } = useQuery({
    queryKey: ['it-changes', statusFilter, typeFilter],
    queryFn: async () => {
      let query = supabase
        .from('it_changes')
        .select(`
          *,
          assigned_to_profile:profiles!it_changes_assigned_to_fkey(first_name, last_name),
          requested_by_profile:profiles!it_changes_requested_by_fkey(first_name, last_name)
        `)
        .order('created_at', { ascending: false });

      if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter as any);
      }
      if (typeFilter !== 'all') {
        query = query.eq('change_type', typeFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    }
  });

  const filteredChanges = changes?.filter(change => {
    if (!searchTerm) return true;
    const search = searchTerm.toLowerCase();
    return (
      change.change_number?.toLowerCase().includes(search) ||
      change.title?.toLowerCase().includes(search)
    );
  });

  const getTypeBadge = (type: string) => {
    const config: Record<string, { variant: 'destructive' | 'default' | 'secondary', label: string }> = {
      emergency: { variant: 'destructive', label: 'Emergência' },
      normal: { variant: 'default', label: 'Normal' },
      standard: { variant: 'secondary', label: 'Padrão' }
    };
    const c = config[type] || config.normal;
    return <Badge variant={c.variant}>{c.label}</Badge>;
  };

  const getRiskBadge = (risk: string) => {
    const colors: Record<string, string> = {
      critical: 'bg-red-100 text-red-700',
      high: 'bg-orange-100 text-orange-700',
      medium: 'bg-yellow-100 text-yellow-700',
      low: 'bg-green-100 text-green-700'
    };
    return <Badge variant="outline" className={colors[risk]}>{risk?.toUpperCase()}</Badge>;
  };

  const getStatusBadge = (status: string) => {
    const labels: Record<string, { label: string, className: string }> = {
      draft: { label: 'Rascunho', className: 'bg-gray-100 text-gray-700' },
      submitted: { label: 'Submetida', className: 'bg-blue-100 text-blue-700' },
      under_assessment: { label: 'Em Avaliação', className: 'bg-purple-100 text-purple-700' },
      pending_approval: { label: 'Aguardando Aprovação', className: 'bg-yellow-100 text-yellow-700' },
      approved: { label: 'Aprovada', className: 'bg-green-100 text-green-700' },
      rejected: { label: 'Rejeitada', className: 'bg-red-100 text-red-700' },
      scheduled: { label: 'Agendada', className: 'bg-indigo-100 text-indigo-700' },
      implementing: { label: 'Implementando', className: 'bg-orange-100 text-orange-700' },
      under_review: { label: 'Em Revisão', className: 'bg-purple-100 text-purple-700' },
      completed: { label: 'Concluída', className: 'bg-green-100 text-green-700' },
      cancelled: { label: 'Cancelada', className: 'bg-gray-100 text-gray-700' },
      failed: { label: 'Falhou', className: 'bg-red-100 text-red-700' },
      rolled_back: { label: 'Revertida', className: 'bg-red-100 text-red-700' }
    };
    const config = labels[status] || { label: status, className: '' };
    return <Badge variant="outline" className={config.className}>{config.label}</Badge>;
  };

  // Stats
  const pendingApproval = changes?.filter(c => c.status === 'pending_approval').length || 0;
  const scheduled = changes?.filter(c => c.status === 'scheduled').length || 0;
  const implementing = changes?.filter(c => c.status === 'implementing').length || 0;

  return (
    <div className="space-y-6">
      <ModuleHeroBanner
        module="itsm"
        title="Gestão de Mudanças"
        subtitle="Change Management - Controle de mudanças em TI"
        compact
        actions={
          <Button asChild className="gap-2 bg-white text-foreground hover:bg-white/90">
            <Link to="/it/changes/new">
              <Plus className="h-4 w-4" /> Nova Mudança
            </Link>
          </Button>
        }
      />

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{changes?.length || 0}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Aguardando Aprovação</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-yellow-600">{pendingApproval}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Agendadas</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-blue-600">{scheduled}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Em Implementação</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-orange-600">{implementing}</div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Filtros</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col gap-4 md:flex-row">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Buscar por número ou título..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-full md:w-48">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos os Status</SelectItem>
                <SelectItem value="draft">Rascunho</SelectItem>
                <SelectItem value="submitted">Submetida</SelectItem>
                <SelectItem value="pending_approval">Aguardando Aprovação</SelectItem>
                <SelectItem value="approved">Aprovada</SelectItem>
                <SelectItem value="scheduled">Agendada</SelectItem>
                <SelectItem value="implementing">Implementando</SelectItem>
                <SelectItem value="completed">Concluída</SelectItem>
              </SelectContent>
            </Select>
            <Select value={typeFilter} onValueChange={setTypeFilter}>
              <SelectTrigger className="w-full md:w-48">
                <SelectValue placeholder="Tipo" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos os Tipos</SelectItem>
                <SelectItem value="standard">Padrão</SelectItem>
                <SelectItem value="normal">Normal</SelectItem>
                <SelectItem value="emergency">Emergência</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Número</TableHead>
                <TableHead>Título</TableHead>
                <TableHead>Tipo</TableHead>
                <TableHead>Risco</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Agendamento</TableHead>
                <TableHead>Responsável</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8">
                    Carregando...
                  </TableCell>
                </TableRow>
              ) : filteredChanges && filteredChanges.length > 0 ? (
                filteredChanges.map((change) => (
                  <TableRow key={change.id}>
                    <TableCell>
                      <Link 
                        to={`/it/changes/${change.id}`}
                        className="font-medium text-primary hover:underline"
                      >
                        {change.change_number}
                      </Link>
                    </TableCell>
                    <TableCell>
                      <div className="max-w-xs truncate">{change.title}</div>
                    </TableCell>
                    <TableCell>{getTypeBadge(change.change_type)}</TableCell>
                    <TableCell>{getRiskBadge(change.risk_level)}</TableCell>
                    <TableCell>{getStatusBadge(change.status)}</TableCell>
                    <TableCell>
                      {change.scheduled_start ? (
                        <div className="flex items-center gap-1 text-sm">
                          <Calendar className="h-3 w-3" />
                          {format(new Date(change.scheduled_start), "dd/MM/yy HH:mm", { locale: ptBR })}
                        </div>
                      ) : (
                        <span className="text-muted-foreground text-sm">Não agendada</span>
                      )}
                    </TableCell>
                    <TableCell>
                      {change.assigned_to_profile ? (
                        <div className="flex items-center gap-1">
                          <User className="h-3 w-3" />
                          <span className="text-sm">
                            {change.assigned_to_profile.first_name} {change.assigned_to_profile.last_name}
                          </span>
                        </div>
                      ) : (
                        <span className="text-muted-foreground text-sm">Não atribuído</span>
                      )}
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8">
                    <GitBranch className="mx-auto h-12 w-12 text-muted-foreground opacity-50" />
                    <p className="mt-2 text-muted-foreground">Nenhuma mudança encontrada</p>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Separator } from '@/components/ui/separator';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  ArrowLeft, 
  Edit, 
  Clock, 
  User, 
  AlertTriangle,
  CheckCircle,
  MessageSquare,
  Send,
  Loader2,
  Calendar,
  Building
} from '@/components/icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

export default function ITIncidentDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const queryClient = useQueryClient();

  const [newNote, setNewNote] = useState('');
  const [noteType, setNoteType] = useState<'work_note' | 'customer_note'>('work_note');

  // Fetch incident details
  const { data: incident, isLoading } = useQuery({
    queryKey: ['it-incident', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('it_incidents')
        .select(`
          *,
          assigned_to_profile:profiles!it_incidents_assigned_to_fkey(id, first_name, last_name, email),
          reported_by_profile:profiles!it_incidents_reported_by_fkey(id, first_name, last_name, email),
          resolved_by_profile:profiles!it_incidents_resolved_by_fkey(id, first_name, last_name),
          assignment_group:teams!it_incidents_assignment_group_id_fkey(id, name)
        `)
        .eq('id', id)
        .single();

      if (error) throw error;
      return data;
    },
    enabled: Boolean(id)
  });

  // Fetch work notes
  const { data: workNotes } = useQuery({
    queryKey: ['it-work-notes', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('it_work_notes')
        .select(`
          *,
          created_by_profile:profiles!it_work_notes_created_by_fkey(first_name, last_name)
        `)
        .eq('entity_type', 'incident')
        .eq('entity_id', id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data;
    },
    enabled: Boolean(id)
  });

  // Add work note mutation
  const addNoteMutation = useMutation({
    mutationFn: async () => {
      if (!profile?.organization_id || !id) throw new Error('Missing data');

      const { error } = await supabase
        .from('it_work_notes')
        .insert({
          organization_id: profile.organization_id,
          entity_type: 'incident',
          entity_id: id,
          content: newNote,
          note_type: noteType,
          is_internal: noteType === 'work_note',
          created_by: profile.id
        });

      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Nota adicionada!');
      setNewNote('');
      queryClient.invalidateQueries({ queryKey: ['it-work-notes', id] });
    },
    onError: () => {
      toast.error('Erro ao adicionar nota');
    }
  });

  // Update status mutation
  const updateStatusMutation = useMutation({
    mutationFn: async (newStatus: string) => {
      const { error } = await supabase
        .from('it_incidents')
        .update({ status: newStatus as any })
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Status atualizado!');
      queryClient.invalidateQueries({ queryKey: ['it-incident', id] });
    },
    onError: () => {
      toast.error('Erro ao atualizar status');
    }
  });

  const getPriorityBadge = (priority: string) => {
    const config: Record<string, { variant: 'destructive' | 'default' | 'secondary', label: string, className?: string }> = {
      critical: { variant: 'destructive', label: 'Crítica', className: 'animate-pulse' },
      high: { variant: 'destructive', label: 'Alta' },
      medium: { variant: 'default', label: 'Média' },
      low: { variant: 'secondary', label: 'Baixa' }
    };
    const c = config[priority] || config.medium;
    return <Badge variant={c.variant} className={c.className}>{c.label}</Badge>;
  };

  const getStatusBadge = (status: string) => {
    const labels: Record<string, { label: string, className: string }> = {
      new: { label: 'Novo', className: 'bg-blue-100 text-blue-700' },
      acknowledged: { label: 'Reconhecido', className: 'bg-purple-100 text-purple-700' },
      in_progress: { label: 'Em Andamento', className: 'bg-yellow-100 text-yellow-700' },
      pending_info: { label: 'Aguardando Info', className: 'bg-orange-100 text-orange-700' },
      pending_vendor: { label: 'Aguardando Vendor', className: 'bg-orange-100 text-orange-700' },
      on_hold: { label: 'Em Espera', className: 'bg-gray-100 text-gray-700' },
      resolved: { label: 'Resolvido', className: 'bg-green-100 text-green-700' },
      closed: { label: 'Fechado', className: 'bg-slate-100 text-slate-700' },
      cancelled: { label: 'Cancelado', className: 'bg-red-100 text-red-700' }
    };
    const config = labels[status] || { label: status, className: '' };
    return <Badge variant="outline" className={config.className}>{config.label}</Badge>;
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  if (!incident) {
    return (
      <div className="text-center py-12">
        <AlertTriangle className="mx-auto h-12 w-12 text-muted-foreground" />
        <h2 className="mt-4 text-xl font-semibold">Incidente não encontrado</h2>
        <Button asChild className="mt-4">
          <Link to="/it/incidents">Voltar</Link>
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div className="flex items-start gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/it/incidents')}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold">{incident.incident_number}</h1>
              {getStatusBadge(incident.status)}
              {getPriorityBadge(incident.priority)}
            </div>
            <p className="text-lg mt-1">{incident.title}</p>
            <div className="flex items-center gap-4 mt-2 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Calendar className="h-4 w-4" />
                {format(new Date(incident.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
              </span>
              {incident.category && (
                <span className="flex items-center gap-1">
                  <Building className="h-4 w-4" />
                  {incident.category}
                </span>
              )}
            </div>
          </div>
        </div>
        <Button asChild>
          <Link to={`/it/incidents/${id}/edit`}>
            <Edit className="mr-2 h-4 w-4" />
            Editar
          </Link>
        </Button>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Main Content */}
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Descrição</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="whitespace-pre-wrap">{incident.description || 'Sem descrição'}</p>
            </CardContent>
          </Card>

          {incident.workaround_available && incident.workaround && (
            <Card className="border-yellow-200 bg-yellow-50">
              <CardHeader>
                <CardTitle className="text-yellow-800">Workaround Disponível</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="whitespace-pre-wrap text-yellow-900">{incident.workaround}</p>
              </CardContent>
            </Card>
          )}

          {incident.resolution && (
            <Card className="border-green-200 bg-green-50">
              <CardHeader>
                <CardTitle className="text-green-800">Resolução</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="whitespace-pre-wrap text-green-900">{incident.resolution}</p>
                {incident.resolved_at && (
                  <p className="mt-2 text-sm text-green-700">
                    Resolvido em {format(new Date(incident.resolved_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                    {incident.resolved_by_profile && ` por ${incident.resolved_by_profile.first_name} ${incident.resolved_by_profile.last_name}`}
                  </p>
                )}
              </CardContent>
            </Card>
          )}

          {/* Work Notes */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <MessageSquare className="h-5 w-5" />
                Notas de Trabalho
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {/* Add Note Form */}
              <div className="space-y-3 p-4 border rounded-lg bg-muted/50">
                <div className="flex gap-2">
                  <Select value={noteType} onValueChange={(v: 'work_note' | 'customer_note') => setNoteType(v)}>
                    <SelectTrigger className="w-48">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="work_note">Nota Interna</SelectItem>
                      <SelectItem value="customer_note">Nota para Cliente</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <Textarea
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="Adicionar nota..."
                  rows={3}
                />
                <div className="flex justify-end">
                  <Button 
                    onClick={() => addNoteMutation.mutate()}
                    disabled={!newNote.trim() || addNoteMutation.isPending}
                  >
                    {addNoteMutation.isPending ? (
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    ) : (
                      <Send className="mr-2 h-4 w-4" />
                    )}
                    Adicionar
                  </Button>
                </div>
              </div>

              <Separator />

              {/* Notes List */}
              {workNotes && workNotes.length > 0 ? (
                <div className="space-y-4">
                  {workNotes.map((note) => (
                    <div key={note.id} className={`p-4 rounded-lg border ${note.is_internal ? 'bg-muted/30' : 'bg-blue-50 border-blue-200'}`}>
                      <div className="flex items-center justify-between mb-2">
                        <div className="flex items-center gap-2">
                          <User className="h-4 w-4" />
                          <span className="font-medium">
                            {note.created_by_profile?.first_name} {note.created_by_profile?.last_name}
                          </span>
                          {note.is_internal ? (
                            <Badge variant="secondary" className="text-xs">Interna</Badge>
                          ) : (
                            <Badge variant="outline" className="text-xs bg-blue-100">Cliente</Badge>
                          )}
                        </div>
                        <span className="text-xs text-muted-foreground">
                          {format(new Date(note.created_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                        </span>
                      </div>
                      <p className="whitespace-pre-wrap">{note.content}</p>
                      {note.time_spent_minutes > 0 && (
                        <p className="mt-2 text-xs text-muted-foreground">
                          <Clock className="inline h-3 w-3 mr-1" />
                          {note.time_spent_minutes} min
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-center text-muted-foreground py-4">Nenhuma nota registrada</p>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Status</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <Select 
                value={incident.status} 
                onValueChange={(v) => updateStatusMutation.mutate(v)}
                disabled={updateStatusMutation.isPending}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="new">Novo</SelectItem>
                  <SelectItem value="acknowledged">Reconhecido</SelectItem>
                  <SelectItem value="in_progress">Em Andamento</SelectItem>
                  <SelectItem value="pending_info">Aguardando Info</SelectItem>
                  <SelectItem value="pending_vendor">Aguardando Vendor</SelectItem>
                  <SelectItem value="on_hold">Em Espera</SelectItem>
                  <SelectItem value="resolved">Resolvido</SelectItem>
                  <SelectItem value="closed">Fechado</SelectItem>
                </SelectContent>
              </Select>

              {incident.sla_breached && (
                <div className="p-3 rounded-lg bg-red-50 border border-red-200">
                  <p className="text-sm text-red-700 font-medium flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4" />
                    SLA Violado
                  </p>
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Priorização</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="flex justify-between">
                <span className="text-sm text-muted-foreground">Prioridade</span>
                {getPriorityBadge(incident.priority)}
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-muted-foreground">Impacto</span>
                <Badge variant="outline">{incident.impact?.toUpperCase()}</Badge>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-muted-foreground">Urgência</span>
                <Badge variant="outline">{incident.urgency?.toUpperCase()}</Badge>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Atribuição</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div>
                <span className="text-sm text-muted-foreground">Grupo</span>
                <p className="font-medium">
                  {incident.assignment_group?.name || 'Não atribuído'}
                </p>
              </div>
              <div>
                <span className="text-sm text-muted-foreground">Atribuído a</span>
                <p className="font-medium flex items-center gap-2">
                  <User className="h-4 w-4" />
                  {incident.assigned_to_profile 
                    ? `${incident.assigned_to_profile.first_name} ${incident.assigned_to_profile.last_name}`
                    : 'Não atribuído'
                  }
                </p>
              </div>
              <Separator />
              <div>
                <span className="text-sm text-muted-foreground">Reportado por</span>
                <p className="font-medium">
                  {incident.reported_by_profile 
                    ? `${incident.reported_by_profile.first_name} ${incident.reported_by_profile.last_name}`
                    : 'Desconhecido'
                  }
                </p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Datas</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Criado</span>
                <span>{format(new Date(incident.created_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}</span>
              </div>
              {incident.acknowledged_at && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Reconhecido</span>
                  <span>{format(new Date(incident.acknowledged_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}</span>
                </div>
              )}
              {incident.first_response_at && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Primeira Resposta</span>
                  <span>{format(new Date(incident.first_response_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}</span>
                </div>
              )}
              {incident.resolved_at && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Resolvido</span>
                  <span>{format(new Date(incident.resolved_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}</span>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { ArrowLeft, Save, Loader2 } from '@/components/icons';
import { toast } from 'sonner';

export default function ITIncidentForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const isEdit = Boolean(id);

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: '',
    subcategory: '',
    impact: 'medium' as 'low' | 'medium' | 'high' | 'critical',
    urgency: 'medium' as 'low' | 'medium' | 'high' | 'critical',
    status: 'new' as string,
    affected_service: '',
    workaround: '',
    workaround_available: false,
    customer_visible: false,
    customer_communication: '',
    source: 'manual'
  });

  // Fetch existing incident for edit mode
  const { isLoading: isLoadingIncident } = useQuery({
    queryKey: ['it-incident', id],
    queryFn: async () => {
      if (!id) return null;
      const { data, error } = await supabase
        .from('it_incidents')
        .select('*')
        .eq('id', id)
        .single();

      if (error) throw error;

      if (data) {
        setFormData({
          title: data.title || '',
          description: data.description || '',
          category: data.category || '',
          subcategory: data.subcategory || '',
          impact: data.impact || 'medium',
          urgency: data.urgency || 'medium',
          status: data.status || 'new',
          affected_service: data.affected_service || '',
          workaround: data.workaround || '',
          workaround_available: data.workaround_available || false,
          customer_visible: data.customer_visible || false,
          customer_communication: data.customer_communication || '',
          source: data.source || 'manual'
        });
      }

      return data;
    },
    enabled: isEdit
  });

  // Fetch users for assignment
  const { data: users } = useQuery({
    queryKey: ['users-list'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email')
        .order('first_name');

      if (error) throw error;
      return data;
    }
  });

  // Fetch teams
  const { data: teams } = useQuery({
    queryKey: ['teams-list'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('teams')
        .select('id, name')
        .order('name');

      if (error) throw error;
      return data;
    }
  });

  const [assignedTo, setAssignedTo] = useState<string>('');
  const [assignmentGroupId, setAssignmentGroupId] = useState<string>('');

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (!profile?.organization_id) {
        throw new Error('Organização não encontrada');
      }

      const incidentData: any = {
        ...formData,
        organization_id: profile.organization_id,
        assigned_to: assignedTo || null,
        assignment_group_id: assignmentGroupId || null
      };

      if (isEdit && id) {
        const { error } = await supabase
          .from('it_incidents')
          .update(incidentData)
          .eq('id', id);

        if (error) throw error;
      } else {
        // Generate incident number
        const { data: numberData, error: numberError } = await supabase
          .rpc('generate_incident_number', { org_id: profile.organization_id });

        if (numberError) throw numberError;

        incidentData.incident_number = numberData;
        incidentData.reported_by = profile.id;

        const { error } = await supabase
          .from('it_incidents')
          .insert(incidentData);

        if (error) throw error;
      }
    },
    onSuccess: () => {
      toast.success(isEdit ? 'Incidente atualizado!' : 'Incidente criado!');
      queryClient.invalidateQueries({ queryKey: ['it-incidents'] });
      navigate('/it/incidents');
    },
    onError: (error) => {
      console.error('Error saving incident:', error);
      toast.error('Erro ao salvar incidente');
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title.trim()) {
      toast.error('Título é obrigatório');
      return;
    }
    saveMutation.mutate();
  };

  const categories = [
    'Hardware',
    'Software',
    'Rede',
    'Segurança',
    'Email',
    'Acesso',
    'Impressora',
    'Telefonia',
    'Backup',
    'Banco de Dados',
    'Servidor',
    'Outro'
  ];

  const sources = [
    { value: 'manual', label: 'Manual' },
    { value: 'email', label: 'E-mail' },
    { value: 'phone', label: 'Telefone' },
    { value: 'chat', label: 'Chat' },
    { value: 'monitoring', label: 'Monitoramento' },
    { value: 'portal', label: 'Portal Self-Service' },
    { value: 'api', label: 'API/Integração' }
  ];

  if (isEdit && isLoadingIncident) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button variant="ghost" size="icon" onClick={() => navigate('/it/incidents')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div>
          <h1 className="text-3xl font-bold tracking-tight">
            {isEdit ? 'Editar Incidente' : 'Novo Incidente'}
          </h1>
          <p className="text-muted-foreground">
            {isEdit ? 'Atualize as informações do incidente' : 'Registre um novo incidente de TI'}
          </p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Info */}
          <div className="lg:col-span-2 space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Informações do Incidente</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="title">Título *</Label>
                  <Input
                    id="title"
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    placeholder="Descreva o incidente brevemente"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="description">Descrição</Label>
                  <Textarea
                    id="description"
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Descreva o incidente em detalhes..."
                    rows={5}
                  />
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="category">Categoria</Label>
                    <Select 
                      value={formData.category} 
                      onValueChange={(v) => setFormData({ ...formData, category: v })}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione..." />
                      </SelectTrigger>
                      <SelectContent>
                        {categories.map((cat) => (
                          <SelectItem key={cat} value={cat.toLowerCase()}>
                            {cat}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="subcategory">Subcategoria</Label>
                    <Input
                      id="subcategory"
                      value={formData.subcategory}
                      onChange={(e) => setFormData({ ...formData, subcategory: e.target.value })}
                      placeholder="Ex: Windows, SAP, etc."
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="affected_service">Serviço Afetado</Label>
                  <Input
                    id="affected_service"
                    value={formData.affected_service}
                    onChange={(e) => setFormData({ ...formData, affected_service: e.target.value })}
                    placeholder="Ex: E-mail Corporativo, ERP, etc."
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="source">Fonte</Label>
                  <Select 
                    value={formData.source} 
                    onValueChange={(v) => setFormData({ ...formData, source: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {sources.map((s) => (
                        <SelectItem key={s.value} value={s.value}>
                          {s.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Workaround</CardTitle>
                <CardDescription>Solução temporária enquanto o incidente é resolvido</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center space-x-2">
                  <Switch
                    id="workaround_available"
                    checked={formData.workaround_available}
                    onCheckedChange={(checked) => setFormData({ ...formData, workaround_available: checked })}
                  />
                  <Label htmlFor="workaround_available">Workaround disponível</Label>
                </div>

                {formData.workaround_available && (
                  <div className="space-y-2">
                    <Label htmlFor="workaround">Descrição do Workaround</Label>
                    <Textarea
                      id="workaround"
                      value={formData.workaround}
                      onChange={(e) => setFormData({ ...formData, workaround: e.target.value })}
                      placeholder="Descreva o workaround..."
                      rows={3}
                    />
                  </div>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Comunicação com Cliente</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center space-x-2">
                  <Switch
                    id="customer_visible"
                    checked={formData.customer_visible}
                    onCheckedChange={(checked) => setFormData({ ...formData, customer_visible: checked })}
                  />
                  <Label htmlFor="customer_visible">Visível para o cliente</Label>
                </div>

                {formData.customer_visible && (
                  <div className="space-y-2">
                    <Label htmlFor="customer_communication">Mensagem para o Cliente</Label>
                    <Textarea
                      id="customer_communication"
                      value={formData.customer_communication}
                      onChange={(e) => setFormData({ ...formData, customer_communication: e.target.value })}
                      placeholder="Mensagem que será exibida para o cliente..."
                      rows={3}
                    />
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Priorização</CardTitle>
                <CardDescription>A prioridade é calculada automaticamente</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Impacto</Label>
                  <Select 
                    value={formData.impact} 
                    onValueChange={(v: 'low' | 'medium' | 'high' | 'critical') => 
                      setFormData({ ...formData, impact: v })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixo - Poucos usuários</SelectItem>
                      <SelectItem value="medium">Médio - Área/Departamento</SelectItem>
                      <SelectItem value="high">Alto - Múltiplas áreas</SelectItem>
                      <SelectItem value="critical">Crítico - Toda empresa</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Urgência</Label>
                  <Select 
                    value={formData.urgency} 
                    onValueChange={(v: 'low' | 'medium' | 'high' | 'critical') => 
                      setFormData({ ...formData, urgency: v })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixa - Pode aguardar</SelectItem>
                      <SelectItem value="medium">Média - Afeta trabalho</SelectItem>
                      <SelectItem value="high">Alta - Impede trabalho</SelectItem>
                      <SelectItem value="critical">Crítica - Parada total</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                {isEdit && (
                  <div className="space-y-2">
                    <Label>Status</Label>
                    <Select 
                      value={formData.status} 
                      onValueChange={(v) => setFormData({ ...formData, status: v })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="new">Novo</SelectItem>
                        <SelectItem value="acknowledged">Reconhecido</SelectItem>
                        <SelectItem value="in_progress">Em Andamento</SelectItem>
                        <SelectItem value="pending_info">Aguardando Info</SelectItem>
                        <SelectItem value="pending_vendor">Aguardando Vendor</SelectItem>
                        <SelectItem value="on_hold">Em Espera</SelectItem>
                        <SelectItem value="resolved">Resolvido</SelectItem>
                        <SelectItem value="closed">Fechado</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Atribuição</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Grupo de Atribuição</Label>
                  <Select value={assignmentGroupId} onValueChange={setAssignmentGroupId}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione um grupo..." />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="">Nenhum</SelectItem>
                      {teams?.map((team) => (
                        <SelectItem key={team.id} value={team.id}>
                          {team.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Atribuído a</Label>
                  <Select value={assignedTo} onValueChange={setAssignedTo}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione..." />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="">Não atribuído</SelectItem>
                      {users?.map((user) => (
                        <SelectItem key={user.id} value={user.id}>
