import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface Journey {
  id: string;
  name: string;
  description: string | null;
  status: string;
  trigger_type: string;
  trigger_segment_id: string | null;
  trigger_event_name: string | null;
  trigger_config: Record<string, unknown>;
  allow_reentry: boolean;
  reentry_wait_days: number;
  goal_type: string | null;
  entry_count: number;
  active_count: number;
  completed_count: number;
  goal_achieved_count: number;
  conversion_rate: number | null;
  created_at: string;
}

interface JourneyStep {
  id: string;
  journey_id: string;
  step_key: string;
  step_order: number;
  type: string;
  name: string;
  description: string | null;
  config: Record<string, unknown>;
  wait_duration_value: number | null;
  wait_duration_unit: string | null;
  conditions: unknown[];
  next_step_on_success: string | null;
  next_step_on_failure: string | null;
  is_entry_point: boolean;
  is_exit_point: boolean;
  entered_count: number;
  completed_count: number;
}

interface Segment {
  id: string;
  name: string;
  member_count: number;
}

const stepTypeConfig: Record<string, { label: string; icon: React.ReactNode; color: string; description: string }> = {
  email: { label: 'Enviar Email', icon: <Mail className="h-4 w-4" />, color: 'bg-pink-500', description: 'Envia um email para o contato' },
  sms: { label: 'Enviar SMS', icon: <MessageSquare className="h-4 w-4" />, color: 'bg-green-500', description: 'Envia um SMS' },
  whatsapp: { label: 'WhatsApp', icon: <MessageSquare className="h-4 w-4" />, color: 'bg-green-600', description: 'Envia mensagem WhatsApp' },
  wait: { label: 'Aguardar', icon: <Clock className="h-4 w-4" />, color: 'bg-gray-500', description: 'Aguarda um tempo antes de continuar' },
  condition: { label: 'Condição', icon: <Filter className="h-4 w-4" />, color: 'bg-yellow-500', description: 'Verifica uma condição' },
  split: { label: 'Divisão A/B', icon: <GitBranch className="h-4 w-4" />, color: 'bg-purple-500', description: 'Divide o fluxo em caminhos' },
  goal: { label: 'Meta', icon: <Target className="h-4 w-4" />, color: 'bg-blue-500', description: 'Define uma meta de conversão' },
  action: { label: 'Ação', icon: <Zap className="h-4 w-4" />, color: 'bg-orange-500', description: 'Executa uma ação' },
  add_to_segment: { label: 'Adicionar a Segmento', icon: <Users className="h-4 w-4" />, color: 'bg-indigo-500', description: 'Adiciona o contato a um segmento' },
  update_field: { label: 'Atualizar Campo', icon: <Settings className="h-4 w-4" />, color: 'bg-teal-500', description: 'Atualiza um campo do contato' },
  notify_owner: { label: 'Notificar Responsável', icon: <Bell className="h-4 w-4" />, color: 'bg-red-500', description: 'Envia notificação ao responsável' },
  create_task: { label: 'Criar Tarefa', icon: <Target className="h-4 w-4" />, color: 'bg-cyan-500', description: 'Cria uma tarefa de follow-up' },
};

const triggerTypeLabels: Record<string, string> = {
  segment_entry: 'Entrada em Segmento',
  event: 'Evento',
  manual: 'Manual',
  scheduled: 'Agendado',
  form_submit: 'Submissão de Formulário',
  page_visit: 'Visita à Página',
};

export default function JourneyBuilder() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const [journey, setJourney] = useState<Journey | null>(null);
  const [steps, setSteps] = useState<JourneyStep[]>([]);
  const [segments, setSegments] = useState<Segment[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [selectedStep, setSelectedStep] = useState<JourneyStep | null>(null);
  const [stepSheetOpen, setStepSheetOpen] = useState(false);
  const [addStepDialogOpen, setAddStepDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [stepToDelete, setStepToDelete] = useState<JourneyStep | null>(null);
  const isNew = id === 'new';

  useEffect(() => {
    fetchSegments();
    if (!isNew && id) {
      fetchJourney();
      fetchSteps();
    } else {
      setJourney({
        id: '',
        name: '',
        description: null,
        status: 'draft',
        trigger_type: 'segment_entry',
        trigger_segment_id: null,
        trigger_event_name: null,
        trigger_config: {},
        allow_reentry: false,
        reentry_wait_days: 30,
        goal_type: null,
        entry_count: 0,
        active_count: 0,
        completed_count: 0,
        goal_achieved_count: 0,
        conversion_rate: null,
        created_at: new Date().toISOString(),
      });
      setLoading(false);
    }
  }, [id]);

  const fetchSegments = async () => {
    if (!profile?.organization_id) return;

    const { data } = await supabase
      .from('segments')
      .select('id, name, member_count')
      .eq('organization_id', profile.organization_id)
      .eq('is_active', true)
      .order('name');

    if (data) {
      setSegments(data);
    }
  };

  const fetchJourney = async () => {
    if (!id) return;

    const { data, error } = await supabase
      .from('journeys')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Jornada não encontrada',
      });
      navigate('/marketing');
      return;
    }

    setJourney(data as unknown as Journey);
    setLoading(false);
  };

  const fetchSteps = async () => {
    if (!id || isNew) return;

    const { data } = await supabase
      .from('journey_steps')
      .select('*')
      .eq('journey_id', id)
      .order('step_order');

    if (data) {
      setSteps(data as unknown as JourneyStep[]);
    }
  };

  const handleSave = async () => {
    if (!profile?.organization_id || !journey?.name) return;

    setSaving(true);

    const journeyData = {
      name: journey.name,
      description: journey.description,
      trigger_type: journey.trigger_type,
      trigger_segment_id: journey.trigger_segment_id || null,
      trigger_event_name: journey.trigger_event_name || null,
      trigger_config: journey.trigger_config as any,
      allow_reentry: journey.allow_reentry,
      reentry_wait_days: journey.reentry_wait_days,
      goal_type: journey.goal_type || null,
      organization_id: profile.organization_id,
      created_by: profile.id,
    };

    let error;
    let savedId = id;

    if (isNew) {
      const result = await supabase
        .from('journeys')
        .insert([journeyData])
        .select()
        .single();
      error = result.error;
      if (!error && result.data) {
        savedId = result.data.id;
        navigate(`/marketing/journeys/${savedId}`, { replace: true });
      }
    } else {
      const result = await supabase
        .from('journeys')
        .update(journeyData)
        .eq('id', id);
      error = result.error;
    }

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao salvar jornada',
      });
    } else {
      toast({
        title: 'Jornada salva',
        description: `"${journey.name}" foi salva com sucesso.`,
      });
    }

    setSaving(false);
  };

  const toggleJourneyStatus = async () => {
    if (!journey || isNew) return;

    const newStatus = journey.status === 'active' ? 'paused' : 'active';

    const { error } = await supabase
      .from('journeys')
      .update({ status: newStatus, published_at: newStatus === 'active' ? new Date().toISOString() : null })
      .eq('id', journey.id);

    if (!error) {
      setJourney({ ...journey, status: newStatus });
      toast({
        title: newStatus === 'active' ? 'Jornada ativada' : 'Jornada pausada',
        description: `A jornada foi ${newStatus === 'active' ? 'ativada' : 'pausada'}.`,
      });
    }
  };

  const addStep = async (type: string) => {
    if (!journey?.id || isNew) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Salve a jornada antes de adicionar steps',
      });
      return;
    }

    const stepConfig = stepTypeConfig[type];
    const stepKey = `step_${Date.now()}`;
    const stepOrder = steps.length + 1;

    const { data, error } = await supabase
      .from('journey_steps')
      .insert([{
        journey_id: journey.id,
        step_key: stepKey,
        step_order: stepOrder,
        type: type as any,
        name: stepConfig.label,
        config: {} as any,
        is_entry_point: steps.length === 0,
        position_x: 100,
        position_y: stepOrder * 120,
      }])
      .select()
      .single();

    if (!error && data) {
      setSteps([...steps, data as unknown as JourneyStep]);
      setAddStepDialogOpen(false);
      toast({
        title: 'Step adicionado',
        description: `"${stepConfig.label}" foi adicionado à jornada.`,
      });
    }
  };

  const updateStep = async (step: JourneyStep) => {
    const { error } = await supabase
      .from('journey_steps')
      .update({
        name: step.name,
        description: step.description,
        config: step.config as any,
        wait_duration_value: step.wait_duration_value,
        wait_duration_unit: step.wait_duration_unit,
        conditions: step.conditions as any,
      })
      .eq('id', step.id);

    if (!error) {
      setSteps(steps.map(s => s.id === step.id ? step : s));
      toast({
        title: 'Step atualizado',
        description: 'As alterações foram salvas.',
      });
    }
  };

  const deleteStep = async () => {
    if (!stepToDelete) return;

    const { error } = await supabase
      .from('journey_steps')
      .delete()
      .eq('id', stepToDelete.id);

    if (!error) {
      setSteps(steps.filter(s => s.id !== stepToDelete.id));
      setDeleteDialogOpen(false);
      setStepToDelete(null);
      toast({
        title: 'Step removido',
        description: 'O step foi removido da jornada.',
      });
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!journey) return null;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/marketing')}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold">
                {isNew ? 'Nova Jornada' : journey.name || 'Jornada sem nome'}
              </h1>
              {!isNew && (
                <Badge variant={journey.status === 'active' ? 'default' : 'secondary'}>
                  {journey.status === 'active' ? 'Ativa' : journey.status === 'paused' ? 'Pausada' : 'Rascunho'}
                </Badge>
              )}
            </div>
            {journey.description && (
              <p className="text-muted-foreground">{journey.description}</p>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          {!isNew && (
            <Button variant="outline" onClick={toggleJourneyStatus}>
              {journey.status === 'active' ? (
                <>
                  <Pause className="mr-2 h-4 w-4" />
                  Pausar
                </>
              ) : (
                <>
                  <Play className="mr-2 h-4 w-4" />
                  Ativar
                </>
              )}
            </Button>
          )}
          <Button onClick={handleSave} disabled={saving || !journey.name}>
            {saving ? <RefreshCw className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
            Salvar
          </Button>
        </div>
      </div>

      <Tabs defaultValue="builder" className="space-y-4">
        <TabsList>
          <TabsTrigger value="builder">Builder</TabsTrigger>
          <TabsTrigger value="trigger">Trigger</TabsTrigger>
          <TabsTrigger value="settings">Configurações</TabsTrigger>
          <TabsTrigger value="analytics" disabled={isNew}>Analytics</TabsTrigger>
        </TabsList>

        <TabsContent value="builder" className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold">Steps da Jornada</h2>
            <Button onClick={() => setAddStepDialogOpen(true)} disabled={isNew}>
              <Plus className="mr-2 h-4 w-4" />
              Adicionar Step
            </Button>
          </div>

          {/* Trigger Card */}
          <Card className="border-l-4 border-l-primary">
            <CardContent className="py-4">
              <div className="flex items-center gap-4">
                <div className="p-2 rounded-lg bg-primary/10 text-primary">
                  <GitBranch className="h-6 w-6" />
                </div>
                <div className="flex-1">
                  <p className="font-medium">Trigger: {triggerTypeLabels[journey.trigger_type]}</p>
                  {journey.trigger_segment_id && (
                    <p className="text-sm text-muted-foreground">
                      Segmento: {segments.find(s => s.id === journey.trigger_segment_id)?.name || 'Selecione'}
                    </p>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Steps List */}
          <div className="space-y-3">
            {steps.length === 0 ? (
              <Card>
                <CardContent className="py-12 text-center">
                  <GitBranch className="h-12 w-12 mx-auto mb-4 text-muted-foreground opacity-50" />
                  <p className="text-muted-foreground mb-4">
                    {isNew ? 'Salve a jornada para adicionar steps' : 'Nenhum step configurado'}
                  </p>
                  <Button onClick={() => setAddStepDialogOpen(true)} disabled={isNew}>
                    <Plus className="mr-2 h-4 w-4" />
                    Adicionar Primeiro Step
                  </Button>
                </CardContent>
              </Card>
            ) : (
              steps.map((step, index) => {
                const config = stepTypeConfig[step.type] || { label: step.type, icon: <Zap className="h-4 w-4" />, color: 'bg-gray-500' };
                return (
                  <Card
                    key={step.id}
                    className="cursor-pointer hover:border-primary transition-colors"
                    onClick={() => {
                      setSelectedStep(step);
                      setStepSheetOpen(true);
                    }}
                  >
                    <CardContent className="py-4">
                      <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <GripVertical className="h-4 w-4" />
                          <span className="text-sm font-medium">{index + 1}</span>
                        </div>
                        <div className={`p-2 rounded-lg text-white ${config.color}`}>
                          {config.icon}
                        </div>
                        <div className="flex-1">
                          <p className="font-medium">{step.name}</p>
                          {step.description && (
                            <p className="text-sm text-muted-foreground">{step.description}</p>
                          )}
                          {step.type === 'wait' && step.wait_duration_value && (
                            <p className="text-sm text-muted-foreground">
                              Aguardar {step.wait_duration_value} {step.wait_duration_unit || 'dias'}
                            </p>
                          )}
                        </div>
                        <div className="flex items-center gap-4 text-sm text-muted-foreground">
                          <span>{step.entered_count} entradas</span>
                          <span>{step.completed_count} concluídos</span>
                        </div>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={(e) => {
                            e.stopPropagation();
                            setStepToDelete(step);
                            setDeleteDialogOpen(true);
                          }}
                        >
                          <Trash2 className="h-4 w-4 text-muted-foreground" />
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                );
              })
            )}
          </div>

          {steps.length > 0 && (
            <div className="flex justify-center">
              <Button variant="outline" onClick={() => setAddStepDialogOpen(true)}>
                <Plus className="mr-2 h-4 w-4" />
                Adicionar Step
              </Button>
            </div>
          )}
        </TabsContent>

        <TabsContent value="trigger" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Configuração do Trigger</CardTitle>
              <CardDescription>
                Defina quando os contatos entram nesta jornada
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Tipo de Trigger</Label>
                <Select
                  value={journey.trigger_type}
                  onValueChange={(v) => setJourney({ ...journey, trigger_type: v })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(triggerTypeLabels).map(([key, label]) => (
                      <SelectItem key={key} value={key}>{label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {journey.trigger_type === 'segment_entry' && (
                <div className="space-y-2">
                  <Label>Segmento</Label>
                  <Select
                    value={journey.trigger_segment_id || ''}
                    onValueChange={(v) => setJourney({ ...journey, trigger_segment_id: v })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione um segmento" />
                    </SelectTrigger>
                    <SelectContent>
                      {segments.map((segment) => (
                        <SelectItem key={segment.id} value={segment.id}>
                          <div className="flex items-center justify-between w-full">
                            <span>{segment.name}</span>
                            <Badge variant="secondary" className="ml-2">
                              {segment.member_count}
                            </Badge>
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <p className="text-sm text-muted-foreground">
                    Contatos entrarão na jornada quando forem adicionados a este segmento
                  </p>
                </div>
              )}

              {journey.trigger_type === 'event' && (
                <div className="space-y-2">
                  <Label>Nome do Evento</Label>
                  <Input
                    value={journey.trigger_event_name || ''}
                    onChange={(e) => setJourney({ ...journey, trigger_event_name: e.target.value })}
                    placeholder="Ex: form_submitted, page_viewed"
                  />
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="settings" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Informações Básicas</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Nome da Jornada *</Label>
                <Input
                  value={journey.name}
                  onChange={(e) => setJourney({ ...journey, name: e.target.value })}
                  placeholder="Ex: Onboarding de Novos Clientes"
                />
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={journey.description || ''}
                  onChange={(e) => setJourney({ ...journey, description: e.target.value })}
                  placeholder="Descreva o objetivo desta jornada..."
                  rows={3}
                />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Comportamento</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label>Permitir Re-entrada</Label>
                  <p className="text-sm text-muted-foreground">
                    Contatos podem entrar na jornada mais de uma vez
                  </p>
                </div>
                <Switch
                  checked={journey.allow_reentry}
                  onCheckedChange={(checked) => setJourney({ ...journey, allow_reentry: checked })}
                />
              </div>
              {journey.allow_reentry && (
                <div className="space-y-2">
                  <Label>Tempo mínimo entre re-entradas (dias)</Label>
                  <Input
                    type="number"
                    value={journey.reentry_wait_days}
                    onChange={(e) => setJourney({ ...journey, reentry_wait_days: parseInt(e.target.value) || 30 })}
                    min={1}
                  />
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Meta de Conversão</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Tipo de Meta</Label>
                <Select
                  value={journey.goal_type || 'none'}
                  onValueChange={(v) => setJourney({ ...journey, goal_type: v === 'none' ? null : v })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Sem meta" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Sem meta</SelectItem>
                    <SelectItem value="segment_entry">Entrada em Segmento</SelectItem>
                    <SelectItem value="conversion">Conversão</SelectItem>
                    <SelectItem value="engagement">Engajamento</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="analytics" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-4">
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium">Entradas</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{journey.entry_count}</div>
              </CardContent>
            </Card>
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium">Ativos</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-blue-600">{journey.active_count}</div>
              </CardContent>
            </Card>
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium">Concluídos</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600">{journey.completed_count}</div>
              </CardContent>
            </Card>
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium">Conversão</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{journey.conversion_rate || 0}%</div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>

      {/* Step Editor Sheet */}
      <Sheet open={stepSheetOpen} onOpenChange={setStepSheetOpen}>
        <SheetContent className="sm:max-w-lg">
          <SheetHeader>
            <SheetTitle>Editar Step</SheetTitle>
            <SheetDescription>
              Configure as propriedades deste step
            </SheetDescription>
          </SheetHeader>
          {selectedStep && (
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label>Nome</Label>
                <Input
                  value={selectedStep.name}
                  onChange={(e) => setSelectedStep({ ...selectedStep, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={selectedStep.description || ''}
                  onChange={(e) => setSelectedStep({ ...selectedStep, description: e.target.value })}
                  rows={2}
                />
              </div>

              {selectedStep.type === 'wait' && (
                <div className="grid gap-4 grid-cols-2">
                  <div className="space-y-2">
                    <Label>Tempo de Espera</Label>
                    <Input
                      type="number"
                      value={selectedStep.wait_duration_value || 1}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        wait_duration_value: parseInt(e.target.value) || 1
                      })}
                      min={1}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Unidade</Label>
                    <Select
                      value={selectedStep.wait_duration_unit || 'days'}
                      onValueChange={(v) => setSelectedStep({
                        ...selectedStep,
                        wait_duration_unit: v
                      })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="minutes">Minutos</SelectItem>
                        <SelectItem value="hours">Horas</SelectItem>
                        <SelectItem value="days">Dias</SelectItem>
                        <SelectItem value="weeks">Semanas</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              )}

              {selectedStep.type === 'email' && (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <Label>Assunto do Email</Label>
                    <Input
                      value={(selectedStep.config as any).subject || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, subject: e.target.value }
                      })}
                      placeholder="Olá {{nome}}, temos novidades!"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Conteúdo</Label>
                    <Textarea
                      value={(selectedStep.config as any).content || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, content: e.target.value }
                      })}
                      rows={6}
                      placeholder="Escreva o conteúdo do email..."
                    />
                  </div>
                </div>
              )}

              <div className="flex gap-2 pt-4">
                <Button
                  variant="outline"
                  className="flex-1"
                  onClick={() => setStepSheetOpen(false)}
                >
                  Cancelar
                </Button>
                <Button
                  className="flex-1"
                  onClick={() => {
                    updateStep(selectedStep);
                    setStepSheetOpen(false);
                  }}
                >
                  Salvar
                </Button>
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>

      {/* Add Step Dialog */}
      <AlertDialog open={addStepDialogOpen} onOpenChange={setAddStepDialogOpen}>
        <AlertDialogContent className="max-w-2xl">
          <AlertDialogHeader>
            <AlertDialogTitle>Adicionar Step</AlertDialogTitle>
            <AlertDialogDescription>
              Escolha o tipo de step que deseja adicionar
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="grid gap-3 md:grid-cols-2 py-4">
            {Object.entries(stepTypeConfig).map(([type, config]) => (
              <Card
                key={type}
                className="cursor-pointer hover:border-primary transition-colors"
                onClick={() => addStep(type)}
              >
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg text-white ${config.color}`}>
                      {config.icon}
                    </div>
                    <div>
                      <p className="font-medium">{config.label}</p>
                      <p className="text-xs text-muted-foreground">{config.description}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Delete Step Dialog */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remover Step</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja remover este step? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={deleteStep}>Remover</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  Plus, 
  Search, 
  Book, 
  FileText, 
  Eye, 
  Edit,
  ThumbsUp,
  ThumbsDown,
  Folder,
  Calendar,
  User,
  RefreshCcw,
  ExternalLink,
  Star
} from '@/components/icons';
import { formatDistanceToNow, format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

type ArticleStatus = 'draft' | 'in_review' | 'published' | 'archived';

interface Article {
  id: string;
  title: string;
  slug: string;
  summary: string | null;
  status: ArticleStatus;
  is_public: boolean;
  is_featured: boolean;
  view_count: number;
  helpful_count: number;
  not_helpful_count: number;
  published_at: string | null;
  created_at: string;
  updated_at: string;
  author?: { first_name: string; last_name: string } | null;
  category?: { id: string; name: string } | null;
}

interface Category {
  id: string;
  name: string;
  slug: string;
  description: string | null;
  article_count: number;
  icon: string | null;
}

const statusConfig: Record<ArticleStatus, { label: string; className: string }> = {
  draft: { label: 'Rascunho', className: 'bg-slate-100 text-slate-700' },
  in_review: { label: 'Em Revisão', className: 'bg-yellow-100 text-yellow-700' },
  published: { label: 'Publicado', className: 'bg-green-100 text-green-700' },
  archived: { label: 'Arquivado', className: 'bg-gray-100 text-gray-700' },
};

export default function Knowledge() {
  const navigate = useNavigate();
  const { profile } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [activeTab, setActiveTab] = useState('articles');

  // Fetch articles
  const { data: articles = [], isLoading: isLoadingArticles, refetch: refetchArticles } = useQuery({
    queryKey: ['knowledge-articles', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('knowledge_articles')
        .select(`
          id, title, slug, summary, status, is_public, is_featured,
          view_count, helpful_count, not_helpful_count,
          published_at, created_at, updated_at,
          category:category_id(id, name)
        `)
        .eq('organization_id', profile.organization_id)
        .order('updated_at', { ascending: false });

      if (error) throw error;

      // Fetch authors separately
      const articlesWithAuthors = await Promise.all(
        (data || []).map(async (article: any) => {
          const { data: authorData } = await supabase
            .from('knowledge_articles')
            .select('author_id')
            .eq('id', article.id)
            .single();

          let author = null;
          if (authorData?.author_id) {
            const { data: profileData } = await supabase
              .from('profiles')
              .select('first_name, last_name')
              .eq('id', authorData.author_id)
              .single();
            author = profileData;
          }

          return { ...article, author } as Article;
        })
      );

      return articlesWithAuthors;
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch categories
  const { data: categories = [], isLoading: isLoadingCategories } = useQuery({
    queryKey: ['knowledge-categories', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('knowledge_categories')
        .select('id, name, slug, description, article_count, icon')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('display_order');

      if (error) throw error;
      return (data || []) as Category[];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch metrics
  const { data: metrics } = useQuery({
    queryKey: ['knowledge-metrics', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return null;

      const { data: allArticles } = await supabase
        .from('knowledge_articles')
        .select('status, view_count, helpful_count, not_helpful_count')
        .eq('organization_id', profile.organization_id);

      const articles = allArticles || [];
      const published = articles.filter(a => a.status === 'published');
      const totalViews = articles.reduce((sum, a) => sum + (a.view_count || 0), 0);
      const totalHelpful = articles.reduce((sum, a) => sum + (a.helpful_count || 0), 0);
      const totalNotHelpful = articles.reduce((sum, a) => sum + (a.not_helpful_count || 0), 0);
      const helpfulRate = totalHelpful + totalNotHelpful > 0 
        ? Math.round((totalHelpful / (totalHelpful + totalNotHelpful)) * 100)
        : 0;

      return {
        total: articles.length,
        published: published.length,
        drafts: articles.filter(a => a.status === 'draft').length,
        inReview: articles.filter(a => a.status === 'in_review').length,
        totalViews,
        helpfulRate,
      };
    },
    enabled: !!profile?.organization_id,
  });

  // Filter articles
  const filteredArticles = articles.filter(article => {
    const matchesSearch = 
      article.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      article.summary?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'all' || article.status === statusFilter;
    const matchesCategory = categoryFilter === 'all' || article.category?.id === categoryFilter;

    return matchesSearch && matchesStatus && matchesCategory;
  });

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="service"
          title="Base de Conhecimento"
          subtitle="Gerencie artigos, tutoriais e documentação de suporte"
          compact
          actions={
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={() => refetchArticles()} className="gap-2 bg-white/10 text-white border-white/20 hover:bg-white/20">
                <RefreshCcw className="h-4 w-4" /> Atualizar
              </Button>
              <Button onClick={() => navigate('/knowledge/new')} className="gap-2 bg-white text-foreground hover:bg-white/90">
                <Plus className="h-4 w-4" /> Novo Artigo
              </Button>
            </div>
          }
        />

        {/* Metrics Cards */}
        <div className="grid gap-4 md:grid-cols-5">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Total de Artigos</CardTitle>
              <Book className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{metrics?.total || 0}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Publicados</CardTitle>
              <FileText className="h-4 w-4 text-green-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-green-600">{metrics?.published || 0}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Rascunhos</CardTitle>
              <FileText className="h-4 w-4 text-slate-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-slate-600">{metrics?.drafts || 0}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Visualizações</CardTitle>
              <Eye className="h-4 w-4 text-blue-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-blue-600">{metrics?.totalViews || 0}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Taxa de Utilidade</CardTitle>
              <ThumbsUp className="h-4 w-4 text-green-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-green-600">{metrics?.helpfulRate || 0}%</div>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="articles">
              <FileText className="mr-2 h-4 w-4" />
              Artigos ({articles.length})
            </TabsTrigger>
            <TabsTrigger value="categories">
              <Folder className="mr-2 h-4 w-4" />
              Categorias ({categories.length})
            </TabsTrigger>
          </TabsList>

          <TabsContent value="articles" className="mt-4 space-y-4">
            {/* Filters */}
            <div className="flex flex-wrap gap-4">
              <div className="relative flex-1 min-w-[200px]">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Buscar artigos..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>

              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[150px]">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos Status</SelectItem>
                  <SelectItem value="draft">Rascunho</SelectItem>
                  <SelectItem value="in_review">Em Revisão</SelectItem>
                  <SelectItem value="published">Publicado</SelectItem>
                  <SelectItem value="archived">Arquivado</SelectItem>
                </SelectContent>
              </Select>

              <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder="Categoria" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todas Categorias</SelectItem>
                  {categories.map((cat) => (
                    <SelectItem key={cat.id} value={cat.id}>
                      {cat.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Articles Grid */}
            {isLoadingArticles ? (
              <div className="flex items-center justify-center py-12">
                <RefreshCcw className="h-8 w-8 animate-spin text-muted-foreground" />
              </div>
            ) : filteredArticles.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-12">
                  <Book className="h-12 w-12 text-muted-foreground mb-4" />
                  <h3 className="text-lg font-semibold">Nenhum artigo encontrado</h3>
                  <p className="text-muted-foreground">
                    Crie seu primeiro artigo de suporte
                  </p>
                  <Button className="mt-4" onClick={() => navigate('/knowledge/new')}>
                    <Plus className="mr-2 h-4 w-4" />
                    Criar Artigo
                  </Button>
                </CardContent>
              </Card>
            ) : (
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {filteredArticles.map((article) => (
                  <Card 
                    key={article.id} 
                    className="cursor-pointer hover:shadow-md transition-shadow"
                    onClick={() => navigate(`/knowledge/${article.id}`)}
                  >
                    <CardHeader className="pb-2">
                      <div className="flex items-start justify-between gap-2">
                        <Badge className={statusConfig[article.status].className}>
                          {statusConfig[article.status].label}
                        </Badge>
                        {article.is_featured && (
                          <Star className="h-4 w-4 text-yellow-500 fill-yellow-500" />
                        )}
                      </div>
                      <CardTitle className="text-lg line-clamp-2 mt-2">
                        {article.title}
                      </CardTitle>
                      {article.summary && (
                        <CardDescription className="line-clamp-2">
                          {article.summary}
                        </CardDescription>
                      )}
                    </CardHeader>
                    <CardContent>
                      <div className="flex flex-wrap gap-2 mb-3">
                        {article.category && (
                          <Badge variant="outline" className="text-xs">
                            <Folder className="h-3 w-3 mr-1" />
                            {article.category.name}
                          </Badge>
                        )}
                        {article.is_public && (
                          <Badge variant="outline" className="text-xs text-green-600">
                            <ExternalLink className="h-3 w-3 mr-1" />
                            Público
                          </Badge>
                        )}
                      </div>

                      <div className="flex items-center justify-between text-xs text-muted-foreground">
                        <div className="flex items-center gap-3">
                          <span className="flex items-center gap-1">
                            <Eye className="h-3 w-3" />
                            {article.view_count}
                          </span>
                          <span className="flex items-center gap-1">
                            <ThumbsUp className="h-3 w-3" />
                            {article.helpful_count}
                          </span>
                          <span className="flex items-center gap-1">
                            <ThumbsDown className="h-3 w-3" />
                            {article.not_helpful_count}
                          </span>
                        </div>
                        <span>
                          {formatDistanceToNow(new Date(article.updated_at), {
                            addSuffix: true,
                            locale: ptBR,
                          })}
                        </span>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </TabsContent>

          <TabsContent value="categories" className="mt-4">
            {isLoadingCategories ? (
              <div className="flex items-center justify-center py-12">
                <RefreshCcw className="h-8 w-8 animate-spin text-muted-foreground" />
              </div>
            ) : categories.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-12">
                  <Folder className="h-12 w-12 text-muted-foreground mb-4" />
                  <h3 className="text-lg font-semibold">Nenhuma categoria</h3>
                  <p className="text-muted-foreground">
                    Crie categorias para organizar seus artigos
                  </p>
                </CardContent>
              </Card>
            ) : (
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {categories.map((category) => (
                  <Card key={category.id}>
                    <CardHeader>
                      <div className="flex items-center gap-3">
                        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
                          <Folder className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                          <CardTitle className="text-lg">{category.name}</CardTitle>
                          <CardDescription>/{category.slug}</CardDescription>
                        </div>
                      </div>
                    </CardHeader>
                    <CardContent>
                      {category.description && (
                        <p className="text-sm text-muted-foreground mb-3">
                          {category.description}
                        </p>
                      )}
                      <div className="flex items-center justify-between">
                        <Badge variant="secondary">
                          {category.article_count} artigos
                        </Badge>
                        <Button 
                          variant="ghost" 
                          size="sm"
                          onClick={() => setCategoryFilter(category.id)}
                        >
                          Ver Artigos
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ArrowLeft, Save, Shield, User, Clock, CheckCircle2, XCircle } from '@/components/icons';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { format, differenceInDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';

const lgpdRequestSchema = z.object({
  type: z.enum(['access', 'rectification', 'deletion', 'portability', 'objection', 'restriction']),
  requester_email: z.string().email('Email inválido'),
  requester_name: z.string().min(1, 'Nome é obrigatório'),
  requester_document: z.string().optional(),
  request_details: z.string().optional(),
  priority: z.enum(['low', 'normal', 'high', 'urgent']).default('normal'),
});

type LGPDRequestFormData = z.infer<typeof lgpdRequestSchema>;

const typeLabels: Record<string, { label: string; description: string }> = {
  access: {
    label: 'Acesso aos Dados',
    description: 'Solicitação de acesso aos dados pessoais armazenados',
  },
  rectification: {
    label: 'Retificação',
    description: 'Correção de dados pessoais incorretos ou incompletos',
  },
  deletion: {
    label: 'Exclusão (Esquecimento)',
    description: 'Solicitação de exclusão de dados pessoais',
  },
  portability: {
    label: 'Portabilidade',
    description: 'Transferência de dados para outro controlador',
  },
  objection: {
    label: 'Oposição',
    description: 'Oposição ao tratamento de dados pessoais',
  },
  restriction: {
    label: 'Restrição',
    description: 'Limitação do tratamento de dados pessoais',
  },
};

const statusLabels: Record<string, { label: string; color: string }> = {
  received: { label: 'Recebida', color: 'bg-blue-100 text-blue-800' },
  verified: { label: 'Verificada', color: 'bg-purple-100 text-purple-800' },
  processing: { label: 'Em Processamento', color: 'bg-yellow-100 text-yellow-800' },
  completed: { label: 'Concluída', color: 'bg-green-100 text-green-800' },
  denied: { label: 'Negada', color: 'bg-red-100 text-red-800' },
  expired: { label: 'Expirada', color: 'bg-gray-100 text-gray-800' },
};

export default function LGPDRequestForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const isEditing = !!id;

  const form = useForm<LGPDRequestFormData>({
    resolver: zodResolver(lgpdRequestSchema),
    defaultValues: {
      type: 'access',
      requester_email: '',
      requester_name: '',
      requester_document: '',
      request_details: '',
      priority: 'normal',
    },
  });

  // Fetch existing request if editing
  const { data: request, isLoading } = useQuery({
    queryKey: ['lgpd-request', id],
    queryFn: async () => {
      if (!id) return null;
      const { data, error } = await supabase
        .from('lgpd_requests')
        .select('*')
        .eq('id', id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: isEditing,
  });

  useEffect(() => {
    if (request) {
      form.reset({
        type: request.type as any,
        requester_email: request.requester_email,
        requester_name: request.requester_name || '',
        requester_document: request.requester_document || '',
        request_details: request.request_details || '',
        priority: (request.priority as any) || 'normal',
      });
    }
  }, [request, form]);

  const mutation = useMutation({
    mutationFn: async (data: LGPDRequestFormData) => {
      if (!profile?.organization_id) throw new Error('Organização não encontrada');

      if (isEditing) {
        const { error } = await supabase
          .from('lgpd_requests')
          .update({
            type: data.type,
            requester_email: data.requester_email,
            requester_name: data.requester_name,
            requester_document: data.requester_document || null,
            request_details: data.request_details || null,
            priority: data.priority,
          })
          .eq('id', id);
        if (error) throw error;
        return id;
      } else {
        const insertData = {
          organization_id: profile.organization_id,
          type: data.type,
          requester_email: data.requester_email,
          requester_name: data.requester_name,
          requester_document: data.requester_document || null,
          request_details: data.request_details || null,
          priority: data.priority,
        };

        const { data: newRequest, error } = await supabase
          .from('lgpd_requests')
          .insert(insertData)
          .select('id')
          .single();
        if (error) throw error;
        return newRequest.id;
      }
    },
    onSuccess: (requestId) => {
      toast.success(isEditing ? 'Solicitação atualizada!' : 'Solicitação criada!');
      queryClient.invalidateQueries({ queryKey: ['lgpd-requests'] });
      navigate(`/governance/lgpd/${requestId}`);
    },
    onError: (error) => {
      toast.error('Erro ao salvar solicitação');
      console.error(error);
    },
  });

  const updateStatusMutation = useMutation({
    mutationFn: async (newStatus: string) => {
      if (!id) return;

      const updateData: any = { status: newStatus };

      if (newStatus === 'completed') {
        updateData.completed_at = new Date().toISOString();
        updateData.completed_by = profile?.id;
      }

      const { error } = await supabase
        .from('lgpd_requests')
        .update(updateData)
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Status atualizado!');
      queryClient.invalidateQueries({ queryKey: ['lgpd-request', id] });
    },
    onError: (error) => {
      toast.error('Erro ao atualizar status');
      console.error(error);
    },
  });

  const onSubmit = (data: LGPDRequestFormData) => {
    mutation.mutate(data);
  };

  if (isLoading) {
    return (
      <>
        <div className="flex items-center justify-center h-64">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      </>
    );
  }

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/governance')}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div className="flex-1">
            <h1 className="text-2xl font-bold tracking-tight">
              {isEditing ? 'Detalhes da Solicitação LGPD' : 'Nova Solicitação LGPD'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing
                ? 'Visualize e gerencie esta solicitação de titular'
                : 'Registre uma nova solicitação de direitos do titular'}
            </p>
          </div>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Form */}
          <div className="lg:col-span-2">
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                <Card>
                  <CardHeader>
                    <CardTitle>Dados do Titular</CardTitle>
                    <CardDescription>
                      Informações do solicitante
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <FormField
                      control={form.control}
                      name="requester_name"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Nome Completo *</FormLabel>
                          <FormControl>
                            <Input placeholder="Nome do titular" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="requester_email"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Email *</FormLabel>
                          <FormControl>
                            <Input type="email" placeholder="email@exemplo.com" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="requester_document"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>CPF/CNPJ</FormLabel>
                          <FormControl>
                            <Input placeholder="000.000.000-00" {...field} />
                          </FormControl>
                          <FormDescription>
                            Documento para verificação de identidade
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader>
                    <CardTitle>Detalhes da Solicitação</CardTitle>
                    <CardDescription>
                      Tipo e informações adicionais
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <FormField
                      control={form.control}
                      name="type"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Tipo de Solicitação *</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Selecione o tipo" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {Object.entries(typeLabels).map(([value, { label, description }]) => (
                                <SelectItem key={value} value={value}>
                                  <div>
                                    <p className="font-medium">{label}</p>
                                    <p className="text-xs text-muted-foreground">{description}</p>
                                  </div>
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="priority"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Prioridade</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="low">Baixa</SelectItem>
                              <SelectItem value="normal">Normal</SelectItem>
                              <SelectItem value="high">Alta</SelectItem>
                              <SelectItem value="urgent">Urgente</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="request_details"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Detalhes Adicionais</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="Descreva os detalhes da solicitação..."
                              className="min-h-[120px]"
                              {...field}
                            />
                          </FormControl>
                          <FormDescription>
                            Informações adicionais sobre a solicitação do titular
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </CardContent>
                </Card>

                <div className="flex justify-end gap-4">
                  <Button type="button" variant="outline" onClick={() => navigate('/governance')}>
                    Cancelar
                  </Button>
                  <Button type="submit" disabled={mutation.isPending}>
                    <Save className="mr-2 h-4 w-4" />
                    {isEditing ? 'Atualizar' : 'Criar Solicitação'}
                  </Button>
                </div>
              </form>
            </Form>
          </div>

          {/* Sidebar */}
          <div className="space-y-4">
            {isEditing && request && (
              <>
                {/* Status Card */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-lg">Status</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-muted-foreground">Status Atual</span>
                      <Badge className={statusLabels[request.status]?.color}>
                        {statusLabels[request.status]?.label || request.status}
                      </Badge>
                    </div>

                    <Separator />

                    <div className="space-y-2">
                      <Label>Alterar Status</Label>
                      <div className="grid grid-cols-2 gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => updateStatusMutation.mutate('verified')}
                          disabled={request.status === 'verified' || updateStatusMutation.isPending}
                        >
                          Verificar
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => updateStatusMutation.mutate('processing')}
                          disabled={request.status === 'processing' || updateStatusMutation.isPending}
                        >
                          Processar
                        </Button>
                        <Button
                          size="sm"
                          className="bg-green-600 hover:bg-green-700"
                          onClick={() => updateStatusMutation.mutate('completed')}
                          disabled={request.status === 'completed' || updateStatusMutation.isPending}
                        >
                          <CheckCircle2 className="mr-1 h-3 w-3" />
                          Concluir
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => updateStatusMutation.mutate('denied')}
                          disabled={request.status === 'denied' || updateStatusMutation.isPending}
                        >
                          <XCircle className="mr-1 h-3 w-3" />
                          Negar
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                {/* Timeline Card */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-lg">Prazos</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="flex items-center gap-3">
                      <Clock className="h-4 w-4 text-muted-foreground" />
                      <div>
                        <p className="text-sm font-medium">
                          Prazo: {format(new Date(request.deadline), 'dd/MM/yyyy', { locale: ptBR })}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {differenceInDays(new Date(request.deadline), new Date())} dias restantes
                        </p>
                      </div>
                    </div>

                    <Separator />

                    <div className="space-y-2 text-sm">
                      <div className="flex justify-between">
                        <span className="text-muted-foreground">Criada em</span>
                        <span>{format(new Date(request.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</span>
                      </div>
                      {request.verified_at && (
                        <div className="flex justify-between">
                          <span className="text-muted-foreground">Verificada em</span>
                          <span>{format(new Date(request.verified_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</span>
                        </div>
                      )}
                      {request.completed_at && (
                        <div className="flex justify-between">
                          <span className="text-muted-foreground">Concluída em</span>
                          <span>{format(new Date(request.completed_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</span>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>

                {/* Info Card */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-lg">Informações LGPD</CardTitle>
                  </CardHeader>
                  <CardContent className="text-sm text-muted-foreground space-y-2">
                    <p>
                      <strong>Art. 18 da LGPD:</strong> O titular tem direito a obter do controlador confirmação
                      da existência de tratamento, acesso aos dados, correção, anonimização, portabilidade,
                      eliminação, e outras garantias.
                    </p>
                    <p>
                      <strong>Prazo Legal:</strong> O controlador deve responder às solicitações em até 15 dias
                      (art. 18, §4º).
                    </p>
                  </CardContent>
                </Card>
              </>
            )}

            {!isEditing && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <Shield className="h-5 w-5" />
                    Direitos do Titular
                  </CardTitle>
                </CardHeader>
                <CardContent className="text-sm text-muted-foreground space-y-3">
                  <p>
                    A LGPD (Lei 13.709/2018) garante aos titulares diversos direitos sobre seus dados pessoais.
                  </p>
                  <ul className="list-disc list-inside space-y-1">
                    <li>Confirmação de tratamento</li>
                    <li>Acesso aos dados</li>
                    <li>Correção de dados incompletos</li>
                    <li>Anonimização ou bloqueio</li>
                    <li>Portabilidade</li>
                    <li>Eliminação</li>
                    <li>Revogação do consentimento</li>
                  </ul>
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Edit,
  Trash2,
  Phone,
  Mail,
  Building2,
  MapPin,
  Calendar,
  User,
  Activity,
  FileText,
  Plus,
  RefreshCw,
  Target,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Separator } from '@/components/ui/separator';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { LeadConversionWizard } from '@/components/LeadConversionWizard';
import { Timeline } from '@/components/Timeline';
import { ChangeHistory } from '@/components/ChangeHistory';

interface Lead {
  id: string;
  first_name: string;
  last_name: string;
  email: string | null;
  phone: string | null;
  mobile: string | null;
  company: string | null;
  job_title: string | null;
  industry: string | null;
  website: string | null;
  address_street: string | null;
  address_city: string | null;
  address_state: string | null;
  address_postal_code: string | null;
  address_country: string | null;
  status: 'new' | 'contacted' | 'qualified' | 'unqualified' | 'converted';
  source: string | null;
  score: number;
  rating: string | null;
  description: string | null;
  tags: string[] | null;
  created_at: string;
  updated_at: string;
}

const statusColors: Record<string, string> = {
  new: 'bg-info/10 text-info border-info/20',
  contacted: 'bg-warning/10 text-warning border-warning/20',
  qualified: 'bg-success/10 text-success border-success/20',
  unqualified: 'bg-muted text-muted-foreground border-muted',
  converted: 'bg-primary/10 text-primary border-primary/20',
};

export default function LeadDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const { toast } = useToast();
  const [lead, setLead] = useState<Lead | null>(null);
  const [loading, setLoading] = useState(true);
  const [showConversionWizard, setShowConversionWizard] = useState(false);


  useEffect(() => {
    if (id && user) {
      fetchLead();
    }
  }, [id, user]);

  const fetchLead = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('leads')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      console.error('Error fetching lead:', error);
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar detalhes do lead',
      });
      navigate('/leads');
    } else {
      setLead(data);
    }
    setLoading(false);
  };

  const deleteLead = async () => {
    if (!id) return;

    const { error } = await supabase.from('leads').delete().eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao excluir lead',
      });
    } else {
      toast({
        title: 'Lead excluído',
        description: 'O lead foi excluído com sucesso.',
      });
      navigate('/leads');
    }
  };

  const formatAddress = () => {
    if (!lead) return null;
    const parts = [
      lead.address_street,
      lead.address_city,
      lead.address_state,
      lead.address_postal_code,
      lead.address_country,
    ].filter(Boolean);
    return parts.length > 0 ? parts.join(', ') : null;
  };

  if (authLoading || loading) {
    return (
        <div className="flex items-center justify-center h-64">
          <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
    );
  }

  if (!lead) {
    return (
        <div className="flex flex-col items-center justify-center h-64 gap-4">
          <p className="text-muted-foreground">Lead não encontrado</p>
          <Button onClick={() => navigate('/leads')}>Voltar para Leads</Button>
        </div>
    );
  }

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
          <div className="flex items-start gap-4">
            <Button
              variant="ghost"
              size="icon"
              className="shrink-0"
              onClick={() => navigate('/leads')}
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-bold tracking-tight">
                  {lead.first_name} {lead.last_name}
                </h1>
                <Badge variant="outline" className={statusColors[lead.status]}>
                  {lead.status.charAt(0).toUpperCase() + lead.status.slice(1)}
                </Badge>
              </div>
              <p className="text-muted-foreground">
                {lead.job_title && lead.company
                  ? `${lead.job_title} at ${lead.company}`
                  : lead.job_title || lead.company || 'No company'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            {lead.status !== 'converted' && (
              <Button variant="default" onClick={() => setShowConversionWizard(true)}>
                <Target className="mr-2 h-4 w-4" />
                Converter Lead
              </Button>
            )}
            <Button variant="outline" onClick={() => navigate(`/leads/${id}/edit`)}>
              <Edit className="mr-2 h-4 w-4" />
              Editar
            </Button>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="destructive">
                  <Trash2 className="mr-2 h-4 w-4" />
                  Excluir
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Excluir Lead</AlertDialogTitle>
                  <AlertDialogDescription>
                    Tem certeza que deseja excluir este lead? Esta ação não pode ser desfeita.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                  <AlertDialogAction onClick={deleteLead}>Excluir</AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </div>

        {/* Content */}
        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-6">
            <Tabs defaultValue="details" className="w-full">
              <TabsList>
                <TabsTrigger value="details">Detalhes</TabsTrigger>
                <TabsTrigger value="activities">Atividades</TabsTrigger>
                <TabsTrigger value="notes">Notas</TabsTrigger>
                <TabsTrigger value="timeline">Timeline</TabsTrigger>
                <TabsTrigger value="history">Histórico</TabsTrigger>
              </TabsList>

              <TabsContent value="details" className="mt-6">
                <Card>
                  <CardHeader>
                    <CardTitle>Informações do Lead</CardTitle>
                    <CardDescription>Dados de contato e empresa</CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-6">
                    {/* Contact Info */}
                    <div>
                      <h4 className="text-sm font-medium text-muted-foreground mb-3">
                        Informações de Contato
                      </h4>
                      <div className="grid gap-4 sm:grid-cols-2">
                        {lead.email && (
                          <div className="flex items-center gap-3">
                            <Mail className="h-4 w-4 text-muted-foreground" />
                            <a href={`mailto:${lead.email}`} className="text-sm hover:underline">
                              {lead.email}
                            </a>
                          </div>
                        )}
                        {lead.phone && (
                          <div className="flex items-center gap-3">
                            <Phone className="h-4 w-4 text-muted-foreground" />
                            <a href={`tel:${lead.phone}`} className="text-sm hover:underline">
                              {lead.phone}
                            </a>
                          </div>
                        )}
                        {lead.mobile && (
                          <div className="flex items-center gap-3">
                            <Phone className="h-4 w-4 text-muted-foreground" />
                            <a href={`tel:${lead.mobile}`} className="text-sm hover:underline">
                              {lead.mobile} (Celular)
                            </a>
                          </div>
                        )}
                      </div>
                    </div>

                    <Separator />

                    {/* Company Info */}
                    <div>
                      <h4 className="text-sm font-medium text-muted-foreground mb-3">
                        Informações da Empresa
                      </h4>
                      <div className="grid gap-4 sm:grid-cols-2">
                        {lead.company && (
                          <div className="flex items-center gap-3">
                            <Building2 className="h-4 w-4 text-muted-foreground" />
                            <span className="text-sm">{lead.company}</span>
                          </div>
                        )}
                        {lead.industry && (
                          <div className="flex items-center gap-3">
                            <Activity className="h-4 w-4 text-muted-foreground" />
                            <span className="text-sm">{lead.industry}</span>
                          </div>
                        )}
                        {lead.website && (
                          <div className="flex items-center gap-3">
                            <FileText className="h-4 w-4 text-muted-foreground" />
                            <a
                              href={lead.website}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="text-sm hover:underline"
                            >
                              {lead.website}
                            </a>
                          </div>
                        )}
                        {formatAddress() && (
                          <div className="flex items-start gap-3 sm:col-span-2">
                            <MapPin className="h-4 w-4 text-muted-foreground mt-0.5" />
                            <span className="text-sm">{formatAddress()}</span>
                          </div>
                        )}
                      </div>
                    </div>

                    {lead.description && (
                      <>
                        <Separator />
                        <div>
                          <h4 className="text-sm font-medium text-muted-foreground mb-3">
                            Descrição
                          </h4>
                          <p className="text-sm whitespace-pre-wrap">{lead.description}</p>
                        </div>
                      </>
                    )}

                    {lead.tags && lead.tags.length > 0 && (
                      <>
                        <Separator />
                        <div>
                          <h4 className="text-sm font-medium text-muted-foreground mb-3">Tags</h4>
                          <div className="flex flex-wrap gap-2">
                            {lead.tags.map((tag) => (
                              <Badge key={tag} variant="secondary">
                                {tag}
                              </Badge>
                            ))}
                          </div>
                        </div>
                      </>
                    )}
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="activities" className="mt-6">
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between">
                    <div>
                      <CardTitle>Atividades</CardTitle>
                      <CardDescription>Ligações, reuniões e tarefas</CardDescription>
                    </div>
                    <Button size="sm">
                      <Plus className="mr-2 h-4 w-4" />
                      Registrar Atividade
                    </Button>
                  </CardHeader>
                  <CardContent>
                    <div className="flex flex-col items-center justify-center h-32 text-muted-foreground">
                      <Activity className="h-8 w-8 mb-2" />
                      <p>Nenhuma atividade ainda</p>
                    </div>
                  </CardContent>
                </Card>
