              <TabsContent value="notes" className="mt-6">
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between">
                    <div>
                      <CardTitle>Notas</CardTitle>
                      <CardDescription>Notas internas e comentários</CardDescription>
