import { useState, useEffect, useCallback, useMemo } from 'react';

import { TooltipProvider } from '@/components/ui/tooltip';
import { Inbox } from '@/components/icons';
import {
  useConversations,
  useConversationMessages,
  useAgentStatus,
  type Conversation,
  type ConversationStatus,
  type ConversationChannel,
  type AgentStatus,
} from '@/hooks/useConversations';
import { useConversationActions } from '@/hooks/useConversationActions';
import { useSendMessage } from '@/hooks/useSendMessage';
import { useAuth } from '@/hooks/useAuth';
import { InboxConversationList } from '@/components/inbox/InboxConversationList';
import { InboxConversationHeader } from '@/components/inbox/InboxConversationHeader';
import { InboxMessageThread } from '@/components/inbox/InboxMessageThread';
import { InboxReplyBox } from '@/components/inbox/InboxReplyBox';
import { InboxContextPanel } from '@/components/inbox/InboxContextPanel';

// ──────────────────────────────────────────────
// Status filter → query status mapping
// ──────────────────────────────────────────────
function resolveStatusFilter(tab: string): ConversationStatus | ConversationStatus[] | undefined {
  switch (tab) {
    case 'active':
      return ['open', 'waiting_agent', 'bot_handling'] as ConversationStatus[];
    case 'waiting':
      return 'waiting_customer';
    case 'closed':
      return 'closed';
    default:
      return undefined;
  }
}

export default function OmnichannelInbox() {
  const { profile } = useAuth();

  // ── Selection & filters ──
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [statusFilter, setStatusFilter] = useState('active');
  const [channelFilter, setChannelFilter] = useState('all');
  const [ownerFilter, setOwnerFilter] = useState('all');
  const [showContextPanel, setShowContextPanel] = useState(true);

  // ── Derive query options from filters ──
  const queryOptions = useMemo(() => {
    const opts: {
      status?: ConversationStatus | ConversationStatus[];
      channel?: ConversationChannel;
      ownerId?: string;
    } = {};

    const resolvedStatus = resolveStatusFilter(statusFilter);
    if (resolvedStatus) opts.status = resolvedStatus;
    if (channelFilter !== 'all') opts.channel = channelFilter as ConversationChannel;
    if (ownerFilter === 'mine' && profile?.id) opts.ownerId = profile.id;

    return opts;
  }, [statusFilter, channelFilter, ownerFilter, profile?.id]);

  // ── Data hooks ──
  const { status: agentStatus, updateStatus: updateAgentStatus } = useAgentStatus();
  const {
    conversations: rawConversations,
    loading: conversationsLoading,
    refetch: refetchConversations,
  } = useConversations(queryOptions);

  // Apply client-side owner filter for "unassigned"
  const conversations = useMemo(() => {
    if (ownerFilter === 'unassigned') {
      return rawConversations.filter(c => !c.owner_id);
    }
    return rawConversations;
  }, [rawConversations, ownerFilter]);

  const {
    messages,
    loading: messagesLoading,
    refetch: refetchMessages,
  } = useConversationMessages(selectedConversation?.id || null);

  // ── Actions ──
  const actions = useConversationActions(() => {
    refetchConversations();
  });

  const { sendMessage, sending } = useSendMessage();

  // ── Keep selected conversation in sync with refreshed data ──
  useEffect(() => {
    if (!selectedConversation) return;
    const updated = conversations.find(c => c.id === selectedConversation.id);
    if (updated) {
      setSelectedConversation(updated);
    }
  }, [conversations, selectedConversation?.id]);

  // ── Mark conversation as read when selected ──
  useEffect(() => {
    if (selectedConversation && selectedConversation.unread_count > 0) {
      actions.markRead(selectedConversation.id);
    }
  }, [selectedConversation?.id]);

  // ── Keyboard shortcuts ──
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const tag = (e.target as HTMLElement)?.tagName;
      if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;

      const currentIdx = selectedConversation
        ? conversations.findIndex(c => c.id === selectedConversation.id)
        : -1;

      switch (e.key) {
        case 'ArrowDown':
        case 'j': {
          e.preventDefault();
          const nextIdx = Math.min(currentIdx + 1, conversations.length - 1);
          if (conversations[nextIdx]) setSelectedConversation(conversations[nextIdx]);
          break;
        }
        case 'ArrowUp':
        case 'k': {
          e.preventDefault();
          const prevIdx = Math.max(currentIdx - 1, 0);
          if (conversations[prevIdx]) setSelectedConversation(conversations[prevIdx]);
          break;
        }
        case 'e': {
          if (selectedConversation && selectedConversation.status !== 'closed') {
            e.preventDefault();
            actions.closeConversation(selectedConversation.id);
          }
          break;
        }
        case 'a': {
          if (selectedConversation && !selectedConversation.owner_id) {
            e.preventDefault();
            actions.assignToMe(selectedConversation.id);
          }
          break;
        }
        case 'i': {
          e.preventDefault();
          setShowContextPanel(prev => !prev);
          break;
        }
        case 'Escape': {
          setSelectedConversation(null);
          break;
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedConversation, conversations, actions]);

  // ── Handlers ──
  const handleSelectConversation = useCallback((conv: Conversation) => {
    setSelectedConversation(conv);
  }, []);

  const handleAssignToMe = useCallback(() => {
    if (!selectedConversation) return;
    actions.assignToMe(selectedConversation.id);
  }, [selectedConversation, actions]);

  const handleClose = useCallback(() => {
    if (!selectedConversation) return;
    actions.closeConversation(selectedConversation.id);
  }, [selectedConversation, actions]);

  const handleUpdateStatus = useCallback((status: ConversationStatus) => {
    if (!selectedConversation) return;
    actions.updateStatus(selectedConversation.id, status);
  }, [selectedConversation, actions]);

  const handleUpdatePriority = useCallback((priority: string) => {
    if (!selectedConversation) return;
    actions.updatePriority(selectedConversation.id, priority as 'low' | 'medium' | 'high' | 'critical');
  }, [selectedConversation, actions]);

  const handleSnooze = useCallback((until: Date) => {
    if (!selectedConversation) return;
    actions.snoozeConversation(selectedConversation.id, until);
  }, [selectedConversation, actions]);

  const handleMarkSpam = useCallback(() => {
    if (!selectedConversation) return;
    actions.markAsSpam(selectedConversation.id);
  }, [selectedConversation, actions]);

  const handleTransfer = useCallback((agentId: string) => {
    if (!selectedConversation) return;
    actions.transferConversation(selectedConversation.id, agentId);
  }, [selectedConversation, actions]);

  const handleSendMessage = useCallback(async (content: string, isInternal: boolean): Promise<boolean> => {
    if (!selectedConversation) return false;
    const success = await sendMessage({
      conversationId: selectedConversation.id,
      content,
      isInternal,
    });
    if (success) {
      refetchMessages();
    }
    return success;
  }, [selectedConversation, sendMessage, refetchMessages]);

  // ──────────────────────────────────────────────
  // Render
  // ──────────────────────────────────────────────
  return (
    <>
      <TooltipProvider delayDuration={200}>
        <div className="flex h-[calc(100vh-72px)] overflow-hidden -m-6 rounded-none bg-card">
          {/* ───── Left: Conversation List ───── */}
          <InboxConversationList
            conversations={conversations}
            loading={conversationsLoading}
            selectedId={selectedConversation?.id || null}
            agentStatus={agentStatus}
            onSelect={handleSelectConversation}
            onRefresh={refetchConversations}
            onUpdateAgentStatus={(s) => updateAgentStatus(s as AgentStatus)}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            channelFilter={channelFilter}
            onChannelFilterChange={setChannelFilter}
            ownerFilter={ownerFilter}
            onOwnerFilterChange={setOwnerFilter}
          />

          {/* ───── Center: Thread + Reply ───── */}
          <div className="flex-1 flex flex-col bg-background min-w-0">
            {selectedConversation ? (
              <>
                <InboxConversationHeader
                  conversation={selectedConversation}
                  onAssignToMe={handleAssignToMe}
                  onClose={handleClose}
                  onUpdateStatus={handleUpdateStatus}
                  onUpdatePriority={handleUpdatePriority}
                  onSnooze={handleSnooze}
                  onMarkSpam={handleMarkSpam}
                  onTransfer={handleTransfer}
                />

                <InboxMessageThread
                  messages={messages}
                  loading={messagesLoading}
                  currentUserId={profile?.id}
                />

                {selectedConversation.status !== 'closed' && (
                  <InboxReplyBox
                    conversationId={selectedConversation.id}
                    contactId={selectedConversation.contact_id}
                    onSend={handleSendMessage}
                    sending={sending}
                    disabled={selectedConversation.status === 'spam'}
                  />
                )}
              </>
            ) : (
              <div className="flex-1 flex items-center justify-center text-muted-foreground animate-fade-in">
                  <div className="text-center space-y-2">
                    <div className="h-12 w-12 mx-auto rounded-xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center">
                      <Inbox className="h-5 w-5 text-primary/40" />
                    </div>
                    <div>
                      <h3 className="text-xs font-bold text-foreground">Selecione uma conversação</h3>
                      <p className="text-[11px] mt-0.5 text-muted-foreground">Escolha uma conversação da lista para começar o atendimento</p>
                    </div>
                    <div className="flex flex-wrap justify-center gap-1 mt-2">
                      <kbd className="bg-muted rounded-md px-1.5 py-0 text-[9px] font-mono border border-border/50">↑↓ navegar</kbd>
                      <kbd className="bg-muted rounded-md px-1.5 py-0 text-[9px] font-mono border border-border/50">E resolver</kbd>
                      <kbd className="bg-muted rounded-md px-1.5 py-0 text-[9px] font-mono border border-border/50">A assumir</kbd>
                      <kbd className="bg-muted rounded-md px-1.5 py-0 text-[9px] font-mono border border-border/50">I contexto</kbd>
                      <kbd className="bg-muted rounded-md px-1.5 py-0 text-[9px] font-mono border border-border/50">Esc voltar</kbd>
                    </div>
                </div>
              </div>
            )}
          </div>

          {/* ───── Right: Context Panel ───── */}
          {selectedConversation && showContextPanel && (
            <InboxContextPanel conversation={selectedConversation} />
          )}
        </div>
      </TooltipProvider>
    </>
  );
}

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ArrowLeft, Loader2 } from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { Database } from '@/integrations/supabase/types';
import { CustomFieldsRenderer } from '@/components/CustomFieldsRenderer';
import { useCustomFieldDefinitions, useCustomFieldValues, useSaveCustomFieldValues, getFieldValue } from '@/hooks/useCustomFields';

type OpportunityStage = Database['public']['Enums']['opportunity_stage'];

const opportunitySchema = z.object({
  name: z.string().min(1, 'Nome é obrigatório').max(200),
  account_id: z.string().min(1, 'Conta é obrigatória'),
  stage: z.enum(['prospecting', 'qualification', 'proposal', 'negotiation', 'closed_won', 'closed_lost'] as const),
  amount: z.coerce.number().min(0).optional(),
  probability: z.coerce.number().min(0).max(100).optional(),
  close_date: z.string().optional(),
  description: z.string().max(5000).optional(),
  next_step: z.string().max(500).optional(),
  source: z.string().max(100).optional(),
  competitor: z.string().max(200).optional(),
});

type OpportunityFormData = z.infer<typeof opportunitySchema>;

interface Account {
  id: string;
  name: string;
}

export default function OpportunityForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading: authLoading, profile } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [accounts, setAccounts] = useState<Account[]>([]);
  const { data: customFieldDefs = [] } = useCustomFieldDefinitions('opportunity');
  const { data: customFieldValuesData = [] } = useCustomFieldValues('opportunity', id && id !== 'new' ? id : undefined);
  const saveCustomFields = useSaveCustomFieldValues();
  const [customFieldValues, setCustomFieldValues] = useState<Record<string, any>>({});

  useEffect(() => {
    if (customFieldDefs.length > 0) {
      const values: Record<string, any> = {};
      customFieldDefs.forEach(def => {
        const fieldValue = customFieldValuesData.find(v => v.field_definition_id === def.id);
        values[def.id] = getFieldValue(def, fieldValue);
      });
      setCustomFieldValues(values);
    }
  }, [customFieldDefs, customFieldValuesData]);

  const form = useForm<OpportunityFormData>({
    resolver: zodResolver(opportunitySchema),
    defaultValues: {
      name: '',
      account_id: '',
      stage: 'prospecting',
      amount: undefined,
      probability: 10,
      close_date: '',
      description: '',
      next_step: '',
      source: '',
      competitor: '',
    },
  });


  useEffect(() => {
    async function fetchAccounts() {
      if (!profile?.organization_id) return;

      const { data } = await supabase
        .from('accounts')
        .select('id, name')
        .eq('organization_id', profile.organization_id)
        .order('name');

      if (data) setAccounts(data);
    }
    fetchAccounts();
  }, [profile?.organization_id]);

  useEffect(() => {
    async function fetchOpportunity() {
      if (!id || id === 'new') return;

      setLoading(true);
      const { data, error } = await supabase
        .from('opportunities')
        .select('*')
        .eq('id', id)
        .maybeSingle();

      if (error) {
        toast({ title: 'Erro ao carregar oportunidade', description: error.message, variant: 'destructive' });
        navigate('/opportunities');
      } else if (data) {
        form.reset({
          name: data.name,
          account_id: data.account_id,
          stage: data.stage,
          amount: data.amount || undefined,
          probability: data.probability || 10,
          close_date: data.close_date || '',
          description: data.description || '',
          next_step: data.next_step || '',
          source: data.source || '',
          competitor: data.competitor || '',
        });
      }
      setLoading(false);
    }
    fetchOpportunity();
  }, [id, form, toast, navigate]);

  const onSubmit = async (data: OpportunityFormData) => {
    if (!profile?.organization_id) {
      toast({ title: 'Erro', description: 'Organização não encontrada', variant: 'destructive' });
      return;
    }

    setLoading(true);

    let error;
    if (id && id !== 'new') {
      const { error: updateError } = await supabase
        .from('opportunities')
        .update({
          name: data.name,
          account_id: data.account_id,
          stage: data.stage,
          amount: data.amount || null,
          probability: data.probability || null,
          close_date: data.close_date || null,
          description: data.description || null,
          next_step: data.next_step || null,
          source: data.source || null,
          competitor: data.competitor || null,
        })
        .eq('id', id);
      error = updateError;
    } else {
      const { error: insertError } = await supabase
        .from('opportunities')
        .insert([{
          name: data.name,
          account_id: data.account_id,
          stage: data.stage,
          organization_id: profile.organization_id,
          owner_id: user?.id,
          amount: data.amount || null,
          probability: data.probability || null,
          close_date: data.close_date || null,
          description: data.description || null,
          next_step: data.next_step || null,
          source: data.source || null,
          competitor: data.competitor || null,
        }]);
      error = insertError;
    }

    if (error) {
      toast({ title: 'Erro ao salvar oportunidade', description: error.message, variant: 'destructive' });
    } else {
      toast({ title: id ? 'Oportunidade atualizada' : 'Oportunidade criada' });
      if (customFieldDefs.length > 0 && id && id !== 'new') {
        saveCustomFields.mutate({ entityType: 'opportunity', entityId: id, values: customFieldValues, definitions: customFieldDefs });
      }
      navigate('/opportunities');
    }
    setLoading(false);
  };

  if (authLoading || !user) return null;

  return (

      <div className="space-y-6 max-w-3xl">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/opportunities')}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <h1 className="text-2xl font-bold">{id && id !== 'new' ? 'Editar Oportunidade' : 'Nova Oportunidade'}</h1>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Detalhes da Oportunidade</CardTitle>
          </CardHeader>
          <CardContent>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                <div className="grid gap-4 md:grid-cols-2">
                  <FormField
                    control={form.control}
                    name="name"
                    render={({ field }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>Nome da Oportunidade *</FormLabel>
                        <FormControl>
                          <Input placeholder="Ex: Licença Corporativa" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="account_id"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Conta *</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione a conta" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {accounts.map((account) => (
                              <SelectItem key={account.id} value={account.id}>
                                {account.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="stage"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Estágio *</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione o estágio" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="prospecting">Prospecção</SelectItem>
                            <SelectItem value="qualification">Qualificação</SelectItem>
                            <SelectItem value="proposal">Proposta</SelectItem>
                            <SelectItem value="negotiation">Negociação</SelectItem>
                            <SelectItem value="closed_won">Ganho</SelectItem>
                            <SelectItem value="closed_lost">Perdido</SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="amount"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Valor (R$)</FormLabel>
                        <FormControl>
                          <Input type="number" placeholder="0" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="probability"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Probabilidade (%)</FormLabel>
                        <FormControl>
                          <Input type="number" min="0" max="100" placeholder="50" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="close_date"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Data Prevista de Fechamento</FormLabel>
                        <FormControl>
                          <Input type="date" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="source"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Origem do Lead</FormLabel>
                        <FormControl>
                          <Input placeholder="Ex: Website, Indicação" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="competitor"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Principal Concorrente</FormLabel>
                        <FormControl>
                          <Input placeholder="Ex: Empresa Concorrente" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="next_step"
                    render={({ field }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>Próximo Passo</FormLabel>
                        <FormControl>
                          <Input placeholder="Ex: Agendar reunião de demonstração" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>Descrição</FormLabel>
                        <FormControl>
                          <Textarea placeholder="Adicione notas sobre esta oportunidade..." rows={4} {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                {/* Custom Fields */}
                {customFieldDefs.length > 0 && (
                  <CustomFieldsRenderer
                    entityType="opportunity"
                    definitions={customFieldDefs}
                    values={customFieldValues}
                    onChange={setCustomFieldValues}
                  />
                )}

                <div className="flex gap-3 pt-4">
                  <Button type="submit" disabled={loading}>
                    {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    {id && id !== 'new' ? 'Atualizar Oportunidade' : 'Criar Oportunidade'}
                  </Button>
                  <Button type="button" variant="outline" onClick={() => navigate('/opportunities')}>
                    Cancelar
                  </Button>
                </div>
              </form>
            </Form>
          </CardContent>
        </Card>
      </div>

  );
}

import { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { 
  ArrowLeft, 
  Package, 
  Truck, 
  CreditCard, 
  User, 
  MapPin,
  Clock,
  CheckCircle,
  XCircle,
  RefreshCw,
  FileText,
  Building
} from '@/components/icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { Timeline } from '@/components/Timeline';
import { ChangeHistory } from '@/components/ChangeHistory';

type OrderStatus = 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled' | 'refunded';

const statusConfig: Record<OrderStatus, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline'; color: string }> = {
  pending: { label: 'Pendente', variant: 'secondary', color: 'text-yellow-600' },
  confirmed: { label: 'Confirmado', variant: 'default', color: 'text-blue-600' },
  processing: { label: 'Processando', variant: 'default', color: 'text-blue-600' },
  shipped: { label: 'Enviado', variant: 'default', color: 'text-purple-600' },
  delivered: { label: 'Entregue', variant: 'default', color: 'text-green-600' },
  cancelled: { label: 'Cancelado', variant: 'destructive', color: 'text-red-600' },
  refunded: { label: 'Reembolsado', variant: 'outline', color: 'text-gray-600' },
};

const statusFlow: OrderStatus[] = ['pending', 'confirmed', 'processing', 'shipped', 'delivered'];

export default function OrderDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [newStatus, setNewStatus] = useState<string>('');

  const { data: order, isLoading } = useQuery({
    queryKey: ['order', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('orders')
        .select(`
          *,
          account:accounts(id, name, email, phone),
          contact:contacts(id, first_name, last_name, email, phone)
        `)
        .eq('id', id)
        .single();

      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: orderItems } = useQuery({
    queryKey: ['order-items', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('order_items')
        .select(`
          *,
          product:products(id, name, sku)
        `)
        .eq('order_id', id);

      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: payments } = useQuery({
    queryKey: ['order-payments', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('payments')
        .select('*')
        .eq('order_id', id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: shipments } = useQuery({
    queryKey: ['order-shipments', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('shipments')
        .select('*')
        .eq('order_id', id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: statusHistory } = useQuery({
    queryKey: ['order-status-history', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('order_status_history')
        .select(`
          *
        `)
        .eq('order_id', id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const updateStatusMutation = useMutation({
    mutationFn: async (status: string) => {
      const { error } = await supabase
        .from('orders')
        .update({ status: status as OrderStatus })
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['order', id] });
      queryClient.invalidateQueries({ queryKey: ['order-status-history', id] });
      toast.success('Status atualizado com sucesso');
      setNewStatus('');
    },
    onError: (error) => {
      toast.error('Erro ao atualizar status: ' + error.message);
    },
  });

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(value);
  };

  const formatAddress = (address: any) => {
    if (!address) return '-';
    return `${address.street || ''}, ${address.number || ''} - ${address.city || ''}, ${address.state || ''} - ${address.zip_code || ''}`;
  };

  if (isLoading) {
    return (
      <>
        <div className="flex items-center justify-center h-64">
          <div className="text-muted-foreground">Carregando...</div>
        </div>
      </>
    );
  }

  if (!order) {
    return (
      <>
        <div className="flex flex-col items-center justify-center h-64 gap-4">
          <div className="text-muted-foreground">Pedido não encontrado</div>
          <Button variant="outline" onClick={() => navigate('/orders')}>
            Voltar para Pedidos
          </Button>
        </div>
      </>
    );
  }

  const currentStatus = order.status as OrderStatus;
  const statusCfg = statusConfig[currentStatus] || statusConfig.pending;

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate('/orders')}>
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-bold">{order.order_number}</h1>
                <Badge variant={statusCfg.variant}>{statusCfg.label}</Badge>
              </div>
              <p className="text-muted-foreground">
                Criado em {format(new Date(order.created_at), "dd 'de' MMMM 'de' yyyy 'às' HH:mm", { locale: ptBR })}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {currentStatus !== 'cancelled' && currentStatus !== 'refunded' && (
              <>
                <Select value={newStatus} onValueChange={setNewStatus}>
                  <SelectTrigger className="w-[180px]">
                    <SelectValue placeholder="Alterar Status" />
                  </SelectTrigger>
                  <SelectContent>
                    {statusFlow.map((status) => (
                      <SelectItem key={status} value={status} disabled={status === currentStatus}>
                        {statusConfig[status].label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {newStatus && (
                  <Button onClick={() => updateStatusMutation.mutate(newStatus)}>
                    Atualizar
                  </Button>
                )}
                <AlertDialog>
                  <AlertDialogTrigger asChild>
                    <Button variant="destructive">
                      <XCircle className="mr-2 h-4 w-4" />
                      Cancelar
                    </Button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>Cancelar Pedido</AlertDialogTitle>
                      <AlertDialogDescription>
                        Tem certeza que deseja cancelar este pedido? Esta ação não pode ser desfeita.
                      </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                      <AlertDialogCancel>Não</AlertDialogCancel>
                      <AlertDialogAction onClick={() => updateStatusMutation.mutate('cancelled')}>
                        Sim, cancelar
                      </AlertDialogAction>
                    </AlertDialogFooter>
                  </AlertDialogContent>
                </AlertDialog>
              </>
            )}
          </div>
        </div>

        {/* Status Progress */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              {statusFlow.map((status, index) => {
                const isCompleted = statusFlow.indexOf(currentStatus) >= index;
                const isCurrent = status === currentStatus;
                return (
                  <div key={status} className="flex items-center flex-1">
                    <div className="flex flex-col items-center">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 ${
                        isCompleted 
                          ? 'bg-primary border-primary text-primary-foreground' 
                          : 'border-muted-foreground/30 text-muted-foreground'
                      } ${isCurrent ? 'ring-2 ring-primary ring-offset-2' : ''}`}>
                        {status === 'pending' && <Clock className="h-5 w-5" />}
                        {status === 'confirmed' && <CheckCircle className="h-5 w-5" />}
                        {status === 'processing' && <Package className="h-5 w-5" />}
                        {status === 'shipped' && <Truck className="h-5 w-5" />}
                        {status === 'delivered' && <CheckCircle className="h-5 w-5" />}
                      </div>
                      <span className={`mt-2 text-xs font-medium ${isCompleted ? '' : 'text-muted-foreground'}`}>
                        {statusConfig[status].label}
                      </span>
                    </div>
                    {index < statusFlow.length - 1 && (
                      <div className={`h-1 flex-1 mx-2 ${
                        statusFlow.indexOf(currentStatus) > index ? 'bg-primary' : 'bg-muted'
                      }`} />
                    )}
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>

        <div className="grid gap-6 md:grid-cols-3">
          {/* Main Content */}
          <div className="md:col-span-2 space-y-6">
            {/* Order Items */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Package className="h-5 w-5" />
                  Itens do Pedido
                </CardTitle>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Produto</TableHead>
                      <TableHead>SKU</TableHead>
                      <TableHead className="text-center">Qtd</TableHead>
                      <TableHead className="text-right">Preço Unit.</TableHead>
                      <TableHead className="text-right">Total</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {orderItems?.map((item) => (
                      <TableRow key={item.id}>
                        <TableCell className="font-medium">
                          {item.product ? (
                            <Link to={`/products/${item.product.id}`} className="text-primary hover:underline">
                              {item.name}
                            </Link>
                          ) : (
                            item.name
                          )}
                        </TableCell>
                        <TableCell className="text-muted-foreground">{item.sku || '-'}</TableCell>
                        <TableCell className="text-center">{item.quantity}</TableCell>
                        <TableCell className="text-right">{formatCurrency(Number(item.unit_price))}</TableCell>
                        <TableCell className="text-right font-medium">{formatCurrency(Number(item.total))}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>

                <Separator className="my-4" />

                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">Subtotal</span>
                    <span>{formatCurrency(Number(order.subtotal))}</span>
                  </div>
                  {Number(order.discount_total) > 0 && (
                    <div className="flex justify-between text-sm text-green-600">
                      <span>Desconto</span>
                      <span>-{formatCurrency(Number(order.discount_total))}</span>
                    </div>
                  )}
                  {Number(order.shipping_total) > 0 && (
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Frete</span>
                      <span>{formatCurrency(Number(order.shipping_total))}</span>
                    </div>
                  )}
                  {Number(order.tax_total) > 0 && (
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Impostos</span>
                      <span>{formatCurrency(Number(order.tax_total))}</span>
                    </div>
                  )}
                  <Separator />
                  <div className="flex justify-between font-bold text-lg">
                    <span>Total</span>
                    <span>{formatCurrency(Number(order.grand_total))}</span>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Tabs for Payments, Shipments, History */}
            <Card>
              <Tabs defaultValue="payments">
                <CardHeader>
                  <TabsList>
                    <TabsTrigger value="payments">Pagamentos</TabsTrigger>
                    <TabsTrigger value="shipments">Envios</TabsTrigger>
                    <TabsTrigger value="history">Histórico</TabsTrigger>
                    <TabsTrigger value="audit">Alterações</TabsTrigger>
                  </TabsList>
                </CardHeader>
                <CardContent>
                  <TabsContent value="payments" className="mt-0">
                    {payments?.length === 0 ? (
                      <p className="text-muted-foreground text-center py-8">Nenhum pagamento registrado</p>
                    ) : (
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead>Método</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead className="text-right">Valor</TableHead>
                            <TableHead>Data</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {payments?.map((payment) => (
                            <TableRow key={payment.id}>
                              <TableCell className="capitalize">{payment.method.replace('_', ' ')}</TableCell>
                              <TableCell>
                                <Badge variant={payment.status === 'captured' ? 'default' : 'secondary'}>
                                  {payment.status}
                                </Badge>
                              </TableCell>
                              <TableCell className="text-right">{formatCurrency(Number(payment.amount))}</TableCell>
                              <TableCell>{format(new Date(payment.created_at), "dd/MM/yyyy HH:mm")}</TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    )}
                  </TabsContent>

                  <TabsContent value="shipments" className="mt-0">
                    {shipments?.length === 0 ? (
                      <p className="text-muted-foreground text-center py-8">Nenhum envio registrado</p>
                    ) : (
                      <div className="space-y-4">
                        {shipments?.map((shipment) => (
                          <div key={shipment.id} className="border rounded-lg p-4">
                            <div className="flex items-center justify-between mb-2">
                              <div className="flex items-center gap-2">
                                <Truck className="h-4 w-4" />
                                <span className="font-medium">{shipment.carrier || 'Transportadora'}</span>
                              </div>
                              <Badge>{shipment.status}</Badge>
                            </div>
                            {shipment.tracking_number && (
                              <p className="text-sm text-muted-foreground">
                                Rastreio: <span className="font-mono">{shipment.tracking_number}</span>
                              </p>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </TabsContent>

                  <TabsContent value="history" className="mt-0">
                    {statusHistory?.length === 0 ? (
                      <p className="text-muted-foreground text-center py-8">Nenhum histórico</p>
                    ) : (
                      <div className="space-y-3">
                        {statusHistory?.map((entry) => (
                          <div key={entry.id} className="flex items-start gap-3 text-sm">
                            <RefreshCw className="h-4 w-4 mt-0.5 text-muted-foreground" />
                            <div>
                              <p>
                                Status alterado de <Badge variant="outline" className="mx-1">{entry.old_status || 'N/A'}</Badge>
                                para <Badge variant="outline" className="mx-1">{entry.new_status}</Badge>
                              </p>
                              <p className="text-muted-foreground">
                                {format(new Date(entry.created_at), "dd/MM/yyyy 'às' HH:mm")}
                              </p>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </TabsContent>

                  <TabsContent value="audit" className="mt-0">
                    <ChangeHistory entityType="order" entityId={id!} />
                  </TabsContent>
                </CardContent>
              </Tabs>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Customer Info */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <User className="h-5 w-5" />
                  Cliente
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {order.account && (
                  <div>
                    <p className="text-sm text-muted-foreground">Empresa</p>
                    <Link to={`/accounts/${order.account.id}`} className="font-medium text-primary hover:underline flex items-center gap-1">
                      <Building className="h-4 w-4" />
                      {order.account.name}
                    </Link>
                    {order.account.email && <p className="text-sm">{order.account.email}</p>}
                    {order.account.phone && <p className="text-sm">{order.account.phone}</p>}
                  </div>
                )}
                {order.contact && (
                  <div>
                    <p className="text-sm text-muted-foreground">Contato</p>
                    <Link to={`/contacts/${order.contact.id}`} className="font-medium text-primary hover:underline">
                      {order.contact.first_name} {order.contact.last_name}
                    </Link>
                    {order.contact.email && <p className="text-sm">{order.contact.email}</p>}
                    {order.contact.phone && <p className="text-sm">{order.contact.phone}</p>}
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Shipping Address */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <MapPin className="h-5 w-5" />
                  Endereço de Entrega
                </CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-sm">{formatAddress(order.shipping_address)}</p>
              </CardContent>
            </Card>

            {/* Payment Info */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <CreditCard className="h-5 w-5" />
                  Pagamento
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-sm text-muted-foreground">Método</span>
                  <span className="text-sm capitalize">{order.payment_method?.replace('_', ' ') || '-'}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-sm text-muted-foreground">Status</span>
                  <Badge variant={order.payment_status === 'captured' ? 'default' : 'secondary'}>
                    {order.payment_status}
                  </Badge>
                </div>
              </CardContent>
            </Card>

            {/* Notes */}
            {(order.customer_notes || order.internal_notes) && (
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <FileText className="h-5 w-5" />
                    Notas
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  {order.customer_notes && (
                    <div>
                      <p className="text-sm text-muted-foreground mb-1">Notas do Cliente</p>
                      <p className="text-sm">{order.customer_notes}</p>
                    </div>
                  )}
                  {order.internal_notes && (
                    <div>
                      <p className="text-sm text-muted-foreground mb-1">Notas Internas</p>
                      <p className="text-sm">{order.internal_notes}</p>
                    </div>
                  )}
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { ArrowLeft, Plus, Trash2, Package, Search } from '@/components/icons';
import { toast } from 'sonner';
import { CustomFieldsRenderer } from '@/components/CustomFieldsRenderer';
import { useCustomFieldDefinitions, useCustomFieldValues, useSaveCustomFieldValues, getFieldValue } from '@/hooks/useCustomFields';

interface OrderItem {
  id: string;
  product_id: string | null;
  name: string;
  sku: string;
  quantity: number;
  unit_price: number;
  discount: number;
  tax: number;
  total: number;
}

export default function OrderForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { profile } = useAuth();
  const isEditing = !!id;

  const [formData, setFormData] = useState({
    account_id: '',
    contact_id: '',
    shipping_method: '',
    shipping_total: 0,
    payment_method: '',
    customer_notes: '',
    internal_notes: '',
    shipping_address: {
      street: '',
      number: '',
      complement: '',
      neighborhood: '',
      city: '',
      state: '',
      zip_code: '',
      country: 'Brasil',
    },
  });

  const [items, setItems] = useState<OrderItem[]>([]);
  const [productSearch, setProductSearch] = useState('');
  const [customFieldValues, setCustomFieldValues] = useState<Record<string, any>>({});

  // Custom Fields
  const { data: customFieldDefs = [] } = useCustomFieldDefinitions('order');
  const { data: existingCustomValues = [] } = useCustomFieldValues('order', isEditing ? id : undefined);
  const saveCustomFields = useSaveCustomFieldValues();

  // Initialize custom field values when editing
  useEffect(() => {
    if (isEditing && customFieldDefs.length > 0 && existingCustomValues.length > 0) {
      const initial: Record<string, any> = {};
      customFieldDefs.forEach((def) => {
        const fieldValue = existingCustomValues.find((v) => v.field_definition_id === def.id);
        initial[def.id] = getFieldValue(def, fieldValue);
      });
      setCustomFieldValues(initial);
    }
  }, [isEditing, customFieldDefs, existingCustomValues]);

  // Fetch accounts
  const { data: accounts } = useQuery({
    queryKey: ['accounts-select'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('accounts')
        .select('id, name')
        .order('name');
      if (error) throw error;
      return data;
    },
  });

  // Fetch contacts based on selected account
  const { data: contacts } = useQuery({
    queryKey: ['contacts-select', formData.account_id],
    queryFn: async () => {
      let query = supabase
        .from('contacts')
        .select('id, first_name, last_name')
        .order('first_name');

      if (formData.account_id) {
        query = query.eq('account_id', formData.account_id);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  // Fetch products
  const { data: products } = useQuery({
    queryKey: ['products-select', productSearch],
    queryFn: async () => {
      let query = supabase
        .from('products')
        .select('id, name, sku, unit_price')
        .eq('is_active', true)
        .order('name')
        .limit(20);

      if (productSearch) {
        query = query.or(`name.ilike.%${productSearch}%,sku.ilike.%${productSearch}%`);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  // Fetch existing order for editing
  const { data: existingOrder } = useQuery({
    queryKey: ['order-edit', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('id', id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: isEditing,
  });

  const { data: existingItems } = useQuery({
    queryKey: ['order-items-edit', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('order_items')
        .select('*')
        .eq('order_id', id);
      if (error) throw error;
      return data;
    },
    enabled: isEditing,
  });

  // Load existing data
  useEffect(() => {
    if (existingOrder) {
      const shippingAddr = existingOrder.shipping_address as any || {};
      setFormData({
        account_id: existingOrder.account_id || '',
        contact_id: existingOrder.contact_id || '',
        shipping_method: existingOrder.shipping_method || '',
        shipping_total: Number(existingOrder.shipping_total) || 0,
        payment_method: existingOrder.payment_method || '',
        customer_notes: existingOrder.customer_notes || '',
        internal_notes: existingOrder.internal_notes || '',
        shipping_address: {
          street: shippingAddr.street || '',
          number: shippingAddr.number || '',
          complement: shippingAddr.complement || '',
          neighborhood: shippingAddr.neighborhood || '',
          city: shippingAddr.city || '',
          state: shippingAddr.state || '',
          zip_code: shippingAddr.zip_code || '',
          country: shippingAddr.country || 'Brasil',
        },
      });
    }
  }, [existingOrder]);

  useEffect(() => {
    if (existingItems) {
      setItems(existingItems.map(item => ({
        id: item.id,
        product_id: item.product_id,
        name: item.name,
        sku: item.sku || '',
        quantity: item.quantity,
        unit_price: Number(item.unit_price),
        discount: Number(item.discount) || 0,
        tax: Number(item.tax) || 0,
        total: Number(item.total),
      })));
    }
  }, [existingItems]);

  const addItem = (product: any) => {
    const newItem: OrderItem = {
      id: crypto.randomUUID(),
      product_id: product.id,
      name: product.name,
      sku: product.sku || '',
      quantity: 1,
      unit_price: Number(product.price) || 0,
      discount: 0,
      tax: 0,
      total: Number(product.price) || 0,
    };
    setItems([...items, newItem]);
    setProductSearch('');
  };

  const updateItem = (id: string, field: keyof OrderItem, value: any) => {
    setItems(items.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        updated.total = (updated.unit_price * updated.quantity) - updated.discount + updated.tax;
        return updated;
      }
      return item;
    }));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const calculateTotals = () => {
    const subtotal = items.reduce((sum, item) => sum + (item.unit_price * item.quantity), 0);
    const discountTotal = items.reduce((sum, item) => sum + item.discount, 0);
    const taxTotal = items.reduce((sum, item) => sum + item.tax, 0);
    const shippingTotal = formData.shipping_total;
    const grandTotal = subtotal - discountTotal + taxTotal + shippingTotal;

    return { subtotal, discountTotal, taxTotal, shippingTotal, grandTotal };
  };

  const createOrderMutation = useMutation({
    mutationFn: async () => {
      if (!profile?.organization_id) throw new Error('Organização não encontrada');
      if (items.length === 0) throw new Error('Adicione pelo menos um item');

      const totals = calculateTotals();

      // Generate order number
      const { data: orderNumber } = await supabase.rpc('generate_order_number', {
        org_id: profile.organization_id,
      });

      // Create order
      const { data: order, error: orderError } = await supabase
        .from('orders')
        .insert({
          organization_id: profile.organization_id,
          order_number: orderNumber || `ORD-${Date.now()}`,
          account_id: formData.account_id || null,
          contact_id: formData.contact_id || null,
          status: 'pending',
          subtotal: totals.subtotal,
          discount_total: totals.discountTotal,
          tax_total: totals.taxTotal,
          shipping_total: totals.shippingTotal,
          grand_total: totals.grandTotal,
          shipping_method: formData.shipping_method || null,
          payment_method: formData.payment_method || null,
          shipping_address: formData.shipping_address,
          customer_notes: formData.customer_notes || null,
          internal_notes: formData.internal_notes || null,
          created_by: profile.id,
          source: 'admin',
        })
        .select()
        .single();

      if (orderError) throw orderError;

      // Create order items
      const orderItems = items.map(item => ({
        order_id: order.id,
        product_id: item.product_id,
        name: item.name,
        sku: item.sku,
        quantity: item.quantity,
        unit_price: item.unit_price,
        discount: item.discount,
        tax: item.tax,
        total: item.total,
      }));

      const { error: itemsError } = await supabase
        .from('order_items')
        .insert(orderItems);

      if (itemsError) throw itemsError;

      return order;
    },
    onSuccess: (order) => {
      // Save custom fields
      if (customFieldDefs.length > 0 && Object.keys(customFieldValues).length > 0) {
        saveCustomFields.mutate({
          entityType: 'order',
          entityId: order.id,
          values: customFieldValues,
          definitions: customFieldDefs,
        });
      }
      queryClient.invalidateQueries({ queryKey: ['orders'] });
      toast.success('Pedido criado com sucesso');
      navigate(`/orders/${order.id}`);
    },
    onError: (error) => {
      toast.error('Erro ao criar pedido: ' + error.message);
    },
  });

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(value);
  };

  const totals = calculateTotals();

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/orders')}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold">
              {isEditing ? 'Editar Pedido' : 'Novo Pedido'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing ? 'Atualize os dados do pedido' : 'Crie um pedido manualmente'}
            </p>
          </div>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Form */}
          <div className="lg:col-span-2 space-y-6">
            {/* Customer */}
            <Card>
              <CardHeader>
                <CardTitle>Cliente</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Conta/Empresa</Label>
                  <Select
                    value={formData.account_id}
                    onValueChange={(value) => setFormData({ ...formData, account_id: value, contact_id: '' })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione uma conta" />
                    </SelectTrigger>
                    <SelectContent>
                      {accounts?.map((account) => (
                        <SelectItem key={account.id} value={account.id}>
                          {account.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Contato</Label>
                  <Select
                    value={formData.contact_id}
                    onValueChange={(value) => setFormData({ ...formData, contact_id: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione um contato" />
                    </SelectTrigger>
                    <SelectContent>
                      {contacts?.map((contact) => (
                        <SelectItem key={contact.id} value={contact.id}>
                          {contact.first_name} {contact.last_name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </CardContent>
            </Card>

            {/* Items */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Package className="h-5 w-5" />
                  Itens do Pedido
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* Product Search */}
                <div className="flex gap-2">
                  <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      placeholder="Buscar produto por nome ou SKU..."
                      value={productSearch}
                      onChange={(e) => setProductSearch(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                </div>

                {/* Product Search Results */}
                {productSearch && products && products.length > 0 && (
                  <div className="border rounded-lg divide-y max-h-48 overflow-y-auto">
                    {products.map((product) => (
                      <div
                        key={product.id}
                        className="p-3 hover:bg-muted cursor-pointer flex items-center justify-between"
                        onClick={() => addItem({ ...product, price: product.unit_price })}
                      >
                        <div>
                          <p className="font-medium">{product.name}</p>
                          <p className="text-sm text-muted-foreground">SKU: {product.sku || 'N/A'}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-medium">{formatCurrency(Number(product.unit_price) || 0)}</p>
                          <Button size="sm" variant="ghost">
                            <Plus className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {/* Items Table */}
                {items.length > 0 ? (
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Produto</TableHead>
                        <TableHead className="w-[80px]">Qtd</TableHead>
                        <TableHead className="w-[120px]">Preço Unit.</TableHead>
                        <TableHead className="w-[100px]">Desconto</TableHead>
                        <TableHead className="text-right">Total</TableHead>
                        <TableHead className="w-[50px]"></TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {items.map((item) => (
                        <TableRow key={item.id}>
                          <TableCell>
                            <div>
                              <p className="font-medium">{item.name}</p>
                              <p className="text-sm text-muted-foreground">{item.sku}</p>
                            </div>
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="1"
                              value={item.quantity}
                              onChange={(e) => updateItem(item.id, 'quantity', parseInt(e.target.value) || 1)}
                              className="w-16"
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0"
                              step="0.01"
                              value={item.unit_price}
                              onChange={(e) => updateItem(item.id, 'unit_price', parseFloat(e.target.value) || 0)}
                              className="w-24"
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0"
                              step="0.01"
                              value={item.discount}
                              onChange={(e) => updateItem(item.id, 'discount', parseFloat(e.target.value) || 0)}
                              className="w-20"
                            />
                          </TableCell>
                          <TableCell className="text-right font-medium">
                            {formatCurrency(item.total)}
                          </TableCell>
                          <TableCell>
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => removeItem(item.id)}
                            >
                              <Trash2 className="h-4 w-4 text-destructive" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    Nenhum item adicionado. Busque e adicione produtos acima.
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Shipping Address */}
            <Card>
              <CardHeader>
                <CardTitle>Endereço de Entrega</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2 md:col-span-2">
                  <Label>Rua</Label>
                  <Input
                    value={formData.shipping_address.street}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, street: e.target.value }
                    })}
                    placeholder="Nome da rua"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Número</Label>
                  <Input
                    value={formData.shipping_address.number}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, number: e.target.value }
                    })}
                    placeholder="Número"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Complemento</Label>
                  <Input
                    value={formData.shipping_address.complement}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, complement: e.target.value }
                    })}
                    placeholder="Apto, Bloco, etc."
                  />
                </div>
                <div className="space-y-2">
                  <Label>Bairro</Label>
                  <Input
                    value={formData.shipping_address.neighborhood}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, neighborhood: e.target.value }
                    })}
                    placeholder="Bairro"
                  />
                </div>
                <div className="space-y-2">
                  <Label>CEP</Label>
                  <Input
                    value={formData.shipping_address.zip_code}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, zip_code: e.target.value }
                    })}
                    placeholder="00000-000"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Cidade</Label>
                  <Input
                    value={formData.shipping_address.city}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, city: e.target.value }
                    })}
                    placeholder="Cidade"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Estado</Label>
                  <Input
                    value={formData.shipping_address.state}
                    onChange={(e) => setFormData({
                      ...formData,
                      shipping_address: { ...formData.shipping_address, state: e.target.value }
                    })}
                    placeholder="UF"
                  />
                </div>
              </CardContent>
            </Card>

            {/* Notes */}
            <Card>
              <CardHeader>
                <CardTitle>Observações</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Notas do Cliente</Label>
                  <Textarea
                    value={formData.customer_notes}
                    onChange={(e) => setFormData({ ...formData, customer_notes: e.target.value })}
                    placeholder="Instruções especiais do cliente..."
                    rows={3}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Notas Internas</Label>
                  <Textarea
                    value={formData.internal_notes}
                    onChange={(e) => setFormData({ ...formData, internal_notes: e.target.value })}
                    placeholder="Notas para a equipe interna..."
                    rows={3}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Custom Fields */}
            {customFieldDefs.length > 0 && (
              <Card>
                <CardContent className="pt-6">
                  <CustomFieldsRenderer
                    entityType="order"
                    definitions={customFieldDefs}
                    values={customFieldValues}
                    onChange={setCustomFieldValues}
                  />
                </CardContent>
              </Card>
            )}
          </div>

          {/* Sidebar - Summary */}
          <div className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Resumo do Pedido</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">Subtotal ({items.length} itens)</span>
                    <span>{formatCurrency(totals.subtotal)}</span>
                  </div>
                  {totals.discountTotal > 0 && (
                    <div className="flex justify-between text-sm text-green-600">
                      <span>Descontos</span>
                      <span>-{formatCurrency(totals.discountTotal)}</span>
                    </div>
                  )}
                  {totals.taxTotal > 0 && (
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Impostos</span>
                      <span>{formatCurrency(totals.taxTotal)}</span>
                    </div>
                  )}
                </div>

                <Separator />

                <div className="space-y-2">
                  <Label>Método de Envio</Label>
                  <Select
                    value={formData.shipping_method}
                    onValueChange={(value) => setFormData({ ...formData, shipping_method: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="standard">Padrão</SelectItem>
                      <SelectItem value="express">Expresso</SelectItem>
                      <SelectItem value="pickup">Retirada</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Valor do Frete</Label>
                  <Input
                    type="number"
                    min="0"
                    step="0.01"
                    value={formData.shipping_total}
                    onChange={(e) => setFormData({ ...formData, shipping_total: parseFloat(e.target.value) || 0 })}
                  />
                </div>

                <div className="space-y-2">
                  <Label>Método de Pagamento</Label>
                  <Select
                    value={formData.payment_method}
                    onValueChange={(value) => setFormData({ ...formData, payment_method: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="credit_card">Cartão de Crédito</SelectItem>
                      <SelectItem value="debit_card">Cartão de Débito</SelectItem>
                      <SelectItem value="pix">PIX</SelectItem>
                      <SelectItem value="boleto">Boleto</SelectItem>
                      <SelectItem value="bank_transfer">Transferência</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <Separator />

                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Frete</span>
                  <span>{formatCurrency(totals.shippingTotal)}</span>
                </div>

                <div className="flex justify-between font-bold text-lg">
                  <span>Total</span>
                  <span>{formatCurrency(totals.grandTotal)}</span>
                </div>

                <Button
                  className="w-full"
                  size="lg"
                  onClick={() => createOrderMutation.mutate()}
                  disabled={createOrderMutation.isPending || items.length === 0}
                >
                  {createOrderMutation.isPending ? 'Criando...' : 'Criar Pedido'}
                </Button>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';

import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { 
  Plus, 
  Search, 
  Package, 
  DollarSign, 
  Truck, 
  CheckCircle,
  Clock,
  XCircle,
  Eye,
  FileText
} from '@/components/icons';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

type OrderStatus = 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled' | 'refunded';
type PaymentStatus = 'pending' | 'authorized' | 'captured' | 'failed' | 'refunded' | 'partially_refunded';

const statusConfig: Record<OrderStatus, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline'; icon: React.ReactNode }> = {
  pending: { label: 'Pendente', variant: 'secondary', icon: <Clock className="h-3 w-3" /> },
  confirmed: { label: 'Confirmado', variant: 'default', icon: <CheckCircle className="h-3 w-3" /> },
  processing: { label: 'Processando', variant: 'default', icon: <Package className="h-3 w-3" /> },
  shipped: { label: 'Enviado', variant: 'default', icon: <Truck className="h-3 w-3" /> },
  delivered: { label: 'Entregue', variant: 'default', icon: <CheckCircle className="h-3 w-3" /> },
  cancelled: { label: 'Cancelado', variant: 'destructive', icon: <XCircle className="h-3 w-3" /> },
  refunded: { label: 'Reembolsado', variant: 'outline', icon: <DollarSign className="h-3 w-3" /> },
};

const paymentStatusConfig: Record<PaymentStatus, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  pending: { label: 'Pendente', variant: 'secondary' },
  authorized: { label: 'Autorizado', variant: 'default' },
  captured: { label: 'Capturado', variant: 'default' },
  failed: { label: 'Falhou', variant: 'destructive' },
  refunded: { label: 'Reembolsado', variant: 'outline' },
  partially_refunded: { label: 'Parcial', variant: 'outline' },
};

export default function Orders() {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [paymentFilter, setPaymentFilter] = useState<string>('all');

  const { data: orders, isLoading } = useQuery({
    queryKey: ['orders', search, statusFilter, paymentFilter],
    queryFn: async () => {
      let query = supabase
        .from('orders')
        .select(`
          *,
          account:accounts(id, name),
          contact:contacts(id, first_name, last_name)
        `)
        .order('created_at', { ascending: false });

      if (search) {
        query = query.or(`order_number.ilike.%${search}%`);
      }
      if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter as any);
      }
      if (paymentFilter !== 'all') {
        query = query.eq('payment_status', paymentFilter as any);
      }

      const { data, error } = await query.limit(100);
      if (error) throw error;
      return data;
    },
  });

  const { data: stats } = useQuery({
    queryKey: ['order-stats'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('orders')
        .select('status, grand_total, payment_status');

      if (error) throw error;

      const pending = data?.filter(o => o.status === 'pending').length || 0;
      const processing = data?.filter(o => ['confirmed', 'processing'].includes(o.status as string)).length || 0;
      const shipped = data?.filter(o => o.status === 'shipped').length || 0;
      const totalRevenue = data?.filter(o => o.payment_status === 'captured')
        .reduce((sum, o) => sum + (Number(o.grand_total) || 0), 0) || 0;

      return { pending, processing, shipped, totalRevenue };
    },
  });

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(value);
  };

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="commerce"
          title="Pedidos"
          subtitle="Gerencie todos os pedidos do e-commerce"
          compact
          actions={
            <Button asChild className="gap-2 bg-white text-foreground hover:bg-white/90">
              <Link to="/orders/new">
                <Plus className="h-4 w-4" /> Novo Pedido
              </Link>
            </Button>
          }
        />

        {/* Stats Cards */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Pendentes</CardTitle>
              <Clock className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.pending || 0}</div>
              <p className="text-xs text-muted-foreground">Aguardando processamento</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Em Processamento</CardTitle>
              <Package className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.processing || 0}</div>
              <p className="text-xs text-muted-foreground">Sendo preparados</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Enviados</CardTitle>
              <Truck className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats?.shipped || 0}</div>
              <p className="text-xs text-muted-foreground">Em trânsito</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Receita Total</CardTitle>
              <DollarSign className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{formatCurrency(stats?.totalRevenue || 0)}</div>
              <p className="text-xs text-muted-foreground">Pagamentos capturados</p>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap gap-4">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Buscar por número do pedido..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-10"
            />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Status do Pedido" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os Status</SelectItem>
              {Object.entries(statusConfig).map(([key, config]) => (
                <SelectItem key={key} value={key}>{config.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select value={paymentFilter} onValueChange={setPaymentFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Status Pagamento" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos</SelectItem>
              {Object.entries(paymentStatusConfig).map(([key, config]) => (
                <SelectItem key={key} value={key}>{config.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Orders Table */}
        <Card>
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Pedido</TableHead>
                  <TableHead>Cliente</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Pagamento</TableHead>
                  <TableHead className="text-right">Total</TableHead>
                  <TableHead>Data</TableHead>
                  <TableHead className="w-[100px]">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-8">
                      Carregando...
                    </TableCell>
                  </TableRow>
                ) : orders?.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-8">
                      Nenhum pedido encontrado
                    </TableCell>
                  </TableRow>
                ) : (
                  orders?.map((order) => {
                    const status = order.status as OrderStatus;
                    const paymentStatus = order.payment_status as PaymentStatus;
                    const statusCfg = statusConfig[status] || statusConfig.pending;
                    const paymentCfg = paymentStatusConfig[paymentStatus] || paymentStatusConfig.pending;

                    return (
                      <TableRow key={order.id}>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <FileText className="h-4 w-4 text-muted-foreground" />
                            <span className="font-medium">{order.order_number}</span>
                          </div>
                        </TableCell>
                        <TableCell>
                          {order.account ? (
                            <Link 
                              to={`/accounts/${order.account.id}`}
                              className="text-primary hover:underline"
                            >
                              {order.account.name}
                            </Link>
                          ) : order.contact ? (
                            <Link 
                              to={`/contacts/${order.contact.id}`}
                              className="text-primary hover:underline"
                            >
                              {order.contact.first_name} {order.contact.last_name}
                            </Link>
                          ) : (
                            <span className="text-muted-foreground">-</span>
                          )}
                        </TableCell>
                        <TableCell>
                          <Badge variant={statusCfg.variant} className="gap-1">
                            {statusCfg.icon}
                            {statusCfg.label}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <Badge variant={paymentCfg.variant}>
                            {paymentCfg.label}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-right font-medium">
                          {formatCurrency(Number(order.grand_total) || 0)}
                        </TableCell>
                        <TableCell>
                          {format(new Date(order.created_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                        </TableCell>
                        <TableCell>
                          <Button variant="ghost" size="sm" asChild>
                            <Link to={`/orders/${order.id}`}>
                              <Eye className="h-4 w-4" />
                            </Link>
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })
                )}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Edit,
  Trash2,
  Package,
  DollarSign,
  Tag,
  Calendar,
  RefreshCw,
  CheckCircle,
  XCircle,
  FileText,
  TrendingUp,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';

interface Product {
  id: string;
  name: string;
  sku: string | null;
  description: string | null;
  category: string | null;
  unit_price: number;
  cost: number | null;
  is_active: boolean;
  created_at: string;
  updated_at: string;
}

interface QuoteUsage {
  quote_id: string;
  quote_name: string;
  quantity: number;
  total: number;
}

export default function ProductDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const { toast } = useToast();
  const [product, setProduct] = useState<Product | null>(null);
  const [loading, setLoading] = useState(true);
  const [quoteUsage, setQuoteUsage] = useState<QuoteUsage[]>([]);
  const [stats, setStats] = useState({
    totalQuotes: 0,
    totalQuantity: 0,
    totalRevenue: 0,
  });


  useEffect(() => {
    if (id && user) {
      fetchProduct();
      fetchQuoteUsage();
    }
  }, [id, user]);

  const fetchProduct = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('products')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      console.error('Error fetching product:', error);
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar detalhes do produto',
      });
      navigate('/products');
    } else {
      setProduct(data);
    }
    setLoading(false);
  };

  const fetchQuoteUsage = async () => {
    const { data, error } = await supabase
      .from('quote_items')
      .select(`
        quote_id,
        quantity,
        total,
        quotes!inner(name)
      `)
      .eq('product_id', id);

    if (!error && data) {
      const usage = data.map((item: any) => ({
        quote_id: item.quote_id,
        quote_name: item.quotes.name,
        quantity: item.quantity,
        total: item.total,
      }));
      setQuoteUsage(usage);

      // Calculate stats
      setStats({
        totalQuotes: new Set(usage.map(u => u.quote_id)).size,
        totalQuantity: usage.reduce((sum, u) => sum + u.quantity, 0),
        totalRevenue: usage.reduce((sum, u) => sum + u.total, 0),
      });
    }
  };

  const deleteProduct = async () => {
    if (!id) return;

    const { error } = await supabase.from('products').delete().eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao excluir produto. Ele pode estar sendo usado em propostas.',
      });
    } else {
      toast({
        title: 'Produto excluído',
        description: 'O produto foi excluído com sucesso.',
      });
      navigate('/products');
    }
  };

  const toggleStatus = async () => {
    if (!product) return;

    const { error } = await supabase
      .from('products')
      .update({ is_active: !product.is_active })
      .eq('id', id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao atualizar status do produto',
      });
    } else {
      toast({
        title: 'Produto atualizado',
        description: `Produto ${!product.is_active ? 'ativado' : 'desativado'} com sucesso.`,
      });
      fetchProduct();
    }
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(value);
  };

  if (authLoading || loading) {
    return (
        <div className="flex items-center justify-center h-64">
          <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
    );
  }

  if (!product) {
    return (
        <div className="flex flex-col items-center justify-center h-64 gap-4">
          <Package className="h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">Produto não encontrado</p>
          <Button onClick={() => navigate('/products')}>Voltar para Produtos</Button>
        </div>
    );
  }

  const margin = product.cost 
    ? ((product.unit_price - product.cost) / product.unit_price * 100).toFixed(1)
    : null;

  return (

      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
          <div className="flex items-start gap-4">
            <Button
              variant="ghost"
              size="icon"
              className="shrink-0"
              onClick={() => navigate('/products')}
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-bold tracking-tight">
                  {product.name}
                </h1>
                <Badge 
                  variant="outline" 
                  className={product.is_active 
                    ? 'bg-success/10 text-success border-success/20' 
                    : 'bg-muted text-muted-foreground'
                  }
                >
                  {product.is_active ? 'Ativo' : 'Inativo'}
                </Badge>
              </div>
              {product.sku && (
                <p className="text-muted-foreground font-mono">
                  SKU: {product.sku}
                </p>
              )}
            </div>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={toggleStatus}>
              {product.is_active ? (
                <>
                  <XCircle className="mr-2 h-4 w-4" />
                  Desativar
                </>
              ) : (
                <>
                  <CheckCircle className="mr-2 h-4 w-4" />
                  Ativar
                </>
              )}
            </Button>
            <Button variant="outline" onClick={() => navigate(`/products/${id}/edit`)}>
              <Edit className="mr-2 h-4 w-4" />
              Editar
            </Button>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="destructive">
                  <Trash2 className="mr-2 h-4 w-4" />
                  Excluir
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Excluir Produto</AlertDialogTitle>
                  <AlertDialogDescription>
                    Tem certeza que deseja excluir este produto? Esta ação não pode ser desfeita.
                    Produtos utilizados em propostas não podem ser excluídos.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                  <AlertDialogAction onClick={deleteProduct}>Excluir</AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </div>

        {/* Content Grid */}
        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-6">
            {/* Product Information */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Package className="h-5 w-5" />
                  Informações do Produto
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                {product.description && (
                  <div>
                    <h4 className="text-sm font-medium text-muted-foreground mb-2">
                      Descrição
                    </h4>
                    <p className="text-sm whitespace-pre-wrap">{product.description}</p>
                  </div>
                )}

                <Separator />

                <div className="grid gap-4 sm:grid-cols-2">
                  <div className="flex items-center gap-3">
                    <Tag className="h-4 w-4 text-muted-foreground" />
                    <div>
                      <p className="text-sm text-muted-foreground">Categoria</p>
                      <p className="font-medium">{product.category || 'Sem categoria'}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <div>
                      <p className="text-sm text-muted-foreground">Criado em</p>
                      <p className="font-medium">
                        {new Date(product.created_at).toLocaleDateString('pt-BR')}
                      </p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Quote Usage */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <FileText className="h-5 w-5" />
                  Uso em Propostas
                </CardTitle>
                <CardDescription>
                  Propostas que contêm este produto
                </CardDescription>
              </CardHeader>
              <CardContent>
                {quoteUsage.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-24 text-muted-foreground">
                    <FileText className="h-8 w-8 mb-2" />
                    <p>Ainda não utilizado em nenhuma proposta</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {quoteUsage.slice(0, 5).map((usage) => (
                      <div
                        key={`${usage.quote_id}`}
                        className="flex items-center justify-between p-3 rounded-lg border hover:bg-muted/50 cursor-pointer"
                        onClick={() => navigate(`/quotes/${usage.quote_id}`)}
                      >
                        <div>
                          <p className="font-medium">{usage.quote_name}</p>
                          <p className="text-sm text-muted-foreground">
                            Qtd: {usage.quantity}
                          </p>
                        </div>
                        <p className="font-medium">{formatCurrency(usage.total)}</p>
                      </div>
                    ))}
                    {quoteUsage.length > 5 && (
                      <p className="text-sm text-muted-foreground text-center">
                        E mais {quoteUsage.length - 5} propostas...
                      </p>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Pricing Card */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <DollarSign className="h-5 w-5" />
                  Precificação
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Preço Unitário</span>
                  <span className="text-2xl font-bold">
                    {formatCurrency(product.unit_price)}
                  </span>
                </div>
                <Separator />
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Custo</span>
                  <span className="font-medium">
                    {product.cost ? formatCurrency(product.cost) : '-'}
                  </span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Margem</span>
                  {margin ? (
                    <span className={`font-medium ${Number(margin) >= 0 ? 'text-success' : 'text-destructive'}`}>
                      {margin}%
                    </span>
                  ) : (
                    <span className="text-muted-foreground">-</span>
                  )}
                </div>
              </CardContent>
            </Card>

            {/* Usage Stats */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <TrendingUp className="h-5 w-5" />
                  Estatísticas de Uso
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Total de Propostas</span>
                  <span className="font-bold">{stats.totalQuotes}</span>
                </div>
                <Separator />
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Quantidade Total</span>
                  <span className="font-bold">{stats.totalQuantity}</span>
                </div>
                <Separator />
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Receita Total</span>
                  <span className="font-bold text-success">
                    {formatCurrency(stats.totalRevenue)}
                  </span>
                </div>
              </CardContent>
            </Card>

            {/* Quick Info */}
            <Card>
              <CardHeader>
                <CardTitle>Informações Rápidas</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Última Atualização</span>
                  <span>{new Date(product.updated_at).toLocaleDateString('pt-BR')}</span>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ArrowLeft, Save, Loader2, Package } from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';

import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

const productSchema = z.object({
  name: z.string().min(1, 'O nome do produto é obrigatório').max(255, 'O nome deve ter no máximo 255 caracteres'),
  sku: z.string().max(100, 'O SKU deve ter no máximo 100 caracteres').optional().or(z.literal('')),
  description: z.string().max(2000, 'A descrição deve ter no máximo 2000 caracteres').optional().or(z.literal('')),
  category: z.string().max(100, 'A categoria deve ter no máximo 100 caracteres').optional().or(z.literal('')),
  unit_price: z.coerce.number().min(0, 'O preço deve ser positivo'),
  cost: z.coerce.number().min(0, 'O custo deve ser positivo').optional().or(z.literal('')),
  is_active: z.boolean().default(true),
});

type ProductFormData = z.infer<typeof productSchema>;

const PRESET_CATEGORIES = [
  'Software',
  'Hardware',
  'Serviços',
  'Consultoria',
  'Suporte',
  'Treinamento',
  'Licença',
  'Assinatura',
  'Implementação',
  'Outros',
];

export default function ProductForm() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, profile, loading: authLoading } = useAuth();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [fetchingProduct, setFetchingProduct] = useState(!!id);
  const [existingCategories, setExistingCategories] = useState<string[]>([]);
  const [customCategory, setCustomCategory] = useState(false);

  const isEditing = !!id;

  const form = useForm<ProductFormData>({
    resolver: zodResolver(productSchema),
    defaultValues: {
      name: '',
      sku: '',
      description: '',
      category: '',
      unit_price: 0,
      cost: undefined,
      is_active: true,
    },
  });


  useEffect(() => {
    fetchCategories();
  }, []);

  useEffect(() => {
    if (id && user) {
      fetchProduct();
    }
  }, [id, user]);

  const fetchCategories = async () => {
    const { data } = await supabase
      .from('products')
      .select('category')
      .not('category', 'is', null);

    if (data) {
      const uniqueCategories = [...new Set(data.map(p => p.category).filter(Boolean) as string[])];
      setExistingCategories(uniqueCategories);
    }
  };

  const fetchProduct = async () => {
    setFetchingProduct(true);
    const { data, error } = await supabase
      .from('products')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      console.error('Error fetching product:', error);
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao carregar produto',
      });
      navigate('/products');
    } else if (data) {
      form.reset({
        name: data.name,
        sku: data.sku || '',
        description: data.description || '',
        category: data.category || '',
        unit_price: data.unit_price,
        cost: data.cost || undefined,
        is_active: data.is_active,
      });

      // Check if category is custom
      const allCategories = [...PRESET_CATEGORIES, ...existingCategories];
      if (data.category && !allCategories.includes(data.category)) {
        setCustomCategory(true);
      }
    }
    setFetchingProduct(false);
  };

  const onSubmit = async (data: ProductFormData) => {
    if (!profile?.organization_id) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Você precisa fazer parte de uma organização para gerenciar produtos.',
      });
      return;
    }

    setLoading(true);

    const productData = {
      name: data.name,
      sku: data.sku || null,
      description: data.description || null,
      category: data.category || null,
      unit_price: data.unit_price,
      cost: data.cost ? Number(data.cost) : null,
      is_active: data.is_active,
      organization_id: profile.organization_id,
    };

    try {
      if (isEditing) {
        const { error } = await supabase
          .from('products')
          .update(productData)
          .eq('id', id);

        if (error) throw error;

        toast({
          title: 'Produto atualizado',
          description: 'O produto foi atualizado com sucesso.',
        });
      } else {
        const { error } = await supabase.from('products').insert([productData]);

        if (error) throw error;

        toast({
          title: 'Produto criado',
          description: 'O produto foi criado com sucesso.',
        });
      }

      navigate('/products');
    } catch (error: any) {
      console.error('Error saving product:', error);
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: error.message || 'Falha ao salvar produto',
      });
    } finally {
      setLoading(false);
    }
  };

  // Calculate margin
  const watchedPrice = form.watch('unit_price');
  const watchedCost = form.watch('cost');
  const margin = watchedPrice && watchedCost 
    ? ((watchedPrice - Number(watchedCost)) / watchedPrice * 100).toFixed(1)
    : null;

  const allCategories = [...new Set([...PRESET_CATEGORIES, ...existingCategories])];

  if (authLoading || fetchingProduct) {
    return (
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
    );
  }

  return (

      <div className="space-y-6 max-w-3xl">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => navigate('/products')}
          >
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">
              {isEditing ? 'Editar Produto' : 'Novo Produto'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing ? 'Atualizar informações do produto' : 'Adicionar um novo produto ao catálogo'}
            </p>
          </div>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            {/* Basic Information */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Package className="h-5 w-5" />
                  Informações Básicas
                </CardTitle>
                <CardDescription>
                  Nome do produto, SKU e descrição
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 md:grid-cols-2">
                  <FormField
                    control={form.control}
                    name="name"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Nome do Produto *</FormLabel>
                        <FormControl>
                          <Input placeholder="Licença de Software Empresarial" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="sku"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>SKU</FormLabel>
                        <FormControl>
                          <Input placeholder="PROD-001" className="font-mono" {...field} />
                        </FormControl>
                        <FormDescription>Código de identificação do produto</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Descrição</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Descrição detalhada do produto..."
                          className="min-h-[100px] resize-y"
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="category"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Categoria</FormLabel>
                      {customCategory ? (
                        <div className="flex gap-2">
                          <FormControl>
                            <Input placeholder="Categoria personalizada" {...field} />
                          </FormControl>
                          <Button 
                            type="button" 
                            variant="outline"
                            onClick={() => {
                              setCustomCategory(false);
                              field.onChange('');
                            }}
                          >
                            Selecionar
                          </Button>
                        </div>
                      ) : (
                        <div className="flex gap-2">
                          <Select
                            value={field.value}
                            onValueChange={field.onChange}
                          >
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Selecione uma categoria" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {allCategories.map((cat) => (
                                <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <Button 
                            type="button" 
                            variant="outline"
                            onClick={() => setCustomCategory(true)}
                          >
                            Personalizada
                          </Button>
                        </div>
                      )}
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* Pricing */}
            <Card>
              <CardHeader>
                <CardTitle>Precificação</CardTitle>
                <CardDescription>
                  Defina o preço e o custo do produto
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 md:grid-cols-3">
                  <FormField
                    control={form.control}
                    name="unit_price"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Preço Unitário *</FormLabel>
                        <FormControl>
                          <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                              R$
                            </span>
                            <Input 
                              type="number" 
                              step="0.01"
                              min="0"
                              className="pl-9"
                              {...field} 
                            />
                          </div>
                        </FormControl>
                        <FormDescription>Preço de venda para clientes</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="cost"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Custo</FormLabel>
                        <FormControl>
                          <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                              R$
                            </span>
                            <Input 
                              type="number" 
                              step="0.01"
                              min="0"
                              className="pl-9"
                              {...field} 
                              value={field.value || ''}
                            />
                          </div>
                        </FormControl>
                        <FormDescription>Seu custo (opcional)</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <div>
                    <FormLabel>Margem</FormLabel>
                    <div className="h-10 flex items-center">
                      {margin ? (
                        <span className={`text-lg font-semibold ${Number(margin) >= 0 ? 'text-success' : 'text-destructive'}`}>
                          {margin}%
                        </span>
                      ) : (
                        <span className="text-muted-foreground">-</span>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground">Calculado automaticamente</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Status */}
            <Card>
              <CardHeader>
                <CardTitle>Status</CardTitle>
                <CardDescription>
                  Controle a disponibilidade do produto
                </CardDescription>
              </CardHeader>
              <CardContent>
                <FormField
                  control={form.control}
                  name="is_active"
                  render={({ field }) => (
                    <FormItem className="flex items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <FormLabel className="text-base">Ativo</FormLabel>
                        <FormDescription>
                          Produtos ativos podem ser adicionados a propostas e pedidos
                        </FormDescription>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* Actions */}
            <div className="flex justify-end gap-4">
              <Button
                type="button"
                variant="outline"
                onClick={() => navigate('/products')}
              >
                Cancelar
              </Button>
              <Button type="submit" disabled={loading}>
                {loading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Salvando...
                  </>
                ) : (
                  <>
                    <Save className="mr-2 h-4 w-4" />
                    {isEditing ? 'Atualizar Produto' : 'Criar Produto'}
                  </>
                )}
              </Button>
            </div>
          </form>
        </Form>
      </div>

  );
}

import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
