export default function SegmentForm() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const [form, setForm] = useState<SegmentForm>(initialForm);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [estimatedCount, setEstimatedCount] = useState<number | null>(null);
  const isEditing = Boolean(id);

  useEffect(() => {
    if (id) {
      fetchSegment();
    }
  }, [id]);

  const fetchSegment = async () => {
    if (!id) return;

    setLoading(true);
    const { data, error } = await supabase
      .from('segments')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Segmento não encontrado',
      });
      navigate('/marketing');
      return;
    }

    setForm({
      name: data.name || '',
      description: data.description || '',
      type: data.type as 'static' | 'dynamic',
      entity_type: data.entity_type as 'contact' | 'lead' | 'account',
      filters: (data.filters as unknown as SegmentFilter[]) || [],
      filter_logic: data.filter_logic || 'and',
      auto_refresh: data.auto_refresh ?? true,
      refresh_interval_hours: data.refresh_interval_hours || 24,
      color: data.color || '#3B82F6',
    });
    setEstimatedCount(data.member_count);
    setLoading(false);
  };

  const addFilter = () => {
    const newFilter: SegmentFilter = {
      id: `filter_${Date.now()}`,
      field: '',
      operator: 'equals',
      value: '',
      logic: 'and',
    };
    setForm({ ...form, filters: [...form.filters, newFilter] });
  };

  const removeFilter = (filterId: string) => {
    setForm({
      ...form,
      filters: form.filters.filter(f => f.id !== filterId),
    });
  };

  const updateFilter = (filterId: string, updates: Partial<SegmentFilter>) => {
    setForm({
      ...form,
      filters: form.filters.map(f => f.id === filterId ? { ...f, ...updates } : f),
    });
  };

  const estimateCount = async () => {
    if (!profile?.organization_id) return;

    let count = 0;
    if (form.entity_type === 'contact') {
      const { count: c } = await supabase.from('contacts').select('*', { count: 'exact', head: true }).eq('organization_id', profile.organization_id);
      count = c || 0;
    } else if (form.entity_type === 'lead') {
      const { count: c } = await supabase.from('leads').select('*', { count: 'exact', head: true }).eq('organization_id', profile.organization_id);
      count = c || 0;
    } else {
      const { count: c } = await supabase.from('accounts').select('*', { count: 'exact', head: true }).eq('organization_id', profile.organization_id);
      count = c || 0;
    }

    if (count !== null) {
      // Apply rough filter estimation (simplified)
      const filterMultiplier = Math.max(0.1, 1 - (form.filters.length * 0.15));
      setEstimatedCount(Math.round(count * filterMultiplier));
    }
  };

  const handleSave = async () => {
    if (!profile?.organization_id || !form.name) return;

    setSaving(true);

    const segmentData = {
      name: form.name,
      description: form.description || null,
      type: form.type,
      entity_type: form.entity_type,
      filters: form.filters as any,
      filter_logic: form.filter_logic,
      auto_refresh: form.auto_refresh,
      refresh_interval_hours: form.refresh_interval_hours,
      color: form.color || null,
      organization_id: profile.organization_id,
      created_by: profile.id,
      member_count: estimatedCount || 0,
      last_calculated_at: new Date().toISOString(),
    };

    let error;
    if (id) {
      const result = await supabase
        .from('segments')
        .update(segmentData)
        .eq('id', id);
      error = result.error;
    } else {
      const result = await supabase
        .from('segments')
        .insert([segmentData])
        .select()
        .single();
      error = result.error;
      if (!error && result.data) {
        navigate(`/marketing/segments/${result.data.id}`);
      }
    }

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao salvar segmento',
      });
    } else {
      toast({
        title: 'Segmento salvo',
        description: `"${form.name}" foi salvo com sucesso.`,
      });
      if (!id) navigate('/marketing');
    }

    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/marketing')}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold">
              {isEditing ? 'Editar Segmento' : 'Novo Segmento'}
            </h1>
            <p className="text-muted-foreground">
              Crie grupos de contatos baseados em critérios
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={estimateCount}>
            <RefreshCw className="mr-2 h-4 w-4" />
            Estimar
          </Button>
          <Button onClick={handleSave} disabled={saving || !form.name}>
            {saving ? <RefreshCw className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
            Salvar
          </Button>
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-3">
        <div className="md:col-span-2 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Informações Básicas</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Nome do Segmento *</Label>
                  <Input
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    placeholder="Ex: Leads Qualificados SP"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Tipo</Label>
                  <Select
                    value={form.type}
                    onValueChange={(v) => setForm({ ...form, type: v as 'static' | 'dynamic' })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="dynamic">
                        <div className="flex items-center gap-2">
                          <RefreshCw className="h-4 w-4" />
                          <span>Dinâmico</span>
                        </div>
                      </SelectItem>
                      <SelectItem value="static">
                        <div className="flex items-center gap-2">
                          <Database className="h-4 w-4" />
                          <span>Estático</span>
                        </div>
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  placeholder="Descreva o objetivo deste segmento..."
                  rows={2}
                />
              </div>
              <div className="space-y-2">
                <Label>Entidade Base</Label>
                <Select
                  value={form.entity_type}
                  onValueChange={(v) => setForm({ ...form, entity_type: v as 'contact' | 'lead' | 'account', filters: [] })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="contact">Contatos</SelectItem>
                    <SelectItem value="lead">Leads</SelectItem>
                    <SelectItem value="account">Contas</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {form.type === 'dynamic' && (
            <Card>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <div>
                    <CardTitle>Filtros</CardTitle>
                    <CardDescription>
                      Defina os critérios para incluir registros neste segmento
                    </CardDescription>
                  </div>
                  <Button onClick={addFilter} size="sm">
                    <Plus className="mr-2 h-4 w-4" />
                    Adicionar Filtro
                  </Button>
                </div>
              </CardHeader>
              <CardContent>
                {form.filters.length === 0 ? (
                  <div className="text-center py-8 border border-dashed rounded-lg">
                    <Filter className="h-8 w-8 mx-auto mb-2 text-muted-foreground opacity-50" />
                    <p className="text-muted-foreground mb-4">Nenhum filtro configurado</p>
                    <p className="text-sm text-muted-foreground mb-4">
                      Sem filtros, todos os {form.entity_type === 'contact' ? 'contatos' : form.entity_type === 'lead' ? 'leads' : 'contas'} serão incluídos
                    </p>
                    <Button variant="outline" onClick={addFilter}>
                      <Plus className="mr-2 h-4 w-4" />
                      Adicionar Primeiro Filtro
                    </Button>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {form.filters.map((filter, index) => (
                      <div key={filter.id} className="flex items-center gap-3">
                        {index > 0 && (
                          <Select
                            value={filter.logic}
                            onValueChange={(v) => updateFilter(filter.id, { logic: v as 'and' | 'or' })}
                          >
                            <SelectTrigger className="w-[80px]">
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="and">E</SelectItem>
                              <SelectItem value="or">OU</SelectItem>
                            </SelectContent>
                          </Select>
                        )}
                        <Select
                          value={filter.field}
                          onValueChange={(v) => updateFilter(filter.id, { field: v })}
                        >
                          <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder="Campo" />
                          </SelectTrigger>
                          <SelectContent>
                            {fieldOptions[form.entity_type].map((field) => (
                              <SelectItem key={field.value} value={field.value}>
                                {field.label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Select
                          value={filter.operator}
                          onValueChange={(v) => updateFilter(filter.id, { operator: v })}
                        >
                          <SelectTrigger className="w-[150px]">
                            <SelectValue placeholder="Operador" />
                          </SelectTrigger>
                          <SelectContent>
                            {operatorOptions.map((op) => (
                              <SelectItem key={op.value} value={op.value}>
                                {op.label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        {!['is_empty', 'is_not_empty'].includes(filter.operator) && (
                          <Input
                            value={filter.value}
                            onChange={(e) => updateFilter(filter.id, { value: e.target.value })}
                            placeholder="Valor"
                            className="flex-1"
                          />
                        )}
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeFilter(filter.id)}
                        >
                          <Trash2 className="h-4 w-4 text-muted-foreground" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          )}

          {form.type === 'dynamic' && (
            <Card>
              <CardHeader>
                <CardTitle>Atualização Automática</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <Label>Atualizar automaticamente</Label>
                    <p className="text-sm text-muted-foreground">
                      Recalcular membros periodicamente
                    </p>
                  </div>
                  <Switch
                    checked={form.auto_refresh}
                    onCheckedChange={(checked) => setForm({ ...form, auto_refresh: checked })}
                  />
                </div>
                {form.auto_refresh && (
                  <div className="space-y-2">
                    <Label>Intervalo (horas)</Label>
                    <Input
                      type="number"
                      value={form.refresh_interval_hours}
                      onChange={(e) => setForm({ ...form, refresh_interval_hours: parseInt(e.target.value) || 24 })}
                      min={1}
                      max={168}
                    />
                  </div>
                )}
              </CardContent>
            </Card>
          )}
        </div>

        <div className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Estimativa</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-center py-4">
                <Users className="h-12 w-12 mx-auto mb-2 text-primary opacity-50" />
                <p className="text-4xl font-bold">
                  {estimatedCount !== null ? estimatedCount.toLocaleString() : '—'}
                </p>
                <p className="text-muted-foreground">
                  {form.entity_type === 'contact' ? 'contatos' : form.entity_type === 'lead' ? 'leads' : 'contas'}
                </p>
              </div>
              <Button variant="outline" className="w-full" onClick={estimateCount}>
                <RefreshCw className="mr-2 h-4 w-4" />
                Recalcular
              </Button>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Personalização</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Cor</Label>
                <div className="flex items-center gap-2">
                  <Input
                    type="color"
                    value={form.color}
                    onChange={(e) => setForm({ ...form, color: e.target.value })}
                    className="w-12 h-10 p-1"
                  />
                  <Input
                    value={form.color}
                    onChange={(e) => setForm({ ...form, color: e.target.value })}
                    placeholder="#3B82F6"
                    className="flex-1"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Tipo de Segmento</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Badge variant={form.type === 'dynamic' ? 'default' : 'secondary'}>
                  {form.type === 'dynamic' ? 'Dinâmico' : 'Estático'}
                </Badge>
                <p className="text-sm text-muted-foreground">
                  {form.type === 'dynamic'
                    ? 'Membros são calculados automaticamente com base nos filtros definidos.'
                    : 'Membros são adicionados manualmente e não mudam automaticamente.'}
                </p>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  Headphones, 
  Ticket, 
  Clock, 
  CheckCircle2, 
  AlertTriangle,
  TrendingUp,
  TrendingDown,
  Users,
  Star,
  MessageSquare,
  RefreshCcw,
  ArrowRight,
  ThumbsUp,
  XCircle,
  Timer,
  BarChart3,
  Target
} from '@/components/icons';
import { formatDistanceToNow, format, subDays, startOfDay, endOfDay } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  LineChart,
  Line,
  Legend,
  Area,
  AreaChart,
} from 'recharts';
import { TicketStatusBadge } from '@/components/service/TicketStatusBadge';
import { TicketPriorityBadge } from '@/components/service/TicketPriorityBadge';

type TicketStatus = 'new' | 'open' | 'pending' | 'on_hold' | 'resolved' | 'closed';

const COLORS = ['#3b82f6', '#f97316', '#eab308', '#6b7280', '#22c55e', '#64748b'];

const statusLabels: Record<TicketStatus, string> = {
  new: 'Novo',
  open: 'Aberto',
  pending: 'Pendente',
  on_hold: 'Em Espera',
  resolved: 'Resolvido',
  closed: 'Fechado',
};

export default function ServiceDashboard() {
  const navigate = useNavigate();
  const { profile } = useAuth();
  const [dateRange, setDateRange] = useState('7');

  // Fetch all tickets for metrics
  const { data: tickets = [], isLoading, refetch } = useQuery({
    queryKey: ['service-dashboard-tickets', profile?.organization_id, dateRange],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const startDate = startOfDay(subDays(new Date(), parseInt(dateRange)));

      const { data, error } = await supabase
        .from('tickets')
        .select(`
          id, ticket_number, subject, status, priority, type, channel,
          created_at, updated_at, resolved_at, closed_at,
          sla_first_response_due, sla_first_response_at, sla_first_response_breached,
          sla_resolution_due, sla_resolution_breached,
          assigned_to
        `)
        .eq('organization_id', profile.organization_id)
        .gte('created_at', startDate.toISOString());

      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch CSAT data
  const { data: csatData = [] } = useQuery({
    queryKey: ['service-csat', profile?.organization_id, dateRange],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const startDate = startOfDay(subDays(new Date(), parseInt(dateRange)));

      const { data, error } = await supabase
        .from('csat_responses')
        .select('score, submitted_at')
        .eq('organization_id', profile.organization_id)
        .gte('submitted_at', startDate.toISOString());

      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch team performance
  const { data: teamPerformance = [] } = useQuery({
    queryKey: ['service-team-performance', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const { data: teamMembers, error: teamError } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, avatar_url')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true);

      if (teamError) throw teamError;

      const { data: ticketCounts } = await supabase
        .from('tickets')
        .select('assigned_to, status')
        .eq('organization_id', profile.organization_id);

      return (teamMembers || []).map(member => {
        const memberTickets = (ticketCounts || []).filter(t => t.assigned_to === member.id);
        const openTickets = memberTickets.filter(t => !['resolved', 'closed'].includes(t.status)).length;
        const resolvedTickets = memberTickets.filter(t => t.status === 'resolved').length;

        return {
          ...member,
          openTickets,
          resolvedTickets,
          totalTickets: memberTickets.length,
        };
      }).filter(m => m.totalTickets > 0).sort((a, b) => b.resolvedTickets - a.resolvedTickets);
    },
    enabled: !!profile?.organization_id,
  });

  // Calculate metrics
  const metrics = {
    total: tickets.length,
    open: tickets.filter(t => !['resolved', 'closed'].includes(t.status)).length,
    resolved: tickets.filter(t => t.status === 'resolved').length,
    closed: tickets.filter(t => t.status === 'closed').length,
    breachedSLA: tickets.filter(t => t.sla_first_response_breached || t.sla_resolution_breached).length,
    avgResolutionTime: 0,
    slaCompliance: 0,
    csatScore: 0,
  };

  // Calculate SLA compliance
  const ticketsWithSLA = tickets.filter(t => t.sla_first_response_due);
  if (ticketsWithSLA.length > 0) {
    const compliant = ticketsWithSLA.filter(t => !t.sla_first_response_breached && !t.sla_resolution_breached).length;
    metrics.slaCompliance = Math.round((compliant / ticketsWithSLA.length) * 100);
  }

  // Calculate CSAT score
  if (csatData.length > 0) {
    const totalScore = csatData.reduce((sum, r) => sum + r.score, 0);
    metrics.csatScore = Math.round((totalScore / csatData.length) * 20); // Convert 1-5 to percentage
  }

  // Tickets by status for pie chart
  const ticketsByStatus = Object.entries(statusLabels).map(([status, label]) => ({
    name: label,
    value: tickets.filter(t => t.status === status).length,
    status,
  })).filter(item => item.value > 0);

  // Tickets by priority
  const ticketsByPriority = [
    { name: 'Crítica', value: tickets.filter(t => t.priority === 'critical').length, color: '#ef4444' },
    { name: 'Alta', value: tickets.filter(t => t.priority === 'high').length, color: '#f97316' },
    { name: 'Média', value: tickets.filter(t => t.priority === 'medium').length, color: '#3b82f6' },
    { name: 'Baixa', value: tickets.filter(t => t.priority === 'low').length, color: '#6b7280' },
  ].filter(item => item.value > 0);

  // Tickets by channel
  const ticketsByChannel = [
    { name: 'E-mail', value: tickets.filter(t => t.channel === 'email').length },
    { name: 'Chat', value: tickets.filter(t => t.channel === 'chat').length },
    { name: 'Telefone', value: tickets.filter(t => t.channel === 'phone').length },
    { name: 'WhatsApp', value: tickets.filter(t => t.channel === 'whatsapp').length },
    { name: 'Portal', value: tickets.filter(t => t.channel === 'portal').length },
    { name: 'Formulário', value: tickets.filter(t => t.channel === 'form').length },
  ].filter(item => item.value > 0);

  // Tickets trend over time
  const ticketsTrend = [];
  for (let i = parseInt(dateRange) - 1; i >= 0; i--) {
    const date = subDays(new Date(), i);
    const dayStart = startOfDay(date);
    const dayEnd = endOfDay(date);

    const dayTickets = tickets.filter(t => {
      const created = new Date(t.created_at);
      return created >= dayStart && created <= dayEnd;
    });

    const resolved = tickets.filter(t => {
      if (!t.resolved_at) return false;
      const resolvedDate = new Date(t.resolved_at);
      return resolvedDate >= dayStart && resolvedDate <= dayEnd;
    });

    ticketsTrend.push({
      date: format(date, 'dd/MM'),
      criados: dayTickets.length,
      resolvidos: resolved.length,
    });
  }

  // Recent tickets
  const recentTickets = [...tickets]
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
    .slice(0, 5);

  // Urgent tickets (SLA breached or about to breach)
  const urgentTickets = tickets
    .filter(t => {
      if (['resolved', 'closed'].includes(t.status)) return false;
      if (t.sla_first_response_breached || t.sla_resolution_breached) return true;
      return t.priority === 'critical';
    })
    .slice(0, 5);

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="service"
          title="Dashboard de Atendimento"
          subtitle="Visão geral de performance e métricas de suporte"
          compact
        />
        <div className="flex justify-end gap-3">
          <Select value={dateRange} onValueChange={setDateRange}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Período" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="7">Últimos 7 dias</SelectItem>
              <SelectItem value="14">Últimos 14 dias</SelectItem>
              <SelectItem value="30">Últimos 30 dias</SelectItem>
              <SelectItem value="60">Últimos 60 dias</SelectItem>
              <SelectItem value="90">Últimos 90 dias</SelectItem>
            </SelectContent>
          </Select>
          <Button variant="outline" size="icon" onClick={() => refetch()}>
            <RefreshCcw className="h-4 w-4" />
          </Button>
        </div>

        {/* KPI Cards */}
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Tickets Abertos</CardTitle>
              <Ticket className="h-4 w-4 text-orange-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{metrics.open}</div>
              <p className="text-xs text-muted-foreground">
                de {metrics.total} no período
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">SLA Compliance</CardTitle>
              <Target className="h-4 w-4 text-green-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{metrics.slaCompliance}%</div>
              <Progress value={metrics.slaCompliance} className="h-2 mt-2" />
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">CSAT Score</CardTitle>
              <Star className="h-4 w-4 text-yellow-500" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{metrics.csatScore}%</div>
              <p className="text-xs text-muted-foreground">
                {csatData.length} avaliações
              </p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">SLA Violado</CardTitle>
              <AlertTriangle className="h-4 w-4 text-destructive" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-destructive">{metrics.breachedSLA}</div>
              <p className="text-xs text-muted-foreground">
                tickets precisam de atenção
              </p>
            </CardContent>
          </Card>
        </div>

        {/* Charts Row */}
        <div className="grid gap-6 lg:grid-cols-2">
          {/* Tickets Trend */}
          <Card>
            <CardHeader>
              <CardTitle>Tendência de Tickets</CardTitle>
              <CardDescription>Criados vs Resolvidos por dia</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={ticketsTrend}>
                    <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                    <XAxis dataKey="date" className="text-xs" />
                    <YAxis className="text-xs" />
                    <Tooltip 
                      contentStyle={{ 
                        backgroundColor: 'hsl(var(--background))',
                        border: '1px solid hsl(var(--border))'
                      }}
                    />
                    <Legend />
                    <Area 
                      type="monotone" 
                      dataKey="criados" 
                      name="Criados"
                      stroke="#f97316" 
                      fill="#f97316"
                      fillOpacity={0.2}
                    />
                    <Area 
                      type="monotone" 
                      dataKey="resolvidos"
                      name="Resolvidos" 
                      stroke="#22c55e" 
                      fill="#22c55e"
                      fillOpacity={0.2}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          {/* Tickets by Status */}
          <Card>
            <CardHeader>
              <CardTitle>Distribuição por Status</CardTitle>
              <CardDescription>Tickets agrupados por status atual</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={ticketsByStatus}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={100}
                      paddingAngle={2}
                      dataKey="value"
                      label={({ name, value }) => `${name}: ${value}`}
                    >
                      {ticketsByStatus.map((entry, index) => (
                        <Cell key={entry.status} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Second Charts Row */}
        <div className="grid gap-6 lg:grid-cols-2">
          {/* Tickets by Channel */}
          <Card>
            <CardHeader>
              <CardTitle>Tickets por Canal</CardTitle>
              <CardDescription>Origem das solicitações</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="h-[250px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={ticketsByChannel} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                    <XAxis type="number" className="text-xs" />
                    <YAxis dataKey="name" type="category" className="text-xs" width={80} />
                    <Tooltip 
                      contentStyle={{ 
                        backgroundColor: 'hsl(var(--background))',
                        border: '1px solid hsl(var(--border))'
                      }}
                    />
                    <Bar dataKey="value" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          {/* Team Performance */}
          <Card>
            <CardHeader>
              <CardTitle>Performance da Equipe</CardTitle>
              <CardDescription>Tickets resolvidos por agente</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {teamPerformance.slice(0, 5).map((member, index) => (
                  <div key={member.id} className="flex items-center gap-4">
                    <div className="flex items-center gap-3 flex-1">
                      <div className="flex items-center justify-center w-6 text-sm font-medium text-muted-foreground">
                        #{index + 1}
                      </div>
                      <Avatar className="h-8 w-8">
                        <AvatarImage src={member.avatar_url || ''} />
                        <AvatarFallback className="text-xs">
                          {member.first_name?.[0]}{member.last_name?.[0]}
                        </AvatarFallback>
                      </Avatar>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">
                          {member.first_name} {member.last_name}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {member.openTickets} abertos
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-bold text-green-600">
                        {member.resolvedTickets}
                      </p>
                      <p className="text-xs text-muted-foreground">resolvidos</p>
                    </div>
                  </div>
                ))}
                {teamPerformance.length === 0 && (
                  <div className="text-center text-muted-foreground py-8">
                    <Users className="h-8 w-8 mx-auto mb-2 opacity-50" />
                    <p className="text-sm">Nenhum agente com tickets</p>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Tickets Lists */}
        <div className="grid gap-6 lg:grid-cols-2">
          {/* Urgent Tickets */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle className="text-red-600">Tickets Urgentes</CardTitle>
                <CardDescription>Requerem atenção imediata</CardDescription>
              </div>
              <Button variant="outline" size="sm" onClick={() => navigate('/tickets?filter=breached')}>
                Ver Todos
                <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            </CardHeader>
            <CardContent>
              {urgentTickets.length === 0 ? (
                <div className="text-center text-muted-foreground py-8">
                  <CheckCircle2 className="h-8 w-8 mx-auto mb-2 text-green-500" />
                  <p className="text-sm font-medium">Nenhum ticket urgente!</p>
                  <p className="text-xs">Todos os SLAs estão sendo cumpridos</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {urgentTickets.map((ticket) => (
                    <div
                      key={ticket.id}
                      className="flex items-center gap-3 p-3 rounded-lg border border-destructive/20 bg-destructive/5 cursor-pointer hover:bg-destructive/10 transition-colors"
                      onClick={() => navigate(`/tickets/${ticket.id}`)}
                    >
                      <AlertTriangle className="h-4 w-4 text-destructive flex-shrink-0" />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{ticket.subject}</p>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs font-mono text-muted-foreground">
                            {ticket.ticket_number}
                          </span>
                          <TicketPriorityBadge priority={ticket.priority as any} size="sm" />
                        </div>
                      </div>
                      {(ticket.sla_first_response_breached || ticket.sla_resolution_breached) && (
                        <Badge variant="destructive" className="text-xs">
                          SLA Violado
                        </Badge>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Recent Tickets */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle>Tickets Recentes</CardTitle>
                <CardDescription>Últimos tickets criados</CardDescription>
              </div>
              <Button variant="outline" size="sm" onClick={() => navigate('/tickets')}>
                Ver Todos
                <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            </CardHeader>
            <CardContent>
              {recentTickets.length === 0 ? (
                <div className="text-center text-muted-foreground py-8">
                  <Ticket className="h-8 w-8 mx-auto mb-2 opacity-50" />
                  <p className="text-sm">Nenhum ticket no período</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {recentTickets.map((ticket) => (
                    <div
                      key={ticket.id}
                      className="flex items-center gap-3 p-3 rounded-lg border hover:bg-muted/50 cursor-pointer transition-colors"
                      onClick={() => navigate(`/tickets/${ticket.id}`)}
                    >
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{ticket.subject}</p>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs font-mono text-muted-foreground">
                            {ticket.ticket_number}
                          </span>
                          <span className="text-xs text-muted-foreground">
                            {formatDistanceToNow(new Date(ticket.created_at), {
                              addSuffix: true,
                              locale: ptBR,
                            })}
                          </span>
                        </div>
                      </div>
                      <TicketStatusBadge status={ticket.status as TicketStatus} size="sm" />
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Settings as SettingsIcon, GripVertical, Plus, Edit, Trash2, Check, X, Users, Tag, Target, Award, ChevronDown, ChevronUp, Save, UserPlus } from '@/components/icons';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useAuth } from '@/hooks/useAuth';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';

interface OpportunityStage {
  id: string;
  name: string;
  probability: number;
  display_order: number;
  is_closed: boolean;
  is_won: boolean;
  organization_id: string;
}

interface WinLossReason {
  id: string;
  name: string;
  type: 'win' | 'loss';
  is_active: boolean;
  organization_id: string;
}

interface LeadSource {
  id: string;
  name: string;
  is_active: boolean;
  organization_id: string;
}

interface TeamMember {
  id: string;
  email: string;
  first_name: string | null;
  last_name: string | null;
  role: 'user' | 'manager' | 'admin';
  is_active: boolean;
  team_id: string | null;
  job_title: string | null;
}

interface Team {
  id: string;
  name: string;
  description: string | null;
  organization_id: string;
}

export default function Settings() {
  const { user, loading } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [activeTab, setActiveTab] = useState('pipeline');

  // Stage form
  const [stageFormOpen, setStageFormOpen] = useState(false);
  const [editingStage, setEditingStage] = useState<OpportunityStage | null>(null);
  const [stageForm, setStageForm] = useState({ name: '', probability: 0, is_closed: false, is_won: false });

  // Reason form
  const [reasonFormOpen, setReasonFormOpen] = useState(false);
  const [editingReason, setEditingReason] = useState<WinLossReason | null>(null);
  const [reasonForm, setReasonForm] = useState({ name: '', type: 'win' as 'win' | 'loss' });

  // Source form
  const [sourceFormOpen, setSourceFormOpen] = useState(false);
  const [editingSource, setEditingSource] = useState<LeadSource | null>(null);
  const [sourceForm, setSourceForm] = useState({ name: '' });

  // Team member form
  const [memberFormOpen, setMemberFormOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<TeamMember | null>(null);
  const [memberForm, setMemberForm] = useState({ email: '', first_name: '', last_name: '', role: 'user' as 'user' | 'manager' | 'admin', job_title: '', team_id: '' });

  // Team form
  const [teamFormOpen, setTeamFormOpen] = useState(false);
  const [editingTeam, setEditingTeam] = useState<Team | null>(null);
  const [teamForm, setTeamForm] = useState({ name: '', description: '' });

  // Fetch organization ID
  const { data: profile } = useQuery({
    queryKey: ['user-profile', user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('organization_id, role')
        .eq('id', user?.id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!user
  });

  // Fetch stages
  const { data: stages = [], isLoading: stagesLoading } = useQuery({
    queryKey: ['opportunity-stages'],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('opportunity_stages')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('display_order');
      if (error) throw error;
      return data as OpportunityStage[];
    },
    enabled: !!profile?.organization_id
  });

  // Fetch win/loss reasons
  const { data: reasons = [] } = useQuery({
    queryKey: ['win-loss-reasons'],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('win_loss_reasons')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('name');
      if (error) throw error;
      return data as WinLossReason[];
    },
    enabled: !!profile?.organization_id
  });

  // Fetch lead sources
  const { data: sources = [] } = useQuery({
    queryKey: ['lead-sources'],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('lead_sources')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('name');
      if (error) throw error;
      return data as LeadSource[];
    },
    enabled: !!profile?.organization_id
  });

  // Fetch team members
  const { data: members = [] } = useQuery({
    queryKey: ['team-members-settings'],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('first_name');
      if (error) throw error;
      return data as TeamMember[];
    },
    enabled: !!profile?.organization_id
  });

  // Fetch teams
  const { data: teams = [] } = useQuery({
    queryKey: ['teams'],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('teams')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('name');
      if (error) throw error;
      return data as Team[];
    },
    enabled: !!profile?.organization_id
  });

  // Stage mutations
  const saveStage = useMutation({
    mutationFn: async (data: typeof stageForm & { id?: string; display_order: number }) => {
      const payload = {
        name: data.name,
        probability: data.probability,
        is_closed: data.is_closed,
        is_won: data.is_won,
        display_order: data.display_order,
        organization_id: profile!.organization_id
      };

      if (data.id) {
        const { error } = await supabase.from('opportunity_stages').update(payload).eq('id', data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('opportunity_stages').insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['opportunity-stages'] });
      setStageFormOpen(false);
      setEditingStage(null);
      setStageForm({ name: '', probability: 0, is_closed: false, is_won: false });
      toast({ title: 'Estágio salvo' });
    },
    onError: (error: any) => toast({ title: 'Erro', description: error.message, variant: 'destructive' })
  });

  const deleteStage = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from('opportunity_stages').delete().eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['opportunity-stages'] });
      toast({ title: 'Estágio excluído' });
    }
  });

  const reorderStages = useMutation({
    mutationFn: async (reordered: OpportunityStage[]) => {
      for (let i = 0; i < reordered.length; i++) {
        await supabase.from('opportunity_stages').update({ display_order: i }).eq('id', reordered[i].id);
      }
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['opportunity-stages'] })
  });

  // Reason mutations
  const saveReason = useMutation({
    mutationFn: async (data: typeof reasonForm & { id?: string }) => {
      const payload = { name: data.name, type: data.type, organization_id: profile!.organization_id, is_active: true };

      if (data.id) {
        const { error } = await supabase.from('win_loss_reasons').update(payload).eq('id', data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('win_loss_reasons').insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['win-loss-reasons'] });
      setReasonFormOpen(false);
      setEditingReason(null);
      setReasonForm({ name: '', type: 'win' });
      toast({ title: 'Motivo salvo' });
    },
    onError: (error: any) => toast({ title: 'Erro', description: error.message, variant: 'destructive' })
  });

  const toggleReason = useMutation({
    mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
      const { error } = await supabase.from('win_loss_reasons').update({ is_active }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['win-loss-reasons'] })
  });

  // Source mutations
  const saveSource = useMutation({
    mutationFn: async (data: typeof sourceForm & { id?: string }) => {
      const payload = { name: data.name, organization_id: profile!.organization_id, is_active: true };

      if (data.id) {
        const { error } = await supabase.from('lead_sources').update(payload).eq('id', data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('lead_sources').insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['lead-sources'] });
      setSourceFormOpen(false);
      setEditingSource(null);
      setSourceForm({ name: '' });
      toast({ title: 'Fonte salva' });
    },
    onError: (error: any) => toast({ title: 'Erro', description: error.message, variant: 'destructive' })
  });

  const toggleSource = useMutation({
    mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
      const { error } = await supabase.from('lead_sources').update({ is_active }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['lead-sources'] })
  });

  // Team mutations
  const saveTeam = useMutation({
    mutationFn: async (data: typeof teamForm & { id?: string }) => {
      const payload = { name: data.name, description: data.description || null, organization_id: profile!.organization_id };

      if (data.id) {
        const { error } = await supabase.from('teams').update(payload).eq('id', data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('teams').insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['teams'] });
      setTeamFormOpen(false);
      setEditingTeam(null);
      setTeamForm({ name: '', description: '' });
      toast({ title: 'Equipe salva' });
    },
    onError: (error: any) => toast({ title: 'Erro', description: error.message, variant: 'destructive' })
  });

  // Member mutations
  const updateMember = useMutation({
    mutationFn: async (data: { id: string; role?: 'user' | 'manager' | 'admin'; team_id?: string | null; is_active?: boolean }) => {
      const { error } = await supabase.from('profiles').update(data).eq('id', data.id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['team-members-settings'] });
      toast({ title: 'Membro atualizado' });
    },
    onError: (error: any) => toast({ title: 'Erro', description: error.message, variant: 'destructive' })
  });

  const handleDragEndStages = (result: any) => {
    if (!result.destination) return;
    const items = Array.from(stages);
    const [reorderedItem] = items.splice(result.source.index, 1);
    items.splice(result.destination.index, 0, reorderedItem);
    reorderStages.mutate(items);
  };

  const openEditStage = (stage: OpportunityStage) => {
    setEditingStage(stage);
    setStageForm({ name: stage.name, probability: stage.probability, is_closed: stage.is_closed, is_won: stage.is_won });
    setStageFormOpen(true);
  };

  const openEditReason = (reason: WinLossReason) => {
    setEditingReason(reason);
    setReasonForm({ name: reason.name, type: reason.type });
    setReasonFormOpen(true);
  };

  const openEditSource = (source: LeadSource) => {
    setEditingSource(source);
    setSourceForm({ name: source.name });
    setSourceFormOpen(true);
  };

  const openEditTeam = (team: Team) => {
    setEditingTeam(team);
    setTeamForm({ name: team.name, description: team.description || '' });
    setTeamFormOpen(true);
  };

  const isAdmin = profile?.role === 'admin';

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="admin"
          title="Configurações"
          subtitle="Configure seu CRM — pipeline, equipes e origens de dados"
          compact
        />

        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="pipeline">Estágios do Pipeline</TabsTrigger>
            <TabsTrigger value="reasons">Motivos de Ganho/Perda</TabsTrigger>
            <TabsTrigger value="sources">Fontes de Lead</TabsTrigger>
            <TabsTrigger value="team">Gestão de Equipe</TabsTrigger>
          </TabsList>

          {/* Pipeline Stages */}
          <TabsContent value="pipeline">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <div>
                  <CardTitle>Estágios do Pipeline de Oportunidades</CardTitle>
                  <CardDescription>Arraste para reordenar. Defina a probabilidade para cada estágio.</CardDescription>
                </div>
                <Dialog open={stageFormOpen} onOpenChange={(open) => {
                  setStageFormOpen(open);
                  if (!open) { setEditingStage(null); setStageForm({ name: '', probability: 0, is_closed: false, is_won: false }); }
                }}>
                  <DialogTrigger asChild>
                    <Button size="sm" disabled={!isAdmin}>
                      <Plus className="h-4 w-4 mr-1" /> Adicionar Estágio
                    </Button>
                  </DialogTrigger>
                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>{editingStage ? 'Editar Estágio' : 'Adicionar Estágio'}</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                      <div className="space-y-2">
                        <Label>Nome do Estágio *</Label>
                        <Input value={stageForm.name} onChange={(e) => setStageForm({ ...stageForm, name: e.target.value })} placeholder="ex: Descoberta" />
                      </div>
                      <div className="space-y-2">
                        <Label>Probabilidade de Ganho (%)</Label>
                        <Input type="number" min="0" max="100" value={stageForm.probability} onChange={(e) => setStageForm({ ...stageForm, probability: parseInt(e.target.value) || 0 })} />
                      </div>
                      <div className="flex items-center gap-6">
                        <div className="flex items-center gap-2">
                          <Switch checked={stageForm.is_closed} onCheckedChange={(checked) => setStageForm({ ...stageForm, is_closed: checked })} />
                          <Label>Estágio Fechado</Label>
                        </div>
                        <div className="flex items-center gap-2">
                          <Switch checked={stageForm.is_won} onCheckedChange={(checked) => setStageForm({ ...stageForm, is_won: checked, is_closed: checked ? true : stageForm.is_closed })} />
                          <Label>Estágio Ganho</Label>
                        </div>
                      </div>
                    </div>
                    <DialogFooter>
                      <Button variant="outline" onClick={() => setStageFormOpen(false)}>Cancelar</Button>
                      <Button onClick={() => saveStage.mutate({ ...stageForm, id: editingStage?.id, display_order: editingStage?.display_order ?? stages.length })} disabled={!stageForm.name}>
                        {editingStage ? 'Atualizar' : 'Criar'}
                      </Button>
                    </DialogFooter>
                  </DialogContent>
                </Dialog>
              </CardHeader>
              <CardContent>
                {stagesLoading ? (
                  <div className="text-center py-8 text-muted-foreground">Carregando...</div>
                ) : stages.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    <Target className="h-8 w-8 mx-auto mb-2" />
                    <p>Nenhum estágio definido</p>
                  </div>
                ) : (
                  <DragDropContext onDragEnd={handleDragEndStages}>
                    <Droppable droppableId="stages">
                      {(provided) => (
                        <div {...provided.droppableProps} ref={provided.innerRef} className="space-y-2">
                          {stages.map((stage, index) => (
                            <Draggable key={stage.id} draggableId={stage.id} index={index} isDragDisabled={!isAdmin}>
                              {(provided) => (
                                <div ref={provided.innerRef} {...provided.draggableProps} className="flex items-center gap-3 p-3 border rounded-lg bg-background">
                                  <div {...provided.dragHandleProps} className="cursor-grab">
                                    <GripVertical className="h-5 w-5 text-muted-foreground" />
                                  </div>
                                  <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                      <span className="font-medium">{stage.name}</span>
                                      {stage.is_won && <Badge variant="default">Won</Badge>}
                                      {stage.is_closed && !stage.is_won && <Badge variant="secondary">Closed</Badge>}
                                    </div>
                                    <span className="text-sm text-muted-foreground">{stage.probability}% probability</span>
                                  </div>
                                  {isAdmin && (
                                    <div className="flex gap-1">
                                      <Button variant="ghost" size="sm" onClick={() => openEditStage(stage)}>
                                        <Edit className="h-4 w-4" />
                                      </Button>
                                      <Button variant="ghost" size="sm" onClick={() => deleteStage.mutate(stage.id)}>
                                        <Trash2 className="h-4 w-4" />
                                      </Button>
                                    </div>
                                  )}
                                </div>
                              )}
                            </Draggable>
                          ))}
                          {provided.placeholder}
                        </div>
                      )}
                    </Droppable>
                  </DragDropContext>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          {/* Win/Loss Reasons */}
          <TabsContent value="reasons">
            <div className="grid gap-6 md:grid-cols-2">
              {/* Win Reasons */}
              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle className="text-green-600">Win Reasons</CardTitle>
                    <CardDescription>Why deals are won</CardDescription>
                  </div>
                  <Dialog open={reasonFormOpen && reasonForm.type === 'win'} onOpenChange={(open) => {
                    if (!open) { setReasonFormOpen(false); setEditingReason(null); setReasonForm({ name: '', type: 'win' }); }
                  }}>
                    <DialogTrigger asChild>
                      <Button size="sm" disabled={!isAdmin} onClick={() => setReasonForm({ name: '', type: 'win' })}>
                        <Plus className="h-4 w-4 mr-1" /> Add
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>{editingReason ? 'Edit' : 'Add'} Win Reason</DialogTitle>
                      </DialogHeader>
                      <div className="space-y-4 py-4">
                        <div className="space-y-2">
                          <Label>Reason Name *</Label>
                          <Input value={reasonForm.name} onChange={(e) => setReasonForm({ ...reasonForm, name: e.target.value })} placeholder="e.g., Best price" />
                        </div>
                      </div>
                      <DialogFooter>
                        <Button variant="outline" onClick={() => setReasonFormOpen(false)}>Cancel</Button>
                        <Button onClick={() => saveReason.mutate({ ...reasonForm, id: editingReason?.id })} disabled={!reasonForm.name}>Save</Button>
                      </DialogFooter>
                    </DialogContent>
                  </Dialog>
                </CardHeader>
                <CardContent>
                  <div className="space-y-2">
                    {reasons.filter(r => r.type === 'win').map(reason => (
                      <div key={reason.id} className="flex items-center gap-3 p-2 border rounded">
                        <Award className="h-4 w-4 text-green-600" />
                        <span className={`flex-1 ${!reason.is_active ? 'text-muted-foreground line-through' : ''}`}>{reason.name}</span>
                        {isAdmin && (
                          <>
                            <Switch checked={reason.is_active} onCheckedChange={(checked) => toggleReason.mutate({ id: reason.id, is_active: checked })} />
                            <Button variant="ghost" size="sm" onClick={() => { openEditReason(reason); setReasonFormOpen(true); }}>
                              <Edit className="h-4 w-4" />
                            </Button>
                          </>
                        )}
                      </div>
                    ))}
                    {reasons.filter(r => r.type === 'win').length === 0 && (
                      <p className="text-center text-muted-foreground py-4">No win reasons defined</p>
                    )}
                  </div>
                </CardContent>
              </Card>

              {/* Loss Reasons */}
              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle className="text-red-600">Loss Reasons</CardTitle>
                    <CardDescription>Why deals are lost</CardDescription>
                  </div>
                  <Dialog open={reasonFormOpen && reasonForm.type === 'loss'} onOpenChange={(open) => {
                    if (!open) { setReasonFormOpen(false); setEditingReason(null); setReasonForm({ name: '', type: 'loss' }); }
                  }}>
                    <DialogTrigger asChild>
                      <Button size="sm" disabled={!isAdmin} onClick={() => { setReasonForm({ name: '', type: 'loss' }); setReasonFormOpen(true); }}>
                        <Plus className="h-4 w-4 mr-1" /> Add
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>{editingReason ? 'Edit' : 'Add'} Loss Reason</DialogTitle>
                      </DialogHeader>
                      <div className="space-y-4 py-4">
                        <div className="space-y-2">
                          <Label>Reason Name *</Label>
                          <Input value={reasonForm.name} onChange={(e) => setReasonForm({ ...reasonForm, name: e.target.value })} placeholder="e.g., Lost to competitor" />
                        </div>
                      </div>
                      <DialogFooter>
                        <Button variant="outline" onClick={() => setReasonFormOpen(false)}>Cancel</Button>
                        <Button onClick={() => saveReason.mutate({ ...reasonForm, id: editingReason?.id })} disabled={!reasonForm.name}>Save</Button>
                      </DialogFooter>
                    </DialogContent>
                  </Dialog>
                </CardHeader>
                <CardContent>
                  <div className="space-y-2">
                    {reasons.filter(r => r.type === 'loss').map(reason => (
                      <div key={reason.id} className="flex items-center gap-3 p-2 border rounded">
                        <X className="h-4 w-4 text-red-600" />
                        <span className={`flex-1 ${!reason.is_active ? 'text-muted-foreground line-through' : ''}`}>{reason.name}</span>
                        {isAdmin && (
                          <>
                            <Switch checked={reason.is_active} onCheckedChange={(checked) => toggleReason.mutate({ id: reason.id, is_active: checked })} />
                            <Button variant="ghost" size="sm" onClick={() => { openEditReason(reason); setReasonFormOpen(true); }}>
                              <Edit className="h-4 w-4" />
                            </Button>
                          </>
                        )}
                      </div>
                    ))}
                    {reasons.filter(r => r.type === 'loss').length === 0 && (
                      <p className="text-center text-muted-foreground py-4">No loss reasons defined</p>
                    )}
                  </div>
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          {/* Lead Sources */}
          <TabsContent value="sources">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <div>
                  <CardTitle>Lead Sources</CardTitle>
                  <CardDescription>Track where your leads come from</CardDescription>
                </div>
                <Dialog open={sourceFormOpen} onOpenChange={(open) => {
                  setSourceFormOpen(open);
                  if (!open) { setEditingSource(null); setSourceForm({ name: '' }); }
                }}>
                  <DialogTrigger asChild>
                    <Button size="sm" disabled={!isAdmin}>
                      <Plus className="h-4 w-4 mr-1" /> Add Source
                    </Button>
                  </DialogTrigger>
                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>{editingSource ? 'Edit' : 'Add'} Lead Source</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                      <div className="space-y-2">
                        <Label>Source Name *</Label>
                        <Input value={sourceForm.name} onChange={(e) => setSourceForm({ ...sourceForm, name: e.target.value })} placeholder="e.g., Website, Referral, Event" />
                      </div>
                    </div>
                    <DialogFooter>
                      <Button variant="outline" onClick={() => setSourceFormOpen(false)}>Cancel</Button>
                      <Button onClick={() => saveSource.mutate({ ...sourceForm, id: editingSource?.id })} disabled={!sourceForm.name}>Save</Button>
                    </DialogFooter>
                  </DialogContent>
                </Dialog>
              </CardHeader>
              <CardContent>
                <div className="grid gap-2 md:grid-cols-2 lg:grid-cols-3">
                  {sources.map(source => (
                    <div key={source.id} className="flex items-center gap-3 p-3 border rounded">
                      <Tag className="h-4 w-4 text-muted-foreground" />
                      <span className={`flex-1 ${!source.is_active ? 'text-muted-foreground line-through' : ''}`}>{source.name}</span>
                      {isAdmin && (
                        <>
                          <Switch checked={source.is_active} onCheckedChange={(checked) => toggleSource.mutate({ id: source.id, is_active: checked })} />
                          <Button variant="ghost" size="sm" onClick={() => openEditSource(source)}>
                            <Edit className="h-4 w-4" />
                          </Button>
                        </>
                      )}
                    </div>
                  ))}
                  {sources.length === 0 && (
                    <p className="col-span-full text-center text-muted-foreground py-8">No lead sources defined</p>
                  )}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Team Management */}
          <TabsContent value="team">
            <div className="space-y-6">
              {/* Teams */}
              <Card>
                <CardHeader className="flex flex-row items-center justify-between">
                  <div>
                    <CardTitle>Teams</CardTitle>
                    <CardDescription>Organize users into teams</CardDescription>
                  </div>
                  <Dialog open={teamFormOpen} onOpenChange={(open) => {
                    setTeamFormOpen(open);
                    if (!open) { setEditingTeam(null); setTeamForm({ name: '', description: '' }); }
                  }}>
                    <DialogTrigger asChild>
                      <Button size="sm" disabled={!isAdmin}>
                        <Plus className="h-4 w-4 mr-1" /> Add Team
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>{editingTeam ? 'Edit' : 'Create'} Team</DialogTitle>
                      </DialogHeader>
                      <div className="space-y-4 py-4">
                        <div className="space-y-2">
                          <Label>Team Name *</Label>
                          <Input value={teamForm.name} onChange={(e) => setTeamForm({ ...teamForm, name: e.target.value })} placeholder="e.g., Enterprise Sales" />
                        </div>
                        <div className="space-y-2">
                          <Label>Description</Label>
                          <Input value={teamForm.description} onChange={(e) => setTeamForm({ ...teamForm, description: e.target.value })} placeholder="Team description..." />
                        </div>
                      </div>
                      <DialogFooter>
                        <Button variant="outline" onClick={() => setTeamFormOpen(false)}>Cancel</Button>
                        <Button onClick={() => saveTeam.mutate({ ...teamForm, id: editingTeam?.id })} disabled={!teamForm.name}>Save</Button>
                      </DialogFooter>
                    </DialogContent>
                  </Dialog>
                </CardHeader>
                <CardContent>
                  <div className="grid gap-4 md:grid-cols-3">
                    {teams.map(team => {
                      const teamMembers = members.filter(m => m.team_id === team.id);
                      return (
                        <Card key={team.id} className="bg-muted/30">
                          <CardContent className="p-4">
                            <div className="flex items-center justify-between mb-2">
                              <h4 className="font-medium">{team.name}</h4>
                              {isAdmin && (
                                <Button variant="ghost" size="sm" onClick={() => openEditTeam(team)}>
                                  <Edit className="h-4 w-4" />
                                </Button>
                              )}
                            </div>
                            {team.description && <p className="text-sm text-muted-foreground mb-2">{team.description}</p>}
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                              <Users className="h-4 w-4" />
                              <span>{teamMembers.length} member{teamMembers.length !== 1 ? 's' : ''}</span>
                            </div>
                          </CardContent>
                        </Card>
                      );
                    })}
                    {teams.length === 0 && (
                      <p className="col-span-full text-center text-muted-foreground py-4">No teams created</p>
                    )}
                  </div>
                </CardContent>
              </Card>

              {/* Members */}
              <Card>
                <CardHeader>
                  <CardTitle>Team Members</CardTitle>
                  <CardDescription>Manage users and their roles</CardDescription>
                </CardHeader>
                <CardContent>
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Name</TableHead>
                        <TableHead>Email</TableHead>
                        <TableHead>Role</TableHead>
                        <TableHead>Team</TableHead>
                        <TableHead>Status</TableHead>
                        <TableHead></TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {members.map(member => (
                        <TableRow key={member.id}>
                          <TableCell className="font-medium">
                            {member.first_name || '-'} {member.last_name || ''}
                            {member.job_title && <div className="text-xs text-muted-foreground">{member.job_title}</div>}
                          </TableCell>
                          <TableCell>{member.email}</TableCell>
                          <TableCell>
                            {isAdmin ? (
                              <Select
                                value={member.role}
                                onValueChange={(value: 'user' | 'manager' | 'admin') => updateMember.mutate({ id: member.id, role: value })}
                              >
                                <SelectTrigger className="w-28 h-8">
                                  <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                  <SelectItem value="user">User</SelectItem>
                                  <SelectItem value="manager">Manager</SelectItem>
                                  <SelectItem value="admin">Admin</SelectItem>
                                </SelectContent>
                              </Select>
                            ) : (
                              <Badge variant="outline">{member.role}</Badge>
                            )}
                          </TableCell>
                          <TableCell>
                            {isAdmin ? (
                              <Select
                                value={member.team_id || ''}
                                onValueChange={(value) => updateMember.mutate({ id: member.id, team_id: value || null })}
                              >
                                <SelectTrigger className="w-32 h-8">
                                  <SelectValue placeholder="No team" />
                                </SelectTrigger>
                                <SelectContent>
                                  <SelectItem value="">No team</SelectItem>
                                  {teams.map(team => (
                                    <SelectItem key={team.id} value={team.id}>{team.name}</SelectItem>
                                  ))}
                                </SelectContent>
                              </Select>
                            ) : (
                              <span>{teams.find(t => t.id === member.team_id)?.name || '-'}</span>
                            )}
                          </TableCell>
                          <TableCell>
                            <Badge variant={member.is_active ? 'default' : 'secondary'}>
                              {member.is_active ? 'Active' : 'Inactive'}
                            </Badge>
                          </TableCell>
                          <TableCell>
                            {isAdmin && member.id !== user?.id && (
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => updateMember.mutate({ id: member.id, is_active: !member.is_active })}
                              >
                                {member.is_active ? 'Deactivate' : 'Activate'}
                              </Button>
                            )}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </CardContent>
              </Card>
            </div>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useEffect, useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useNavigate } from 'react-router-dom';
import { Map, Plus, Search, ChevronRight, ChevronDown, Edit, Trash2, Users, Building2, UserCircle } from '@/components/icons';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useAuth } from '@/hooks/useAuth';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

interface Territory {
  id: string;
  name: string;
  description: string | null;
  region: string | null;
  criteria: any;
  parent_territory_id: string | null;
  owner_id: string | null;
  organization_id: string;
  created_at: string;
  owner?: { first_name: string | null; last_name: string | null; email: string } | null;
  children?: Territory[];
  account_count?: number;
  lead_count?: number;
}

interface Profile {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string;
}

export default function Territories() {
  const { user, loading } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState('');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTerritory, setEditingTerritory] = useState<Territory | null>(null);
  const [expandedIds, setExpandedIds] = useState<string[]>([]);

  // Form state
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    region: '',
    parent_territory_id: '',
    owner_id: ''
  });

  // Fetch territories
  const { data: territories = [], isLoading: territoriesLoading } = useQuery({
    queryKey: ['territories'],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('territories')
        .select(`
          *,
          owner:profiles!territories_owner_id_fkey(first_name, last_name, email)
        `)
        .eq('organization_id', profile.organization_id)
        .order('name');

      if (error) throw error;
      return data as Territory[];
    },
    enabled: !!user
  });

  // Fetch team members for owner selection
  const { data: teamMembers = [] } = useQuery({
    queryKey: ['team-members'],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('first_name');

      if (error) throw error;
      return data as Profile[];
    },
    enabled: !!user
  });

  // Fetch counts for territories
  const { data: territoryCounts = {} } = useQuery({
    queryKey: ['territory-counts'],
    queryFn: async () => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) return {};

      const [accountsRes, leadsRes] = await Promise.all([
        supabase
          .from('accounts')
          .select('territory_id')
          .eq('organization_id', profile.organization_id)
          .not('territory_id', 'is', null),
        supabase
          .from('leads')
          .select('territory_id')
          .eq('organization_id', profile.organization_id)
          .not('territory_id', 'is', null)
      ]);

      const counts: Record<string, { accounts: number; leads: number }> = {};

      accountsRes.data?.forEach(a => {
        if (a.territory_id) {
          if (!counts[a.territory_id]) counts[a.territory_id] = { accounts: 0, leads: 0 };
          counts[a.territory_id].accounts++;
        }
      });

      leadsRes.data?.forEach(l => {
        if (l.territory_id) {
          if (!counts[l.territory_id]) counts[l.territory_id] = { accounts: 0, leads: 0 };
          counts[l.territory_id].leads++;
        }
      });

      return counts;
    },
    enabled: !!user
  });

  // Create/Update mutation
  const saveMutation = useMutation({
    mutationFn: async (data: typeof formData & { id?: string }) => {
      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user?.id)
        .single();

      if (!profile?.organization_id) throw new Error('No organization');

      const payload = {
        name: data.name,
        description: data.description || null,
        region: data.region || null,
        parent_territory_id: data.parent_territory_id || null,
        owner_id: data.owner_id || null,
        organization_id: profile.organization_id
      };

      if (data.id) {
        const { error } = await supabase
          .from('territories')
          .update(payload)
          .eq('id', data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('territories')
          .insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['territories'] });
      setIsFormOpen(false);
      setEditingTerritory(null);
      resetForm();
      toast({
        title: editingTerritory ? 'Território atualizado' : 'Território criado',
        description: 'Alterações salvas com sucesso.'
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.message,
        variant: 'destructive'
      });
    }
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('territories')
        .delete()
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['territories'] });
      toast({
        title: 'Território excluído',
        description: 'Território foi removido.'
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.message,
        variant: 'destructive'
      });
    }
  });

  const resetForm = () => {
    setFormData({
      name: '',
      description: '',
      region: '',
      parent_territory_id: '',
      owner_id: ''
    });
  };

  const openEditForm = (territory: Territory) => {
    setEditingTerritory(territory);
    setFormData({
      name: territory.name,
      description: territory.description || '',
      region: territory.region || '',
      parent_territory_id: territory.parent_territory_id || '',
      owner_id: territory.owner_id || ''
    });
    setIsFormOpen(true);
  };

  const toggleExpand = (id: string) => {
    if (expandedIds.includes(id)) {
      setExpandedIds(expandedIds.filter(eid => eid !== id));
    } else {
      setExpandedIds([...expandedIds, id]);
    }
  };

  // Build territory tree
  const buildTree = (territories: Territory[]): Territory[] => {
    const nodeMap: Record<string, Territory> = {};
    const roots: Territory[] = [];

    territories.forEach(t => {
      nodeMap[t.id] = { ...t, children: [] };
    });

    territories.forEach(t => {
      const node = nodeMap[t.id];
      if (t.parent_territory_id && nodeMap[t.parent_territory_id]) {
        nodeMap[t.parent_territory_id].children!.push(node);
      } else {
        roots.push(node);
      }
    });

    return roots;
  };

  const filteredTerritories = territories.filter(t =>
    t.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    t.region?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const territoryTree = buildTree(filteredTerritories);

  const renderTerritoryNode = (territory: Territory, level: number = 0) => {
    const hasChildren = territory.children && territory.children.length > 0;
    const isExpanded = expandedIds.includes(territory.id);
    const counts = territoryCounts[territory.id] || { accounts: 0, leads: 0 };

    return (
      <div key={territory.id}>
        <div 
          className="flex items-center gap-3 p-3 hover:bg-muted/50 rounded-lg transition-colors"
          style={{ paddingLeft: `${level * 24 + 12}px` }}
        >
          {hasChildren ? (
            <Button
              variant="ghost"
              size="sm"
              className="h-6 w-6 p-0"
              onClick={() => toggleExpand(territory.id)}
            >
              {isExpanded ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
            </Button>
          ) : (
            <div className="w-6" />
          )}

          <Map className="h-5 w-5 text-muted-foreground" />

          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
              <span className="font-medium">{territory.name}</span>
              {territory.region && (
                <Badge variant="outline" className="text-xs">{territory.region}</Badge>
              )}
            </div>
            {territory.description && (
              <p className="text-sm text-muted-foreground truncate">{territory.description}</p>
            )}
          </div>

          <div className="flex items-center gap-4 text-sm text-muted-foreground">
            <div className="flex items-center gap-1" title="Accounts">
              <Building2 className="h-4 w-4" />
              <span>{counts.accounts}</span>
            </div>
            <div className="flex items-center gap-1" title="Leads">
              <Users className="h-4 w-4" />
              <span>{counts.leads}</span>
            </div>
            {territory.owner && (
              <div className="flex items-center gap-1" title="Owner">
                <UserCircle className="h-4 w-4" />
                <span className="max-w-[100px] truncate">
                  {territory.owner.first_name || territory.owner.email}
                </span>
              </div>
            )}
          </div>

          <div className="flex items-center gap-1">
            <Button variant="ghost" size="sm" onClick={() => openEditForm(territory)}>
              <Edit className="h-4 w-4" />
            </Button>
            <Button 
              variant="ghost" 
              size="sm" 
              onClick={() => deleteMutation.mutate(territory.id)}
              disabled={hasChildren}
              title={hasChildren ? 'Delete child territories first' : 'Delete territory'}
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {hasChildren && isExpanded && (
          <div>
            {territory.children!.map(child => renderTerritoryNode(child, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="sales"
          title="Territórios"
          subtitle="Gerencie territórios de vendas e atribuições"
          compact
        />
        {/* Territory Form */}
        <div className="flex items-center justify-end">
          <div className="hidden" />
          <Dialog open={isFormOpen} onOpenChange={(open) => {
            setIsFormOpen(open);
            if (!open) {
              setEditingTerritory(null);
              resetForm();
            }
          }}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="h-4 w-4 mr-2" />
                Adicionar Território
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-lg">
              <DialogHeader>
                <DialogTitle>{editingTerritory ? 'Editar Território' : 'Criar Território'}</DialogTitle>
              </DialogHeader>
              <div className="space-y-4 py-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Nome *</Label>
                  <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    placeholder="ex: América do Norte"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="region">Região</Label>
                  <Input
                    id="region"
                    value={formData.region}
                    onChange={(e) => setFormData({ ...formData, region: e.target.value })}
                    placeholder="ex: SUL, SUDESTE, NORDESTE"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="description">Descrição</Label>
                  <Textarea
                    id="description"
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Detalhes de cobertura do território..."
                    rows={3}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="parent">Território Pai</Label>
                  <Select
                    value={formData.parent_territory_id}
                    onValueChange={(value) => setFormData({ ...formData, parent_territory_id: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione pai (opcional)" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="">Sem pai</SelectItem>
                      {territories
                        .filter(t => t.id !== editingTerritory?.id)
                        .map(t => (
                          <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="owner">Proprietário do Território</Label>
                  <Select
                    value={formData.owner_id}
                    onValueChange={(value) => setFormData({ ...formData, owner_id: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Atribuir proprietário" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="">Não atribuído</SelectItem>
                      {teamMembers.map(m => (
                        <SelectItem key={m.id} value={m.id}>
                          {m.first_name || m.email} {m.last_name || ''}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <DialogFooter>
                <Button variant="outline" onClick={() => setIsFormOpen(false)}>
                  Cancelar
                </Button>
                <Button 
                  onClick={() => saveMutation.mutate({ ...formData, id: editingTerritory?.id })}
                  disabled={!formData.name || saveMutation.isPending}
                >
                  {saveMutation.isPending ? 'Salvando...' : editingTerritory ? 'Atualizar' : 'Criar'}
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-4 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold">{territories.length}</div>
              <div className="text-sm text-muted-foreground">Total de Territórios</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold">
                {territories.filter(t => !t.parent_territory_id).length}
              </div>
              <div className="text-sm text-muted-foreground">Top-Level Regions</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold">
                {territories.filter(t => t.owner_id).length}
              </div>
              <div className="text-sm text-muted-foreground">Assigned Territories</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold">
                {Object.values(territoryCounts).reduce((sum, c) => sum + c.accounts, 0)}
              </div>
              <div className="text-sm text-muted-foreground">Accounts Assigned</div>
            </CardContent>
          </Card>
        </div>

        {/* Search */}
        <div className="relative max-w-sm">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search territories..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9"
          />
        </div>

        {/* Territory Tree */}
        <Card>
          <CardHeader>
            <CardTitle>Territory Hierarchy</CardTitle>
            <CardDescription>Click to expand/collapse nested territories</CardDescription>
          </CardHeader>
          <CardContent>
            {territoriesLoading ? (
              <div className="flex items-center justify-center h-32 text-muted-foreground">
                Loading territories...
              </div>
            ) : territoryTree.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-32 text-muted-foreground">
                <Map className="h-8 w-8 mb-2" />
                <p>No territories defined yet</p>
                <p className="text-sm">Create your first territory to get started</p>
              </div>
            ) : (
              <div className="divide-y">
                {territoryTree.map(territory => renderTerritoryNode(territory))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Textarea } from '@/components/ui/textarea';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Separator } from '@/components/ui/separator';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from '@/components/ui/dropdown-menu';
import { 
  ArrowLeft, 
  Edit, 
  MoreHorizontal, 
  Send,
  MessageSquare,
  Clock,
  User,
  Building2,
  Mail,
  Phone,
  Globe,
  Calendar,
  AlertTriangle,
  CheckCircle2,
  XCircle,
  Eye,
  EyeOff,
  Paperclip,
  RefreshCcw,
  UserPlus,
  Flag,
  Trash2
} from '@/components/icons';
import { formatDistanceToNow, format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { useToast } from '@/hooks/use-toast';
import { ChangeHistory } from '@/components/ChangeHistory';
import { TicketStatusBadge } from '@/components/service/TicketStatusBadge';
import { TicketPriorityBadge } from '@/components/service/TicketPriorityBadge';
import { SLACountdown } from '@/components/service/SLACountdown';
import { TicketMessages } from '@/components/service/TicketMessages';
import { TicketTimeline } from '@/components/service/TicketTimeline';
import { CannedResponsePicker } from '@/components/service/CannedResponsePicker';

type TicketStatus = 'new' | 'open' | 'pending' | 'on_hold' | 'resolved' | 'closed';
type TicketPriority = 'low' | 'medium' | 'high' | 'critical';

const statusTransitions: Record<TicketStatus, TicketStatus[]> = {
  new: ['open', 'pending', 'on_hold', 'closed'],
  open: ['pending', 'on_hold', 'resolved', 'closed'],
  pending: ['open', 'on_hold', 'resolved', 'closed'],
  on_hold: ['open', 'pending', 'resolved', 'closed'],
  resolved: ['open', 'closed'],
  closed: ['open'],
};

const statusLabels: Record<TicketStatus, string> = {
  new: 'Novo',
  open: 'Aberto',
  pending: 'Pendente',
  on_hold: 'Em Espera',
  resolved: 'Resolvido',
  closed: 'Fechado',
};

export default function TicketDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [newMessage, setNewMessage] = useState('');
  const [isInternalNote, setIsInternalNote] = useState(false);
  const [activeTab, setActiveTab] = useState('conversation');

  // Fetch ticket details
  const { data: ticket, isLoading } = useQuery({
    queryKey: ['ticket', id],
    queryFn: async () => {
      if (!id) return null;

      const { data, error } = await supabase
        .from('tickets')
        .select(`
          *,
          accounts:account_id(id, name, phone, email, website),
          contacts:contact_id(id, first_name, last_name, email, phone, job_title),
          queue:queue_id(id, name),
          category:category_id(id, name),
          sla:sla_id(id, name)
        `)
        .eq('id', id)
        .single();

      if (error) throw error;

      // Fetch related profiles separately
      let assignee = null;
      let reporter = null;

      if (data.assigned_to) {
        const { data: assigneeData } = await supabase
          .from('profiles')
          .select('id, first_name, last_name, email, avatar_url')
          .eq('id', data.assigned_to)
          .single();
        assignee = assigneeData;
      }

      if (data.reporter_id) {
        const { data: reporterData } = await supabase
          .from('profiles')
          .select('id, first_name, last_name, email')
          .eq('id', data.reporter_id)
          .single();
        reporter = reporterData;
      }

      return { ...data, assignee, reporter };
    },
    enabled: !!id,
  });

  // Fetch messages
  const { data: messages = [], refetch: refetchMessages } = useQuery({
    queryKey: ['ticket-messages', id],
    queryFn: async () => {
      if (!id) return [];

      const { data, error } = await supabase
        .from('ticket_messages')
        .select(`
          *,
          sender:sender_id(id, first_name, last_name, email, avatar_url)
        `)
        .eq('ticket_id', id)
        .order('created_at', { ascending: true });

      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch status history
  const { data: statusHistory = [] } = useQuery({
    queryKey: ['ticket-status-history', id],
    queryFn: async () => {
      if (!id) return [];

      const { data, error } = await supabase
        .from('ticket_status_history')
        .select(`
          *,
          changed_by_user:changed_by(first_name, last_name)
        `)
        .eq('ticket_id', id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  // Fetch team members for assignment
  const { data: teamMembers = [] } = useQuery({
    queryKey: ['team-members', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];

      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email, avatar_url')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true);

      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Update ticket mutation
  const updateTicketMutation = useMutation({
    mutationFn: async (updates: Partial<typeof ticket>) => {
      const { error } = await supabase
        .from('tickets')
        .update(updates)
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ticket', id] });
      queryClient.invalidateQueries({ queryKey: ['ticket-status-history', id] });
      toast({
        title: 'Ticket atualizado',
        description: 'As alterações foram salvas com sucesso.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao atualizar',
        description: error.message,
        variant: 'destructive',
      });
    },
  });

  // Send message mutation
  const sendMessageMutation = useMutation({
    mutationFn: async ({ content, isInternal }: { content: string; isInternal: boolean }) => {
      const { error } = await supabase
        .from('ticket_messages')
        .insert({
          ticket_id: id,
          sender_type: 'agent',
          sender_id: profile?.id,
          sender_name: `${profile?.first_name} ${profile?.last_name}`,
          sender_email: profile?.email,
          content,
          is_internal: isInternal,
        });

      if (error) throw error;

      // Update ticket status to open if it's new and this is an agent response
      if (ticket?.status === 'new' && !isInternal) {
        await supabase
          .from('tickets')
          .update({ status: 'open' })
          .eq('id', id);
      }
    },
    onSuccess: () => {
      setNewMessage('');
      setIsInternalNote(false);
      refetchMessages();
      queryClient.invalidateQueries({ queryKey: ['ticket', id] });
      toast({
        title: isInternalNote ? 'Nota interna adicionada' : 'Mensagem enviada',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao enviar mensagem',
        description: error.message,
        variant: 'destructive',
      });
    },
  });

  const handleStatusChange = (newStatus: TicketStatus) => {
    updateTicketMutation.mutate({ status: newStatus });
  };

  const handlePriorityChange = (newPriority: TicketPriority) => {
    updateTicketMutation.mutate({ priority: newPriority });
  };

  const handleAssigneeChange = (newAssignee: string) => {
    updateTicketMutation.mutate({ 
      assigned_to: newAssignee === 'unassigned' ? null : newAssignee,
      assigned_at: newAssignee === 'unassigned' ? null : new Date().toISOString(),
    });
  };

  const handleSendMessage = () => {
    if (!newMessage.trim()) return;
    sendMessageMutation.mutate({ content: newMessage, isInternal: isInternalNote });
  };

  const handleAssignToMe = () => {
    if (profile?.id) {
      handleAssigneeChange(profile.id);
    }
  };

  if (isLoading) {
    return (
      <>
        <div className="flex items-center justify-center py-12">
          <RefreshCcw className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </>
    );
  }

  if (!ticket) {
    return (
      <>
        <div className="flex flex-col items-center justify-center py-12">
          <h2 className="text-xl font-semibold">Ticket não encontrado</h2>
          <Button className="mt-4" onClick={() => navigate('/tickets')}>
            Voltar para Tickets
          </Button>
        </div>
      </>
    );
  }

  const allowedTransitions = statusTransitions[ticket.status as TicketStatus] || [];

  return (
    <>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
          <div className="flex items-start gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate('/tickets')}>
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <div className="flex items-center gap-3 flex-wrap">
                <h1 className="text-2xl font-bold tracking-tight font-mono">
                  {ticket.ticket_number}
                </h1>
                <TicketStatusBadge status={ticket.status as TicketStatus} size="md" />
                <TicketPriorityBadge priority={ticket.priority as TicketPriority} size="md" />
              </div>
              <h2 className="text-xl text-muted-foreground mt-1">
                {ticket.subject}
              </h2>
            </div>
          </div>

          <div className="flex gap-2">
            {!ticket.assigned_to && (
              <Button variant="outline" onClick={handleAssignToMe}>
                <UserPlus className="mr-2 h-4 w-4" />
                Assumir
              </Button>
            )}
            <Button variant="outline" onClick={() => navigate(`/tickets/${id}/edit`)}>
              <Edit className="mr-2 h-4 w-4" />
              Editar
            </Button>
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="icon">
                  <MoreHorizontal className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem>
                  <Flag className="mr-2 h-4 w-4" />
                  Escalar
                </DropdownMenuItem>
                <DropdownMenuItem>
                  <Paperclip className="mr-2 h-4 w-4" />
                  Adicionar Anexo
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem className="text-destructive">
                  <Trash2 className="mr-2 h-4 w-4" />
                  Excluir Ticket
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-6">
            {/* Description Card */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Descrição</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="prose prose-sm max-w-none">
                  {ticket.description}
                </div>
              </CardContent>
            </Card>

            {/* Conversation / Timeline Tabs */}
            <Tabs value={activeTab} onValueChange={setActiveTab}>
              <TabsList>
                <TabsTrigger value="conversation">
                  <MessageSquare className="mr-2 h-4 w-4" />
                  Conversa
                </TabsTrigger>
                <TabsTrigger value="timeline">
                  <Clock className="mr-2 h-4 w-4" />
                  Linha do Tempo
                </TabsTrigger>
                <TabsTrigger value="history">
                  Histórico de Alterações
                </TabsTrigger>
              </TabsList>

              <TabsContent value="conversation" className="mt-4">
                <Card>
                  <CardContent className="p-4">
                    <TicketMessages 
                      messages={messages.filter(m => !m.is_internal)} 
                      currentUserId={profile?.id}
                    />
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="internal" className="mt-4">
                <Card>
                  <CardContent className="p-4">
                    <TicketMessages 
                      messages={messages.filter(m => m.is_internal)} 
                      currentUserId={profile?.id}
                      isInternal
                    />
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="timeline" className="mt-4">
                <Card>
                  <CardContent className="p-4">
                    <TicketTimeline 
                      statusHistory={statusHistory}
                      ticket={ticket}
                    />
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="history" className="mt-4">
                <ChangeHistory entityType="ticket" entityId={id!} />
              </TabsContent>
            </Tabs>

            {/* Reply Box */}
            <Card>
              <CardContent className="p-4">
                <div className="space-y-4">
                  <div className="flex items-center gap-2">
                    <Checkbox
                      id="internal"
                      checked={isInternalNote}
                      onCheckedChange={(checked) => setIsInternalNote(!!checked)}
                    />
                    <label 
                      htmlFor="internal" 
                      className="text-sm font-medium leading-none cursor-pointer flex items-center gap-1"
                    >
                      <EyeOff className="h-3.5 w-3.5" />
                      Nota interna (não visível para o cliente)
                    </label>
                  </div>

                  <Textarea
                    placeholder={isInternalNote ? "Escreva uma nota interna..." : "Escreva sua resposta..."}
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    className="min-h-[120px]"
                  />

                  <div className="flex items-center justify-between">
                    <div className="flex gap-2">
                      <CannedResponsePicker
                        ticketId={id}
                        contactId={ticket.contact_id}
                        onSelect={(content) => setNewMessage(prev => prev + content)}
                      />
                      <Button variant="outline" size="sm">
                        <Paperclip className="mr-2 h-4 w-4" />
                        Anexar
                      </Button>
                    </div>
                    <Button 
                      onClick={handleSendMessage}
                      disabled={!newMessage.trim() || sendMessageMutation.isPending}
                    >
                      <Send className="mr-2 h-4 w-4" />
                      {isInternalNote ? 'Adicionar Nota' : 'Enviar Resposta'}
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Status Actions */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium">Status do Ticket</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="flex flex-wrap gap-2">
                  {allowedTransitions.map((status) => (
                    <Button
                      key={status}
                      variant="outline"
                      size="sm"
                      onClick={() => handleStatusChange(status)}
                      disabled={updateTicketMutation.isPending}
                    >
                      {statusLabels[status]}
                    </Button>
                  ))}
                </div>
              </CardContent>
            </Card>

            {/* SLA Info */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium">SLA</CardTitle>
                {ticket.sla && (
                  <CardDescription>{ticket.sla.name}</CardDescription>
                )}
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <p className="text-xs text-muted-foreground mb-2">Primeira Resposta</p>
                  <SLACountdown
                    dueAt={ticket.sla_first_response_due}
                    completedAt={ticket.sla_first_response_at}
                    breached={ticket.sla_first_response_breached}
                    createdAt={ticket.created_at}
                    showProgress
                    compact={false}
                  />
                </div>
                <Separator />
                <div>
                  <p className="text-xs text-muted-foreground mb-2">Resolução</p>
                  <SLACountdown
                    dueAt={ticket.sla_resolution_due}
                    completedAt={ticket.resolved_at}
                    breached={ticket.sla_resolution_breached}
                    createdAt={ticket.created_at}
                    showProgress
                    compact={false}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Ticket Details */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium">Detalhes</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <p className="text-xs text-muted-foreground mb-1">Responsável</p>
                  <Select 
                    value={ticket.assigned_to || 'unassigned'} 
                    onValueChange={handleAssigneeChange}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue>
                        {ticket.assignee ? (
                          <div className="flex items-center gap-2">
                            <Avatar className="h-5 w-5">
                              <AvatarImage src={ticket.assignee.avatar_url || ''} />
                              <AvatarFallback className="text-[10px]">
                                {ticket.assignee.first_name?.[0]}{ticket.assignee.last_name?.[0]}
                              </AvatarFallback>
                            </Avatar>
                            <span>{ticket.assignee.first_name} {ticket.assignee.last_name}</span>
                          </div>
                        ) : (
                          'Não atribuído'
                        )}
                      </SelectValue>
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="unassigned">Não atribuído</SelectItem>
                      {teamMembers.map((member) => (
                        <SelectItem key={member.id} value={member.id}>
                          <div className="flex items-center gap-2">
                            <Avatar className="h-5 w-5">
                              <AvatarImage src={member.avatar_url || ''} />
                              <AvatarFallback className="text-[10px]">
                                {member.first_name?.[0]}{member.last_name?.[0]}
                              </AvatarFallback>
                            </Avatar>
                            <span>{member.first_name} {member.last_name}</span>
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <p className="text-xs text-muted-foreground mb-1">Prioridade</p>
                  <Select 
                    value={ticket.priority} 
                    onValueChange={(v) => handlePriorityChange(v as TicketPriority)}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue>
                        <TicketPriorityBadge priority={ticket.priority as TicketPriority} />
                      </SelectValue>
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">
                        <TicketPriorityBadge priority="low" />
                      </SelectItem>
                      <SelectItem value="medium">
                        <TicketPriorityBadge priority="medium" />
                      </SelectItem>
                      <SelectItem value="high">
                        <TicketPriorityBadge priority="high" />
                      </SelectItem>
                      <SelectItem value="critical">
                        <TicketPriorityBadge priority="critical" />
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <Separator />

                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div>
                    <p className="text-xs text-muted-foreground">Tipo</p>
                    <p className="capitalize">{ticket.type}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">Canal</p>
                    <p className="capitalize">{ticket.channel}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">Categoria</p>
                    <p>{ticket.category?.name || '-'}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">Fila</p>
                    <p>{ticket.queue?.name || '-'}</p>
                  </div>
                </div>

                <Separator />

                <div className="text-sm">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Calendar className="h-4 w-4" />
                    Criado em {format(new Date(ticket.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                  </div>
                  <div className="flex items-center gap-2 text-muted-foreground mt-1">
                    <Clock className="h-4 w-4" />
                    Atualizado {formatDistanceToNow(new Date(ticket.updated_at), { addSuffix: true, locale: ptBR })}
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Customer Info */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium">Cliente</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {ticket.contacts && (
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <Avatar className="h-8 w-8">
                        <AvatarFallback>
                          {ticket.contacts.first_name?.[0]}{ticket.contacts.last_name?.[0]}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <Link 
                          to={`/contacts/${ticket.contacts.id}`}
                          className="font-medium hover:underline"
                        >
                          {ticket.contacts.first_name} {ticket.contacts.last_name}
                        </Link>
                        {ticket.contacts.job_title && (
                          <p className="text-xs text-muted-foreground">
                            {ticket.contacts.job_title}
                          </p>
                        )}
                      </div>
                    </div>
                    {ticket.contacts.email && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Mail className="h-4 w-4" />
                        <a href={`mailto:${ticket.contacts.email}`} className="hover:underline">
                          {ticket.contacts.email}
                        </a>
                      </div>
                    )}
                    {ticket.contacts.phone && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Phone className="h-4 w-4" />
                        <a href={`tel:${ticket.contacts.phone}`} className="hover:underline">
                          {ticket.contacts.phone}
                        </a>
                      </div>
                    )}
                  </div>
                )}

                {ticket.accounts && (
                  <>
                    <Separator />
                    <div className="space-y-2">
                      <div className="flex items-center gap-2">
                        <Building2 className="h-4 w-4 text-muted-foreground" />
                        <Link 
                          to={`/accounts/${ticket.accounts.id}`}
                          className="font-medium hover:underline"
                        >
                          {ticket.accounts.name}
                        </Link>
                      </div>
                      {ticket.accounts.website && (
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <Globe className="h-4 w-4" />
                          <a 
                            href={ticket.accounts.website} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="hover:underline"
                          >
                            {ticket.accounts.website}
                          </a>
                        </div>
                      )}
                    </div>
                  </>
                )}

                {!ticket.contacts && !ticket.accounts && (
                  <div className="text-center text-muted-foreground py-4">
                    <User className="h-8 w-8 mx-auto mb-2 opacity-50" />
                    <p className="text-sm">Nenhum cliente vinculado</p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { ArrowLeft, Save, Loader2 } from '@/components/icons';
import { useToast } from '@/hooks/use-toast';
import { CustomFieldsRenderer } from '@/components/CustomFieldsRenderer';
import { useCustomFieldDefinitions, useCustomFieldValues, useSaveCustomFieldValues, getFieldValue } from '@/hooks/useCustomFields';

const ticketSchema = z.object({
  subject: z.string().min(5, 'O assunto deve ter pelo menos 5 caracteres').max(200),
  description: z.string().min(10, 'A descrição deve ter pelo menos 10 caracteres'),
  type: z.enum(['incident', 'request', 'question', 'complaint', 'return']),
  priority: z.enum(['low', 'medium', 'high', 'critical']),
  channel: z.enum(['email', 'chat', 'phone', 'whatsapp', 'portal', 'form']),
  account_id: z.string().optional().nullable(),
  contact_id: z.string().optional().nullable(),
  category_id: z.string().optional().nullable(),
  queue_id: z.string().optional().nullable(),
  assigned_to: z.string().optional().nullable(),
});

type TicketFormData = z.infer<typeof ticketSchema>;

const typeLabels = {
  incident: 'Incidente',
  request: 'Solicitação',
  question: 'Dúvida',
  complaint: 'Reclamação',
  return: 'Devolução',
};

const priorityLabels = {
  low: 'Baixa',
  medium: 'Média',
  high: 'Alta',
  critical: 'Crítica',
};

const channelLabels = {
  email: 'E-mail',
  chat: 'Chat',
  phone: 'Telefone',
  whatsapp: 'WhatsApp',
  portal: 'Portal',
  form: 'Formulário',
};

export default function TicketForm() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const isEditing = !!id;
  const { data: customFieldDefs = [] } = useCustomFieldDefinitions('ticket');
  const { data: customFieldValuesData = [] } = useCustomFieldValues('ticket', id);
  const saveCustomFields = useSaveCustomFieldValues();
  const [customFieldValues, setCustomFieldValues] = useState<Record<string, any>>({});

  useEffect(() => {
    if (customFieldDefs.length > 0) {
      const values: Record<string, any> = {};
      customFieldDefs.forEach(def => {
        const fieldValue = customFieldValuesData.find(v => v.field_definition_id === def.id);
        values[def.id] = getFieldValue(def, fieldValue);
      });
      setCustomFieldValues(values);
    }
  }, [customFieldDefs, customFieldValuesData]);

  const form = useForm<TicketFormData>({
    resolver: zodResolver(ticketSchema),
    defaultValues: {
      subject: '',
      description: '',
      type: 'request',
      priority: 'medium',
      channel: 'portal',
      account_id: null,
      contact_id: null,
      category_id: null,
      queue_id: null,
      assigned_to: null,
    },
  });

  // Fetch existing ticket for edit mode
  const { data: ticket, isLoading: isLoadingTicket } = useQuery({
    queryKey: ['ticket', id],
    queryFn: async () => {
      if (!id) return null;
      const { data, error } = await supabase
        .from('tickets')
        .select('*')
        .eq('id', id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: isEditing,
  });

  // Fetch accounts
  const { data: accounts = [] } = useQuery({
    queryKey: ['accounts-select', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('accounts')
        .select('id, name')
        .eq('organization_id', profile.organization_id)
        .order('name');
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch contacts
  const { data: contacts = [] } = useQuery({
    queryKey: ['contacts-select', profile?.organization_id, form.watch('account_id')],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      let query = supabase
        .from('contacts')
        .select('id, first_name, last_name, email')
        .eq('organization_id', profile.organization_id)
        .order('first_name');

      const accountId = form.watch('account_id');
      if (accountId) {
        query = query.eq('account_id', accountId);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch categories
  const { data: categories = [] } = useQuery({
    queryKey: ['ticket-categories', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('ticket_categories')
        .select('id, name')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('name');
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch queues
  const { data: queues = [] } = useQuery({
    queryKey: ['ticket-queues', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('ticket_queues')
        .select('id, name')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('name');
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Fetch team members
  const { data: teamMembers = [] } = useQuery({
    queryKey: ['team-members', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name')
        .eq('organization_id', profile.organization_id)
        .eq('is_active', true)
        .order('first_name');
      if (error) throw error;
      return data || [];
    },
    enabled: !!profile?.organization_id,
  });

  // Populate form when editing
  useEffect(() => {
    if (ticket) {
      form.reset({
        subject: ticket.subject,
        description: ticket.description,
        type: ticket.type,
        priority: ticket.priority,
        channel: ticket.channel,
        account_id: ticket.account_id,
        contact_id: ticket.contact_id,
        category_id: ticket.category_id,
        queue_id: ticket.queue_id,
        assigned_to: ticket.assigned_to,
      });
    }
  }, [ticket, form]);

  // Create/Update mutation
  const mutation = useMutation({
    mutationFn: async (data: TicketFormData) => {
      if (!profile?.organization_id) throw new Error('Organização não encontrada');

      if (isEditing) {
        const updateData = {
          subject: data.subject,
          description: data.description,
          type: data.type,
          priority: data.priority,
          channel: data.channel,
          account_id: data.account_id || null,
          contact_id: data.contact_id || null,
          category_id: data.category_id || null,
          queue_id: data.queue_id || null,
          assigned_to: data.assigned_to || null,
          ...(data.assigned_to && !ticket?.assigned_to ? { assigned_at: new Date().toISOString() } : {}),
        };

        const { error } = await supabase
          .from('tickets')
          .update(updateData)
          .eq('id', id);
        if (error) throw error;
        return id;
      } else {
        // Generate ticket number using RPC
        const { data: ticketNumber } = await supabase.rpc('generate_ticket_number', {
          org_id: profile.organization_id,
        });

        const insertData = {
          organization_id: profile.organization_id,
          subject: data.subject,
          description: data.description,
          type: data.type,
          priority: data.priority,
          channel: data.channel,
          account_id: data.account_id || null,
          contact_id: data.contact_id || null,
          category_id: data.category_id || null,
          queue_id: data.queue_id || null,
          assigned_to: data.assigned_to || null,
          ticket_number: ticketNumber || `TKT-${Date.now()}`,
          reporter_id: profile.id,
          ...(data.assigned_to ? { assigned_at: new Date().toISOString() } : {}),
        };

        const { data: newTicket, error } = await supabase
          .from('tickets')
          .insert(insertData)
          .select('id')
          .single();
        if (error) throw error;
        return newTicket.id;
      }
    },
    onSuccess: (ticketId) => {
      queryClient.invalidateQueries({ queryKey: ['tickets'] });
      queryClient.invalidateQueries({ queryKey: ['ticket', ticketId] });
      if (customFieldDefs.length > 0 && ticketId) {
        saveCustomFields.mutate({ entityType: 'ticket', entityId: ticketId, values: customFieldValues, definitions: customFieldDefs });
      }
      toast({
        title: isEditing ? 'Ticket atualizado' : 'Ticket criado',
        description: isEditing 
          ? 'As alterações foram salvas com sucesso.'
          : 'O ticket foi criado com sucesso.',
      });
      navigate(`/tickets/${ticketId}`);
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao salvar',
        description: error.message,
        variant: 'destructive',
      });
    },
  });

  const onSubmit = (data: TicketFormData) => {
    mutation.mutate(data);
  };

  if (isEditing && isLoadingTicket) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate(-1)}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">
              {isEditing ? 'Editar Ticket' : 'Novo Ticket'}
            </h1>
            <p className="text-muted-foreground">
              {isEditing 
                ? 'Atualize as informações do ticket'
                : 'Preencha os dados para criar um novo ticket de suporte'
              }
            </p>
          </div>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            {/* Main Info */}
            <Card>
              <CardHeader>
                <CardTitle>Informações do Ticket</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="subject"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Assunto *</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Descreva brevemente o problema ou solicitação" 
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Descrição *</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Forneça todos os detalhes relevantes..."
                          className="min-h-[150px]"
                          {...field} 
                        />
                      </FormControl>
                      <FormDescription>
                        Inclua todas as informações necessárias para resolver o ticket.
                      </FormDescription>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <FormField
                    control={form.control}
                    name="type"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Tipo *</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione o tipo" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {Object.entries(typeLabels).map(([value, label]) => (
                              <SelectItem key={value} value={value}>
                                {label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="priority"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Prioridade *</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione a prioridade" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {Object.entries(priorityLabels).map(([value, label]) => (
                              <SelectItem key={value} value={value}>
                                {label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="channel"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Canal *</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione o canal" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {Object.entries(channelLabels).map(([value, label]) => (
                              <SelectItem key={value} value={value}>
                                {label}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Customer Info */}
            <Card>
              <CardHeader>
                <CardTitle>Cliente</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="account_id"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Conta/Empresa</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          value={field.value || ''}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione uma conta" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="">Nenhuma</SelectItem>
                            {accounts.map((account) => (
                              <SelectItem key={account.id} value={account.id}>
                                {account.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="contact_id"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Contato</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          value={field.value || ''}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione um contato" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="">Nenhum</SelectItem>
                            {contacts.map((contact) => (
                              <SelectItem key={contact.id} value={contact.id}>
                                {contact.first_name} {contact.last_name}
                                {contact.email && ` (${contact.email})`}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Assignment */}
            <Card>
              <CardHeader>
                <CardTitle>Atribuição</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <FormField
                    control={form.control}
                    name="category_id"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Categoria</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          value={field.value || ''}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione uma categoria" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="">Nenhuma</SelectItem>
                            {categories.map((cat) => (
                              <SelectItem key={cat.id} value={cat.id}>
                                {cat.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="queue_id"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Fila</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          value={field.value || ''}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione uma fila" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="">Nenhuma</SelectItem>
                            {queues.map((queue) => (
                              <SelectItem key={queue.id} value={queue.id}>
                                {queue.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="assigned_to"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Responsável</FormLabel>
                        <Select 
                          onValueChange={field.onChange} 
                          value={field.value || ''}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Atribuir para..." />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="">Não atribuído</SelectItem>
                            {teamMembers.map((member) => (
                              <SelectItem key={member.id} value={member.id}>
                                {member.first_name} {member.last_name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Custom Fields */}
            {customFieldDefs.length > 0 && (
              <CustomFieldsRenderer
                entityType="ticket"
                definitions={customFieldDefs}
                values={customFieldValues}
                onChange={setCustomFieldValues}
              />
            )}

            {/* Actions */}
            <div className="flex justify-end gap-4">
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => navigate(-1)}
              >
                Cancelar
              </Button>
              <Button type="submit" disabled={mutation.isPending}>
                {mutation.isPending && (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                )}
                <Save className="mr-2 h-4 w-4" />
                {isEditing ? 'Salvar Alterações' : 'Criar Ticket'}
              </Button>
            </div>
          </form>
        </Form>
      </div>
    </>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  ArrowLeft,
  Save,
  Play,
  Pause,
  Plus,
  Trash2,
  Settings,
  Zap,
  Clock,
  CheckCircle,
  XCircle,
  Mail,
  Bell,
  Users,
  FileText,
  Target,
  GitBranch,
  ArrowRight,
  Filter,
  RotateCcw,
  AlertTriangle,
  RefreshCw,
  GripVertical,
} from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Workflow {
  id: string;
  name: string;
  description: string | null;
  trigger_type: string;
  trigger_entity: string;
  trigger_conditions: Record<string, unknown>;
  trigger_fields: string[] | null;
  status: string;
  version: number;
  run_count: number;
  success_count: number;
  failure_count: number;
  last_run_at: string | null;
  retry_on_failure: boolean;
  max_retries: number;
  notify_on_failure: boolean;
  timeout_minutes: number;
  created_at: string;
  updated_at: string;
}

interface WorkflowStep {
  id: string;
  workflow_id: string;
  step_order: number;
  step_key: string;
  type: string;
  name: string;
  description: string | null;
  config: Record<string, unknown>;
  conditions: unknown[];
  next_step_on_success: string | null;
  next_step_on_failure: string | null;
  is_entry_point: boolean;
  is_exit_point: boolean;
  continue_on_error: boolean;
  position_x: number;
  position_y: number;
}

const stepTypeConfig: Record<string, { label: string; icon: React.ReactNode; color: string; description: string }> = {
  condition: { label: 'Condição', icon: <Filter className="h-4 w-4" />, color: 'bg-yellow-500', description: 'Verifica uma condição antes de continuar' },
  action: { label: 'Ação', icon: <Zap className="h-4 w-4" />, color: 'bg-blue-500', description: 'Executa uma ação genérica' },
  delay: { label: 'Delay', icon: <Clock className="h-4 w-4" />, color: 'bg-gray-500', description: 'Aguarda um tempo antes de continuar' },
  approval: { label: 'Aprovação', icon: <CheckCircle className="h-4 w-4" />, color: 'bg-purple-500', description: 'Solicita aprovação de um usuário' },
  notification: { label: 'Notificação', icon: <Bell className="h-4 w-4" />, color: 'bg-green-500', description: 'Envia uma notificação' },
  field_update: { label: 'Atualizar Campo', icon: <FileText className="h-4 w-4" />, color: 'bg-orange-500', description: 'Atualiza um campo do registro' },
  send_email: { label: 'Enviar Email', icon: <Mail className="h-4 w-4" />, color: 'bg-pink-500', description: 'Envia um email' },
  assign_owner: { label: 'Atribuir Responsável', icon: <Users className="h-4 w-4" />, color: 'bg-indigo-500', description: 'Atribui um novo responsável' },
  create_task: { label: 'Criar Tarefa', icon: <Target className="h-4 w-4" />, color: 'bg-teal-500', description: 'Cria uma nova tarefa' },
  create_record: { label: 'Criar Registro', icon: <Plus className="h-4 w-4" />, color: 'bg-cyan-500', description: 'Cria um novo registro' },
  webhook: { label: 'Webhook', icon: <ArrowRight className="h-4 w-4" />, color: 'bg-red-500', description: 'Chama uma URL externa' },
};

const triggerTypeLabels: Record<string, string> = {
  record_created: 'Registro Criado',
  record_updated: 'Registro Atualizado',
  field_changed: 'Campo Alterado',
  scheduled: 'Agendado',
  manual: 'Manual',
  approval_completed: 'Aprovação Concluída',
  sla_breach: 'SLA Violado',
  stage_changed: 'Estágio Alterado',
  score_changed: 'Score Alterado',
};

const entityLabels: Record<string, string> = {
  lead: 'Lead',
  opportunity: 'Oportunidade',
  account: 'Conta',
  contact: 'Contato',
  ticket: 'Ticket',
  quote: 'Cotação',
  contract: 'Contrato',
};

export default function WorkflowBuilder() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const { toast } = useToast();
  const [workflow, setWorkflow] = useState<Workflow | null>(null);
  const [steps, setSteps] = useState<WorkflowStep[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [selectedStep, setSelectedStep] = useState<WorkflowStep | null>(null);
  const [stepSheetOpen, setStepSheetOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [stepToDelete, setStepToDelete] = useState<WorkflowStep | null>(null);
  const [addStepDialogOpen, setAddStepDialogOpen] = useState(false);

  useEffect(() => {
    if (id) {
      fetchWorkflow();
      fetchSteps();
    }
  }, [id]);

  const fetchWorkflow = async () => {
    if (!id) return;

    const { data, error } = await supabase
      .from('workflows')
      .select('*')
      .eq('id', id)
      .single();

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Workflow não encontrado',
      });
      navigate('/automations');
      return;
    }

    setWorkflow(data as unknown as Workflow);
    setLoading(false);
  };

  const fetchSteps = async () => {
    if (!id) return;

    const { data, error } = await supabase
      .from('workflow_steps')
      .select('*')
      .eq('workflow_id', id)
      .order('step_order');

    if (!error && data) {
      setSteps(data as unknown as WorkflowStep[]);
    }
  };

  const handleSaveWorkflow = async () => {
    if (!workflow) return;

    setSaving(true);

    const { error } = await supabase
      .from('workflows')
      .update({
        name: workflow.name,
        description: workflow.description,
        trigger_type: workflow.trigger_type as any,
        trigger_entity: workflow.trigger_entity,
        trigger_conditions: workflow.trigger_conditions as any,
        trigger_fields: workflow.trigger_fields,
        retry_on_failure: workflow.retry_on_failure,
        max_retries: workflow.max_retries,
        notify_on_failure: workflow.notify_on_failure,
        timeout_minutes: workflow.timeout_minutes,
        updated_by: profile?.id,
      })
      .eq('id', workflow.id);

    if (error) {
      toast({
        variant: 'destructive',
        title: 'Erro',
        description: 'Falha ao salvar workflow',
      });
    } else {
      toast({
        title: 'Workflow salvo',
        description: 'As alterações foram salvas com sucesso.',
      });
    }

    setSaving(false);
  };

  const toggleWorkflowStatus = async () => {
    if (!workflow) return;

    const newStatus = workflow.status === 'active' ? 'paused' : 'active';

    const { error } = await supabase
      .from('workflows')
      .update({ status: newStatus })
      .eq('id', workflow.id);

    if (!error) {
      setWorkflow({ ...workflow, status: newStatus });
      toast({
        title: newStatus === 'active' ? 'Workflow ativado' : 'Workflow pausado',
        description: `O workflow foi ${newStatus === 'active' ? 'ativado' : 'pausado'}.`,
      });
    }
  };

  const addStep = async (type: string) => {
    if (!workflow || !profile?.organization_id) return;

    const stepConfig = stepTypeConfig[type];
    const stepKey = `step_${Date.now()}`;
    const stepOrder = steps.length + 1;

    const { data, error } = await supabase
      .from('workflow_steps')
      .insert([{
        workflow_id: workflow.id,
        step_order: stepOrder,
        step_key: stepKey,
        type: type as any,
        name: stepConfig.label,
        config: {} as any,
        is_entry_point: steps.length === 0,
        position_x: 100,
        position_y: stepOrder * 120,
      }])
      .select()
      .single();

    if (!error && data) {
      setSteps([...steps, data as unknown as WorkflowStep]);
      setAddStepDialogOpen(false);
      toast({
        title: 'Step adicionado',
        description: `"${stepConfig.label}" foi adicionado ao workflow.`,
      });
    }
  };

  const updateStep = async (step: WorkflowStep) => {
    const { error } = await supabase
      .from('workflow_steps')
      .update({
        name: step.name,
        description: step.description,
        config: step.config as any,
        conditions: step.conditions as any,
        next_step_on_success: step.next_step_on_success,
        next_step_on_failure: step.next_step_on_failure,
        continue_on_error: step.continue_on_error,
      })
      .eq('id', step.id);

    if (!error) {
      setSteps(steps.map(s => s.id === step.id ? step : s));
      toast({
        title: 'Step atualizado',
        description: 'As alterações foram salvas.',
      });
    }
  };

  const deleteStep = async () => {
    if (!stepToDelete) return;

    const { error } = await supabase
      .from('workflow_steps')
      .delete()
      .eq('id', stepToDelete.id);

    if (!error) {
      setSteps(steps.filter(s => s.id !== stepToDelete.id));
      setDeleteDialogOpen(false);
      setStepToDelete(null);
      toast({
        title: 'Step removido',
        description: 'O step foi removido do workflow.',
      });
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!workflow) {
    return null;
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate('/automations')}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold">{workflow.name}</h1>
              <Badge variant={workflow.status === 'active' ? 'default' : 'secondary'}>
                {workflow.status === 'active' ? 'Ativo' : workflow.status === 'paused' ? 'Pausado' : 'Rascunho'}
              </Badge>
            </div>
            {workflow.description && (
              <p className="text-muted-foreground">{workflow.description}</p>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={toggleWorkflowStatus}>
            {workflow.status === 'active' ? (
              <>
                <Pause className="mr-2 h-4 w-4" />
                Pausar
              </>
            ) : (
              <>
                <Play className="mr-2 h-4 w-4" />
                Ativar
              </>
            )}
          </Button>
          <Button onClick={handleSaveWorkflow} disabled={saving}>
            {saving ? <RefreshCw className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
            Salvar
          </Button>
        </div>
      </div>

      <Tabs defaultValue="builder" className="space-y-4">
        <TabsList>
          <TabsTrigger value="builder">Builder</TabsTrigger>
          <TabsTrigger value="trigger">Trigger</TabsTrigger>
          <TabsTrigger value="settings">Configurações</TabsTrigger>
          <TabsTrigger value="history">Histórico</TabsTrigger>
        </TabsList>

        <TabsContent value="builder" className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold">Steps do Workflow</h2>
            <Button onClick={() => setAddStepDialogOpen(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Adicionar Step
            </Button>
          </div>

          {/* Trigger Card */}
          <Card className="border-l-4 border-l-primary">
            <CardContent className="py-4">
              <div className="flex items-center gap-4">
                <div className="p-2 rounded-lg bg-primary/10 text-primary">
                  <Zap className="h-6 w-6" />
                </div>
                <div className="flex-1">
                  <p className="font-medium">Trigger: {triggerTypeLabels[workflow.trigger_type]}</p>
                  <p className="text-sm text-muted-foreground">
                    Quando um {entityLabels[workflow.trigger_entity]} for {workflow.trigger_type === 'record_created' ? 'criado' : 'atualizado'}
                  </p>
                </div>
                <Badge variant="outline">{entityLabels[workflow.trigger_entity]}</Badge>
              </div>
            </CardContent>
          </Card>

          {/* Steps List */}
          <div className="space-y-3">
            {steps.length === 0 ? (
              <Card>
                <CardContent className="py-12 text-center">
                  <GitBranch className="h-12 w-12 mx-auto mb-4 text-muted-foreground opacity-50" />
                  <p className="text-muted-foreground mb-4">Nenhum step configurado</p>
                  <Button onClick={() => setAddStepDialogOpen(true)}>
                    <Plus className="mr-2 h-4 w-4" />
                    Adicionar Primeiro Step
                  </Button>
                </CardContent>
              </Card>
            ) : (
              steps.map((step, index) => {
                const config = stepTypeConfig[step.type] || { label: step.type, icon: <Zap className="h-4 w-4" />, color: 'bg-gray-500' };
                return (
                  <Card 
                    key={step.id}
                    className="cursor-pointer hover:border-primary transition-colors"
                    onClick={() => {
                      setSelectedStep(step);
                      setStepSheetOpen(true);
                    }}
                  >
                    <CardContent className="py-4">
                      <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <GripVertical className="h-4 w-4" />
                          <span className="text-sm font-medium">{index + 1}</span>
                        </div>
                        <div className={`p-2 rounded-lg text-white ${config.color}`}>
                          {config.icon}
                        </div>
                        <div className="flex-1">
                          <p className="font-medium">{step.name}</p>
                          {step.description && (
                            <p className="text-sm text-muted-foreground">{step.description}</p>
                          )}
                        </div>
                        <div className="flex items-center gap-2">
                          {step.is_entry_point && <Badge variant="outline">Início</Badge>}
                          {step.is_exit_point && <Badge variant="outline">Fim</Badge>}
                          {step.continue_on_error && (
                            <Badge variant="secondary">Continua em erro</Badge>
                          )}
                        </div>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={(e) => {
                            e.stopPropagation();
                            setStepToDelete(step);
                            setDeleteDialogOpen(true);
                          }}
                        >
                          <Trash2 className="h-4 w-4 text-muted-foreground" />
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                );
              })
            )}
          </div>

          {steps.length > 0 && (
            <div className="flex justify-center">
              <Button variant="outline" onClick={() => setAddStepDialogOpen(true)}>
                <Plus className="mr-2 h-4 w-4" />
                Adicionar Step
              </Button>
            </div>
          )}
        </TabsContent>

        <TabsContent value="trigger" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Configuração do Trigger</CardTitle>
              <CardDescription>
                Defina quando este workflow deve ser executado
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Tipo de Trigger</Label>
                  <Select
                    value={workflow.trigger_type}
                    onValueChange={(v) => setWorkflow({ ...workflow, trigger_type: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(triggerTypeLabels).map(([key, label]) => (
                        <SelectItem key={key} value={key}>{label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Entidade</Label>
                  <Select
                    value={workflow.trigger_entity}
                    onValueChange={(v) => setWorkflow({ ...workflow, trigger_entity: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(entityLabels).map(([key, label]) => (
                        <SelectItem key={key} value={key}>{label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {workflow.trigger_type === 'field_changed' && (
                <div className="space-y-2">
                  <Label>Campos Monitorados</Label>
                  <Input
                    placeholder="status, score, owner_id (separados por vírgula)"
                    value={workflow.trigger_fields?.join(', ') || ''}
                    onChange={(e) => setWorkflow({
                      ...workflow,
                      trigger_fields: e.target.value.split(',').map(f => f.trim()).filter(Boolean)
                    })}
                  />
                  <p className="text-sm text-muted-foreground">
                    O workflow será executado quando qualquer um desses campos for alterado
                  </p>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="settings" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Informações Básicas</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Nome</Label>
                <Input
                  value={workflow.name}
                  onChange={(e) => setWorkflow({ ...workflow, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={workflow.description || ''}
                  onChange={(e) => setWorkflow({ ...workflow, description: e.target.value })}
                  rows={3}
                />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Comportamento</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label>Retentar em Falha</Label>
                  <p className="text-sm text-muted-foreground">
                    Tentar executar novamente se houver erro
                  </p>
                </div>
                <Switch
                  checked={workflow.retry_on_failure}
                  onCheckedChange={(checked) => setWorkflow({ ...workflow, retry_on_failure: checked })}
                />
              </div>

              {workflow.retry_on_failure && (
                <div className="space-y-2">
                  <Label>Máximo de Retentativas</Label>
                  <Input
                    type="number"
                    value={workflow.max_retries}
                    onChange={(e) => setWorkflow({ ...workflow, max_retries: parseInt(e.target.value) || 3 })}
                    min={1}
                    max={10}
                  />
                </div>
              )}

              <div className="flex items-center justify-between">
                <div>
                  <Label>Notificar em Falha</Label>
                  <p className="text-sm text-muted-foreground">
                    Enviar notificação quando o workflow falhar
                  </p>
                </div>
                <Switch
                  checked={workflow.notify_on_failure}
                  onCheckedChange={(checked) => setWorkflow({ ...workflow, notify_on_failure: checked })}
                />
              </div>

              <div className="space-y-2">
                <Label>Timeout (minutos)</Label>
                <Input
                  type="number"
                  value={workflow.timeout_minutes}
                  onChange={(e) => setWorkflow({ ...workflow, timeout_minutes: parseInt(e.target.value) || 60 })}
                  min={1}
                  max={1440}
                />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Estatísticas</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid gap-4 md:grid-cols-4">
                <div>
                  <p className="text-sm text-muted-foreground">Versão</p>
                  <p className="text-2xl font-bold">{workflow.version}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Execuções</p>
                  <p className="text-2xl font-bold">{workflow.run_count}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Sucesso</p>
                  <p className="text-2xl font-bold text-green-600">{workflow.success_count}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Falhas</p>
                  <p className="text-2xl font-bold text-red-600">{workflow.failure_count}</p>
                </div>
              </div>
              {workflow.last_run_at && (
                <p className="text-sm text-muted-foreground mt-4">
                  Última execução: {format(new Date(workflow.last_run_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                </p>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="history" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Histórico de Execuções</CardTitle>
              <CardDescription>
                Veja as últimas execuções deste workflow
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="text-center py-8 text-muted-foreground">
                O histórico de execuções será exibido aqui
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Step Editor Sheet */}
      <Sheet open={stepSheetOpen} onOpenChange={setStepSheetOpen}>
        <SheetContent className="sm:max-w-lg">
          <SheetHeader>
            <SheetTitle>Editar Step</SheetTitle>
            <SheetDescription>
              Configure as propriedades deste step
            </SheetDescription>
          </SheetHeader>
          {selectedStep && (
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label>Nome</Label>
                <Input
                  value={selectedStep.name}
                  onChange={(e) => setSelectedStep({ ...selectedStep, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Descrição</Label>
                <Textarea
                  value={selectedStep.description || ''}
                  onChange={(e) => setSelectedStep({ ...selectedStep, description: e.target.value })}
                  rows={2}
                />
              </div>
              <div className="flex items-center justify-between">
                <div>
                  <Label>Continuar em Erro</Label>
                  <p className="text-sm text-muted-foreground">
                    Prosseguir mesmo se houver erro
                  </p>
                </div>
                <Switch
                  checked={selectedStep.continue_on_error}
                  onCheckedChange={(checked) => setSelectedStep({ ...selectedStep, continue_on_error: checked })}
                />
              </div>

              {/* Config específica por tipo de step */}
              {selectedStep.type === 'delay' && (
                <div className="space-y-2">
                  <Label>Tempo de Espera (minutos)</Label>
                  <Input
                    type="number"
                    value={(selectedStep.config as any).delay_minutes || 0}
                    onChange={(e) => setSelectedStep({
                      ...selectedStep,
                      config: { ...selectedStep.config, delay_minutes: parseInt(e.target.value) || 0 }
                    })}
                  />
                </div>
              )}

              {selectedStep.type === 'notification' && (
                <>
                  <div className="space-y-2">
                    <Label>Título</Label>
                    <Input
                      value={(selectedStep.config as any).title || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, title: e.target.value }
                      })}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Mensagem</Label>
                    <Textarea
                      value={(selectedStep.config as any).message || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, message: e.target.value }
                      })}
                      rows={3}
                    />
                  </div>
                </>
              )}

              {selectedStep.type === 'field_update' && (
                <>
                  <div className="space-y-2">
                    <Label>Campo</Label>
                    <Input
                      value={(selectedStep.config as any).field || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, field: e.target.value }
                      })}
                      placeholder="Ex: status"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Novo Valor</Label>
                    <Input
                      value={(selectedStep.config as any).value || ''}
                      onChange={(e) => setSelectedStep({
                        ...selectedStep,
                        config: { ...selectedStep.config, value: e.target.value }
                      })}
                    />
                  </div>
                </>
              )}

              <div className="flex gap-2 pt-4">
                <Button
                  variant="outline"
                  className="flex-1"
                  onClick={() => setStepSheetOpen(false)}
                >
                  Cancelar
                </Button>
                <Button
                  className="flex-1"
                  onClick={() => {
                    updateStep(selectedStep);
                    setStepSheetOpen(false);
                  }}
                >
                  Salvar
                </Button>
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>

      {/* Add Step Dialog */}
      <AlertDialog open={addStepDialogOpen} onOpenChange={setAddStepDialogOpen}>
        <AlertDialogContent className="max-w-2xl">
          <AlertDialogHeader>
            <AlertDialogTitle>Adicionar Step</AlertDialogTitle>
            <AlertDialogDescription>
              Escolha o tipo de step que deseja adicionar
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="grid gap-3 md:grid-cols-2 py-4">
            {Object.entries(stepTypeConfig).map(([type, config]) => (
              <Card
                key={type}
                className="cursor-pointer hover:border-primary transition-colors"
                onClick={() => addStep(type)}
              >
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg text-white ${config.color}`}>
                      {config.icon}
                    </div>
                    <div>
                      <p className="font-medium">{config.label}</p>
                      <p className="text-xs text-muted-foreground">{config.description}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Delete Step Dialog */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remover Step</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja remover este step? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={deleteStep}>Remover</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { DragDropContext, Droppable, Draggable, type DropResult } from '@hello-pangea/dnd';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import {
  Plus,
  GripVertical,
  Edit,
  Trash2,
  Eye,
  EyeOff,
  Hash,
  Type,
  Calendar,
  ToggleLeft,
  List,
  ListChecks,
  Globe,
  Mail,
  Phone,
  AlignLeft,
  Link,
  Loader2,
} from '@/components/icons';
import { useToast } from '@/hooks/use-toast';
import {
  useAllCustomFieldDefinitions,
  useSaveCustomFieldDefinition,
  useDeleteCustomFieldDefinition,
  useUpdateFieldOrder,
  type CustomFieldDefinition,
  type CustomFieldEntityType,
  type CustomFieldType,
} from '@/hooks/useCustomFields';

const ENTITY_TABS: { value: CustomFieldEntityType; label: string }[] = [
  { value: 'lead', label: 'Leads' },
  { value: 'contact', label: 'Contatos' },
  { value: 'account', label: 'Contas' },
  { value: 'opportunity', label: 'Oportunidades' },
  { value: 'ticket', label: 'Tickets' },
  { value: 'order', label: 'Pedidos' },
];

const FIELD_TYPES: { value: CustomFieldType; label: string; icon: React.ElementType }[] = [
  { value: 'text', label: 'Texto', icon: Type },
  { value: 'number', label: 'Número', icon: Hash },
  { value: 'decimal', label: 'Decimal', icon: Hash },
  { value: 'date', label: 'Data', icon: Calendar },
  { value: 'datetime', label: 'Data e Hora', icon: Calendar },
  { value: 'boolean', label: 'Sim/Não', icon: ToggleLeft },
  { value: 'select', label: 'Seleção', icon: List },
  { value: 'multiselect', label: 'Múltipla Seleção', icon: ListChecks },
  { value: 'url', label: 'URL', icon: Globe },
  { value: 'email', label: 'Email', icon: Mail },
  { value: 'phone', label: 'Telefone', icon: Phone },
  { value: 'textarea', label: 'Texto Longo', icon: AlignLeft },
  { value: 'lookup', label: 'Lookup', icon: Link },
];

const getFieldTypeIcon = (type: CustomFieldType) => {
  const found = FIELD_TYPES.find(f => f.value === type);
  return found?.icon || Type;
};

interface FieldFormState {
  id?: string;
  field_name: string;
  field_label: string;
  field_type: CustomFieldType;
  is_required: boolean;
  default_value: string;
  description: string;
  placeholder: string;
  section_name: string;
  options: { label: string; value: string }[];
  validation_min: string;
  validation_max: string;
  validation_min_length: string;
  validation_max_length: string;
}

const emptyFormState: FieldFormState = {
  field_name: '',
  field_label: '',
  field_type: 'text',
  is_required: false,
  default_value: '',
  description: '',
  placeholder: '',
  section_name: 'Campos Personalizados',
  options: [],
  validation_min: '',
  validation_max: '',
  validation_min_length: '',
  validation_max_length: '',
};

export default function CustomFieldsAdmin() {
  const [activeEntity, setActiveEntity] = useState<CustomFieldEntityType>('lead');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [formState, setFormState] = useState<FieldFormState>(emptyFormState);
  const [optionInput, setOptionInput] = useState('');

  const { data: allDefinitions = [], isLoading } = useAllCustomFieldDefinitions();
  const saveMutation = useSaveCustomFieldDefinition();
  const deleteMutation = useDeleteCustomFieldDefinition();
  const reorderMutation = useUpdateFieldOrder();

  const entityFields = allDefinitions
    .filter((d) => d.entity_type === activeEntity)
    .sort((a, b) => a.display_order - b.display_order);

  const activeFields = entityFields.filter(d => d.is_active);
  const inactiveFields = entityFields.filter(d => !d.is_active);

  const handleOpenCreate = () => {
    setFormState(emptyFormState);
    setDialogOpen(true);
  };

  const handleOpenEdit = (def: CustomFieldDefinition) => {
    setFormState({
      id: def.id,
      field_name: def.field_name,
      field_label: def.field_label,
      field_type: def.field_type,
      is_required: def.is_required,
      default_value: def.default_value || '',
      description: def.description || '',
      placeholder: def.placeholder || '',
      section_name: def.section_name || 'Campos Personalizados',
      options: (def.options || []) as { label: string; value: string }[],
      validation_min: def.validation_rules?.min?.toString() || '',
      validation_max: def.validation_rules?.max?.toString() || '',
      validation_min_length: def.validation_rules?.min_length?.toString() || '',
      validation_max_length: def.validation_rules?.max_length?.toString() || '',
    });
    setDialogOpen(true);
  };

  const handleSave = () => {
    if (!formState.field_label.trim()) return;

    // Auto-generate field_name from label if not set
    const fieldName = formState.field_name.trim() || 
      formState.field_label
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '_')
        .replace(/^_|_$/g, '');

    const validationRules: any = {};
    if (formState.validation_min) validationRules.min = Number(formState.validation_min);
    if (formState.validation_max) validationRules.max = Number(formState.validation_max);
    if (formState.validation_min_length) validationRules.min_length = Number(formState.validation_min_length);
    if (formState.validation_max_length) validationRules.max_length = Number(formState.validation_max_length);

    saveMutation.mutate({
      id: formState.id,
      entity_type: activeEntity,
      field_name: fieldName,
      field_label: formState.field_label,
      field_type: formState.field_type,
      is_required: formState.is_required,
      default_value: formState.default_value || null,
      description: formState.description || null,
      placeholder: formState.placeholder || null,
      section_name: formState.section_name || 'Campos Personalizados',
      options: formState.options,
      validation_rules: Object.keys(validationRules).length > 0 ? validationRules : {},
      display_order: formState.id ? undefined : activeFields.length,
      is_active: true,
    } as any, {
      onSuccess: () => setDialogOpen(false),
    });
  };

  const handleAddOption = () => {
    if (!optionInput.trim()) return;
    const value = optionInput.toLowerCase().replace(/[^a-z0-9]+/g, '_');
    setFormState(prev => ({
      ...prev,
      options: [...prev.options, { label: optionInput.trim(), value }],
    }));
    setOptionInput('');
  };

  const handleRemoveOption = (index: number) => {
    setFormState(prev => ({
      ...prev,
      options: prev.options.filter((_, i) => i !== index),
    }));
  };

  const handleDragEnd = (result: DropResult) => {
    if (!result.destination) return;

    const reordered = [...activeFields];
    const [moved] = reordered.splice(result.source.index, 1);
    reordered.splice(result.destination.index, 0, moved);

    const updates = reordered.map((field, index) => ({
      id: field.id,
      display_order: index,
    }));

    reorderMutation.mutate(updates);
  };

  const showOptions = ['select', 'multiselect'].includes(formState.field_type);
  const showNumericValidation = ['number', 'decimal'].includes(formState.field_type);
  const showTextValidation = ['text', 'textarea', 'email', 'url', 'phone'].includes(formState.field_type);

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Campos Personalizados</h1>
            <p className="text-muted-foreground">
              Configure campos customizados para cada tipo de entidade
            </p>
          </div>
          <Button onClick={handleOpenCreate}>
            <Plus className="mr-2 h-4 w-4" />
            Novo Campo
          </Button>
        </div>

        <Tabs value={activeEntity} onValueChange={(v) => setActiveEntity(v as CustomFieldEntityType)}>
          <TabsList className="grid grid-cols-6 w-full max-w-2xl">
            {ENTITY_TABS.map((tab) => {
              const count = allDefinitions.filter(d => d.entity_type === tab.value && d.is_active).length;
              return (
                <TabsTrigger key={tab.value} value={tab.value} className="text-xs">
                  {tab.label}
                  {count > 0 && (
                    <Badge variant="secondary" className="ml-1.5 text-xs h-5 min-w-[20px]">
                      {count}
                    </Badge>
                  )}
                </TabsTrigger>
              );
            })}
          </TabsList>

          {ENTITY_TABS.map((tab) => (
            <TabsContent key={tab.value} value={tab.value} className="mt-6">
              {isLoading ? (
                <div className="flex items-center justify-center py-12">
                  <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                </div>
              ) : activeFields.length === 0 ? (
                <Card>
                  <CardContent className="flex flex-col items-center justify-center py-12">
                    <Type className="h-12 w-12 text-muted-foreground/50 mb-4" />
                    <h3 className="text-lg font-medium mb-1">Nenhum campo personalizado</h3>
                    <p className="text-sm text-muted-foreground mb-4">
                      Adicione campos customizados para {tab.label.toLowerCase()}
                    </p>
                    <Button onClick={handleOpenCreate}>
                      <Plus className="mr-2 h-4 w-4" />
                      Criar Primeiro Campo
                    </Button>
                  </CardContent>
                </Card>
              ) : (
                <Card>
                  <CardHeader>
                    <CardTitle>Campos Ativos</CardTitle>
                    <CardDescription>
                      Arraste para reordenar. Os campos aparecerão nesta ordem nos formulários.
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    <DragDropContext onDragEnd={handleDragEnd}>
                      <Droppable droppableId="fields">
                        {(provided) => (
                          <div ref={provided.innerRef} {...provided.droppableProps} className="space-y-2">
                            {activeFields.map((field, index) => {
                              const FieldIcon = getFieldTypeIcon(field.field_type);
                              return (
                                <Draggable key={field.id} draggableId={field.id} index={index}>
                                  {(provided, snapshot) => (
                                    <div
                                      ref={provided.innerRef}
                                      {...provided.draggableProps}
                                      className={`flex items-center gap-3 p-3 rounded-lg border transition-colors ${
                                        snapshot.isDragging ? 'bg-accent shadow-lg' : 'bg-card hover:bg-muted/50'
                                      }`}
                                    >
                                      <div {...provided.dragHandleProps} className="cursor-grab">
                                        <GripVertical className="h-4 w-4 text-muted-foreground" />
                                      </div>
                                      <div className="p-1.5 rounded bg-muted">
                                        <FieldIcon className="h-4 w-4 text-muted-foreground" />
                                      </div>
                                      <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2">
                                          <span className="font-medium text-sm">{field.field_label}</span>
                                          {field.is_required && (
                                            <Badge variant="destructive" className="text-[10px] h-4">Obrigatório</Badge>
                                          )}
                                          <Badge variant="outline" className="text-[10px] h-4">{field.field_type}</Badge>
                                        </div>
                                        <p className="text-xs text-muted-foreground truncate">
                                          {field.section_name} · {field.field_name}
                                          {field.description ? ` · ${field.description}` : ''}
                                        </p>
                                      </div>
                                      <div className="flex gap-1">
                                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleOpenEdit(field)}>
                                          <Edit className="h-3.5 w-3.5" />
                                        </Button>
                                        <AlertDialog>
                                          <AlertDialogTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive">
                                              <EyeOff className="h-3.5 w-3.5" />
                                            </Button>
                                          </AlertDialogTrigger>
                                          <AlertDialogContent>
                                            <AlertDialogHeader>
                                              <AlertDialogTitle>Desativar Campo</AlertDialogTitle>
                                              <AlertDialogDescription>
                                                O campo "{field.field_label}" será desativado mas os dados existentes serão preservados.
                                              </AlertDialogDescription>
                                            </AlertDialogHeader>
                                            <AlertDialogFooter>
                                              <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                              <AlertDialogAction onClick={() => deleteMutation.mutate(field.id)}>
                                                Desativar
                                              </AlertDialogAction>
                                            </AlertDialogFooter>
                                          </AlertDialogContent>
                                        </AlertDialog>
                                      </div>
                                    </div>
                                  )}
                                </Draggable>
                              );
                            })}
                            {provided.placeholder}
                          </div>
                        )}
                      </Droppable>
                    </DragDropContext>
                  </CardContent>
                </Card>
              )}

              {inactiveFields.length > 0 && (
                <Card className="mt-4">
                  <CardHeader>
                    <CardTitle className="text-base">Campos Desativados ({inactiveFields.length})</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      {inactiveFields.map((field) => {
                        const FieldIcon = getFieldTypeIcon(field.field_type);
                        return (
                          <div key={field.id} className="flex items-center gap-3 p-3 rounded-lg border opacity-60">
                            <div className="p-1.5 rounded bg-muted">
                              <FieldIcon className="h-4 w-4 text-muted-foreground" />
                            </div>
                            <div className="flex-1">
                              <span className="text-sm line-through">{field.field_label}</span>
                            </div>
                            <Badge variant="outline" className="text-[10px]">Desativado</Badge>
                          </div>
                        );
                      })}
                    </div>
                  </CardContent>
                </Card>
              )}
            </TabsContent>
          ))}
        </Tabs>
      </div>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{formState.id ? 'Editar Campo' : 'Novo Campo Personalizado'}</DialogTitle>
            <DialogDescription>
              {formState.id
                ? 'Atualize as configurações do campo personalizado'
                : `Criar um novo campo para ${ENTITY_TABS.find(t => t.value === activeEntity)?.label || activeEntity}`}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            {/* Basic */}
            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label>Nome de Exibição *</Label>
                <Input
                  value={formState.field_label}
                  onChange={(e) => setFormState(prev => ({ ...prev, field_label: e.target.value }))}
                  placeholder="Ex: CNPJ da Empresa"
                />
              </div>
              <div className="space-y-2">
                <Label>Nome do Campo (slug)</Label>
                <Input
                  value={formState.field_name}
                  onChange={(e) => setFormState(prev => ({ ...prev, field_name: e.target.value }))}
                  placeholder="Auto-gerado do nome"
                />
              </div>
            </div>

            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label>Tipo do Campo *</Label>
                <Select
                  value={formState.field_type}
                  onValueChange={(v) => setFormState(prev => ({ ...prev, field_type: v as CustomFieldType }))}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {FIELD_TYPES.map((ft) => {
                      const Icon = ft.icon;
                      return (
                        <SelectItem key={ft.value} value={ft.value}>
                          <div className="flex items-center gap-2">
                            <Icon className="h-3.5 w-3.5" />
                            {ft.label}
                          </div>
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Seção</Label>
                <Input
                  value={formState.section_name}
                  onChange={(e) => setFormState(prev => ({ ...prev, section_name: e.target.value }))}
                  placeholder="Campos Personalizados"
                />
              </div>
            </div>

            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label>Placeholder</Label>
                <Input
                  value={formState.placeholder}
                  onChange={(e) => setFormState(prev => ({ ...prev, placeholder: e.target.value }))}
                  placeholder="Texto de ajuda no campo"
                />
              </div>
              <div className="space-y-2">
                <Label>Valor Padrão</Label>
                <Input
                  value={formState.default_value}
                  onChange={(e) => setFormState(prev => ({ ...prev, default_value: e.target.value }))}
                  placeholder="Valor inicial"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label>Descrição</Label>
              <Textarea
                value={formState.description}
                onChange={(e) => setFormState(prev => ({ ...prev, description: e.target.value }))}
                placeholder="Descrição do campo para ajudar os usuários"
                rows={2}
              />
            </div>

            <div className="flex items-center gap-2">
              <Switch
                checked={formState.is_required}
                onCheckedChange={(checked) => setFormState(prev => ({ ...prev, is_required: checked }))}
              />
              <Label>Campo obrigatório</Label>
            </div>

            {/* Options for select/multiselect */}
            {showOptions && (
              <div className="space-y-2">
                <Label>Opções</Label>
                <div className="flex gap-2">
                  <Input
                    value={optionInput}
                    onChange={(e) => setOptionInput(e.target.value)}
                    placeholder="Adicionar opção..."
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
                        e.preventDefault();
                        handleAddOption();
                      }
                    }}
                  />
                  <Button type="button" variant="outline" onClick={handleAddOption}>
                    <Plus className="h-4 w-4" />
                  </Button>
                </div>
                <div className="flex flex-wrap gap-2 mt-2">
                  {formState.options.map((opt, i) => (
                    <Badge key={i} variant="secondary" className="gap-1">
                      {opt.label}
                      <button
                        onClick={() => handleRemoveOption(i)}
                        className="ml-1 hover:text-destructive"
                      >
                        ×
                      </button>
                    </Badge>
                  ))}
                </div>
              </div>
            )}

            {/* Validation Rules */}
            {showNumericValidation && (
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label>Valor Mínimo</Label>
                  <Input
                    type="number"
                    value={formState.validation_min}
                    onChange={(e) => setFormState(prev => ({ ...prev, validation_min: e.target.value }))}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Valor Máximo</Label>
                  <Input
                    type="number"
                    value={formState.validation_max}
                    onChange={(e) => setFormState(prev => ({ ...prev, validation_max: e.target.value }))}
                  />
                </div>
              </div>
            )}

            {showTextValidation && (
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label>Comprimento Mínimo</Label>
                  <Input
                    type="number"
                    value={formState.validation_min_length}
                    onChange={(e) => setFormState(prev => ({ ...prev, validation_min_length: e.target.value }))}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Comprimento Máximo</Label>
                  <Input
                    type="number"
                    value={formState.validation_max_length}
                    onChange={(e) => setFormState(prev => ({ ...prev, validation_max_length: e.target.value }))}
                  />
                </div>
              </div>
            )}
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancelar</Button>
            <Button onClick={handleSave} disabled={saveMutation.isPending || !formState.field_label.trim()}>
              {saveMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {formState.id ? 'Atualizar' : 'Criar Campo'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { toast } from 'sonner';
import { 
  ShoppingCart, Headphones, Phone, Megaphone, Store, 
  CreditCard, Calculator, Monitor, Database, Zap, 
  Link, Bot, BarChart3, Users, Shield, Loader2,
  AlertTriangle, Building2, ShieldAlert
} from '@/components/icons';

type ModuleKeyType = 'sales' | 'service' | 'contact_center' | 'marketing' | 'commerce' | 
  'billing' | 'cpq' | 'itsm' | 'data_hub' | 'automations' | 'integrations' | 
  'ai_agents' | 'analytics' | 'portals' | 'governance';

type PlanTierType = 'free' | 'starter' | 'professional' | 'enterprise';

const MODULE_INFO: Record<ModuleKeyType, { name: string; description: string; icon: React.ElementType }> = {
  sales: { name: 'Vendas', description: 'Pipeline, leads, oportunidades e cotações', icon: ShoppingCart },
  service: { name: 'Atendimento', description: 'Tickets, SLA e base de conhecimento', icon: Headphones },
  contact_center: { name: 'Contact Center', description: 'Omnichannel inbox e roteamento', icon: Phone },
  marketing: { name: 'Marketing', description: 'Campanhas, jornadas e segmentação', icon: Megaphone },
  commerce: { name: 'Commerce', description: 'Pedidos, produtos e promoções', icon: Store },
  billing: { name: 'Faturamento', description: 'Faturas, assinaturas e pagamentos', icon: CreditCard },
  cpq: { name: 'CPQ', description: 'Configurador de produtos e preços', icon: Calculator },
  itsm: { name: 'ITSM', description: 'Incidentes, mudanças e CMDB', icon: Monitor },
  data_hub: { name: 'Data Hub', description: 'Customer 360 e unificação de dados', icon: Database },
  automations: { name: 'Automações', description: 'Workflows e regras de negócio', icon: Zap },
  integrations: { name: 'Integrações', description: 'Conectores e APIs externas', icon: Link },
  ai_agents: { name: 'Agentes IA', description: 'Agent Studio e automação inteligente', icon: Bot },
  analytics: { name: 'Analytics', description: 'Dashboards e relatórios', icon: BarChart3 },
  portals: { name: 'Portais', description: 'Portal do cliente e parceiros', icon: Users },
  governance: { name: 'Governança', description: 'LGPD, auditoria e compliance', icon: Shield },
};

const PLAN_TIERS: PlanTierType[] = ['free', 'starter', 'professional', 'enterprise'];

interface OrgModule {
  id: string;
  organization_id: string;
  module_key: ModuleKeyType;
  enabled: boolean;
  plan_tier: PlanTierType;
  limits_json: Record<string, unknown>;
  usage_json: Record<string, unknown>;
  starts_at: string | null;
  ends_at: string | null;
  created_at: string;
  updated_at: string;
}

function parseRLSError(error: unknown): string {
  const message = error instanceof Error ? error.message : String(error);

  if (message.includes('row-level security') || message.includes('42501')) {
    return 'Permissão negada. Verifique se você possui privilégios de administrador e está vinculado a uma organização.';
  }
  if (message.includes('not-null') || message.includes('23502')) {
    return 'Dados obrigatórios ausentes. Sua conta pode não estar vinculada a uma organização.';
  }
  if (message.includes('unique') || message.includes('23505')) {
    return 'Este módulo já está configurado para sua organização.';
  }
  if (message.includes('foreign key') || message.includes('23503')) {
    return 'Referência inválida. A organização ou usuário não foi encontrado.';
  }

  return `Erro ao atualizar módulo: ${message}`;
}

export default function PlatformModules() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const organizationId = profile?.organization_id;
  const isAdmin = profile?.role === 'admin';

  const { data: modules, isLoading } = useQuery({
    queryKey: ['admin-org-modules', organizationId],
    queryFn: async () => {
      if (!organizationId) return [];

      const { data, error } = await supabase
        .from('org_modules')
        .select('*')
        .eq('organization_id', organizationId)
        .order('module_key');

      if (error) throw error;
      return data as OrgModule[];
    },
    enabled: !!organizationId,
  });

  const updateModule = useMutation({
    mutationFn: async ({ moduleKey, updates }: { moduleKey: ModuleKeyType; updates: Record<string, unknown> }) => {
      if (!organizationId) {
        throw new Error('Organização não vinculada ao seu perfil. Não é possível gerenciar módulos.');
      }
      if (!isAdmin) {
        throw new Error('Apenas administradores podem gerenciar módulos da plataforma.');
      }

      const existing = modules?.find(m => m.module_key === moduleKey);

      if (existing) {
        const { error } = await supabase
          .from('org_modules')
          .update({ ...updates, updated_at: new Date().toISOString(), updated_by: profile?.id })
          .eq('id', existing.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('org_modules')
          .insert({
            organization_id: organizationId,
            module_key: moduleKey,
            enabled: true,
            plan_tier: 'free',
            limits_json: {},
            usage_json: {},
            created_by: profile?.id,
            updated_by: profile?.id,
            ...updates,
          } as any);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-org-modules'] });
      queryClient.invalidateQueries({ queryKey: ['org-modules'] });
      toast.success('Módulo atualizado com sucesso');
    },
    onError: (error) => {
      console.error('Error updating module:', error);
      toast.error(parseRLSError(error));
    },
  });

  const getModuleState = (moduleKey: ModuleKeyType) => {
    return modules?.find(m => m.module_key === moduleKey);
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  // Estado: usuário sem organização vinculada
  if (!organizationId) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold">Módulos da Plataforma</h1>
          <p className="text-muted-foreground mt-1">
            Gerencie quais módulos estão habilitados para sua organização
          </p>
        </div>
        <Alert variant="destructive">
          <Building2 className="h-4 w-4" />
          <AlertTitle>Organização não vinculada</AlertTitle>
          <AlertDescription>
            Seu perfil não está associado a nenhuma organização. Para gerenciar módulos, é necessário
            que sua conta esteja vinculada a uma organização. Entre em contato com o administrador do
            sistema ou faça logout e crie uma nova conta para que a organização seja provisionada automaticamente.
          </AlertDescription>
        </Alert>
      </div>
    );
  }

  // Estado: usuário sem permissão de admin
  if (!isAdmin) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold">Módulos da Plataforma</h1>
          <p className="text-muted-foreground mt-1">
            Gerencie quais módulos estão habilitados para sua organização
          </p>
        </div>
        <Alert>
          <ShieldAlert className="h-4 w-4" />
          <AlertTitle>Acesso restrito</AlertTitle>
          <AlertDescription>
            Apenas administradores podem gerenciar os módulos da plataforma. 
            Seu perfil atual possui a role <Badge variant="secondary" className="mx-1">{profile?.role ?? 'desconhecida'}</Badge>.
            Solicite a promoção ao administrador da sua organização.
          </AlertDescription>
        </Alert>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Módulos da Plataforma</h1>
        <p className="text-muted-foreground mt-1">
          Gerencie quais módulos estão habilitados para sua organização
        </p>
      </div>

      {modules && modules.length === 0 && (
        <Alert>
          <AlertTriangle className="h-4 w-4" />
          <AlertTitle>Nenhum módulo provisionado</AlertTitle>
          <AlertDescription>
            Sua organização ainda não possui módulos configurados. Ative os módulos desejados 
            utilizando os controles abaixo.
          </AlertDescription>
        </Alert>
      )}

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
        {(Object.entries(MODULE_INFO) as [ModuleKeyType, typeof MODULE_INFO[ModuleKeyType]][]).map(([key, info]) => {
          const moduleState = getModuleState(key);
          const isEnabled = moduleState?.enabled ?? false;
          const planTier = moduleState?.plan_tier ?? 'free';
          const Icon = info.icon;

          return (
            <Card key={key} className={isEnabled ? 'border-primary/50' : ''}>
              <CardHeader className="pb-3">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg ${isEnabled ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'}`}>
                      <Icon className="h-5 w-5" />
                    </div>
                    <div>
                      <CardTitle className="text-base">{info.name}</CardTitle>
                      <Badge variant={isEnabled ? 'default' : 'secondary'} className="mt-1 text-xs">
                        {planTier}
                      </Badge>
                    </div>
                  </div>
                  <Switch
                    checked={isEnabled}
                    onCheckedChange={(checked) => 
                      updateModule.mutate({ moduleKey: key, updates: { enabled: checked } })
                    }
                    disabled={updateModule.isPending}
                  />
                </div>
              </CardHeader>
              <CardContent className="space-y-3">
                <CardDescription>{info.description}</CardDescription>

                {isEnabled && (
                  <div className="flex items-center gap-2">
                    <span className="text-sm text-muted-foreground">Plano:</span>
                    <Select
                      value={planTier}
                      onValueChange={(value) => 
                        updateModule.mutate({ moduleKey: key, updates: { plan_tier: value } })
                      }
                      disabled={updateModule.isPending}
                    >
                      <SelectTrigger className="h-8 w-32">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {PLAN_TIERS.map(tier => (
                          <SelectItem key={tier} value={tier}>
                            {tier.charAt(0).toUpperCase() + tier.slice(1)}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                )}
              </CardContent>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

