import { useAuth } from '@/hooks/useAuth';

import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { toast } from 'sonner';
import {
  ArrowLeft, Bot, Send, Loader2, User, Wrench,
  AlertTriangle, CheckCircle, Clock, Trash2, XCircle,
  Search, Database, FileText, Users, Package,
  BarChart3, ShieldAlert, ExternalLink
} from '@/components/icons';

interface ToolExecutionResult {
  status: 'success' | 'error' | 'not_found' | 'pending_approval';
  data?: unknown;
  message: string;
  records_affected?: number;
  entity_type?: string;
  entity_id?: string;
}

interface ChatMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
  tool_calls?: Array<{ tool_name: string; result: ToolExecutionResult }>;
  run_id?: string;
  tokens_used?: number;
  duration_ms?: number;
  pii_detected?: boolean;
  requires_approval?: boolean;
}

const ENTITY_ICONS: Record<string, React.ElementType> = {
  knowledge_article: FileText,
  contact: Users,
  account: Database,
  customer: Users,
  ticket: FileText,
  opportunity: BarChart3,
  product: Package,
  order: Package,
  lead: Users,
  activity: Clock,
  note: FileText,
  contract: FileText,
  dashboard: BarChart3,
};

const STATUS_STYLES: Record<string, { icon: React.ElementType; className: string }> = {
  success: { icon: CheckCircle, className: 'text-green-600 dark:text-green-400' },
  error: { icon: XCircle, className: 'text-red-600 dark:text-red-400' },
  not_found: { icon: Search, className: 'text-yellow-600 dark:text-yellow-400' },
  pending_approval: { icon: ShieldAlert, className: 'text-orange-600 dark:text-orange-400' },
};

function ToolResultCard({ toolName, result }: { toolName: string; result: ToolExecutionResult }) {
  const statusInfo = STATUS_STYLES[result.status] || STATUS_STYLES.success;
  const StatusIcon = statusInfo.icon;
  const EntityIcon = ENTITY_ICONS[result.entity_type || ''] || Wrench;

  return (
    <div className="mt-2 border rounded-md bg-background/50 overflow-hidden">
      <div className="flex items-center justify-between px-3 py-2 bg-muted/50 border-b">
        <div className="flex items-center gap-2 text-xs font-medium">
          <Wrench className="h-3 w-3" />
          <span className="font-mono">{toolName}</span>
        </div>
        <div className="flex items-center gap-1.5">
          <StatusIcon className={`h-3.5 w-3.5 ${statusInfo.className}`} />
          <span className={`text-xs font-medium ${statusInfo.className}`}>
            {result.status === 'success' ? 'Sucesso' :
              result.status === 'error' ? 'Erro' :
              result.status === 'not_found' ? 'Não encontrado' : 'Aguardando aprovação'}
          </span>
          {result.records_affected !== undefined && (
            <Badge variant="outline" className="text-xs ml-1">
              {result.records_affected} registro(s)
            </Badge>
          )}
        </div>
      </div>
      <div className="px-3 py-2">
        <p className="text-xs text-muted-foreground">{result.message}</p>
        {result.data && <ToolDataDisplay data={result.data} entityType={result.entity_type} />}
        {result.entity_id && (
          <div className="flex items-center gap-1 mt-2 text-xs text-muted-foreground">
            <EntityIcon className="h-3 w-3" />
            <span>ID: <span className="font-mono">{result.entity_id.substring(0, 8)}...</span></span>
          </div>
        )}
      </div>
    </div>
  );
}

function ToolDataDisplay({ data, entityType }: { data: unknown; entityType?: string }) {
  if (!data || typeof data !== 'object') return null;

  const dataObj = data as Record<string, unknown>;

  // If it's an array, show as compact table
  if (Array.isArray(data)) {
    if (data.length === 0) return <p className="text-xs text-muted-foreground mt-1">Nenhum resultado</p>;

    const items = data.slice(0, 5);
    const keys = Object.keys(items[0] || {}).filter(k => k !== 'id' && typeof (items[0] as any)[k] !== 'object').slice(0, 4);

    return (
      <div className="mt-2 overflow-x-auto">
        <table className="w-full text-xs">
          <thead>
            <tr className="border-b">
              {keys.map(k => (
                <th key={k} className="text-left py-1 px-2 font-medium text-muted-foreground">{formatLabel(k)}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map((item: any, i: number) => (
              <tr key={i} className="border-b last:border-0">
                {keys.map(k => (
                  <td key={k} className="py-1 px-2 truncate max-w-[200px]">{formatValue(item[k])}</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
        {data.length > 5 && (
          <p className="text-xs text-muted-foreground mt-1 px-2">...e mais {data.length - 5} resultado(s)</p>
        )}
      </div>
    );
  }

  // If object has nested arrays (e.g., contacts + accounts)
  const arrayKeys = Object.keys(dataObj).filter(k => Array.isArray(dataObj[k]));
  const scalarKeys = Object.keys(dataObj).filter(k => !Array.isArray(dataObj[k]) && typeof dataObj[k] !== 'object');

  return (
    <div className="mt-2 space-y-2">
      {scalarKeys.length > 0 && (
        <div className="grid grid-cols-2 gap-x-4 gap-y-1">
          {scalarKeys.slice(0, 8).map(k => (
            <div key={k} className="text-xs">
              <span className="text-muted-foreground">{formatLabel(k)}: </span>
              <span className="font-medium">{formatValue(dataObj[k])}</span>
            </div>
          ))}
        </div>
      )}
      {arrayKeys.map(k => {
        const arr = dataObj[k] as any[];
        if (!arr || arr.length === 0) return null;
        const itemKeys = Object.keys(arr[0] || {}).filter(ik => ik !== 'id' && typeof arr[0][ik] !== 'object').slice(0, 4);
        return (
          <div key={k}>
            <p className="text-xs font-medium text-muted-foreground mb-1">{formatLabel(k)} ({arr.length})</p>
            <table className="w-full text-xs">
              <thead>
                <tr className="border-b">
                  {itemKeys.map(ik => (
                    <th key={ik} className="text-left py-1 px-2 font-medium text-muted-foreground">{formatLabel(ik)}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {arr.slice(0, 3).map((item: any, i: number) => (
                  <tr key={i} className="border-b last:border-0">
                    {itemKeys.map(ik => (
                      <td key={ik} className="py-1 px-2 truncate max-w-[180px]">{formatValue(item[ik])}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      })}
    </div>
  );
}

function formatLabel(key: string): string {
  return key
    .replace(/_/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase())
    .replace('Id', 'ID');
}

function formatValue(val: unknown): string {
  if (val === null || val === undefined) return '-';
  if (typeof val === 'boolean') return val ? 'Sim' : 'Não';
  if (typeof val === 'number') {
    if (val > 1000) return val.toLocaleString('pt-BR');
    return String(val);
  }
  if (Array.isArray(val)) return val.join(', ');
  const s = String(val);
  if (s.match(/^\d{4}-\d{2}-\d{2}T/)) {
    try {
      return new Date(s).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
    } catch { return s; }
  }
  return s.length > 60 ? s.substring(0, 60) + '...' : s;
}

export default function AIAgentPlayground() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [conversationId, setConversationId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const { data: agent } = useQuery({
    queryKey: ['ai-agent', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('ai_agents')
        .select('*')
        .eq('id', id!)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: toolsCount } = useQuery({
    queryKey: ['ai-agent-tools-count', id],
    queryFn: async () => {
      const { count } = await supabase
        .from('ai_agent_tools')
        .select('id', { count: 'exact', head: true })
        .eq('agent_id', id!)
        .eq('is_enabled', true);
      return count || 0;
    },
    enabled: !!id,
  });

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading || !id) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setLoading(true);

    try {
      const { data, error } = await supabase.functions.invoke('ai-agent-execute', {
        body: {
          agent_id: id,
          message: userMessage,
          conversation_id: conversationId,
          context: {},
        },
      });

      if (error) throw error;

      if (!data?.success) {
        throw new Error(data?.error || 'Falha na execução');
      }

      if (data.conversation_id && !conversationId) {
        setConversationId(data.conversation_id);
      }

      setMessages(prev => [...prev, {
        role: 'assistant',
        content: data.content || '',
        tool_calls: data.tool_calls,
        run_id: data.run_id,
        tokens_used: data.tokens_used,
        duration_ms: data.duration_ms,
        pii_detected: data.pii_detected,
        requires_approval: data.requires_approval,
      }]);
    } catch (err: any) {
      console.error('AI execution error:', err);
      toast.error('Erro na execução: ' + (err.message || 'Erro desconhecido'));
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: `❌ Erro: ${err.message || 'Falha na comunicação com o agente'}`,
      }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const clearChat = () => {
    setMessages([]);
    setConversationId(null);
  };

  return (
    <>
      <div className="flex flex-col h-[calc(100vh-4rem)]">
        {/* Header */}
        <div className="flex items-center justify-between pb-4">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate(`/ai/agents/${id}`)}>
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <div className="flex items-center gap-2">
                <Bot className="h-5 w-5 text-primary" />
                <h1 className="text-xl font-bold">Playground: {agent?.name || '...'}</h1>
              </div>
              <p className="text-sm text-muted-foreground">
                {(agent?.model_config as any)?.model || 'gemini-3-flash-preview'}
                {toolsCount ? ` • ${toolsCount} ferramenta(s)` : ''}
                {conversationId && ' • Conversa ativa'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={clearChat}>
              <Trash2 className="h-4 w-4 mr-2" />
              Limpar
            </Button>
          </div>
        </div>

        {/* Chat Area */}
        <Card className="flex-1 flex flex-col overflow-hidden">
          <ScrollArea className="flex-1 p-4" ref={scrollRef}>
            <div className="space-y-4 max-w-3xl mx-auto">
              {messages.length === 0 && (
                <div className="text-center py-12 text-muted-foreground">
                  <Bot className="h-16 w-16 mx-auto mb-4 opacity-50" />
                  <p className="text-lg">Comece uma conversa com <strong>{agent?.name}</strong></p>
                  <p className="text-sm mt-2">
                    {toolsCount
                      ? `Este agente tem ${toolsCount} ferramenta(s) que executam ações reais no CRM`
                      : 'Envie uma mensagem para iniciar'}
                  </p>
                  <div className="flex flex-wrap gap-2 justify-center mt-4">
                    {['Buscar artigos sobre...', 'Criar um ticket para...', 'Métricas de vendas', 'Buscar contato...'].map(suggestion => (
                      <Button
                        key={suggestion}
                        variant="outline"
                        size="sm"
                        className="text-xs"
                        onClick={() => setInput(suggestion)}
                      >
                        {suggestion}
                      </Button>
                    ))}
                  </div>
                </div>
              )}

              {messages.map((msg, i) => (
                <div key={i} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  {msg.role === 'assistant' && (
                    <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                      <Bot className="h-4 w-4 text-primary" />
                    </div>
                  )}
                  <div className={`max-w-[80%] ${msg.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-muted'} rounded-lg p-3`}>
                    <p className="text-sm whitespace-pre-wrap">{msg.content}</p>

                    {/* Tool call results - rich display */}
                    {msg.tool_calls && msg.tool_calls.length > 0 && (
                      <div className="mt-3 space-y-2">
                        <Separator />
                        <p className="text-xs font-medium text-muted-foreground flex items-center gap-1">
                          <Wrench className="h-3 w-3" />
                          {msg.tool_calls.length} ferramenta(s) executada(s)
                        </p>
                        {msg.tool_calls.map((tc, j) => (
                          <ToolResultCard key={j} toolName={tc.tool_name} result={tc.result} />
                        ))}
                      </div>
                    )}

                    {/* Metadata */}
                    {msg.role === 'assistant' && (msg.tokens_used || msg.duration_ms) && (
                      <div className="flex items-center flex-wrap gap-2 mt-2 text-xs text-muted-foreground">
                        {msg.tokens_used && <span>{msg.tokens_used.toLocaleString()} tokens</span>}
                        {msg.duration_ms && (
                          <span className="flex items-center gap-0.5">
                            <Clock className="h-3 w-3" />{msg.duration_ms}ms
                          </span>
                        )}
                        {msg.run_id && (
                          <span className="font-mono text-[10px] opacity-60">
                            {msg.run_id.substring(0, 8)}
                          </span>
                        )}
                        {msg.pii_detected && (
                          <Badge variant="destructive" className="text-[10px] h-5">
                            <AlertTriangle className="h-2.5 w-2.5 mr-0.5" />
                            PII
                          </Badge>
                        )}
                        {msg.requires_approval && (
                          <Badge variant="secondary" className="text-[10px] h-5">
                            <ShieldAlert className="h-2.5 w-2.5 mr-0.5" />
                            Aprovação
                          </Badge>
                        )}
                      </div>
                    )}
                  </div>
                  {msg.role === 'user' && (
                    <div className="h-8 w-8 rounded-full bg-primary flex items-center justify-center shrink-0">
                      <User className="h-4 w-4 text-primary-foreground" />
                    </div>
                  )}
                </div>
              ))}

              {loading && (
                <div className="flex gap-3">
                  <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                    <Bot className="h-4 w-4 text-primary" />
                  </div>
                  <div className="bg-muted rounded-lg p-3 flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin" />
                    <span className="text-sm text-muted-foreground">Processando...</span>
                  </div>
                </div>
              )}
            </div>
          </ScrollArea>

          {/* Input */}
          <div className="border-t p-4">
            <div className="flex gap-2 max-w-3xl mx-auto">
              <Textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Digite sua mensagem..."
                className="resize-none"
                rows={2}
                disabled={loading}
              />
              <Button onClick={handleSend} disabled={loading || !input.trim()} className="self-end">
                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
              </Button>
            </div>
          </div>
        </Card>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import {
  Bot, Plus, Search, TrendingUp, Headphones, Megaphone, ShoppingCart,
  Server, Database, Shield, Wrench, Play, Settings, Activity, Loader2,
  Brain, Zap, CheckCircle, PauseCircle, AlertTriangle, Archive
} from '@/components/icons';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';

const AGENT_TYPE_CONFIG: Record<string, { label: string; icon: React.ElementType; color: string }> = {
  sales: { label: 'Vendas', icon: TrendingUp, color: 'text-emerald-500' },
  service: { label: 'Atendimento', icon: Headphones, color: 'text-blue-500' },
  marketing: { label: 'Marketing', icon: Megaphone, color: 'text-purple-500' },
  commerce: { label: 'Commerce', icon: ShoppingCart, color: 'text-orange-500' },
  itsm: { label: 'ITSM', icon: Server, color: 'text-slate-500' },
  data_steward: { label: 'Data Steward', icon: Database, color: 'text-cyan-500' },
  compliance: { label: 'Compliance', icon: Shield, color: 'text-red-500' },
  custom: { label: 'Customizado', icon: Wrench, color: 'text-amber-500' },
};

const STATUS_CONFIG: Record<string, { label: string; icon: React.ElementType; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  draft: { label: 'Rascunho', icon: Archive, variant: 'outline' },
  testing: { label: 'Testando', icon: Zap, variant: 'secondary' },
  active: { label: 'Ativo', icon: CheckCircle, variant: 'default' },
  paused: { label: 'Pausado', icon: PauseCircle, variant: 'secondary' },
  deprecated: { label: 'Descontinuado', icon: AlertTriangle, variant: 'destructive' },
};

export default function AIAgents() {
  const navigate = useNavigate();
  const { profile } = useAuth();
  const orgId = profile?.organization_id;
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<string>('all');
  const [statusFilter, setStatusFilter] = useState<string>('all');

  const { data: agents, isLoading } = useQuery({
    queryKey: ['ai-agents', orgId],
    queryFn: async () => {
      if (!orgId) return [];
      const { data, error } = await supabase
        .from('ai_agents')
        .select('*')
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const { data: metrics } = useQuery({
    queryKey: ['ai-metrics', orgId],
    queryFn: async () => {
      if (!orgId) return null;
      const { data, error } = await supabase.rpc('get_ai_usage_metrics', { _org_id: orgId });
      if (error) throw error;
      return data as Record<string, number>;
    },
    enabled: !!orgId,
  });

  const filtered = (agents || []).filter(a => {
    if (search && !a.name.toLowerCase().includes(search.toLowerCase()) && !a.description?.toLowerCase().includes(search.toLowerCase())) return false;
    if (typeFilter !== 'all' && a.agent_type !== typeFilter) return false;
    if (statusFilter !== 'all' && a.status !== statusFilter) return false;
    return true;
  });

  return (
    <>
      <div className="space-y-6">
        {/* Hero Banner */}
        <ModuleHeroBanner
          module="ai"
          title="Agent Studio"
          subtitle="Gerencie agentes de IA com governança enterprise"
          actions={
            <Button onClick={() => navigate('/ai/agents/new')} className="bg-white text-foreground hover:bg-white/90">
              <Plus className="h-4 w-4 mr-2" />
              Novo Agente
            </Button>
          }
        />

        {/* Metrics */}
        {metrics && (
          <div className="grid gap-4 md:grid-cols-4">
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <Bot className="h-8 w-8 text-primary" />
                  <div>
                    <p className="text-2xl font-bold">{metrics.active_agents ?? 0}</p>
                    <p className="text-xs text-muted-foreground">Agentes Ativos</p>
                  </div>
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <Activity className="h-8 w-8 text-emerald-500" />
                  <div>
                    <p className="text-2xl font-bold">{metrics.total_runs_today ?? 0}</p>
                    <p className="text-xs text-muted-foreground">Execuções Hoje</p>
                  </div>
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <Brain className="h-8 w-8 text-purple-500" />
                  <div>
                    <p className="text-2xl font-bold">{(metrics.total_tokens_today ?? 0).toLocaleString()}</p>
                    <p className="text-xs text-muted-foreground">Tokens Hoje</p>
                  </div>
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <CheckCircle className="h-8 w-8 text-green-500" />
                  <div>
                    <p className="text-2xl font-bold">{metrics.success_rate ?? 0}%</p>
                    <p className="text-xs text-muted-foreground">Taxa de Sucesso</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        )}

        {/* Filters */}
        <div className="flex gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Buscar agentes..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={typeFilter} onValueChange={setTypeFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Tipo" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os tipos</SelectItem>
              {Object.entries(AGENT_TYPE_CONFIG).map(([key, cfg]) => (
                <SelectItem key={key} value={key}>{cfg.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os status</SelectItem>
              {Object.entries(STATUS_CONFIG).map(([key, cfg]) => (
                <SelectItem key={key} value={key}>{cfg.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Agent Cards */}
        {isLoading ? (
          <div className="flex justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : filtered.length === 0 ? (
          <Card>
            <CardContent className="flex flex-col items-center justify-center py-12">
              <Bot className="h-16 w-16 text-muted-foreground mb-4" />
              <h3 className="text-lg font-semibold">Nenhum agente encontrado</h3>
              <p className="text-muted-foreground mt-1">Crie seu primeiro agente de IA para começar.</p>
              <Button className="mt-4" onClick={() => navigate('/ai/agents/new')}>
                <Plus className="h-4 w-4 mr-2" />
                Criar Agente
              </Button>
            </CardContent>
          </Card>
        ) : (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {filtered.map((agent) => {
              const typeCfg = AGENT_TYPE_CONFIG[agent.agent_type] || AGENT_TYPE_CONFIG.custom;
              const statusCfg = STATUS_CONFIG[agent.status] || STATUS_CONFIG.draft;
              const TypeIcon = typeCfg.icon;
              const StatusIcon = statusCfg.icon;

              return (
                <Card key={agent.id} className="cursor-pointer hover:shadow-md transition-shadow" onClick={() => navigate(`/ai/agents/${agent.id}`)}>
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg bg-primary/10 ${typeCfg.color}`}>
                          <TypeIcon className="h-5 w-5" />
                        </div>
                        <div>
                          <CardTitle className="text-base">{agent.name}</CardTitle>
                          <div className="flex items-center gap-2 mt-1">
                            <Badge variant="outline" className="text-xs">{typeCfg.label}</Badge>
                            {agent.is_native && <Badge variant="secondary" className="text-xs">Nativo</Badge>}
                          </div>
                        </div>
                      </div>
                      <Badge variant={statusCfg.variant} className="text-xs">
                        <StatusIcon className="h-3 w-3 mr-1" />
                        {statusCfg.label}
                      </Badge>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <CardDescription className="line-clamp-2 min-h-[2.5rem]">
                      {agent.description || 'Sem descrição'}
                    </CardDescription>
                    <div className="flex items-center justify-between mt-4">
                      <span className="text-xs text-muted-foreground">
                        v{agent.version} • {(agent.model_config as any)?.model?.split('/').pop() || 'gemini'}
                      </span>
                      <div className="flex gap-1">
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => { e.stopPropagation(); navigate(`/ai/agents/${agent.id}/test`); }}>
                          <Play className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => { e.stopPropagation(); navigate(`/ai/agents/${agent.id}`); }}>
                          <Settings className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Progress } from '@/components/ui/progress';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ClipboardList, Plus, Search, Loader2, Play, CheckCircle, XCircle, Bot } from '@/components/icons';

export default function AIEvals() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const orgId = profile?.organization_id;
  const [search, setSearch] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [form, setForm] = useState({
    name: '', description: '', agent_id: '',
    test_cases: '[\n  {\n    "input": "Olá, como posso ajudar?",\n    "expected_contains": ["ajudar", "assistente"]\n  }\n]',
  });

  const { data: evals, isLoading } = useQuery({
    queryKey: ['ai-evals', orgId],
    queryFn: async () => {
      if (!orgId) return [];
      const { data, error } = await supabase
        .from('ai_evals')
        .select('*, ai_agents(name, agent_type)')
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const { data: agents } = useQuery({
    queryKey: ['ai-agents-list', orgId],
    queryFn: async () => {
      if (!orgId) return [];
      const { data, error } = await supabase
        .from('ai_agents')
        .select('id, name')
        .eq('organization_id', orgId);
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const createEval = useMutation({
    mutationFn: async () => {
      if (!orgId || !form.name.trim() || !form.agent_id) throw new Error('Nome e agente são obrigatórios');
      let parsedCases;
      try { parsedCases = JSON.parse(form.test_cases); } catch { throw new Error('Test cases JSON inválido'); }

      const { error } = await supabase.from('ai_evals').insert({
        organization_id: orgId, name: form.name, description: form.description || null,
        agent_id: form.agent_id, test_cases: parsedCases, created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ai-evals'] });
      toast.success('Suite de avaliação criada');
      setDialogOpen(false);
    },
    onError: (err: any) => toast.error(err.message),
  });

  const filtered = (evals || []).filter(e =>
    !search || e.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="ai"
          title="Avaliações de IA"
          subtitle="Suites de teste para validar comportamento dos agentes"
          compact
          actions={
            <Button onClick={() => setDialogOpen(true)}>
              <Plus className="h-4 w-4 mr-2" />Nova Avaliação
            </Button>
          }
        />
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>Nova Suite de Avaliação</DialogTitle>
                <DialogDescription>Configure casos de teste para um agente</DialogDescription>
              </DialogHeader>
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Nome *</Label>
                    <Input value={form.name} onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Teste de Triagem" />
                  </div>
                  <div className="space-y-2">
                    <Label>Agente *</Label>
                    <Select value={form.agent_id} onValueChange={(v) => setForm(p => ({ ...p, agent_id: v }))}>
                      <SelectTrigger><SelectValue placeholder="Selecione" /></SelectTrigger>
                      <SelectContent>
                        {(agents || []).map(a => (
                          <SelectItem key={a.id} value={a.id}>{a.name}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label>Descrição</Label>
                  <Textarea value={form.description} onChange={(e) => setForm(p => ({ ...p, description: e.target.value }))} rows={2} />
                </div>
                <div className="space-y-2">
                  <Label>Casos de Teste (JSON)</Label>
                  <Textarea value={form.test_cases} onChange={(e) => setForm(p => ({ ...p, test_cases: e.target.value }))} rows={10} className="font-mono text-sm" />
                </div>
              </div>
              <DialogFooter>
                <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancelar</Button>
                <Button onClick={() => createEval.mutate()} disabled={createEval.isPending}>
                  {createEval.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                  Criar Avaliação
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>

        <div className="relative max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Buscar avaliações..." value={search} onChange={(e) => setSearch(e.target.value)} className="pl-9" />
        </div>

        {isLoading ? (
          <div className="flex justify-center py-12"><Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /></div>
        ) : filtered.length === 0 ? (
          <Card><CardContent className="text-center py-12">
            <ClipboardList className="h-12 w-12 text-muted-foreground mx-auto mb-3" />
            <p className="text-muted-foreground">Nenhuma avaliação encontrada</p>
          </CardContent></Card>
        ) : (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {filtered.map(ev => {
              const testCases = Array.isArray(ev.test_cases) ? ev.test_cases : [];
              return (
                <Card key={ev.id}>
                  <CardHeader className="pb-3">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-base">{ev.name}</CardTitle>
                      {ev.pass_rate !== null && (
                        <Badge variant={Number(ev.pass_rate) >= 80 ? 'default' : 'destructive'}>
                          {ev.pass_rate}%
                        </Badge>
                      )}
                    </div>
                    <CardDescription>
                      <div className="flex items-center gap-1">
                        <Bot className="h-3 w-3" />
                        {(ev.ai_agents as any)?.name || 'N/A'}
                      </div>
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    <p className="text-sm text-muted-foreground line-clamp-2">{ev.description || 'Sem descrição'}</p>
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                      <span>{testCases.length} caso(s) de teste</span>
                      <span>Runs: {ev.total_runs}</span>
                    </div>
                    {ev.pass_rate !== null && <Progress value={Number(ev.pass_rate)} className="h-2" />}
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                      {ev.last_run_at ? (
                        <span>Último: {format(new Date(ev.last_run_at), 'dd/MM HH:mm')}</span>
                      ) : (
                        <span>Nunca executado</span>
                      )}
                      <Button variant="outline" size="sm" disabled>
                        <Play className="h-3 w-3 mr-1" />
                        Executar
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>
    </>
  );
}

