import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { toast } from 'sonner';
import { Shield, Plus, Search, Loader2, Lock, AlertTriangle, Filter, Gauge, CheckCircle } from '@/components/icons';

const POLICY_TYPE_CONFIG: Record<string, { label: string; icon: React.ElementType; description: string }> = {
  pii_protection: { label: 'Proteção PII', icon: Lock, description: 'Mascarar dados pessoais' },
  rate_limit: { label: 'Rate Limit', icon: Gauge, description: 'Limitar uso por período' },
  action_restriction: { label: 'Restrição de Ação', icon: AlertTriangle, description: 'Bloquear ações específicas' },
  content_filter: { label: 'Filtro de Conteúdo', icon: Filter, description: 'Filtrar conteúdo inapropriado' },
  approval_required: { label: 'Aprovação Obrigatória', icon: CheckCircle, description: 'Exigir aprovação humana' },
};

export default function AIPolicies() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const orgId = profile?.organization_id;
  const [search, setSearch] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [form, setForm] = useState({
    name: '', description: '', policy_type: 'pii_protection' as string,
    actions_on_violation: 'block', priority: 100, is_active: true,
    rules: '[]', scope: '',
  });

  const { data: policies, isLoading } = useQuery({
    queryKey: ['ai-policies', orgId],
    queryFn: async () => {
      if (!orgId) return [];
      const { data, error } = await supabase
        .from('ai_policies')
        .select('*')
        .eq('organization_id', orgId)
        .order('priority', { ascending: true });
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const createPolicy = useMutation({
    mutationFn: async () => {
      if (!orgId || !form.name.trim()) throw new Error('Nome obrigatório');
      let parsedRules;
      try { parsedRules = JSON.parse(form.rules); } catch { throw new Error('Regras JSON inválido'); }

      const { error } = await supabase.from('ai_policies').insert({
        organization_id: orgId, name: form.name, description: form.description || null,
        policy_type: form.policy_type as any, rules: parsedRules,
        actions_on_violation: form.actions_on_violation,
        priority: form.priority, is_active: form.is_active,
        scope: form.scope || null, created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ai-policies'] });
      toast.success('Política criada');
      setDialogOpen(false);
    },
    onError: (err: any) => toast.error(err.message),
  });

  const togglePolicy = useMutation({
    mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
      const { error } = await supabase.from('ai_policies').update({ is_active }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ai-policies'] });
      toast.success('Política atualizada');
    },
  });

  const filtered = (policies || []).filter(p =>
    !search || p.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="ai"
          title="Políticas de IA"
          subtitle="Guardrails e regras de governança para agentes"
          compact
          actions={
            <Button onClick={() => setDialogOpen(true)}>
              <Plus className="h-4 w-4 mr-2" />Nova Política
            </Button>
          }
        />
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>Nova Política</DialogTitle>
                <DialogDescription>Configure regras de governança para agentes de IA</DialogDescription>
              </DialogHeader>
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Nome *</Label>
                    <Input value={form.name} onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Proteção de PII" />
                  </div>
                  <div className="space-y-2">
                    <Label>Tipo</Label>
                    <Select value={form.policy_type} onValueChange={(v) => setForm(p => ({ ...p, policy_type: v }))}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {Object.entries(POLICY_TYPE_CONFIG).map(([key, cfg]) => (
                          <SelectItem key={key} value={key}>{cfg.label}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label>Descrição</Label>
                  <Textarea value={form.description} onChange={(e) => setForm(p => ({ ...p, description: e.target.value }))} rows={2} />
                </div>
                <div className="grid grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label>Ação na Violação</Label>
                    <Select value={form.actions_on_violation} onValueChange={(v) => setForm(p => ({ ...p, actions_on_violation: v }))}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="block">Bloquear</SelectItem>
                        <SelectItem value="warn">Avisar</SelectItem>
                        <SelectItem value="require_approval">Exigir Aprovação</SelectItem>
                        <SelectItem value="log">Apenas Logar</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Prioridade</Label>
                    <Input type="number" value={form.priority} onChange={(e) => setForm(p => ({ ...p, priority: parseInt(e.target.value) || 100 }))} />
                  </div>
                  <div className="space-y-2">
                    <Label>Escopo</Label>
                    <Input value={form.scope} onChange={(e) => setForm(p => ({ ...p, scope: e.target.value }))} placeholder="sales,service" />
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <Switch checked={form.is_active} onCheckedChange={(v) => setForm(p => ({ ...p, is_active: v }))} />
                  <Label>Ativa</Label>
                </div>
                <div className="space-y-2">
                  <Label>Regras (JSON)</Label>
                  <Textarea value={form.rules} onChange={(e) => setForm(p => ({ ...p, rules: e.target.value }))} rows={5} className="font-mono text-sm" placeholder='[{"pattern": "...", "action": "block"}]' />
                </div>
              </div>
              <DialogFooter>
                <Button variant="outline" onClick={() => setDialogOpen(false)}>Cancelar</Button>
                <Button onClick={() => createPolicy.mutate()} disabled={createPolicy.isPending}>
                  {createPolicy.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                  Criar Política
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>

        <div className="relative max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Buscar políticas..." value={search} onChange={(e) => setSearch(e.target.value)} className="pl-9" />
        </div>

        <Card>
          <CardContent className="p-0">
            {isLoading ? (
              <div className="flex justify-center py-12"><Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /></div>
            ) : filtered.length === 0 ? (
              <div className="text-center py-12">
                <Shield className="h-12 w-12 text-muted-foreground mx-auto mb-3" />
                <p className="text-muted-foreground">Nenhuma política encontrada</p>
              </div>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Nome</TableHead>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Ação</TableHead>
                    <TableHead>Prioridade</TableHead>
                    <TableHead>Escopo</TableHead>
                    <TableHead>Ativa</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filtered.map(policy => {
                    const cfg = POLICY_TYPE_CONFIG[policy.policy_type] || { label: policy.policy_type, icon: Shield };
                    const Icon = cfg.icon;
                    return (
                      <TableRow key={policy.id}>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Icon className="h-4 w-4 text-muted-foreground" />
                            <div>
                              <p className="font-medium">{policy.name}</p>
                              <p className="text-xs text-muted-foreground line-clamp-1">{policy.description || '-'}</p>
                            </div>
                          </div>
                        </TableCell>
                        <TableCell><Badge variant="outline">{cfg.label}</Badge></TableCell>
                        <TableCell><Badge variant="secondary">{policy.actions_on_violation}</Badge></TableCell>
                        <TableCell className="text-sm">{policy.priority}</TableCell>
                        <TableCell className="text-sm">{policy.scope || 'Global'}</TableCell>
                        <TableCell>
                          <Switch
                            checked={policy.is_active}
                            onCheckedChange={(v) => togglePolicy.mutate({ id: policy.id, is_active: v })}
                          />
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { format } from 'date-fns';
import {
  Activity, Search, Loader2, Bot, Clock, CheckCircle, XCircle,
  AlertTriangle, PauseCircle, Eye, Shield
} from '@/components/icons';

const STATUS_CONFIG: Record<string, { label: string; icon: React.ElementType; color: string }> = {
  pending: { label: 'Pendente', icon: Clock, color: 'bg-yellow-500' },
  running: { label: 'Executando', icon: Activity, color: 'bg-blue-500' },
  waiting_approval: { label: 'Aguardando Aprovação', icon: PauseCircle, color: 'bg-orange-500' },
  completed: { label: 'Concluído', icon: CheckCircle, color: 'bg-green-500' },
  failed: { label: 'Falhou', icon: XCircle, color: 'bg-red-500' },
  cancelled: { label: 'Cancelado', icon: AlertTriangle, color: 'bg-gray-500' },
};

export default function AIRuns() {
  const { profile } = useAuth();
  const orgId = profile?.organization_id;
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedRun, setSelectedRun] = useState<string | null>(null);

  const { data: runs, isLoading } = useQuery({
    queryKey: ['ai-runs', orgId, statusFilter],
    queryFn: async () => {
      if (!orgId) return [];
      let query = supabase
        .from('ai_runs')
        .select('*, ai_agents(name, agent_type), profiles!ai_runs_triggered_by_fkey(email, first_name, last_name)')
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false })
        .limit(100);

      if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const { data: runDetails } = useQuery({
    queryKey: ['ai-run-detail', selectedRun],
    queryFn: async () => {
      if (!selectedRun) return null;
      const [stepsRes, receiptsRes] = await Promise.all([
        supabase.from('ai_run_steps').select('*').eq('run_id', selectedRun).order('step_order'),
        supabase.from('ai_run_audit_receipts').select('*').eq('run_id', selectedRun).order('created_at'),
      ]);
      return { steps: stepsRes.data || [], receipts: receiptsRes.data || [] };
    },
    enabled: !!selectedRun,
  });

  const filtered = (runs || []).filter(r => {
    if (search) {
      const agentName = (r.ai_agents as any)?.name?.toLowerCase() || '';
      const userEmail = (r.profiles as any)?.email?.toLowerCase() || '';
      if (!agentName.includes(search.toLowerCase()) && !userEmail.includes(search.toLowerCase())) return false;
    }
    return true;
  });

  return (
    <>
      <div className="space-y-6">
        <ModuleHeroBanner
          module="ai"
          title="Execuções de IA"
          subtitle="Histórico completo com auditoria e comprovantes"
          compact
        />

        {/* Filters */}
        <div className="flex gap-3">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input placeholder="Buscar por agente ou usuário..." value={search} onChange={(e) => setSearch(e.target.value)} className="pl-9" />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[200px]">
              <SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os status</SelectItem>
              {Object.entries(STATUS_CONFIG).map(([key, cfg]) => (
                <SelectItem key={key} value={key}>{cfg.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Runs Table */}
        <Card>
          <CardContent className="p-0">
            {isLoading ? (
              <div className="flex justify-center py-12"><Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /></div>
            ) : filtered.length === 0 ? (
              <div className="text-center py-12">
                <Activity className="h-12 w-12 text-muted-foreground mx-auto mb-3" />
                <p className="text-muted-foreground">Nenhuma execução encontrada</p>
              </div>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Status</TableHead>
                    <TableHead>Agente</TableHead>
                    <TableHead>Trigger</TableHead>
                    <TableHead>Usuário</TableHead>
                    <TableHead>Tokens</TableHead>
                    <TableHead>Steps</TableHead>
                    <TableHead>Duração</TableHead>
                    <TableHead>Data</TableHead>
                    <TableHead></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filtered.map(run => {
                    const scfg = STATUS_CONFIG[run.status] || STATUS_CONFIG.pending;
                    const StatusIcon = scfg.icon;
                    const duration = run.started_at && run.completed_at
                      ? Math.round((new Date(run.completed_at).getTime() - new Date(run.started_at).getTime()) / 1000)
                      : null;
                    const agentData = run.ai_agents as any;
                    const profileData = run.profiles as any;

                    return (
                      <TableRow key={run.id}>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <div className={`h-2 w-2 rounded-full ${scfg.color}`} />
                            <span className="text-sm">{scfg.label}</span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Bot className="h-4 w-4 text-muted-foreground" />
                            <span className="font-medium text-sm">{agentData?.name || 'N/A'}</span>
                          </div>
                        </TableCell>
                        <TableCell><Badge variant="outline" className="text-xs">{run.trigger_type}</Badge></TableCell>
                        <TableCell className="text-sm">
                          {profileData?.first_name ? `${profileData.first_name} ${profileData.last_name || ''}`.trim() : profileData?.email || '-'}
                        </TableCell>
                        <TableCell className="text-sm">{run.total_tokens_used?.toLocaleString() || 0}</TableCell>
                        <TableCell className="text-sm">{run.total_steps || 0}</TableCell>
                        <TableCell className="text-sm">{duration !== null ? `${duration}s` : '-'}</TableCell>
                        <TableCell className="text-sm text-muted-foreground">{format(new Date(run.created_at), 'dd/MM HH:mm')}</TableCell>
                        <TableCell>
                          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setSelectedRun(run.id)}>
                            <Eye className="h-4 w-4" />
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>

        {/* Run Detail Dialog */}
        <Dialog open={!!selectedRun} onOpenChange={() => setSelectedRun(null)}>
          <DialogContent className="max-w-3xl max-h-[85vh]">
            <DialogHeader>
              <DialogTitle>Detalhes da Execução</DialogTitle>
            </DialogHeader>
            <ScrollArea className="max-h-[70vh]">
              {runDetails && (
                <div className="space-y-6">
                  {/* Steps */}
                  <div>
                    <h3 className="font-semibold mb-3 flex items-center gap-2">
                      <Activity className="h-4 w-4" />
                      Steps ({runDetails.steps.length})
                    </h3>
                    <div className="space-y-2">
                      {runDetails.steps.map((step: any) => (
                        <Card key={step.id}>
                          <CardContent className="py-3 px-4">
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-2">
                                <Badge variant="outline" className="text-xs">#{step.step_order}</Badge>
                                <span className="font-medium text-sm">{step.step_type}</span>
                                {step.tool_name && <Badge variant="secondary" className="text-xs">{step.tool_name}</Badge>}
                              </div>
                              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                                {step.duration_ms && <span>{step.duration_ms}ms</span>}
                                {step.tokens_used > 0 && <span>{step.tokens_used} tokens</span>}
                                <Badge variant={step.status === 'completed' ? 'default' : 'destructive'} className="text-xs">{step.status}</Badge>
                              </div>
                            </div>
                            {step.error_message && (
                              <p className="text-xs text-destructive mt-2">{step.error_message}</p>
                            )}
                          </CardContent>
                        </Card>
                      ))}
                    </div>
                  </div>

                  <Separator />

                  {/* Audit Receipts */}
                  <div>
                    <h3 className="font-semibold mb-3 flex items-center gap-2">
                      <Shield className="h-4 w-4" />
                      Comprovantes de Auditoria ({runDetails.receipts.length})
                    </h3>
                    <div className="space-y-2">
                      {runDetails.receipts.length === 0 ? (
                        <p className="text-sm text-muted-foreground">Nenhum comprovante gerado</p>
                      ) : (
                        runDetails.receipts.map((receipt: any) => (
                          <Card key={receipt.id}>
                            <CardContent className="py-3 px-4">
                              <div className="flex items-center justify-between">
                                <div>
                                  <p className="font-medium text-sm">{receipt.action_type}</p>
                                  <p className="text-xs text-muted-foreground">{receipt.action_description}</p>
                                </div>
                                <div className="flex items-center gap-2">
                                  <Badge variant={receipt.risk_level === 'critical' ? 'destructive' : 'outline'} className="text-xs">
                                    {receipt.risk_level}
                                  </Badge>
                                  {receipt.pii_detected && (
                                    <Badge variant="destructive" className="text-xs">PII</Badge>
                                  )}
                                  {receipt.requires_approval && (
                                    <Badge variant="secondary" className="text-xs">
                                      {receipt.approval_status || 'pending'}
                                    </Badge>
                                  )}
                                </div>
                              </div>
                              {receipt.tool_used && (
                                <p className="text-xs mt-1">Ferramenta: <code className="bg-muted px-1 rounded">{receipt.tool_used}</code></p>
                              )}
                              {receipt.affected_entity_type && (
                                <p className="text-xs mt-1">Entidade: {receipt.affected_entity_type} ({receipt.affected_entity_id})</p>
                              )}
                            </CardContent>
                          </Card>
                        ))
                      )}
                    </div>
                  </div>
                </div>
              )}
            </ScrollArea>
          </DialogContent>
        </Dialog>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { toast } from 'sonner';
import {
  Wrench, Plus, Search, Shield, AlertTriangle, Loader2,
  Code, Globe, Database, Zap, Workflow
} from '@/components/icons';

const TOOL_TYPE_ICONS: Record<string, React.ElementType> = {
  http_request: Globe,
  database_query: Database,
  rpc_call: Code,
  connector_action: Zap,
  workflow_trigger: Workflow,
};

const RISK_COLORS: Record<string, string> = {
  low: 'bg-green-500/10 text-green-700',
  medium: 'bg-yellow-500/10 text-yellow-700',
  high: 'bg-orange-500/10 text-orange-700',
  critical: 'bg-red-500/10 text-red-700',
};

export default function AITools() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const orgId = profile?.organization_id;
  const [search, setSearch] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [form, setForm] = useState({
    name: '', description: '', tool_type: 'rpc_call' as string,
    risk_level: 'low' as string, requires_approval: false,
    parameters_schema: '{\n  "type": "object",\n  "properties": {}\n}',
    action_config: '{}', category: '',
  });

  const { data: tools, isLoading } = useQuery({
    queryKey: ['ai-tools', orgId],
    queryFn: async () => {
      if (!orgId) return [];
      const { data, error } = await supabase
        .from('ai_tools')
        .select('*')
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!orgId,
  });

  const createTool = useMutation({
    mutationFn: async () => {
      if (!orgId || !form.name.trim()) throw new Error('Nome obrigatório');
      let parsedParams, parsedConfig;
      try { parsedParams = JSON.parse(form.parameters_schema); } catch { throw new Error('Parameters schema inválido'); }
      try { parsedConfig = JSON.parse(form.action_config); } catch { throw new Error('Action config inválido'); }

      const { error } = await supabase.from('ai_tools').insert({
        organization_id: orgId,
        name: form.name, description: form.description || null,
        tool_type: form.tool_type as any, risk_level: form.risk_level as any,
        requires_approval: form.requires_approval,
        parameters_schema: parsedParams, action_config: parsedConfig,
        category: form.category || null, created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ai-tools'] });
      toast.success('Ferramenta criada');
      setDialogOpen(false);
      setForm({ name: '', description: '', tool_type: 'rpc_call', risk_level: 'low', requires_approval: false, parameters_schema: '{\n  "type": "object",\n  "properties": {}\n}', action_config: '{}', category: '' });
    },
