import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';

const STATUS_LABELS: Record<string, string> = {
  pending: 'Pendente',
  confirmed: 'Confirmado',
  processing: 'Processando',
  shipped: 'Enviado',
  delivered: 'Entregue',
  cancelled: 'Cancelado',
  refunded: 'Reembolsado',
};

const STATUS_VARIANT: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
  pending: 'outline',
  confirmed: 'secondary',
  processing: 'secondary',
  shipped: 'default',
  delivered: 'default',
  cancelled: 'destructive',
  refunded: 'destructive',
};

function getPortalSession() {
  try {
    const session = localStorage.getItem('portal_session');
    return session ? JSON.parse(session) : null;
  } catch { return null; }
}

export default function PortalOrders() {
  const session = getPortalSession();
  const accountId = session?.account_id;
  const orgId = session?.organization_id;
  const [selectedOrder, setSelectedOrder] = useState<any>(null);

  const { data: orders, isLoading } = useQuery({
    queryKey: ['portal-orders', accountId],
    queryFn: async () => {
      if (!accountId || !orgId) return [];
      const { data, error } = await supabase
        .from('orders')
        .select('*, order_items(*)')
        .eq('account_id', accountId)
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!accountId && !!orgId,
  });

  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <PortalLayout>
      <div className="space-y-6">
        <h1 className="text-3xl font-bold">Meus Pedidos</h1>

        <Card>
          <CardContent className="p-0">
            {isLoading ? (
              <div className="p-6 space-y-3">
                {[1, 2, 3].map(i => <Skeleton key={i} className="h-14 w-full" />)}
              </div>
            ) : orders && orders.length > 0 ? (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Pedido</TableHead>
                    <TableHead>Data</TableHead>
                    <TableHead>Itens</TableHead>
                    <TableHead>Total</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Rastreio</TableHead>
                    <TableHead></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {orders.map((order) => (
                    <TableRow key={order.id}>
                      <TableCell className="font-mono font-medium">{order.order_number}</TableCell>
                      <TableCell className="text-sm text-muted-foreground">
                        {format(new Date(order.created_at), 'dd/MM/yyyy', { locale: ptBR })}
                      </TableCell>
                      <TableCell>{(order.order_items as any[])?.length ?? 0}</TableCell>
                      <TableCell className="font-semibold">{formatCurrency(Number(order.grand_total))}</TableCell>
                      <TableCell>
                        <Badge variant={STATUS_VARIANT[order.status ?? 'pending'] || 'outline'}>
                          {STATUS_LABELS[order.status ?? 'pending'] || order.status}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-sm">
                        {order.tracking_number || '—'}
                      </TableCell>
                      <TableCell>
                        <Button variant="ghost" size="sm" onClick={() => setSelectedOrder(order)}>
                          <Eye className="h-4 w-4" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            ) : (
              <div className="p-12 text-center text-muted-foreground">
                <ShoppingCart className="h-12 w-12 mx-auto mb-3" />
                <p className="text-lg font-medium">Nenhum pedido encontrado</p>
                <p className="text-sm mt-1">Seus pedidos aparecerão aqui assim que forem realizados.</p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Order Detail Dialog */}
      <Dialog open={!!selectedOrder} onOpenChange={() => setSelectedOrder(null)}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Pedido {selectedOrder?.order_number}</DialogTitle>
          </DialogHeader>
          {selectedOrder && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <span className="text-muted-foreground">Status: </span>
                  <Badge variant={STATUS_VARIANT[selectedOrder.status ?? 'pending'] || 'outline'}>
                    {STATUS_LABELS[selectedOrder.status ?? 'pending'] || selectedOrder.status}
                  </Badge>
                </div>
                <div>
                  <span className="text-muted-foreground">Data: </span>
                  {format(new Date(selectedOrder.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR })}
                </div>
                {selectedOrder.tracking_number && (
                  <div className="col-span-2">
                    <span className="text-muted-foreground">Rastreio: </span>
                    <span className="font-mono">{selectedOrder.tracking_number}</span>
                  </div>
                )}
              </div>
              <Separator />
              <div>
                <h4 className="font-medium mb-2">Itens</h4>
                <div className="space-y-2">
                  {(selectedOrder.order_items as any[])?.map((item: any) => (
                    <div key={item.id} className="flex justify-between text-sm">
                      <span>{item.quantity}x {item.name}</span>
                      <span className="font-medium">{formatCurrency(Number(item.total))}</span>
                    </div>
                  ))}
                </div>
              </div>
              <Separator />
              <div className="space-y-1 text-sm">
                <div className="flex justify-between"><span className="text-muted-foreground">Subtotal</span><span>{formatCurrency(Number(selectedOrder.subtotal))}</span></div>
                {Number(selectedOrder.discount_total) > 0 && (
                  <div className="flex justify-between"><span className="text-muted-foreground">Desconto</span><span className="text-green-600">-{formatCurrency(Number(selectedOrder.discount_total))}</span></div>
                )}
                {Number(selectedOrder.tax_total) > 0 && (
                  <div className="flex justify-between"><span className="text-muted-foreground">Impostos</span><span>{formatCurrency(Number(selectedOrder.tax_total))}</span></div>
                )}
                {Number(selectedOrder.shipping_total) > 0 && (
                  <div className="flex justify-between"><span className="text-muted-foreground">Frete</span><span>{formatCurrency(Number(selectedOrder.shipping_total))}</span></div>
                )}
                <div className="flex justify-between font-bold text-base pt-1 border-t">
                  <span>Total</span><span>{formatCurrency(Number(selectedOrder.grand_total))}</span>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </PortalLayout>
  );
}

import { PortalLayout } from './PortalLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Loader2 } from '@/components/icons';
import { toast } from 'sonner';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Skeleton } from '@/components/ui/skeleton';
import { useState, useEffect } from 'react';

function getPortalSession() {
  try {
    const session = localStorage.getItem('portal_session');
    return session ? JSON.parse(session) : null;
  } catch { return null; }
}

interface ChannelPrefs {
  [key: string]: string;
  email: string;
  sms: string;
  whatsapp: string;
  push: string;
}

export default function PortalPreferences() {
  const session = getPortalSession();
  const contactId = session?.contact_id;
  const orgId = session?.organization_id;
  const queryClient = useQueryClient();

  const [channels, setChannels] = useState<ChannelPrefs>({
    email: 'opt_in',
    sms: 'opt_in',
    whatsapp: 'opt_in',
    push: 'opt_in',
  });
  const [frequency, setFrequency] = useState('normal');
  const [globalOptout, setGlobalOptout] = useState(false);

  const { data: preferences, isLoading } = useQuery({
    queryKey: ['portal-preferences', contactId],
    queryFn: async () => {
      if (!contactId) return null;
      const { data, error } = await supabase
        .from('contact_preferences')
        .select('*')
        .eq('contact_id', contactId)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!contactId,
  });

  useEffect(() => {
    if (preferences) {
      const cp = preferences.channel_preferences as Record<string, string> | null;
      if (cp) {
        setChannels({
          email: cp.email || 'opt_in',
          sms: cp.sms || 'opt_in',
          whatsapp: cp.whatsapp || 'opt_in',
          push: cp.push || 'opt_in',
        });
      }
      setFrequency(preferences.frequency_limit || 'normal');
      setGlobalOptout(preferences.global_optout || false);
    }
  }, [preferences]);

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (!contactId) throw new Error('Sessão inválida');

      const payload = {
        contact_id: contactId,
        channel_preferences: channels as any,
        frequency_limit: frequency,
        global_optout: globalOptout,
        updated_at: new Date().toISOString(),
        updated_source: 'portal',
      };

      if (preferences?.id) {
        const { error } = await supabase
          .from('contact_preferences')
          .update(payload)
          .eq('id', preferences.id);
        if (error) throw error;
      } else {
        // Need organization_id for insert - get from session
        const { error } = await supabase
          .from('contact_preferences')
          .insert({ ...payload, organization_id: orgId } as any);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['portal-preferences'] });
      toast.success('Preferências salvas com sucesso!');
    },
    onError: (err) => toast.error(`Erro ao salvar: ${err.message}`),
  });

  const toggleChannel = (channel: keyof ChannelPrefs) => {
    setChannels(prev => ({
      ...prev,
      [channel]: prev[channel] === 'opt_in' ? 'opt_out' : 'opt_in',
    }));
  };

  return (
    <PortalLayout>
      <div className="space-y-6 max-w-2xl">
        <h1 className="text-3xl font-bold">Preferências de Comunicação</h1>

        {isLoading ? (
          <div className="space-y-4">
            <Skeleton className="h-[200px] w-full" />
            <Skeleton className="h-[150px] w-full" />
          </div>
        ) : (
          <>
            {/* Global Opt-out */}
            <Card>
              <CardHeader><CardTitle>Opt-out Global</CardTitle></CardHeader>
              <CardContent>
                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-base">Desativar todas as comunicações</Label>
                    <p className="text-sm text-muted-foreground">Ao ativar, você não receberá nenhuma comunicação de marketing.</p>
                  </div>
                  <Switch checked={globalOptout} onCheckedChange={setGlobalOptout} />
                </div>
              </CardContent>
            </Card>

            {/* Channel Preferences */}
            <Card>
              <CardHeader><CardTitle>Canais de Comunicação</CardTitle></CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label>Email</Label>
                  <Switch
                    checked={channels.email === 'opt_in'}
                    onCheckedChange={() => toggleChannel('email')}
                    disabled={globalOptout}
                  />
                </div>
                <div className="flex items-center justify-between">
                  <Label>SMS</Label>
                  <Switch
                    checked={channels.sms === 'opt_in'}
                    onCheckedChange={() => toggleChannel('sms')}
                    disabled={globalOptout}
                  />
                </div>
                <div className="flex items-center justify-between">
                  <Label>WhatsApp</Label>
                  <Switch
                    checked={channels.whatsapp === 'opt_in'}
                    onCheckedChange={() => toggleChannel('whatsapp')}
                    disabled={globalOptout}
                  />
                </div>
                <div className="flex items-center justify-between">
                  <Label>Push Notifications</Label>
                  <Switch
                    checked={channels.push === 'opt_in'}
                    onCheckedChange={() => toggleChannel('push')}
                    disabled={globalOptout}
                  />
                </div>
              </CardContent>
            </Card>

            {/* Frequency */}
            <Card>
              <CardHeader><CardTitle>Frequência</CardTitle></CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Limite de frequência</Label>
                  <Select value={frequency} onValueChange={setFrequency} disabled={globalOptout}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Baixa (máx. 1x/semana)</SelectItem>
                      <SelectItem value="normal">Normal (máx. 3x/semana)</SelectItem>
                      <SelectItem value="high">Alta (sem limite)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </CardContent>
            </Card>

            {/* General */}
            <Card>
              <CardHeader><CardTitle>Configurações Gerais</CardTitle></CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Idioma</Label>
                  <Select defaultValue="pt-BR">
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="pt-BR">Português (BR)</SelectItem>
                      <SelectItem value="en">English</SelectItem>
                      <SelectItem value="es">Español</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Fuso Horário</Label>
                  <Select defaultValue="America/Sao_Paulo">
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="America/Sao_Paulo">São Paulo (BRT)</SelectItem>
                      <SelectItem value="America/New_York">New York (EST)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </CardContent>
            </Card>

            <Button
              onClick={() => saveMutation.mutate()}
              disabled={saveMutation.isPending}
              className="gap-2"
            >
              {saveMutation.isPending && <Loader2 className="h-4 w-4 animate-spin" />}
              Salvar Preferências
            </Button>
          </>
        )}
      </div>
    </PortalLayout>
  );
}

import { PortalLayout } from './PortalLayout';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { RotateCcw, Plus, Loader2 } from '@/components/icons';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Skeleton } from '@/components/ui/skeleton';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { useState } from 'react';
import { toast } from 'sonner';

const STATUS_LABELS: Record<string, string> = {
  requested: 'Solicitada',
  approved: 'Aprovada',
  rejected: 'Rejeitada',
  received: 'Recebida',
  refunded: 'Reembolsada',
  completed: 'Concluída',
};

const STATUS_VARIANT: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
  requested: 'outline',
  approved: 'secondary',
  rejected: 'destructive',
  received: 'secondary',
  refunded: 'default',
  completed: 'default',
};

function getPortalSession() {
  try {
    const session = localStorage.getItem('portal_session');
    return session ? JSON.parse(session) : null;
  } catch { return null; }
}

export default function PortalReturns() {
  const session = getPortalSession();
  const accountId = session?.account_id;
  const orgId = session?.organization_id;
  const queryClient = useQueryClient();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [selectedOrderId, setSelectedOrderId] = useState('');
  const [reason, setReason] = useState('');
  const [reasonCategory, setReasonCategory] = useState('');

  const { data: returns, isLoading } = useQuery({
    queryKey: ['portal-returns', accountId],
    queryFn: async () => {
      if (!accountId || !orgId) return [];
      // Get orders for this account first
      const { data: orders } = await supabase
        .from('orders')
        .select('id')
        .eq('account_id', accountId)
        .eq('organization_id', orgId);

      if (!orders || orders.length === 0) return [];
      const orderIds = orders.map(o => o.id);

      const { data, error } = await supabase
        .from('returns')
        .select('*, orders(order_number)')
        .in('order_id', orderIds)
        .eq('organization_id', orgId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!accountId && !!orgId,
  });

  const { data: eligibleOrders } = useQuery({
    queryKey: ['portal-eligible-orders', accountId],
    queryFn: async () => {
      if (!accountId || !orgId) return [];
      const { data, error } = await supabase
        .from('orders')
        .select('id, order_number')
        .eq('account_id', accountId)
        .eq('organization_id', orgId)
        .in('status', ['delivered', 'shipped'])
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!accountId && !!orgId,
  });

  const createReturn = useMutation({
    mutationFn: async () => {
      if (!orgId || !selectedOrderId) throw new Error('Dados incompletos');
      const { data: returnNumber } = await supabase.rpc('generate_return_number', { org_id: orgId });
      const { error } = await supabase.from('returns').insert({
        organization_id: orgId,
        order_id: selectedOrderId,
        return_number: returnNumber || `RMA-${Date.now()}`,
        reason,
        reason_category: reasonCategory,
        items: [],
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['portal-returns'] });
      toast.success('Devolução solicitada com sucesso!');
      setDialogOpen(false);
      setSelectedOrderId('');
      setReason('');
      setReasonCategory('');
    },
    onError: (err) => toast.error(`Erro: ${err.message}`),
  });

  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <PortalLayout>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-3xl font-bold">Devoluções</h1>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button className="gap-2"><Plus className="h-4 w-4" /> Solicitar Devolução</Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Solicitar Devolução</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label>Pedido *</Label>
                  <Select value={selectedOrderId} onValueChange={setSelectedOrderId}>
                    <SelectTrigger><SelectValue placeholder="Selecione o pedido" /></SelectTrigger>
                    <SelectContent>
                      {eligibleOrders?.map(o => (
                        <SelectItem key={o.id} value={o.id}>{o.order_number}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Categoria do Motivo</Label>
                  <Select value={reasonCategory} onValueChange={setReasonCategory}>
                    <SelectTrigger><SelectValue placeholder="Selecione" /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="defective">Produto Defeituoso</SelectItem>
                      <SelectItem value="wrong_item">Produto Errado</SelectItem>
                      <SelectItem value="not_as_described">Diferente da Descrição</SelectItem>
                      <SelectItem value="changed_mind">Desistência</SelectItem>
                      <SelectItem value="damaged">Produto Danificado</SelectItem>
                      <SelectItem value="other">Outro</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Motivo Detalhado *</Label>
                  <Textarea
                    value={reason}
                    onChange={(e) => setReason(e.target.value)}
                    placeholder="Descreva o motivo da devolução..."
                    rows={3}
                  />
                </div>
                <Button
                  className="w-full gap-2"
                  disabled={!selectedOrderId || !reason.trim() || createReturn.isPending}
                  onClick={() => createReturn.mutate()}
                >
                  {createReturn.isPending && <Loader2 className="h-4 w-4 animate-spin" />}
                  Solicitar Devolução
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>

        <Card>
          <CardContent className="p-0">
            {isLoading ? (
              <div className="p-6 space-y-3">
                {[1, 2, 3].map(i => <Skeleton key={i} className="h-12 w-full" />)}
              </div>
            ) : returns && returns.length > 0 ? (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Nº Devolução</TableHead>
                    <TableHead>Pedido</TableHead>
                    <TableHead>Motivo</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Reembolso</TableHead>
                    <TableHead>Data</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {returns.map((ret) => {
                    const order = ret.orders as any;
                    return (
                      <TableRow key={ret.id}>
                        <TableCell className="font-mono font-medium">{ret.return_number}</TableCell>
                        <TableCell className="font-mono text-sm">{order?.order_number || '—'}</TableCell>
                        <TableCell className="max-w-[200px] truncate text-sm">{ret.reason}</TableCell>
                        <TableCell>
                          <Badge variant={STATUS_VARIANT[ret.status ?? 'requested'] || 'outline'}>
                            {STATUS_LABELS[ret.status ?? 'requested'] || ret.status}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          {ret.refund_amount ? formatCurrency(Number(ret.refund_amount)) : '—'}
                        </TableCell>
                        <TableCell className="text-sm text-muted-foreground">
                          {format(new Date(ret.created_at), 'dd/MM/yyyy', { locale: ptBR })}
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            ) : (
              <div className="p-12 text-center text-muted-foreground">
                <RotateCcw className="h-12 w-12 mx-auto mb-3" />
                <p className="text-lg font-medium">Nenhuma devolução em andamento</p>
                <p className="text-sm mt-1">Solicite devoluções para pedidos entregues ou enviados.</p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </PortalLayout>
  );
}

