            ) : (
              <div className="space-y-3">
                {filteredTickets.map((ticket) => {
                  const statusInfo = statusConfig[ticket.status];
                  const StatusIcon = statusInfo.icon;

                  return (
                    <Card
                      key={ticket.id}
                      className="cursor-pointer hover:bg-muted/50 transition-colors"
                      onClick={() => navigate(`/portal/tickets/${ticket.id}`)}
                    >
                      <CardContent className="p-4">
                        <div className="flex items-start gap-4">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                              <span className="font-mono text-sm text-muted-foreground">
                                {ticket.ticket_number}
                              </span>
                              <Badge className={statusInfo.color}>
                                <StatusIcon className="mr-1 h-3 w-3" />
                                {statusInfo.label}
                              </Badge>
                              {ticket.unread_count > 0 && (
                                <Badge variant="destructive" className="rounded-full">
                                  {ticket.unread_count} nova{ticket.unread_count > 1 ? 's' : ''}
                                </Badge>
                              )}
                            </div>
                            <h3 className="font-semibold mt-1 truncate">
                              {ticket.subject}
                            </h3>
                            <p className="text-sm text-muted-foreground mt-1 line-clamp-1">
                              {ticket.last_message}
                            </p>
                            <div className="flex items-center gap-4 mt-2 text-xs text-muted-foreground">
                              <span className="flex items-center gap-1">
                                <Clock className="h-3 w-3" />
                                Criado {formatDistanceToNow(new Date(ticket.created_at), {
                                  addSuffix: true,
                                  locale: ptBR,
                                })}
                              </span>
                              <span>
                                Atualizado {formatDistanceToNow(new Date(ticket.updated_at), {
                                  addSuffix: true,
                                  locale: ptBR,
                                })}
                              </span>
                            </div>
                          </div>
                          <ChevronRight className="h-5 w-5 text-muted-foreground shrink-0" />
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </div>
    </PortalLayout>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Search, Filter, FileText, DollarSign, AlertTriangle,
  CheckCircle, Clock, XCircle, Receipt, ArrowDownRight, ArrowUpRight
} from '@/components/icons';

const invoiceStatusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  draft: { label: 'Rascunho', variant: 'secondary' },
  pending: { label: 'Pendente', variant: 'outline' },
  sent: { label: 'Enviada', variant: 'outline' },
  paid: { label: 'Paga', variant: 'default' },
  partial: { label: 'Parcial', variant: 'outline' },
  overdue: { label: 'Vencida', variant: 'destructive' },
  cancelled: { label: 'Cancelada', variant: 'secondary' },
  void: { label: 'Anulada', variant: 'secondary' },
  refunded: { label: 'Reembolsada', variant: 'outline' },
};

const ledgerTypeLabels: Record<string, { label: string; icon: React.ElementType; color: string }> = {
  charge: { label: 'Cobrança', icon: ArrowUpRight, color: 'text-destructive' },
  payment: { label: 'Pagamento', icon: ArrowDownRight, color: 'text-green-600' },
  credit: { label: 'Crédito', icon: ArrowDownRight, color: 'text-green-600' },
  debit: { label: 'Débito', icon: ArrowUpRight, color: 'text-destructive' },
  refund: { label: 'Reembolso', icon: ArrowDownRight, color: 'text-amber-600' },
  adjustment: { label: 'Ajuste', icon: Receipt, color: 'text-muted-foreground' },
  write_off: { label: 'Baixa', icon: XCircle, color: 'text-muted-foreground' },
};

export default function Billing() {
  const { profile } = useAuth();
  const navigate = useNavigate();
  const organizationId = profile?.organization_id;

  const [activeTab, setActiveTab] = useState('invoices');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');

  // Invoices query
  const { data: invoices = [], isLoading: loadingInvoices } = useQuery({
    queryKey: ['invoices', organizationId, statusFilter, searchTerm],
    queryFn: async () => {
      let query = supabase
        .from('invoices')
        .select(`*, accounts:account_id (name)`)
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false });

      if (statusFilter !== 'all') query = query.eq('status', statusFilter as any);
      if (searchTerm) query = query.or(`invoice_number.ilike.%${searchTerm}%,billing_name.ilike.%${searchTerm}%`);

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // Payment Ledger query
  const { data: ledgerEntries = [], isLoading: loadingLedger } = useQuery({
    queryKey: ['payment-ledger', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('payment_ledger')
        .select(`*, accounts:account_id (name)`)
        .eq('organization_id', organizationId!)
        .order('transaction_date', { ascending: false })
        .limit(100);
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // Dunning query
  const { data: dunningAttempts = [] } = useQuery({
    queryKey: ['dunning-attempts', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('dunning_attempts')
        .select(`*, invoices:invoice_id (invoice_number, total), accounts:account_id (name)`)
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // KPIs
  const totalInvoiced = invoices.reduce((s: number, i: any) => s + (i.total || 0), 0);
  const totalPaid = invoices.filter((i: any) => i.status === 'paid').reduce((s: number, i: any) => s + (i.total || 0), 0);
  const totalOverdue = invoices.filter((i: any) => i.status === 'overdue').reduce((s: number, i: any) => s + (i.amount_due || 0), 0);
  const pendingDunning = dunningAttempts.filter((d: any) => d.status === 'pending' || d.status === 'sent').length;

  const fmt = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  return (
    <>
      <div className="space-y-6 p-6">
        <ModuleHeroBanner
          module="sales"
          title="Faturamento & Billing"
          subtitle="Faturas, pagamentos, livro razão e cobranças automáticas"
          compact
        />

        {/* KPIs */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total Faturado</CardTitle>
              <FileText className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{fmt(totalInvoiced)}</div>
              <p className="text-xs text-muted-foreground">{invoices.length} faturas</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total Pago</CardTitle>
              <CheckCircle className="h-4 w-4 text-green-600" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-green-600">{fmt(totalPaid)}</div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total Vencido</CardTitle>
              <AlertTriangle className="h-4 w-4 text-destructive" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-destructive">{fmt(totalOverdue)}</div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Cobranças Pendentes</CardTitle>
              <Clock className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{pendingDunning}</div>
              <p className="text-xs text-muted-foreground">dunning ativo</p>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="invoices"><FileText className="h-4 w-4 mr-2" />Faturas</TabsTrigger>
            <TabsTrigger value="ledger"><Receipt className="h-4 w-4 mr-2" />Livro Razão</TabsTrigger>
            <TabsTrigger value="dunning"><AlertTriangle className="h-4 w-4 mr-2" />Dunning</TabsTrigger>
          </TabsList>

          {/* Invoices */}
          <TabsContent value="invoices" className="space-y-4">
            <div className="flex items-center gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input placeholder="Buscar faturas..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="pl-10" />
              </div>
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[180px]">
                  <Filter className="h-4 w-4 mr-2" /><SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="draft">Rascunho</SelectItem>
                  <SelectItem value="pending">Pendente</SelectItem>
                  <SelectItem value="sent">Enviada</SelectItem>
                  <SelectItem value="paid">Paga</SelectItem>
                  <SelectItem value="overdue">Vencida</SelectItem>
                  <SelectItem value="cancelled">Cancelada</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Número</TableHead>
                    <TableHead>Conta</TableHead>
                    <TableHead>Emissão</TableHead>
                    <TableHead>Vencimento</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="text-right">Total</TableHead>
                    <TableHead className="text-right">Pago</TableHead>
                    <TableHead className="text-right">Devido</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loadingInvoices ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
                  ) : invoices.length === 0 ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Nenhuma fatura encontrada</TableCell></TableRow>
                  ) : invoices.map((inv: any) => {
                    const st = invoiceStatusConfig[inv.status] || invoiceStatusConfig.draft;
                    return (
                      <TableRow key={inv.id} className="cursor-pointer hover:bg-muted/50" onClick={() => navigate(`/sales/billing/${inv.id}`)}>
                        <TableCell className="font-mono text-sm">{inv.invoice_number}</TableCell>
                        <TableCell className="font-medium">{inv.accounts?.name || '—'}</TableCell>
                        <TableCell className="text-sm">{format(new Date(inv.issue_date), 'dd/MM/yy', { locale: ptBR })}</TableCell>
                        <TableCell className="text-sm">{format(new Date(inv.due_date), 'dd/MM/yy', { locale: ptBR })}</TableCell>
                        <TableCell><Badge variant={st.variant}>{st.label}</Badge></TableCell>
                        <TableCell className="text-right font-mono">{fmt(inv.total)}</TableCell>
                        <TableCell className="text-right font-mono text-green-600">{fmt(inv.amount_paid)}</TableCell>
                        <TableCell className="text-right font-mono font-semibold">{fmt(inv.amount_due)}</TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Ledger */}
          <TabsContent value="ledger" className="space-y-4">
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Data</TableHead>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Conta</TableHead>
                    <TableHead>Descrição</TableHead>
                    <TableHead>Referência</TableHead>
                    <TableHead className="text-right">Valor</TableHead>
                    <TableHead>Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loadingLedger ? (
                    <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
                  ) : ledgerEntries.length === 0 ? (
                    <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">Nenhuma entrada</TableCell></TableRow>
                  ) : ledgerEntries.map((entry: any) => {
                    const lt = ledgerTypeLabels[entry.entry_type] || ledgerTypeLabels.adjustment;
                    const LTIcon = lt.icon;
                    return (
                      <TableRow key={entry.id}>
                        <TableCell className="text-sm">{format(new Date(entry.transaction_date), 'dd/MM/yy HH:mm', { locale: ptBR })}</TableCell>
                        <TableCell>
                          <Badge variant="outline" className="gap-1">
                            <LTIcon className={`h-3 w-3 ${lt.color}`} />{lt.label}
                          </Badge>
                        </TableCell>
                        <TableCell className="font-medium">{entry.accounts?.name || '—'}</TableCell>
                        <TableCell className="text-sm max-w-[200px] truncate">{entry.description}</TableCell>
                        <TableCell className="font-mono text-xs">{entry.reference_number || '—'}</TableCell>
                        <TableCell className={`text-right font-mono font-semibold ${entry.entry_type === 'payment' || entry.entry_type === 'credit' ? 'text-green-600' : ''}`}>
                          {fmt(entry.amount)}
                        </TableCell>
                        <TableCell><Badge variant="outline">{entry.status}</Badge></TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Dunning */}
          <TabsContent value="dunning" className="space-y-4">
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Fatura</TableHead>
                    <TableHead>Conta</TableHead>
                    <TableHead>Tentativa #</TableHead>
                    <TableHead>Canal</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Enviado em</TableHead>
                    <TableHead>Próxima Tentativa</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {dunningAttempts.length === 0 ? (
                    <TableRow><TableCell colSpan={7} className="text-center py-8 text-muted-foreground">Nenhuma cobrança registrada</TableCell></TableRow>
                  ) : dunningAttempts.map((d: any) => (
                    <TableRow key={d.id}>
                      <TableCell className="font-mono text-sm">{d.invoices?.invoice_number || '—'}</TableCell>
                      <TableCell className="font-medium">{d.accounts?.name || '—'}</TableCell>
                      <TableCell><Badge variant="outline">{d.attempt_number}/{d.max_attempts}</Badge></TableCell>
                      <TableCell><Badge variant="secondary">{d.channel}</Badge></TableCell>
                      <TableCell>
                        <Badge variant={d.status === 'resolved' ? 'default' : d.status === 'failed' ? 'destructive' : 'outline'}>
                          {d.status}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-sm">{d.sent_at ? format(new Date(d.sent_at), 'dd/MM/yy HH:mm', { locale: ptBR }) : '—'}</TableCell>
                      <TableCell className="text-sm">{d.next_attempt_at ? format(new Date(d.next_attempt_at), 'dd/MM/yy', { locale: ptBR }) : '—'}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Separator } from '@/components/ui/separator';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  ArrowLeft, CheckCircle, XCircle, Send, DollarSign, FileText,
  Building2, Calendar, Receipt
} from '@/components/icons';

const invoiceStatusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  draft: { label: 'Rascunho', variant: 'secondary' },
  pending: { label: 'Pendente', variant: 'outline' },
  sent: { label: 'Enviada', variant: 'outline' },
  paid: { label: 'Paga', variant: 'default' },
  partial: { label: 'Parcial', variant: 'outline' },
  overdue: { label: 'Vencida', variant: 'destructive' },
  cancelled: { label: 'Cancelada', variant: 'secondary' },
  void: { label: 'Anulada', variant: 'secondary' },
  refunded: { label: 'Reembolsada', variant: 'outline' },
};

export default function BillingDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const queryClient = useQueryClient();

  const { data: invoice, isLoading } = useQuery({
    queryKey: ['invoice', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('invoices')
        .select(`*, accounts:account_id (name, email, phone)`)
        .eq('id', id!)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: items = [] } = useQuery({
    queryKey: ['invoice-items', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('invoice_items')
        .select('*')
        .eq('invoice_id', id!)
        .order('sort_order', { ascending: true });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  const { data: payments = [] } = useQuery({
    queryKey: ['invoice-payments', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('payment_ledger')
        .select('*')
        .eq('invoice_id', id!)
        .order('transaction_date', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  const updateStatus = useMutation({
    mutationFn: async (newStatus: string) => {
      const { error } = await supabase
        .from('invoices')
        .update({ status: newStatus as any })
        .eq('id', id!);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['invoice', id] });
      toast.success('Status da fatura atualizado');
    },
    onError: () => toast.error('Erro ao atualizar status'),
  });

  const recordPayment = useMutation({
    mutationFn: async () => {
      if (!invoice) return;
      const { error } = await supabase.from('payment_ledger').insert({
        organization_id: invoice.organization_id,
        account_id: invoice.account_id,
        invoice_id: id!,
        entry_type: 'payment',
        description: `Pagamento da fatura ${invoice.invoice_number}`,
        amount: invoice.amount_due,
        status: 'completed',
        payment_method: 'manual',
        created_by: profile?.id,
      });
      if (error) throw error;

      // Mark invoice as paid
      await supabase.from('invoices').update({
        status: 'paid',
        amount_paid: invoice.total,
        amount_due: 0,
      }).eq('id', id!);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['invoice', id] });
      queryClient.invalidateQueries({ queryKey: ['invoice-payments', id] });
      toast.success('Pagamento registrado');
    },
    onError: () => toast.error('Erro ao registrar pagamento'),
  });

  if (isLoading || !invoice) {
    return <div className="flex items-center justify-center min-h-[400px] text-muted-foreground">Carregando fatura...</div>;
  }

  const st = invoiceStatusConfig[invoice.status] || invoiceStatusConfig.draft;
  const fmt = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: invoice.currency || 'BRL' }).format(v);

  return (
    <>
      <div className="space-y-6 p-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate('/sales/billing')}>
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-bold">{invoice.invoice_number}</h1>
                <Badge variant={st.variant}>{st.label}</Badge>
              </div>
              <p className="text-muted-foreground">{invoice.accounts?.name}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {invoice.status === 'draft' && (
              <Button variant="outline" onClick={() => updateStatus.mutate('sent')}>
                <Send className="h-4 w-4 mr-2" />Enviar
              </Button>
            )}
            {(invoice.status === 'sent' || invoice.status === 'pending' || invoice.status === 'overdue') && (
              <Button onClick={() => recordPayment.mutate()} disabled={recordPayment.isPending}>
                <DollarSign className="h-4 w-4 mr-2" />
                {recordPayment.isPending ? 'Registrando...' : 'Registrar Pagamento'}
              </Button>
            )}
            {invoice.status !== 'void' && invoice.status !== 'paid' && (
              <Button variant="destructive" size="sm" onClick={() => updateStatus.mutate('void')}>
                <XCircle className="h-4 w-4 mr-2" />Anular
              </Button>
            )}
          </div>
        </div>

        <div className="grid gap-6 md:grid-cols-3">
          {/* Invoice Info */}
          <Card className="md:col-span-2">
            <CardHeader>
              <CardTitle>Detalhes da Fatura</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-sm text-muted-foreground">Emissão</p>
                  <p className="font-medium">{format(new Date(invoice.issue_date), 'dd/MM/yyyy', { locale: ptBR })}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Vencimento</p>
                  <p className="font-medium">{format(new Date(invoice.due_date), 'dd/MM/yyyy', { locale: ptBR })}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Método de Pagamento</p>
                  <p className="font-medium">{invoice.payment_method || '—'}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Referência</p>
                  <p className="font-medium">{invoice.payment_reference || '—'}</p>
                </div>
              </div>

              {invoice.notes && (
                <>
                  <Separator />
                  <div>
                    <p className="text-sm text-muted-foreground mb-1">Observações</p>
                    <p className="text-sm">{invoice.notes}</p>
                  </div>
                </>
              )}

              <Separator />

              {/* Line Items */}
              <div>
                <h3 className="font-semibold mb-3">Itens</h3>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Descrição</TableHead>
                      <TableHead className="text-right">Qtd</TableHead>
                      <TableHead className="text-right">Preço Unit.</TableHead>
                      <TableHead className="text-right">Desconto</TableHead>
                      <TableHead className="text-right">Imposto</TableHead>
                      <TableHead className="text-right">Total</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {items.length === 0 ? (
                      <TableRow><TableCell colSpan={6} className="text-center py-4 text-muted-foreground">Nenhum item</TableCell></TableRow>
                    ) : items.map((item: any) => (
                      <TableRow key={item.id}>
                        <TableCell>
                          <p className="font-medium">{item.description}</p>
                          {item.period_start && item.period_end && (
                            <p className="text-xs text-muted-foreground">
                              {format(new Date(item.period_start), 'dd/MM', { locale: ptBR })} — {format(new Date(item.period_end), 'dd/MM', { locale: ptBR })}
                            </p>
                          )}
                        </TableCell>
                        <TableCell className="text-right">{item.quantity}</TableCell>
                        <TableCell className="text-right font-mono">{fmt(item.unit_price)}</TableCell>
                        <TableCell className="text-right font-mono text-destructive">
                          {item.discount_amount > 0 ? `-${fmt(item.discount_amount)}` : '—'}
                        </TableCell>
                        <TableCell className="text-right font-mono">{fmt(item.tax_amount)}</TableCell>
                        <TableCell className="text-right font-mono font-semibold">{fmt(item.total)}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>

          {/* Summary */}
          <div className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Resumo</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Subtotal</span>
                  <span className="font-mono">{fmt(invoice.subtotal)}</span>
                </div>
                {invoice.discount_amount > 0 && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Desconto</span>
                    <span className="font-mono text-destructive">-{fmt(invoice.discount_amount)}</span>
                  </div>
                )}
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Impostos</span>
                  <span className="font-mono">{fmt(invoice.tax_amount)}</span>
                </div>
                {invoice.shipping_amount > 0 && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Frete</span>
                    <span className="font-mono">{fmt(invoice.shipping_amount)}</span>
                  </div>
                )}
                <Separator />
                <div className="flex justify-between text-lg font-bold">
                  <span>Total</span>
                  <span>{fmt(invoice.total)}</span>
                </div>
                <div className="flex justify-between text-green-600">
                  <span>Pago</span>
                  <span className="font-mono">{fmt(invoice.amount_paid)}</span>
                </div>
                <div className="flex justify-between font-bold text-lg">
                  <span>Saldo Devido</span>
                  <span className={invoice.amount_due > 0 ? 'text-destructive' : 'text-green-600'}>{fmt(invoice.amount_due)}</span>
                </div>
              </CardContent>
            </Card>

            {/* Payment History */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Histórico de Pagamentos</CardTitle>
              </CardHeader>
              <CardContent>
                {payments.length === 0 ? (
                  <p className="text-sm text-muted-foreground text-center py-4">Nenhum pagamento registrado</p>
                ) : (
                  <div className="space-y-3">
                    {payments.map((p: any) => (
                      <div key={p.id} className="flex items-center justify-between py-2 border-b last:border-0">
                        <div>
                          <p className="text-sm font-medium">{p.description}</p>
                          <p className="text-xs text-muted-foreground">
                            {format(new Date(p.transaction_date), "dd/MM/yy HH:mm", { locale: ptBR })}
                          </p>
                        </div>
                        <span className="font-mono font-semibold text-green-600">{fmt(p.amount)}</span>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Separator } from '@/components/ui/separator';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  ArrowLeft, Save, CheckCircle, XCircle, Clock, ShieldCheck,
  AlertTriangle, DollarSign, FileText, History, Settings2, Package
} from '@/components/icons';

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline'; icon: React.ElementType }> = {
  draft: { label: 'Rascunho', variant: 'secondary', icon: Clock },
  valid: { label: 'Válida', variant: 'default', icon: CheckCircle },
  invalid: { label: 'Inválida', variant: 'destructive', icon: XCircle },
  approved: { label: 'Aprovada', variant: 'default', icon: ShieldCheck },
  expired: { label: 'Expirada', variant: 'outline', icon: AlertTriangle },
};

export default function CPQConfigurationDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const organizationId = profile?.organization_id;

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState<any>({});

  const { data: config, isLoading } = useQuery({
    queryKey: ['cpq-config', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('cpq_product_configurations')
        .select('*')
        .eq('id', id!)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: calculations = [] } = useQuery({
    queryKey: ['cpq-calculations', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('cpq_price_calculations')
        .select('*')
        .eq('configuration_id', id!)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data || [];
    },
    enabled: !!id,
  });

  const updateConfig = useMutation({
    mutationFn: async (values: Record<string, any>) => {
      const { error } = await supabase
        .from('cpq_product_configurations')
        .update({ ...values, updated_by: profile?.id })
        .eq('id', id!);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-config', id] });
      setIsEditing(false);
      toast.success('Configuração atualizada');
    },
    onError: () => toast.error('Erro ao atualizar'),
  });

  const recalculate = useMutation({
    mutationFn: async () => {
      if (!config) return;
      const adjustedPrice = config.base_price - config.discount_amount;
      const finalPrice = adjustedPrice > 0 ? adjustedPrice : 0;

      // Log the calculation
      await supabase.from('cpq_price_calculations').insert({
        organization_id: organizationId!,
        configuration_id: id!,
        calculation_type: 'recalculation',
        input_data: { base_price: config.base_price, discount_percent: config.discount_percent },
        list_price: config.base_price,
        calculated_price: finalPrice,
        margin_percent: config.base_price > 0 ? ((finalPrice / config.base_price) * 100) : 0,
        calculated_by: profile?.id,
      });

      // Update config
      await supabase.from('cpq_product_configurations').update({
        adjusted_price: adjustedPrice,
        final_price: finalPrice,
        updated_by: profile?.id,
      }).eq('id', id!);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-config', id] });
      queryClient.invalidateQueries({ queryKey: ['cpq-calculations', id] });
      toast.success('Preço recalculado');
    },
    onError: () => toast.error('Erro ao recalcular'),
  });

  const changeStatus = useMutation({
    mutationFn: async (newStatus: string) => {
      const { error } = await supabase
        .from('cpq_product_configurations')
        .update({ status: newStatus as any, updated_by: profile?.id })
        .eq('id', id!);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-config', id] });
      toast.success('Status atualizado');
    },
    onError: () => toast.error('Erro ao mudar status'),
  });

  if (isLoading || !config) {
    return <div className="flex items-center justify-center min-h-[400px] text-muted-foreground">Carregando configuração...</div>;
  }

  const st = statusConfig[config.status] || statusConfig.draft;
  const StatusIcon = st.icon;
  const fmt = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: config.currency || 'BRL' }).format(v);

  return (
    <>
      <div className="space-y-6 p-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" onClick={() => navigate('/sales/cpq')}>
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-bold">{config.name}</h1>
                <Badge variant={st.variant} className="gap-1">
                  <StatusIcon className="h-3 w-3" />{st.label}
                </Badge>
                <Badge variant="outline">v{config.version}</Badge>
              </div>
              {config.description && <p className="text-muted-foreground mt-1">{config.description}</p>}
            </div>
          </div>
          <div className="flex items-center gap-2">
            {config.status === 'draft' && (
              <Button variant="outline" onClick={() => changeStatus.mutate('valid')}>
                <CheckCircle className="h-4 w-4 mr-2" />Validar
              </Button>
            )}
            {config.status === 'valid' && (
              <Button onClick={() => changeStatus.mutate('approved')}>
                <ShieldCheck className="h-4 w-4 mr-2" />Aprovar
              </Button>
            )}
            <Button variant="outline" onClick={() => recalculate.mutate()} disabled={recalculate.isPending}>
              <DollarSign className="h-4 w-4 mr-2" />Recalcular
            </Button>
          </div>
        </div>

        {/* Price Summary Cards */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Preço Base</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">{fmt(config.base_price)}</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Desconto</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold text-destructive">
                {config.discount_percent > 0 ? `-${config.discount_percent}%` : '—'}
              </p>
              {config.discount_amount > 0 && <p className="text-sm text-muted-foreground">{fmt(config.discount_amount)}</p>}
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">Preço Ajustado</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">{fmt(config.adjusted_price)}</p>
            </CardContent>
          </Card>
          <Card className="border-primary">
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-primary">Preço Final</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold text-primary">{fmt(config.final_price)}</p>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs defaultValue="details">
          <TabsList>
            <TabsTrigger value="details"><Settings2 className="h-4 w-4 mr-2" />Detalhes</TabsTrigger>
            <TabsTrigger value="options"><Package className="h-4 w-4 mr-2" />Opções Selecionadas</TabsTrigger>
            <TabsTrigger value="history"><History className="h-4 w-4 mr-2" />Histórico de Cálculos</TabsTrigger>
          </TabsList>

          <TabsContent value="details" className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle>Informações da Configuração</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {isEditing ? (
                  <>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <Label>Nome</Label>
                        <Input value={editData.name || config.name} onChange={e => setEditData((p: any) => ({ ...p, name: e.target.value }))} />
                      </div>
                      <div>
                        <Label>Preço Base</Label>
                        <Input type="number" step="0.01" value={editData.base_price ?? config.base_price} onChange={e => setEditData((p: any) => ({ ...p, base_price: parseFloat(e.target.value) }))} />
                      </div>
                    </div>
                    <div>
                      <Label>Descrição</Label>
                      <Textarea value={editData.description ?? config.description ?? ''} onChange={e => setEditData((p: any) => ({ ...p, description: e.target.value }))} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <Label>Desconto (%)</Label>
                        <Input type="number" step="0.01" value={editData.discount_percent ?? config.discount_percent} onChange={e => setEditData((p: any) => ({ ...p, discount_percent: parseFloat(e.target.value) }))} />
                      </div>
                      <div>
                        <Label>Desconto (R$)</Label>
                        <Input type="number" step="0.01" value={editData.discount_amount ?? config.discount_amount} onChange={e => setEditData((p: any) => ({ ...p, discount_amount: parseFloat(e.target.value) }))} />
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <Button onClick={() => updateConfig.mutate(editData)} disabled={updateConfig.isPending}>
                        <Save className="h-4 w-4 mr-2" />{updateConfig.isPending ? 'Salvando...' : 'Salvar'}
                      </Button>
                      <Button variant="outline" onClick={() => { setIsEditing(false); setEditData({}); }}>Cancelar</Button>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <p className="text-sm text-muted-foreground">Status</p>
                        <Badge variant={st.variant} className="gap-1 mt-1"><StatusIcon className="h-3 w-3" />{st.label}</Badge>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">Versão</p>
                        <p className="font-medium">v{config.version}</p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">Criado em</p>
                        <p className="font-medium">{format(new Date(config.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}</p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">Válido até</p>
                        <p className="font-medium">{config.valid_until ? format(new Date(config.valid_until), 'dd/MM/yyyy', { locale: ptBR }) : '—'}</p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">Requer Aprovação</p>
                        <p className="font-medium">{config.requires_approval ? 'Sim' : 'Não'}</p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">Moeda</p>
                        <p className="font-medium">{config.currency}</p>
                      </div>
                    </div>
                    <Separator />
                    <Button variant="outline" onClick={() => { setIsEditing(true); setEditData({}); }}>Editar</Button>
                  </>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="options">
            <Card>
              <CardHeader>
                <CardTitle>Opções Selecionadas</CardTitle>
                <CardDescription>Opções e componentes incluídos nesta configuração.</CardDescription>
              </CardHeader>
              <CardContent>
                {Array.isArray(config.selected_options) && (config.selected_options as any[]).length > 0 ? (
                  <div className="space-y-2">
                    {(config.selected_options as any[]).map((opt: any, i: number) => (
                      <div key={i} className="flex items-center justify-between p-3 border rounded-lg">
                        <div>
                          <p className="font-medium">{opt.name || `Opção ${i + 1}`}</p>
                          {opt.description && <p className="text-sm text-muted-foreground">{opt.description}</p>}
                        </div>
                        {opt.price && <p className="font-mono">{fmt(opt.price)}</p>}
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground py-8 text-center">Nenhuma opção selecionada ainda.</p>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="history">
            <Card>
              <CardHeader>
                <CardTitle>Histórico de Cálculos</CardTitle>
                <CardDescription>Auditoria de todas as recalculações de preço.</CardDescription>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Data</TableHead>
                      <TableHead>Tipo</TableHead>
                      <TableHead className="text-right">Preço Lista</TableHead>
                      <TableHead className="text-right">Preço Calculado</TableHead>
                      <TableHead className="text-right">Margem</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {calculations.length === 0 ? (
                      <TableRow><TableCell colSpan={5} className="text-center py-8 text-muted-foreground">Nenhum cálculo registrado</TableCell></TableRow>
                    ) : calculations.map((calc: any) => (
                      <TableRow key={calc.id}>
                        <TableCell className="text-sm">{format(new Date(calc.created_at), "dd/MM/yy HH:mm", { locale: ptBR })}</TableCell>
                        <TableCell><Badge variant="outline">{calc.calculation_type}</Badge></TableCell>
                        <TableCell className="text-right font-mono">{fmt(calc.list_price)}</TableCell>
                        <TableCell className="text-right font-mono font-semibold">{fmt(calc.calculated_price)}</TableCell>
                        <TableCell className="text-right font-mono">{calc.margin_percent ? `${calc.margin_percent.toFixed(1)}%` : '—'}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

