  DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger
} from '@/components/ui/dropdown-menu';

type CPQConfig = {
  id: string;
  name: string;
  description: string | null;
  status: string;
  base_price: number;
  adjusted_price: number;
  discount_amount: number;
  discount_percent: number;
  final_price: number;
  currency: string;
  requires_approval: boolean;
  approval_status: string | null;
  version: number;
  valid_until: string | null;
  created_at: string;
  opportunity_id: string | null;
  quote_id: string | null;
};

type CPQRule = {
  id: string;
  name: string;
  description: string | null;
  rule_type: string;
  action: string;
  priority: number;
  is_active: boolean;
  created_at: string;
};

type CPQBundle = {
  id: string;
  name: string;
  description: string | null;
  sku: string | null;
  bundle_price: number;
  discount_type: string;
  discount_value: number;
  is_active: boolean;
  created_at: string;
};

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline'; icon: React.ElementType }> = {
  draft: { label: 'Rascunho', variant: 'secondary', icon: Clock },
  valid: { label: 'Válida', variant: 'default', icon: CheckCircle },
  invalid: { label: 'Inválida', variant: 'destructive', icon: XCircle },
  approved: { label: 'Aprovada', variant: 'default', icon: ShieldCheck },
  expired: { label: 'Expirada', variant: 'outline', icon: AlertTriangle },
};

export default function CPQConfigurations() {
  const { profile } = useAuth();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const organizationId = profile?.organization_id;

  const [activeTab, setActiveTab] = useState('configurations');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [showNewConfigDialog, setShowNewConfigDialog] = useState(false);
  const [showNewRuleDialog, setShowNewRuleDialog] = useState(false);
  const [showNewBundleDialog, setShowNewBundleDialog] = useState(false);

  // Form states
  const [newConfig, setNewConfig] = useState({ name: '', description: '', base_price: '' });
  const [newRule, setNewRule] = useState({ name: '', description: '', rule_type: 'compatibility', action: 'require', priority: '100' });
  const [newBundle, setNewBundle] = useState({ name: '', description: '', sku: '', bundle_price: '', discount_type: 'percent', discount_value: '' });

  // Queries
  const { data: configurations = [], isLoading: loadingConfigs } = useQuery({
    queryKey: ['cpq-configurations', organizationId, statusFilter, searchTerm],
    queryFn: async () => {
      let query = supabase
        .from('cpq_product_configurations')
        .select('*')
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false });

      if (statusFilter !== 'all') query = query.eq('status', statusFilter as any);
      if (searchTerm) query = query.ilike('name', `%${searchTerm}%`);

      const { data, error } = await query;
      if (error) throw error;
      return (data || []) as CPQConfig[];
    },
    enabled: !!organizationId,
  });

  const { data: rules = [], isLoading: loadingRules } = useQuery({
    queryKey: ['cpq-rules', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('cpq_rules')
        .select('*')
        .eq('organization_id', organizationId!)
        .order('priority', { ascending: true });
      if (error) throw error;
      return (data || []) as CPQRule[];
    },
    enabled: !!organizationId,
  });

  const { data: bundles = [], isLoading: loadingBundles } = useQuery({
    queryKey: ['cpq-bundles', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('cpq_bundles')
        .select('*')
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []) as CPQBundle[];
    },
    enabled: !!organizationId,
  });

  const { data: discountPolicies = [] } = useQuery({
    queryKey: ['cpq-discount-policies', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('cpq_discount_policies')
        .select('*')
        .eq('organization_id', organizationId!)
        .order('tier', { ascending: true });
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // Mutations
  const createConfig = useMutation({
    mutationFn: async (values: typeof newConfig) => {
      const { error } = await supabase.from('cpq_product_configurations').insert({
        organization_id: organizationId!,
        name: values.name,
        description: values.description || null,
        base_price: parseFloat(values.base_price) || 0,
        adjusted_price: parseFloat(values.base_price) || 0,
        final_price: parseFloat(values.base_price) || 0,
        created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-configurations'] });
      setShowNewConfigDialog(false);
      setNewConfig({ name: '', description: '', base_price: '' });
      toast.success('Configuração CPQ criada com sucesso');
    },
    onError: () => toast.error('Erro ao criar configuração'),
  });

  const createRule = useMutation({
    mutationFn: async (values: typeof newRule) => {
      const { error } = await supabase.from('cpq_rules').insert({
        organization_id: organizationId!,
        name: values.name,
        description: values.description || null,
        rule_type: values.rule_type as any,
        action: values.action as any,
        priority: parseInt(values.priority) || 100,
        created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-rules'] });
      setShowNewRuleDialog(false);
      setNewRule({ name: '', description: '', rule_type: 'compatibility', action: 'require', priority: '100' });
      toast.success('Regra CPQ criada com sucesso');
    },
    onError: () => toast.error('Erro ao criar regra'),
  });

  const createBundle = useMutation({
    mutationFn: async (values: typeof newBundle) => {
      const { error } = await supabase.from('cpq_bundles').insert({
        organization_id: organizationId!,
        name: values.name,
        description: values.description || null,
        sku: values.sku || null,
        bundle_price: parseFloat(values.bundle_price) || 0,
        discount_type: values.discount_type,
        discount_value: parseFloat(values.discount_value) || 0,
        created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cpq-bundles'] });
      setShowNewBundleDialog(false);
      setNewBundle({ name: '', description: '', sku: '', bundle_price: '', discount_type: 'percent', discount_value: '' });
      toast.success('Bundle criado com sucesso');
    },
    onError: () => toast.error('Erro ao criar bundle'),
  });

  // Stats
  const totalConfigs = configurations.length;
  const activeConfigs = configurations.filter(c => c.status === 'valid' || c.status === 'approved').length;
  const pendingApproval = configurations.filter(c => c.requires_approval && c.approval_status === 'pending').length;
  const totalValue = configurations.reduce((sum, c) => sum + (c.final_price || 0), 0);

  const ruleTypeLabels: Record<string, string> = {
    compatibility: 'Compatibilidade',
    restriction: 'Restrição',
    dependency: 'Dependência',
    pricing: 'Precificação',
    validation: 'Validação',
  };

  const actionLabels: Record<string, string> = {
    require: 'Obrigatório',
    exclude: 'Excluir',
    suggest: 'Sugerir',
    price_override: 'Override de Preço',
    warn: 'Aviso',
  };

  return (
    <div className="space-y-6">
        <ModuleHeroBanner
          module="sales"
          title="CPQ — Configure, Price, Quote"
          subtitle="Gerencie configurações de produtos, regras de precificação e pacotes comerciais"
          compact
        />

        {/* KPI Cards */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total Configurações</CardTitle>
              <Settings2 className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{totalConfigs}</div>
              <p className="text-xs text-muted-foreground">{activeConfigs} ativas</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Valor Total</CardTitle>
              <DollarSign className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalValue)}
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Regras Ativas</CardTitle>
              <FileText className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{rules.filter(r => r.is_active).length}</div>
              <p className="text-xs text-muted-foreground">de {rules.length} regras</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Pendentes Aprovação</CardTitle>
              <AlertTriangle className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{pendingApproval}</div>
              <p className="text-xs text-muted-foreground">{bundles.filter(b => b.is_active).length} bundles ativos</p>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="configurations">
              <Settings2 className="h-4 w-4 mr-2" />Configurações
            </TabsTrigger>
            <TabsTrigger value="rules">
              <ArrowUpDown className="h-4 w-4 mr-2" />Regras
            </TabsTrigger>
            <TabsTrigger value="bundles">
              <Layers className="h-4 w-4 mr-2" />Bundles
            </TabsTrigger>
            <TabsTrigger value="discounts">
              <Percent className="h-4 w-4 mr-2" />Políticas de Desconto
            </TabsTrigger>
          </TabsList>

          {/* Configurations Tab */}
          <TabsContent value="configurations" className="space-y-4">
            <div className="flex items-center gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar configurações..."
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[180px]">
                  <Filter className="h-4 w-4 mr-2" />
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="draft">Rascunho</SelectItem>
                  <SelectItem value="valid">Válida</SelectItem>
                  <SelectItem value="invalid">Inválida</SelectItem>
                  <SelectItem value="approved">Aprovada</SelectItem>
                  <SelectItem value="expired">Expirada</SelectItem>
                </SelectContent>
              </Select>
              <Button onClick={() => setShowNewConfigDialog(true)}>
                <Plus className="h-4 w-4 mr-2" />Nova Configuração
              </Button>
            </div>

            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Nome</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="text-right">Preço Base</TableHead>
                    <TableHead className="text-right">Desconto</TableHead>
                    <TableHead className="text-right">Preço Final</TableHead>
                    <TableHead>Versão</TableHead>
                    <TableHead>Criado em</TableHead>
                    <TableHead className="w-[50px]" />
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loadingConfigs ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
                  ) : configurations.length === 0 ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Nenhuma configuração encontrada</TableCell></TableRow>
                  ) : configurations.map(config => {
                    const st = statusConfig[config.status] || statusConfig.draft;
                    const Icon = st.icon;
                    return (
                      <TableRow key={config.id} className="cursor-pointer hover:bg-muted/50" onClick={() => navigate(`/sales/cpq/${config.id}`)}>
                        <TableCell>
                          <div>
                            <p className="font-medium">{config.name}</p>
                            {config.description && <p className="text-xs text-muted-foreground truncate max-w-[200px]">{config.description}</p>}
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge variant={st.variant} className="gap-1">
                            <Icon className="h-3 w-3" />{st.label}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-right font-mono">
                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: config.currency }).format(config.base_price)}
                        </TableCell>
                        <TableCell className="text-right font-mono text-destructive">
                          {config.discount_percent > 0 ? `-${config.discount_percent}%` : '—'}
                        </TableCell>
                        <TableCell className="text-right font-mono font-semibold">
                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: config.currency }).format(config.final_price)}
                        </TableCell>
                        <TableCell>
                          <Badge variant="outline">v{config.version}</Badge>
                        </TableCell>
                        <TableCell className="text-muted-foreground text-sm">
                          {format(new Date(config.created_at), 'dd/MM/yy', { locale: ptBR })}
                        </TableCell>
                        <TableCell>
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild onClick={e => e.stopPropagation()}>
                              <Button variant="ghost" size="icon"><MoreHorizontal className="h-4 w-4" /></Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => navigate(`/sales/cpq/${config.id}`)}>
                                <Eye className="h-4 w-4 mr-2" />Ver Detalhes
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Rules Tab */}
          <TabsContent value="rules" className="space-y-4">
            <div className="flex items-center justify-between">
              <p className="text-sm text-muted-foreground">Regras de compatibilidade, restrição e precificação aplicadas automaticamente.</p>
              <Button onClick={() => setShowNewRuleDialog(true)}>
                <Plus className="h-4 w-4 mr-2" />Nova Regra
              </Button>
            </div>
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Prioridade</TableHead>
                    <TableHead>Nome</TableHead>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Ação</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Criado em</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loadingRules ? (
                    <TableRow><TableCell colSpan={6} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
                  ) : rules.length === 0 ? (
                    <TableRow><TableCell colSpan={6} className="text-center py-8 text-muted-foreground">Nenhuma regra cadastrada</TableCell></TableRow>
                  ) : rules.map(rule => (
                    <TableRow key={rule.id}>
                      <TableCell><Badge variant="outline">{rule.priority}</Badge></TableCell>
                      <TableCell>
                        <div>
                          <p className="font-medium">{rule.name}</p>
                          {rule.description && <p className="text-xs text-muted-foreground">{rule.description}</p>}
                        </div>
                      </TableCell>
                      <TableCell><Badge variant="secondary">{ruleTypeLabels[rule.rule_type] || rule.rule_type}</Badge></TableCell>
                      <TableCell><Badge variant="outline">{actionLabels[rule.action] || rule.action}</Badge></TableCell>
                      <TableCell>
                        <Badge variant={rule.is_active ? 'default' : 'secondary'}>
                          {rule.is_active ? 'Ativa' : 'Inativa'}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-muted-foreground text-sm">
                        {format(new Date(rule.created_at), 'dd/MM/yy', { locale: ptBR })}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Bundles Tab */}
          <TabsContent value="bundles" className="space-y-4">
            <div className="flex items-center justify-between">
              <p className="text-sm text-muted-foreground">Pacotes de produtos com preço e desconto especiais.</p>
              <Button onClick={() => setShowNewBundleDialog(true)}>
                <Plus className="h-4 w-4 mr-2" />Novo Bundle
              </Button>
            </div>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {loadingBundles ? (
                <p className="col-span-full text-center py-8 text-muted-foreground">Carregando...</p>
              ) : bundles.length === 0 ? (
                <p className="col-span-full text-center py-8 text-muted-foreground">Nenhum bundle cadastrado</p>
              ) : bundles.map(bundle => (
                <Card key={bundle.id} className="hover:shadow-md transition-shadow">
                  <CardHeader>
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-lg">{bundle.name}</CardTitle>
                      <Badge variant={bundle.is_active ? 'default' : 'secondary'}>
                        {bundle.is_active ? 'Ativo' : 'Inativo'}
                      </Badge>
                    </div>
                    {bundle.sku && <p className="text-xs text-muted-foreground">SKU: {bundle.sku}</p>}
                    {bundle.description && <CardDescription>{bundle.description}</CardDescription>}
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm text-muted-foreground">Preço do Bundle</p>
                        <p className="text-xl font-bold">
                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(bundle.bundle_price)}
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-muted-foreground">Desconto</p>
                        <p className="text-lg font-semibold text-destructive">
                          {bundle.discount_type === 'percent' ? `${bundle.discount_value}%` :
                            new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(bundle.discount_value)}
                        </p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </TabsContent>

          {/* Discount Policies Tab */}
          <TabsContent value="discounts" className="space-y-4">
            <p className="text-sm text-muted-foreground">Políticas de desconto por alçada com aprovação hierárquica.</p>
            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Tier</TableHead>
                    <TableHead>Nome</TableHead>
                    <TableHead>Desc. Máximo (%)</TableHead>
                    <TableHead>Desc. Máximo (R$)</TableHead>
                    <TableHead>Aprovação</TableHead>
                    <TableHead>Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {discountPolicies.length === 0 ? (
                    <TableRow><TableCell colSpan={6} className="text-center py-8 text-muted-foreground">Nenhuma política cadastrada</TableCell></TableRow>
                  ) : discountPolicies.map((policy: any) => (
                    <TableRow key={policy.id}>
                      <TableCell><Badge variant="outline">{policy.tier?.replace('_', ' ').toUpperCase()}</Badge></TableCell>
                      <TableCell className="font-medium">{policy.name}</TableCell>
                      <TableCell className="font-mono">{policy.max_discount_percent}%</TableCell>
                      <TableCell className="font-mono">
                        {policy.max_discount_amount ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(policy.max_discount_amount) : '—'}
                      </TableCell>
                      <TableCell>
                        <Badge variant={policy.requires_approval ? 'destructive' : 'secondary'}>
                          {policy.requires_approval ? 'Obrigatória' : 'Não'}
                        </Badge>
                      </TableCell>
                      <TableCell>
                        <Badge variant={policy.is_active ? 'default' : 'secondary'}>
                          {policy.is_active ? 'Ativa' : 'Inativa'}
                        </Badge>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>
        </Tabs>

        {/* New Configuration Dialog */}
        <Dialog open={showNewConfigDialog} onOpenChange={setShowNewConfigDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Nova Configuração CPQ</DialogTitle>
              <DialogDescription>Crie uma nova configuração de produto com precificação.</DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label>Nome *</Label>
                <Input value={newConfig.name} onChange={e => setNewConfig(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Config Enterprise 2026" />
              </div>
              <div>
                <Label>Descrição</Label>
                <Textarea value={newConfig.description} onChange={e => setNewConfig(p => ({ ...p, description: e.target.value }))} placeholder="Detalhes da configuração..." />
              </div>
              <div>
                <Label>Preço Base (R$)</Label>
                <Input type="number" step="0.01" value={newConfig.base_price} onChange={e => setNewConfig(p => ({ ...p, base_price: e.target.value }))} placeholder="0,00" />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowNewConfigDialog(false)}>Cancelar</Button>
              <Button onClick={() => createConfig.mutate(newConfig)} disabled={!newConfig.name || createConfig.isPending}>
                {createConfig.isPending ? 'Criando...' : 'Criar Configuração'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* New Rule Dialog */}
        <Dialog open={showNewRuleDialog} onOpenChange={setShowNewRuleDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Nova Regra CPQ</DialogTitle>
              <DialogDescription>Defina regras de compatibilidade, restrição ou precificação.</DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label>Nome *</Label>
                <Input value={newRule.name} onChange={e => setNewRule(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Licença Enterprise requer suporte Premium" />
              </div>
              <div>
                <Label>Descrição</Label>
                <Textarea value={newRule.description} onChange={e => setNewRule(p => ({ ...p, description: e.target.value }))} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Tipo</Label>
                  <Select value={newRule.rule_type} onValueChange={v => setNewRule(p => ({ ...p, rule_type: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="compatibility">Compatibilidade</SelectItem>
                      <SelectItem value="restriction">Restrição</SelectItem>
                      <SelectItem value="dependency">Dependência</SelectItem>
                      <SelectItem value="pricing">Precificação</SelectItem>
                      <SelectItem value="validation">Validação</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Ação</Label>
                  <Select value={newRule.action} onValueChange={v => setNewRule(p => ({ ...p, action: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="require">Obrigatório</SelectItem>
                      <SelectItem value="exclude">Excluir</SelectItem>
                      <SelectItem value="suggest">Sugerir</SelectItem>
                      <SelectItem value="price_override">Override de Preço</SelectItem>
                      <SelectItem value="warn">Aviso</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div>
                <Label>Prioridade (menor = executada primeiro)</Label>
                <Input type="number" value={newRule.priority} onChange={e => setNewRule(p => ({ ...p, priority: e.target.value }))} />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowNewRuleDialog(false)}>Cancelar</Button>
              <Button onClick={() => createRule.mutate(newRule)} disabled={!newRule.name || createRule.isPending}>
                {createRule.isPending ? 'Criando...' : 'Criar Regra'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* New Bundle Dialog */}
        <Dialog open={showNewBundleDialog} onOpenChange={setShowNewBundleDialog}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Novo Bundle</DialogTitle>
              <DialogDescription>Crie pacotes de produtos com preço e desconto especiais.</DialogDescription>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label>Nome *</Label>
                <Input value={newBundle.name} onChange={e => setNewBundle(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Pacote Starter" />
              </div>
              <div>
                <Label>Descrição</Label>
                <Textarea value={newBundle.description} onChange={e => setNewBundle(p => ({ ...p, description: e.target.value }))} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>SKU</Label>
                  <Input value={newBundle.sku} onChange={e => setNewBundle(p => ({ ...p, sku: e.target.value }))} placeholder="BDL-001" />
                </div>
                <div>
                  <Label>Preço do Bundle (R$)</Label>
                  <Input type="number" step="0.01" value={newBundle.bundle_price} onChange={e => setNewBundle(p => ({ ...p, bundle_price: e.target.value }))} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Tipo de Desconto</Label>
                  <Select value={newBundle.discount_type} onValueChange={v => setNewBundle(p => ({ ...p, discount_type: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="percent">Percentual</SelectItem>
                      <SelectItem value="fixed">Fixo (R$)</SelectItem>
                      <SelectItem value="tiered">Por Faixa</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Valor do Desconto</Label>
                  <Input type="number" step="0.01" value={newBundle.discount_value} onChange={e => setNewBundle(p => ({ ...p, discount_value: e.target.value }))} />
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowNewBundleDialog(false)}>Cancelar</Button>
              <Button onClick={() => createBundle.mutate(newBundle)} disabled={!newBundle.name || createBundle.isPending}>
                {createBundle.isPending ? 'Criando...' : 'Criar Bundle'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
    </div>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Progress } from '@/components/ui/progress';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Search, Filter, Mic, BarChart3, Brain, MessageSquare,
  TrendingUp, TrendingDown, AlertTriangle, Target,
  ThumbsUp, ThumbsDown, Minus, Clock, Users, Zap
} from '@/components/icons';

const statusLabels: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  processing: { label: 'Processando', variant: 'outline' },
  ready: { label: 'Pronto', variant: 'secondary' },
  transcribed: { label: 'Transcrito', variant: 'outline' },
  analyzed: { label: 'Analisado', variant: 'default' },
  failed: { label: 'Falhou', variant: 'destructive' },
  archived: { label: 'Arquivado', variant: 'secondary' },
};

const sentimentIcons: Record<string, { icon: React.ElementType; color: string; label: string }> = {
  very_positive: { icon: ThumbsUp, color: 'text-green-600', label: 'Muito Positivo' },
  positive: { icon: ThumbsUp, color: 'text-green-500', label: 'Positivo' },
  neutral: { icon: Minus, color: 'text-muted-foreground', label: 'Neutro' },
  negative: { icon: ThumbsDown, color: 'text-amber-500', label: 'Negativo' },
  very_negative: { icon: ThumbsDown, color: 'text-destructive', label: 'Muito Negativo' },
  mixed: { icon: Zap, color: 'text-amber-500', label: 'Misto' },
};

const insightTypeLabels: Record<string, { label: string; color: string }> = {
  objection: { label: 'Objeção', color: 'bg-red-100 text-red-800' },
  competitor_mention: { label: 'Menção a Concorrente', color: 'bg-amber-100 text-amber-800' },
  pricing_discussion: { label: 'Discussão de Preço', color: 'bg-blue-100 text-blue-800' },
  next_step: { label: 'Próximo Passo', color: 'bg-green-100 text-green-800' },
  risk_signal: { label: 'Sinal de Risco', color: 'bg-red-100 text-red-800' },
  buying_signal: { label: 'Sinal de Compra', color: 'bg-green-100 text-green-800' },
  feature_request: { label: 'Pedido de Feature', color: 'bg-purple-100 text-purple-800' },
  pain_point: { label: 'Dor do Cliente', color: 'bg-orange-100 text-orange-800' },
  decision_maker: { label: 'Decision Maker', color: 'bg-blue-100 text-blue-800' },
  timeline: { label: 'Timeline', color: 'bg-teal-100 text-teal-800' },
};

export default function ConversationIntelligence() {
  const { profile } = useAuth();
  const organizationId = profile?.organization_id;

  const [activeTab, setActiveTab] = useState('recordings');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');

  // Recordings
  const { data: recordings = [], isLoading: loadingRecordings } = useQuery({
    queryKey: ['call-recordings', organizationId, statusFilter, searchTerm],
    queryFn: async () => {
      let query = supabase
        .from('sales_call_recordings')
        .select(`
          *,
          caller:caller_id (first_name, last_name),
          contact:contact_id (first_name, last_name),
          account:account_id (name),
          opportunity:opportunity_id (name)
        `)
        .eq('organization_id', organizationId!)
        .order('recorded_at', { ascending: false });

      if (statusFilter !== 'all') query = query.eq('status', statusFilter as any);
      if (searchTerm) query = query.ilike('title', `%${searchTerm}%`);

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // Insights
  const { data: insights = [] } = useQuery({
    queryKey: ['call-insights', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('call_insights')
        .select(`*, recording:recording_id (title)`)
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // Coaching notes
  const { data: coachingNotes = [] } = useQuery({
    queryKey: ['coaching-notes', organizationId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('coaching_notes')
        .select(`
          *,
          recording:recording_id (title),
          coach:coach_id (first_name, last_name),
          rep:rep_id (first_name, last_name)
        `)
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // KPIs
  const analyzed = recordings.filter((r: any) => r.status === 'analyzed');
  const avgScore = analyzed.length > 0 
    ? Math.round(analyzed.reduce((s: number, r: any) => s + (r.call_score || 0), 0) / analyzed.length) 
    : 0;
  const avgEngagement = analyzed.length > 0
    ? Math.round(analyzed.reduce((s: number, r: any) => s + (r.engagement_score || 0), 0) / analyzed.length)
    : 0;
  const insightsByType = insights.reduce((acc: Record<string, number>, i: any) => {
    acc[i.insight_type] = (acc[i.insight_type] || 0) + 1;
    return acc;
  }, {});

  const formatDuration = (seconds: number | null) => {
    if (!seconds) return '—';
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <>
      <div className="space-y-6 p-6">
        <ModuleHeroBanner
          module="sales"
          title="Conversation Intelligence"
          subtitle="Análise de chamadas de vendas com transcrição, insights de IA e coaching"
          compact
        />

        {/* KPIs */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Total de Gravações</CardTitle>
              <Mic className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{recordings.length}</div>
              <p className="text-xs text-muted-foreground">{analyzed.length} analisadas</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Score Médio</CardTitle>
              <BarChart3 className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{avgScore}/100</div>
              <Progress value={avgScore} className="mt-2" />
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Engajamento Médio</CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{avgEngagement}/100</div>
              <Progress value={avgEngagement} className="mt-2" />
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Insights Gerados</CardTitle>
              <Brain className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{insights.length}</div>
              <p className="text-xs text-muted-foreground">{coachingNotes.length} notas de coaching</p>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="recordings"><Mic className="h-4 w-4 mr-2" />Gravações</TabsTrigger>
            <TabsTrigger value="insights"><Brain className="h-4 w-4 mr-2" />Insights</TabsTrigger>
            <TabsTrigger value="coaching"><MessageSquare className="h-4 w-4 mr-2" />Coaching</TabsTrigger>
          </TabsList>

          {/* Recordings */}
          <TabsContent value="recordings" className="space-y-4">
            <div className="flex items-center gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input placeholder="Buscar gravações..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="pl-10" />
              </div>
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[180px]">
                  <Filter className="h-4 w-4 mr-2" /><SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="processing">Processando</SelectItem>
                  <SelectItem value="transcribed">Transcrito</SelectItem>
                  <SelectItem value="analyzed">Analisado</SelectItem>
                  <SelectItem value="failed">Falhou</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Título</TableHead>
                    <TableHead>Vendedor</TableHead>
                    <TableHead>Contato / Conta</TableHead>
                    <TableHead>Duração</TableHead>
                    <TableHead>Sentimento</TableHead>
                    <TableHead>Score</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Data</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loadingRecordings ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
                  ) : recordings.length === 0 ? (
                    <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Nenhuma gravação encontrada</TableCell></TableRow>
                  ) : recordings.map((rec: any) => {
                    const st = statusLabels[rec.status] || statusLabels.processing;
                    const sent = rec.overall_sentiment ? sentimentIcons[rec.overall_sentiment] : null;
                    return (
                      <TableRow key={rec.id}>
                        <TableCell>
                          <div>
                            <p className="font-medium">{rec.title}</p>
                            {rec.opportunity?.name && <p className="text-xs text-muted-foreground">{rec.opportunity.name}</p>}
                          </div>
                        </TableCell>
                        <TableCell className="text-sm">
                          {rec.caller ? `${rec.caller.first_name} ${rec.caller.last_name}` : '—'}
                        </TableCell>
                        <TableCell>
                          <div className="text-sm">
                            {rec.contact ? `${rec.contact.first_name} ${rec.contact.last_name}` : '—'}
                            {rec.account && <p className="text-xs text-muted-foreground">{rec.account.name}</p>}
                          </div>
                        </TableCell>
                        <TableCell className="font-mono text-sm">
                          <div className="flex items-center gap-1">
                            <Clock className="h-3 w-3" />{formatDuration(rec.recording_duration_seconds)}
                          </div>
                        </TableCell>
                        <TableCell>
                          {sent ? (
                            <div className="flex items-center gap-1">
                              <sent.icon className={`h-4 w-4 ${sent.color}`} />
                              <span className={`text-xs ${sent.color}`}>{sent.label}</span>
                            </div>
                          ) : '—'}
                        </TableCell>
                        <TableCell>
                          {rec.call_score ? (
                            <div className="flex items-center gap-2">
                              <span className="font-mono font-bold">{rec.call_score}</span>
                              <Progress value={rec.call_score} className="w-16 h-2" />
                            </div>
                          ) : '—'}
                        </TableCell>
                        <TableCell><Badge variant={st.variant}>{st.label}</Badge></TableCell>
                        <TableCell className="text-sm text-muted-foreground">
                          {format(new Date(rec.recorded_at), 'dd/MM/yy HH:mm', { locale: ptBR })}
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Insights */}
          <TabsContent value="insights" className="space-y-4">
            {/* Insight distribution */}
            <div className="grid gap-3 md:grid-cols-5">
              {Object.entries(insightsByType).slice(0, 5).map(([type, count]) => {
                const cfg = insightTypeLabels[type] || { label: type, color: 'bg-gray-100 text-gray-800' };
                return (
                  <Card key={type}>
                    <CardContent className="pt-4 text-center">
                      <Badge className={cfg.color}>{cfg.label}</Badge>
                      <p className="text-2xl font-bold mt-2">{count as number}</p>
                    </CardContent>
                  </Card>
                );
              })}
            </div>

            <Card>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Título</TableHead>
                    <TableHead>Gravação</TableHead>
                    <TableHead>Confiança</TableHead>
                    <TableHead>Severidade</TableHead>
                    <TableHead>Resolvido</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {insights.length === 0 ? (
                    <TableRow><TableCell colSpan={6} className="text-center py-8 text-muted-foreground">Nenhum insight encontrado</TableCell></TableRow>
                  ) : insights.map((insight: any) => {
                    const cfg = insightTypeLabels[insight.insight_type] || { label: insight.insight_type, color: '' };
                    return (
                      <TableRow key={insight.id}>
                        <TableCell><Badge className={cfg.color}>{cfg.label}</Badge></TableCell>
                        <TableCell>
                          <div>
                            <p className="font-medium">{insight.title}</p>
                            {insight.description && <p className="text-xs text-muted-foreground truncate max-w-[300px]">{insight.description}</p>}
                          </div>
                        </TableCell>
                        <TableCell className="text-sm">{insight.recording?.title || '—'}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <span className="font-mono">{Math.round(insight.confidence * 100)}%</span>
                            <Progress value={insight.confidence * 100} className="w-12 h-2" />
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge variant={insight.severity === 'critical' ? 'destructive' : insight.severity === 'high' ? 'destructive' : 'outline'}>
                            {insight.severity}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          {insight.is_addressed ? (
                            <Badge variant="default" className="gap-1"><Target className="h-3 w-3" />Sim</Badge>
                          ) : (
                            <Badge variant="secondary">Não</Badge>
                          )}
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </Card>
          </TabsContent>

          {/* Coaching */}
          <TabsContent value="coaching" className="space-y-4">
            {coachingNotes.length === 0 ? (
              <Card>
                <CardContent className="py-12 text-center text-muted-foreground">
                  Nenhuma nota de coaching registrada ainda.
                </CardContent>
              </Card>
            ) : (
              <div className="space-y-3">
                {coachingNotes.map((note: any) => (
                  <Card key={note.id}>
                    <CardContent className="pt-4">
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <Badge variant="outline">{note.category || 'Geral'}</Badge>
                            {note.rating && (
                              <Badge variant={note.rating === 'excellent' ? 'default' : note.rating === 'critical' ? 'destructive' : 'secondary'}>
                                {note.rating}
                              </Badge>
                            )}
                            <span className="text-xs text-muted-foreground">
                              {note.recording?.title}
                            </span>
                          </div>
                          <p className="text-sm">{note.content}</p>
                          {note.suggested_action && (
                            <p className="text-sm text-primary mt-2">
                              <strong>Ação sugerida:</strong> {note.suggested_action}
                            </p>
                          )}
                        </div>
                        <div className="text-right text-xs text-muted-foreground ml-4">
                          <p>Coach: {note.coach?.first_name} {note.coach?.last_name}</p>
                          <p>Rep: {note.rep?.first_name} {note.rep?.last_name}</p>
                          <p>{format(new Date(note.created_at), 'dd/MM/yy', { locale: ptBR })}</p>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useState } from 'react';
import { ModuleHeroBanner } from '@/components/ModuleHeroBanner';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { format, differenceInDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Plus, Search, Filter, RefreshCw, TrendingUp, AlertTriangle,
  DollarSign, Users, Pause, Play, XCircle, Clock, CheckCircle
} from '@/components/icons';

const statusLabels: Record<string, { label: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
  trial: { label: 'Trial', variant: 'outline' },
  active: { label: 'Ativa', variant: 'default' },
  past_due: { label: 'Inadimplente', variant: 'destructive' },
  cancelled: { label: 'Cancelada', variant: 'secondary' },
  paused: { label: 'Pausada', variant: 'outline' },
  expired: { label: 'Expirada', variant: 'secondary' },
  pending_activation: { label: 'Pendente', variant: 'outline' },
};

const intervalLabels: Record<string, string> = {
  monthly: 'Mensal',
  quarterly: 'Trimestral',
  semi_annual: 'Semestral',
  annual: 'Anual',
  custom: 'Personalizado',
};

export default function Subscriptions() {
  const { profile } = useAuth();
  const navigate = useNavigate();
  const organizationId = profile?.organization_id;

  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');

  const { data: subscriptions = [], isLoading } = useQuery({
    queryKey: ['subscriptions', organizationId, statusFilter, searchTerm],
    queryFn: async () => {
      let query = supabase
        .from('subscriptions')
        .select(`
          *,
          accounts:account_id (name),
          contacts:contact_id (first_name, last_name)
        `)
        .eq('organization_id', organizationId!)
        .order('created_at', { ascending: false });

      if (statusFilter !== 'all') query = query.eq('status', statusFilter as any);
      if (searchTerm) query = query.or(`plan_name.ilike.%${searchTerm}%,subscription_number.ilike.%${searchTerm}%`);

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
    enabled: !!organizationId,
  });

  // KPIs
  const activeSubs = subscriptions.filter((s: any) => s.status === 'active');
  const mrr = activeSubs.reduce((sum: number, s: any) => {
    const monthly = s.billing_interval === 'monthly' ? s.total_recurring :
      s.billing_interval === 'quarterly' ? s.total_recurring / 3 :
      s.billing_interval === 'semi_annual' ? s.total_recurring / 6 :
      s.billing_interval === 'annual' ? s.total_recurring / 12 :
      s.total_recurring;
    return sum + monthly;
  }, 0);
  const pastDue = subscriptions.filter((s: any) => s.status === 'past_due').length;
  const renewingSoon = subscriptions.filter((s: any) => {
    if (s.status !== 'active' || !s.current_period_end) return false;
    return differenceInDays(new Date(s.current_period_end), new Date()) <= 30;
  }).length;

  const fmt = (v: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

  return (
    <div className="space-y-6">
        <ModuleHeroBanner
          module="sales"
          title="Assinaturas"
          subtitle="Gerencie assinaturas recorrentes, renovações e churn"
          compact
          actions={
            <Button onClick={() => navigate('/sales/subscriptions/new')}>
              <Plus className="h-4 w-4 mr-2" />Nova Assinatura
            </Button>
          }
        />

        {/* KPIs */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">MRR</CardTitle>
              <TrendingUp className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{fmt(mrr)}</div>
              <p className="text-xs text-muted-foreground">Receita Recorrente Mensal</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Assinaturas Ativas</CardTitle>
              <Users className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{activeSubs.length}</div>
              <p className="text-xs text-muted-foreground">de {subscriptions.length} total</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Inadimplentes</CardTitle>
              <AlertTriangle className="h-4 w-4 text-destructive" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-destructive">{pastDue}</div>
              <p className="text-xs text-muted-foreground">requerem atenção</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">Renovação em 30 dias</CardTitle>
              <RefreshCw className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{renewingSoon}</div>
              <p className="text-xs text-muted-foreground">próximas renovações</p>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <div className="flex items-center gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Buscar por plano ou número..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="pl-10"
            />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[200px]">
              <Filter className="h-4 w-4 mr-2" /><SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos</SelectItem>
              <SelectItem value="active">Ativas</SelectItem>
              <SelectItem value="trial">Trial</SelectItem>
              <SelectItem value="past_due">Inadimplentes</SelectItem>
              <SelectItem value="paused">Pausadas</SelectItem>
              <SelectItem value="cancelled">Canceladas</SelectItem>
              <SelectItem value="expired">Expiradas</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Table */}
        <Card>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Número</TableHead>
                <TableHead>Conta</TableHead>
                <TableHead>Plano</TableHead>
                <TableHead>Intervalo</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Valor Recorrente</TableHead>
                <TableHead>Próx. Cobrança</TableHead>
                <TableHead>Início</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Carregando...</TableCell></TableRow>
              ) : subscriptions.length === 0 ? (
                <TableRow><TableCell colSpan={8} className="text-center py-8 text-muted-foreground">Nenhuma assinatura encontrada</TableCell></TableRow>
              ) : subscriptions.map((sub: any) => {
                const st = statusLabels[sub.status] || statusLabels.active;
                return (
                  <TableRow key={sub.id} className="cursor-pointer hover:bg-muted/50">
                    <TableCell className="font-mono text-sm">{sub.subscription_number}</TableCell>
                    <TableCell className="font-medium">{sub.accounts?.name || '—'}</TableCell>
                    <TableCell>{sub.plan_name}</TableCell>
                    <TableCell><Badge variant="outline">{intervalLabels[sub.billing_interval] || sub.billing_interval}</Badge></TableCell>
                    <TableCell><Badge variant={st.variant}>{st.label}</Badge></TableCell>
                    <TableCell className="text-right font-mono font-semibold">{fmt(sub.total_recurring)}</TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {sub.next_billing_date ? format(new Date(sub.next_billing_date), 'dd/MM/yy', { locale: ptBR }) : '—'}
                    </TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {format(new Date(sub.starts_at), 'dd/MM/yy', { locale: ptBR })}
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </Card>
    </div>
  );
}

