const CHART_COLORS = ['#22c55e', '#3b82f6', '#eab308', '#f97316', '#ef4444'];

export default function QADashboard() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState('overview');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [showScorecardDialog, setShowScorecardDialog] = useState(false);
  const [showReviewDialog, setShowReviewDialog] = useState(false);

  // New scorecard form
  const [newScorecard, setNewScorecard] = useState({
    name: '', description: '', passing_score: 70, total_max_score: 100,
    criteria_definitions: [
      { name: 'Saudação e Empatia', category: 'Comunicação', weight: 1.0, max_score: 10 },
      { name: 'Conhecimento do Produto', category: 'Técnico', weight: 1.5, max_score: 10 },
      { name: 'Resolução do Problema', category: 'Técnico', weight: 2.0, max_score: 10 },
      { name: 'Tempo de Resposta', category: 'Eficiência', weight: 1.0, max_score: 10 },
      { name: 'Documentação', category: 'Processo', weight: 0.5, max_score: 10 },
    ],
  });

  // === QUERIES ===

  const { data: scorecards = [], isLoading: scorecardsLoading } = useQuery({
    queryKey: ['qa-scorecards'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('qa_scorecards')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: reviews = [], isLoading: reviewsLoading } = useQuery({
    queryKey: ['qa-reviews', statusFilter],
    queryFn: async () => {
      let query = supabase
        .from('qa_reviews')
        .select(`
          *,
          agent:profiles!qa_reviews_agent_id_fkey(id, first_name, last_name, email),
          reviewer:profiles!qa_reviews_reviewer_id_fkey(id, first_name, last_name, email),
          scorecard:qa_scorecards(id, name)
        `)
        .order('created_at', { ascending: false })
        .limit(100);

      if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const { data: npsSurveys = [] } = useQuery({
    queryKey: ['nps-surveys'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('nps_surveys')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: npsResponses = [] } = useQuery({
    queryKey: ['nps-responses-recent'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('nps_responses')
        .select(`
          *,
          contact:contacts(id, first_name, last_name, email),
          survey:nps_surveys(id, name)
        `)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data;
    },
  });

  // === MUTATIONS ===

  const createScorecardMutation = useMutation({
    mutationFn: async (data: typeof newScorecard) => {
      const { error } = await supabase.from('qa_scorecards').insert({
        organization_id: profile?.organization_id,
        name: data.name,
        description: data.description,
        passing_score: data.passing_score,
        total_max_score: data.total_max_score,
        criteria_definitions: data.criteria_definitions as any,
        status: 'active',
        created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['qa-scorecards'] });
      setShowScorecardDialog(false);
      toast.success('Scorecard criado com sucesso');
      setNewScorecard({
        name: '', description: '', passing_score: 70, total_max_score: 100,
        criteria_definitions: [
          { name: 'Saudação e Empatia', category: 'Comunicação', weight: 1.0, max_score: 10 },
          { name: 'Conhecimento do Produto', category: 'Técnico', weight: 1.5, max_score: 10 },
          { name: 'Resolução do Problema', category: 'Técnico', weight: 2.0, max_score: 10 },
          { name: 'Tempo de Resposta', category: 'Eficiência', weight: 1.0, max_score: 10 },
          { name: 'Documentação', category: 'Processo', weight: 0.5, max_score: 10 },
        ],
      });
    },
    onError: (error: any) => toast.error('Erro ao criar scorecard: ' + error.message),
  });

  // === COMPUTED VALUES ===

  const completedReviews = reviews.filter(r => r.status === 'completed');
  const avgScore = completedReviews.length > 0
    ? completedReviews.reduce((sum, r) => sum + (Number(r.percentage_score) || 0), 0) / completedReviews.length
    : 0;
  const pendingReviews = reviews.filter(r => r.status === 'pending').length;
  const disputedReviews = reviews.filter(r => r.agent_disputed).length;

  // Agent performance aggregation
  const agentPerformance = completedReviews.reduce((acc, r) => {
    const agentName = r.agent?.first_name
      ? `${r.agent.first_name} ${r.agent.last_name || ''}`.trim()
      : 'Desconhecido';
    if (!acc[agentName]) {
      acc[agentName] = { name: agentName, total: 0, sum: 0, reviews: 0 };
    }
    acc[agentName].total += Number(r.percentage_score) || 0;
    acc[agentName].reviews += 1;
    acc[agentName].sum = acc[agentName].total / acc[agentName].reviews;
    return acc;
  }, {} as Record<string, { name: string; total: number; sum: number; reviews: number }>);

  const agentChartData = Object.values(agentPerformance)
    .map(a => ({ name: a.name, score: Math.round(a.sum), reviews: a.reviews }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 10);

  // Rating distribution
  const ratingDistribution = completedReviews.reduce((acc, r) => {
    const rating = r.overall_rating || 'unknown';
    acc[rating] = (acc[rating] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const ratingChartData = Object.entries(ratingDistribution).map(([key, value]) => ({
    name: ratingLabels[key] || key,
    value,
  }));

  // NPS Aggregation
  const totalNpsResponses = npsResponses.length;
  const avgNps = totalNpsResponses > 0
    ? npsResponses.reduce((sum, r) => sum + r.score, 0) / totalNpsResponses
    : 0;
  const promoters = npsResponses.filter(r => r.score >= 9).length;
  const detractors = npsResponses.filter(r => r.score < 7).length;
  const npsScore = totalNpsResponses > 0
    ? Math.round(((promoters - detractors) / totalNpsResponses) * 100)
    : 0;

  // Filtered reviews
  const filteredReviews = reviews.filter(r => {
    if (!searchQuery) return true;
    const s = searchQuery.toLowerCase();
    return (
      r.agent?.first_name?.toLowerCase().includes(s) ||
      r.agent?.last_name?.toLowerCase().includes(s) ||
      r.scorecard?.name?.toLowerCase().includes(s) ||
      r.entity_type?.toLowerCase().includes(s)
    );
  });

  const handleAddCriterion = () => {
    setNewScorecard(prev => ({
      ...prev,
      criteria_definitions: [...prev.criteria_definitions, { name: '', category: '', weight: 1.0, max_score: 10 }],
    }));
  };

  const handleRemoveCriterion = (index: number) => {
    setNewScorecard(prev => ({
      ...prev,
      criteria_definitions: prev.criteria_definitions.filter((_, i) => i !== index),
    }));
  };

  const handleCriterionChange = (index: number, field: string, value: string | number) => {
    setNewScorecard(prev => ({
      ...prev,
      criteria_definitions: prev.criteria_definitions.map((c, i) =>
        i === index ? { ...c, [field]: value } : c
      ),
    }));
  };

  return (
    <>
      <div className="space-y-6 p-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-3">
              <ClipboardCheck className="h-8 w-8 text-primary" />
              Qualidade & NPS
            </h1>
            <p className="text-muted-foreground mt-1">
              Avaliação de qualidade do atendimento, scorecards e pesquisas NPS
            </p>
          </div>
          <div className="flex gap-2">
            <Dialog open={showScorecardDialog} onOpenChange={setShowScorecardDialog}>
              <DialogTrigger asChild>
                <Button variant="outline">
                  <FileText className="h-4 w-4 mr-2" />
                  Novo Scorecard
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle>Criar Scorecard de Qualidade</DialogTitle>
                  <DialogDescription>
                    Configure os critérios de avaliação e pesos para medir a qualidade do atendimento.
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Nome do Scorecard</Label>
                      <Input
                        value={newScorecard.name}
                        onChange={e => setNewScorecard(p => ({ ...p, name: e.target.value }))}
                        placeholder="Ex: Avaliação Padrão de Suporte"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>Nota de Aprovação (%)</Label>
                      <Input
                        type="number"
                        min={0}
                        max={100}
                        value={newScorecard.passing_score}
                        onChange={e => setNewScorecard(p => ({ ...p, passing_score: Number(e.target.value) }))}
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label>Descrição</Label>
                    <Textarea
                      value={newScorecard.description}
                      onChange={e => setNewScorecard(p => ({ ...p, description: e.target.value }))}
                      placeholder="Descreva o propósito deste scorecard..."
                    />
                  </div>

                  {/* Criteria */}
                  <div className="space-y-3">
                    <div className="flex items-center justify-between">
                      <Label className="text-base font-semibold">Critérios de Avaliação</Label>
                      <Button size="sm" variant="outline" onClick={handleAddCriterion}>
                        <Plus className="h-3 w-3 mr-1" /> Adicionar
                      </Button>
                    </div>
                    {newScorecard.criteria_definitions.map((criterion, idx) => (
                      <div key={idx} className="grid grid-cols-12 gap-2 items-end border rounded-lg p-3">
                        <div className="col-span-4 space-y-1">
                          <Label className="text-xs">Nome</Label>
                          <Input
                            value={criterion.name}
                            onChange={e => handleCriterionChange(idx, 'name', e.target.value)}
                            placeholder="Nome do critério"
                          />
                        </div>
                        <div className="col-span-3 space-y-1">
                          <Label className="text-xs">Categoria</Label>
                          <Input
                            value={criterion.category}
                            onChange={e => handleCriterionChange(idx, 'category', e.target.value)}
                            placeholder="Categoria"
                          />
                        </div>
                        <div className="col-span-2 space-y-1">
                          <Label className="text-xs">Peso</Label>
                          <Input
                            type="number"
                            step="0.1"
                            min="0.1"
                            value={criterion.weight}
                            onChange={e => handleCriterionChange(idx, 'weight', Number(e.target.value))}
                          />
                        </div>
                        <div className="col-span-2 space-y-1">
                          <Label className="text-xs">Nota Máx.</Label>
                          <Input
                            type="number"
                            min="1"
                            value={criterion.max_score}
                            onChange={e => handleCriterionChange(idx, 'max_score', Number(e.target.value))}
                          />
                        </div>
                        <div className="col-span-1">
                          <Button
                            size="icon"
                            variant="ghost"
                            className="text-destructive"
                            onClick={() => handleRemoveCriterion(idx)}
                            disabled={newScorecard.criteria_definitions.length <= 1}
                          >
                            ×
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setShowScorecardDialog(false)}>Cancelar</Button>
                  <Button
                    onClick={() => createScorecardMutation.mutate(newScorecard)}
                    disabled={!newScorecard.name || createScorecardMutation.isPending}
                  >
                    {createScorecardMutation.isPending ? 'Criando...' : 'Criar Scorecard'}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Score Médio</p>
                  <p className="text-3xl font-bold">{avgScore.toFixed(1)}%</p>
                </div>
                <div className={cn('p-3 rounded-full', avgScore >= 70 ? 'bg-green-100 dark:bg-green-900' : 'bg-red-100 dark:bg-red-900')}>
                  {avgScore >= 70 ? <TrendingUp className="h-5 w-5 text-green-600" /> : <TrendingDown className="h-5 w-5 text-red-600" />}
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Avaliações Concluídas</p>
                  <p className="text-3xl font-bold">{completedReviews.length}</p>
                </div>
                <div className="p-3 rounded-full bg-blue-100 dark:bg-blue-900">
                  <CheckCircle className="h-5 w-5 text-blue-600" />
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Pendentes</p>
                  <p className="text-3xl font-bold">{pendingReviews}</p>
                </div>
                <div className="p-3 rounded-full bg-yellow-100 dark:bg-yellow-900">
                  <Clock className="h-5 w-5 text-yellow-600" />
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">NPS Score</p>
                  <p className="text-3xl font-bold">{npsScore}</p>
                </div>
                <div className={cn('p-3 rounded-full', npsScore >= 50 ? 'bg-green-100 dark:bg-green-900' : npsScore >= 0 ? 'bg-yellow-100 dark:bg-yellow-900' : 'bg-red-100 dark:bg-red-900')}>
                  <Star className="h-5 w-5 text-primary" />
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Disputas</p>
                  <p className="text-3xl font-bold">{disputedReviews}</p>
                </div>
                <div className="p-3 rounded-full bg-orange-100 dark:bg-orange-900">
                  <AlertTriangle className="h-5 w-5 text-orange-600" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="overview">
              <BarChart3 className="h-4 w-4 mr-2" />
              Visão Geral
            </TabsTrigger>
            <TabsTrigger value="reviews">
              <ClipboardCheck className="h-4 w-4 mr-2" />
              Avaliações
            </TabsTrigger>
            <TabsTrigger value="scorecards">
              <FileText className="h-4 w-4 mr-2" />
              Scorecards
            </TabsTrigger>
            <TabsTrigger value="nps">
              <Star className="h-4 w-4 mr-2" />
              NPS
            </TabsTrigger>
            <TabsTrigger value="agents">
              <Users className="h-4 w-4 mr-2" />
              Por Agente
            </TabsTrigger>
          </TabsList>

          {/* Overview Tab */}
          <TabsContent value="overview" className="space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Rating Distribution */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Distribuição de Ratings</CardTitle>
                </CardHeader>
                <CardContent>
                  {ratingChartData.length > 0 ? (
                    <ResponsiveContainer width="100%" height={300}>
                      <PieChart>
                        <Pie data={ratingChartData} cx="50%" cy="50%" outerRadius={100} dataKey="value" nameKey="name" label>
                          {ratingChartData.map((_, idx) => (
                            <Cell key={idx} fill={CHART_COLORS[idx % CHART_COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                        <Legend />
                      </PieChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="flex items-center justify-center h-[300px] text-muted-foreground">
                      Nenhuma avaliação concluída ainda
                    </div>
                  )}
                </CardContent>
              </Card>

              {/* Agent Performance */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Performance por Agente</CardTitle>
                </CardHeader>
                <CardContent>
                  {agentChartData.length > 0 ? (
                    <ResponsiveContainer width="100%" height={300}>
                      <BarChart data={agentChartData} layout="vertical">
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis type="number" domain={[0, 100]} />
                        <YAxis dataKey="name" type="category" width={120} tick={{ fontSize: 12 }} />
                        <Tooltip formatter={(value: number) => [`${value}%`, 'Score']} />
                        <Bar dataKey="score" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} />
                      </BarChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="flex items-center justify-center h-[300px] text-muted-foreground">
                      Nenhum dado de performance disponível
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>

            {/* NPS Summary */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Resumo NPS</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-4 gap-4">
                  <div className="text-center">
                    <p className="text-sm text-muted-foreground">Respostas</p>
                    <p className="text-2xl font-bold">{totalNpsResponses}</p>
                  </div>
                  <div className="text-center">
                    <p className="text-sm text-muted-foreground">Promotores (9-10)</p>
                    <p className="text-2xl font-bold text-green-600">{promoters}</p>
                  </div>
                  <div className="text-center">
                    <p className="text-sm text-muted-foreground">Passivos (7-8)</p>
                    <p className="text-2xl font-bold text-yellow-600">{totalNpsResponses - promoters - detractors}</p>
                  </div>
                  <div className="text-center">
                    <p className="text-sm text-muted-foreground">Detratores (0-6)</p>
                    <p className="text-2xl font-bold text-red-600">{detractors}</p>
                  </div>
                </div>
                <div className="mt-4">
                  <div className="flex justify-between text-sm mb-1">
                    <span>NPS Score</span>
                    <span className="font-medium">{npsScore}</span>
                  </div>
                  <Progress value={Math.max(0, (npsScore + 100) / 2)} className="h-3" />
                  <div className="flex justify-between text-xs text-muted-foreground mt-1">
                    <span>-100</span>
                    <span>0</span>
                    <span>+100</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Reviews Tab */}
          <TabsContent value="reviews" className="space-y-4">
            <div className="flex items-center gap-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar avaliações..."
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  className="pl-9"
                />
              </div>
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-48">
                  <Filter className="h-4 w-4 mr-2" />
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos os Status</SelectItem>
                  <SelectItem value="pending">Pendentes</SelectItem>
                  <SelectItem value="in_progress">Em Andamento</SelectItem>
                  <SelectItem value="completed">Concluídas</SelectItem>
                  <SelectItem value="disputed">Disputadas</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <Card>
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Agente</TableHead>
                      <TableHead>Scorecard</TableHead>
                      <TableHead>Tipo</TableHead>
                      <TableHead>Score</TableHead>
                      <TableHead>Rating</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Avaliador</TableHead>
                      <TableHead>Data</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {reviewsLoading ? (
                      <TableRow>
                        <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                          Carregando...
                        </TableCell>
                      </TableRow>
                    ) : filteredReviews.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                          <ClipboardCheck className="h-8 w-8 mx-auto mb-2 opacity-50" />
                          Nenhuma avaliação encontrada
                        </TableCell>
                      </TableRow>
                    ) : (
                      filteredReviews.map(review => (
                        <TableRow key={review.id}>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              <Avatar className="h-8 w-8">
                                <AvatarFallback className="text-xs">
                                  {review.agent?.first_name?.[0]}{review.agent?.last_name?.[0]}
                                </AvatarFallback>
                              </Avatar>
                              <span className="font-medium">
                                {review.agent?.first_name} {review.agent?.last_name}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell>{review.scorecard?.name || '-'}</TableCell>
                          <TableCell>
                            <Badge variant="outline" className="capitalize">{review.entity_type}</Badge>
                          </TableCell>
                          <TableCell>
                            <span className="font-mono font-bold">
                              {Number(review.percentage_score).toFixed(1)}%
                            </span>
                          </TableCell>
                          <TableCell>
                            {review.overall_rating ? (
                              <Badge variant={ratingBadgeVariants[review.overall_rating] || 'outline'}>
                                {ratingLabels[review.overall_rating] || review.overall_rating}
                              </Badge>
                            ) : '-'}
                          </TableCell>
                          <TableCell>
                            <Badge variant={
                              review.status === 'completed' ? 'default' :
                              review.status === 'pending' ? 'secondary' :
                              review.status === 'disputed' ? 'destructive' : 'outline'
                            }>
                              {review.status === 'completed' ? 'Concluída' :
                               review.status === 'pending' ? 'Pendente' :
                               review.status === 'in_progress' ? 'Em Andamento' :
                               review.status === 'disputed' ? 'Disputada' :
                               review.status === 'calibrated' ? 'Calibrada' : review.status}
                            </Badge>
                            {review.agent_disputed && (
                              <AlertTriangle className="inline h-3 w-3 ml-1 text-orange-500" />
                            )}
                          </TableCell>
                          <TableCell className="text-sm">
                            {review.reviewer?.first_name} {review.reviewer?.last_name}
                          </TableCell>
                          <TableCell className="text-sm text-muted-foreground">
                            {formatDistanceToNow(new Date(review.created_at), { addSuffix: true, locale: ptBR })}
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Scorecards Tab */}
          <TabsContent value="scorecards" className="space-y-4">
            {scorecardsLoading ? (
              <div className="text-center py-8 text-muted-foreground">Carregando scorecards...</div>
            ) : scorecards.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-12">
                  <FileText className="h-12 w-12 text-muted-foreground mb-4 opacity-50" />
                  <h3 className="text-lg font-medium mb-2">Nenhum scorecard criado</h3>
                  <p className="text-muted-foreground mb-4">Crie seu primeiro scorecard para começar a avaliar a qualidade.</p>
                  <Button onClick={() => setShowScorecardDialog(true)}>
                    <Plus className="h-4 w-4 mr-2" /> Criar Scorecard
                  </Button>
                </CardContent>
              </Card>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {scorecards.map(sc => {
                  const criteria = Array.isArray(sc.criteria_definitions) ? sc.criteria_definitions : [];
                  return (
                    <Card key={sc.id}>
                      <CardHeader>
                        <div className="flex items-center justify-between">
                          <CardTitle className="text-base">{sc.name}</CardTitle>
                          <Badge variant={sc.status === 'active' ? 'default' : 'secondary'}>
                            {sc.status === 'active' ? 'Ativo' : sc.status === 'draft' ? 'Rascunho' : 'Arquivado'}
                          </Badge>
                        </div>
                        {sc.description && (
                          <CardDescription>{sc.description}</CardDescription>
                        )}
                      </CardHeader>
                      <CardContent className="space-y-3">
                        <div className="flex items-center justify-between text-sm">
                          <span className="text-muted-foreground">Nota de Aprovação</span>
                          <span className="font-medium">{sc.passing_score}%</span>
                        </div>
                        <div className="flex items-center justify-between text-sm">
                          <span className="text-muted-foreground">Critérios</span>
                          <span className="font-medium">{criteria.length}</span>
                        </div>
                        <div className="space-y-1">
                          {criteria.slice(0, 4).map((c: any, i: number) => (
                            <div key={i} className="flex items-center justify-between text-xs">
                              <span className="truncate">{c.name}</span>
                              <span className="text-muted-foreground">Peso: {c.weight}x</span>
                            </div>
                          ))}
                          {criteria.length > 4 && (
                            <p className="text-xs text-muted-foreground">+{criteria.length - 4} critérios</p>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            )}
          </TabsContent>

          {/* NPS Tab */}
          <TabsContent value="nps" className="space-y-4">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Active Surveys */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Pesquisas NPS</CardTitle>
                </CardHeader>
                <CardContent>
                  {npsSurveys.length === 0 ? (
                    <div className="text-center py-8 text-muted-foreground">
                      <Star className="h-8 w-8 mx-auto mb-2 opacity-50" />
                      <p>Nenhuma pesquisa NPS configurada</p>
                    </div>
                  ) : (
                    <div className="space-y-3">
                      {npsSurveys.map(survey => (
                        <div key={survey.id} className="border rounded-lg p-3 space-y-2">
                          <div className="flex items-center justify-between">
                            <span className="font-medium">{survey.name}</span>
                            <Badge variant={survey.status === 'active' ? 'default' : 'secondary'}>
                              {survey.status === 'active' ? 'Ativa' : survey.status === 'draft' ? 'Rascunho' : survey.status}
                            </Badge>
                          </div>
                          <div className="grid grid-cols-3 gap-2 text-center text-sm">
                            <div>
                              <p className="text-muted-foreground text-xs">Enviadas</p>
                              <p className="font-bold">{survey.total_sent}</p>
                            </div>
                            <div>
                              <p className="text-muted-foreground text-xs">Respostas</p>
                              <p className="font-bold">{survey.total_responses}</p>
                            </div>
                            <div>
                              <p className="text-muted-foreground text-xs">NPS</p>
                              <p className="font-bold">{Number(survey.nps_score || 0).toFixed(0)}</p>
                            </div>
                          </div>
                          <Progress value={Number(survey.response_rate || 0)} className="h-2" />
                          <p className="text-xs text-muted-foreground">
                            Taxa de resposta: {Number(survey.response_rate || 0).toFixed(1)}%
                          </p>
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>

              {/* Recent Responses */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Respostas Recentes</CardTitle>
                </CardHeader>
                <CardContent>
                  {npsResponses.length === 0 ? (
                    <div className="text-center py-8 text-muted-foreground">
                      <ThumbsUp className="h-8 w-8 mx-auto mb-2 opacity-50" />
                      <p>Nenhuma resposta recebida</p>
                    </div>
                  ) : (
                    <ScrollArea className="h-[400px]">
                      <div className="space-y-3">
                        {npsResponses.map(resp => (
                          <div key={resp.id} className="border rounded-lg p-3 space-y-2">
                            <div className="flex items-center justify-between">
                              <span className="text-sm font-medium">
                                {resp.contact?.first_name} {resp.contact?.last_name || resp.contact?.email || 'Anônimo'}
                              </span>
                              <Badge
                                variant={resp.score >= 9 ? 'default' : resp.score >= 7 ? 'secondary' : 'destructive'}
                                className="text-lg px-3 py-1 font-bold"
                              >
                                {resp.score}
                              </Badge>
                            </div>
                            {resp.feedback && (
                              <p className="text-sm text-muted-foreground italic">"{resp.feedback}"</p>
                            )}
                            <div className="flex items-center justify-between text-xs text-muted-foreground">
                              <span>{resp.survey?.name}</span>
                              <span>{formatDistanceToNow(new Date(resp.created_at), { addSuffix: true, locale: ptBR })}</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    </ScrollArea>
                  )}
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          {/* Agents Tab */}
          <TabsContent value="agents" className="space-y-4">
            <Card>
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Agente</TableHead>
                      <TableHead>Score Médio</TableHead>
                      <TableHead>Avaliações</TableHead>
                      <TableHead>Progresso</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {agentChartData.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={4} className="text-center py-8 text-muted-foreground">
                          Nenhum dado de agente disponível
                        </TableCell>
                      </TableRow>
                    ) : (
                      agentChartData.map((agent, idx) => (
                        <TableRow key={idx}>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              <Avatar className="h-8 w-8">
                                <AvatarFallback className="text-xs">
                                  {agent.name.split(' ').map(n => n[0]).join('').substring(0, 2)}
                                </AvatarFallback>
                              </Avatar>
                              <span className="font-medium">{agent.name}</span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <span className={cn(
                              'font-mono font-bold',
                              agent.score >= 70 ? 'text-green-600' : agent.score >= 50 ? 'text-yellow-600' : 'text-red-600'
                            )}>
                              {agent.score}%
                            </span>
                          </TableCell>
                          <TableCell>{agent.reviews}</TableCell>
                          <TableCell className="w-48">
                            <Progress value={agent.score} className="h-2" />
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Progress } from '@/components/ui/progress';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Layers, Plus, Settings, Users, Activity, Inbox,
  CheckCircle, Clock, AlertTriangle, Zap, Trash2,
  UserPlus, Shield, BarChart3, Search, RefreshCw
} from '@/components/icons';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { toast } from 'sonner';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { cn } from '@/lib/utils';

const routingMethodLabels: Record<string, string> = {
  round_robin: 'Round Robin',
  skill_based: 'Baseado em Skills',
  load_balanced: 'Balanceamento de Carga',
  manual: 'Manual',
  broadcast: 'Broadcast',
};

export default function ServiceQueues() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [showMembersDialog, setShowMembersDialog] = useState(false);
  const [selectedQueue, setSelectedQueue] = useState<any>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Form state
  const [newQueue, setNewQueue] = useState({
    name: '',
    description: '',
    routing_method: 'round_robin',
    priority: 50,
    max_capacity: 100,
    skills_required: '',
    auto_accept_enabled: false,
    auto_accept_delay_seconds: 30,
    wrap_up_time_seconds: 60,
    is_default: false,
  });

  // === QUERIES ===

  const { data: queues = [], isLoading } = useQuery({
    queryKey: ['routing-queues'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('routing_queues')
        .select('*')
        .order('priority', { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: queueMembers = [] } = useQuery({
    queryKey: ['queue-members'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('queue_members')
        .select(`
          *,
          user:profiles!queue_members_user_id_fkey(id, first_name, last_name, email),
          queue:routing_queues!queue_members_queue_id_fkey(id, name)
        `)
        .eq('is_active', true);
      if (error) throw error;
      return data;
    },
  });

  const { data: conversations = [] } = useQuery({
    queryKey: ['queue-conversations-count'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('conversations')
        .select('id, queue_id, status')
        .not('queue_id', 'is', null);
      if (error) throw error;
      return data;
    },
  });

  const { data: agentStatuses = [] } = useQuery({
    queryKey: ['agent-statuses-all'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('agent_status')
        .select(`
          *,
          user:profiles!agent_status_user_id_fkey(id, first_name, last_name, email)
        `);
      if (error) throw error;
      return data;
    },
  });

  const { data: availableAgents = [] } = useQuery({
    queryKey: ['available-agents-for-queue'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email')
        .not('organization_id', 'is', null)
        .limit(100);
      if (error) throw error;
      return data;
    },
  });

  // Members of selected queue
  const selectedQueueMembers = selectedQueue
    ? queueMembers.filter(m => m.queue_id === selectedQueue.id)
    : [];

  // === MUTATIONS ===

  const createQueueMutation = useMutation({
    mutationFn: async (data: typeof newQueue) => {
      const { error } = await supabase.from('routing_queues').insert({
        organization_id: profile?.organization_id,
        name: data.name,
        description: data.description || null,
        routing_method: data.routing_method as any,
        priority: data.priority,
        max_capacity: data.max_capacity,
        skills_required: data.skills_required ? data.skills_required.split(',').map(s => s.trim()) : [],
        auto_accept_enabled: data.auto_accept_enabled,
        auto_accept_delay_seconds: data.auto_accept_delay_seconds,
        wrap_up_time_seconds: data.wrap_up_time_seconds,
        is_default: data.is_default,
        created_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['routing-queues'] });
      setShowCreateDialog(false);
      toast.success('Fila criada com sucesso');
      setNewQueue({
        name: '', description: '', routing_method: 'round_robin', priority: 50,
        max_capacity: 100, skills_required: '', auto_accept_enabled: false,
        auto_accept_delay_seconds: 30, wrap_up_time_seconds: 60, is_default: false,
      });
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  const addMemberMutation = useMutation({
    mutationFn: async ({ queueId, userId }: { queueId: string; userId: string }) => {
      const { error } = await supabase.from('queue_members').insert({
        organization_id: profile?.organization_id,
        queue_id: queueId,
        user_id: userId,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['queue-members'] });
      toast.success('Membro adicionado');
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  const removeMemberMutation = useMutation({
    mutationFn: async (memberId: string) => {
      const { error } = await supabase.from('queue_members')
        .update({ is_active: false, left_at: new Date().toISOString() })
        .eq('id', memberId);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['queue-members'] });
      toast.success('Membro removido');
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  const toggleQueueActiveMutation = useMutation({
    mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
      const { error } = await supabase.from('routing_queues')
        .update({ is_active })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['routing-queues'] });
      toast.success('Status da fila atualizado');
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  // === COMPUTED ===

  const getQueueStats = (queueId: string) => {
    const queueConvs = conversations.filter(c => c.queue_id === queueId);
    const open = queueConvs.filter(c => c.status === 'open' || c.status === 'waiting_agent').length;
    const total = queueConvs.length;
    const members = queueMembers.filter(m => m.queue_id === queueId).length;
    return { open, total, members };
  };

  const totalOpenConversations = conversations.filter(c =>
    c.status === 'open' || c.status === 'waiting_agent'
  ).length;

  const totalAgentsOnline = agentStatuses.filter(a => a.status === 'available').length;
  const totalQueues = queues.length;
  const activeQueues = queues.filter(q => q.is_active).length;

  const filteredQueues = queues.filter(q => {
    if (!searchQuery) return true;
    return q.name.toLowerCase().includes(searchQuery.toLowerCase());
  });

  const agentsNotInQueue = selectedQueue
    ? availableAgents.filter(a => !selectedQueueMembers.some(m => m.user_id === a.id))
    : [];

  return (
    <>
      <div className="space-y-6 p-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-3">
              <Layers className="h-8 w-8 text-primary" />
              Filas de Atendimento
            </h1>
            <p className="text-muted-foreground mt-1">
              Gerencie filas, membros, roteamento e capacidade dos agentes
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => queryClient.invalidateQueries()}>
              <RefreshCw className="h-4 w-4 mr-2" /> Atualizar
            </Button>
            <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
              <DialogTrigger asChild>
                <Button>
                  <Plus className="h-4 w-4 mr-2" /> Nova Fila
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-lg">
                <DialogHeader>
                  <DialogTitle>Criar Nova Fila</DialogTitle>
                  <DialogDescription>Configure uma nova fila de roteamento para distribuição de conversas.</DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label>Nome da Fila</Label>
                    <Input
                      value={newQueue.name}
                      onChange={e => setNewQueue(p => ({ ...p, name: e.target.value }))}
                      placeholder="Ex: Suporte Nível 1"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Descrição</Label>
                    <Textarea
                      value={newQueue.description}
                      onChange={e => setNewQueue(p => ({ ...p, description: e.target.value }))}
                      placeholder="Descrição da fila..."
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Método de Roteamento</Label>
                      <Select
                        value={newQueue.routing_method}
                        onValueChange={v => setNewQueue(p => ({ ...p, routing_method: v }))}
                      >
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="round_robin">Round Robin</SelectItem>
                          <SelectItem value="skill_based">Baseado em Skills</SelectItem>
                          <SelectItem value="load_balanced">Balanceamento de Carga</SelectItem>
                          <SelectItem value="manual">Manual</SelectItem>
                          <SelectItem value="broadcast">Broadcast</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label>Prioridade (0-100)</Label>
                      <Input
                        type="number"
                        min={0}
                        max={100}
                        value={newQueue.priority}
                        onChange={e => setNewQueue(p => ({ ...p, priority: Number(e.target.value) }))}
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Capacidade Máxima</Label>
                      <Input
                        type="number"
                        min={1}
                        value={newQueue.max_capacity}
                        onChange={e => setNewQueue(p => ({ ...p, max_capacity: Number(e.target.value) }))}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>Skills (separadas por vírgula)</Label>
                      <Input
                        value={newQueue.skills_required}
                        onChange={e => setNewQueue(p => ({ ...p, skills_required: e.target.value }))}
                        placeholder="billing, technical"
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Delay Auto-Accept (s)</Label>
                      <Input
                        type="number"
                        value={newQueue.auto_accept_delay_seconds}
                        onChange={e => setNewQueue(p => ({ ...p, auto_accept_delay_seconds: Number(e.target.value) }))}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>Wrap-up Time (s)</Label>
                      <Input
                        type="number"
                        value={newQueue.wrap_up_time_seconds}
                        onChange={e => setNewQueue(p => ({ ...p, wrap_up_time_seconds: Number(e.target.value) }))}
                      />
                    </div>
                  </div>
                  <div className="flex items-center justify-between border rounded-lg p-3">
                    <div>
                      <Label>Auto-Accept</Label>
                      <p className="text-xs text-muted-foreground">Aceitar conversas automaticamente</p>
                    </div>
                    <Switch
                      checked={newQueue.auto_accept_enabled}
                      onCheckedChange={v => setNewQueue(p => ({ ...p, auto_accept_enabled: v }))}
                    />
                  </div>
                  <div className="flex items-center justify-between border rounded-lg p-3">
                    <div>
                      <Label>Fila Padrão</Label>
                      <p className="text-xs text-muted-foreground">Fila padrão para novas conversas</p>
                    </div>
                    <Switch
                      checked={newQueue.is_default}
                      onCheckedChange={v => setNewQueue(p => ({ ...p, is_default: v }))}
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setShowCreateDialog(false)}>Cancelar</Button>
                  <Button
                    onClick={() => createQueueMutation.mutate(newQueue)}
                    disabled={!newQueue.name || createQueueMutation.isPending}
                  >
                    {createQueueMutation.isPending ? 'Criando...' : 'Criar Fila'}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Filas Ativas</p>
                  <p className="text-3xl font-bold">{activeQueues}/{totalQueues}</p>
                </div>
                <Layers className="h-8 w-8 text-primary opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Conversas Abertas</p>
                  <p className="text-3xl font-bold">{totalOpenConversations}</p>
                </div>
                <Inbox className="h-8 w-8 text-blue-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Agentes Online</p>
                  <p className="text-3xl font-bold text-green-600">{totalAgentsOnline}</p>
                </div>
                <Users className="h-8 w-8 text-green-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Total Membros</p>
                  <p className="text-3xl font-bold">{queueMembers.length}</p>
                </div>
                <UserPlus className="h-8 w-8 text-muted-foreground opacity-50" />
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Search */}
        <div className="relative max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar filas..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="pl-9"
          />
        </div>

        {/* Queues Table */}
        <Card>
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Fila</TableHead>
                  <TableHead>Roteamento</TableHead>
                  <TableHead>Prioridade</TableHead>
                  <TableHead>Membros</TableHead>
                  <TableHead>Conversas Abertas</TableHead>
                  <TableHead>Capacidade</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                      Carregando filas...
                    </TableCell>
                  </TableRow>
                ) : filteredQueues.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                      <Layers className="h-8 w-8 mx-auto mb-2 opacity-50" />
                      Nenhuma fila encontrada
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredQueues.map(queue => {
                    const stats = getQueueStats(queue.id);
                    const capacityPct = queue.max_capacity ? (stats.open / queue.max_capacity) * 100 : 0;
                    return (
                      <TableRow key={queue.id}>
                        <TableCell>
                          <div>
                            <span className="font-medium">{queue.name}</span>
                            {queue.is_default && (
                              <Badge variant="outline" className="ml-2 text-xs">Padrão</Badge>
                            )}
                            {queue.description && (
                              <p className="text-xs text-muted-foreground truncate max-w-[200px]">
                                {queue.description}
                              </p>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge variant="secondary">
                            {routingMethodLabels[queue.routing_method] || queue.routing_method}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <span className="font-mono">{queue.priority}</span>
                            <Progress value={queue.priority} className="h-2 w-16" />
                          </div>
                        </TableCell>
                        <TableCell>
                          <span className="font-bold">{stats.members}</span>
                        </TableCell>
                        <TableCell>
                          <span className={cn(
                            'font-bold',
                            stats.open > 20 ? 'text-red-600' : stats.open > 10 ? 'text-yellow-600' : 'text-green-600'
                          )}>
                            {stats.open}
                          </span>
                        </TableCell>
                        <TableCell>
                          <div className="space-y-1">
                            <Progress value={Math.min(capacityPct, 100)} className="h-2 w-20" />
                            <span className="text-xs text-muted-foreground">
                              {stats.open}/{queue.max_capacity}
                            </span>
                          </div>
                        </TableCell>
                        <TableCell>
                          <Switch
                            checked={queue.is_active}
                            onCheckedChange={v => toggleQueueActiveMutation.mutate({ id: queue.id, is_active: v })}
                          />
                        </TableCell>
                        <TableCell>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => {
                              setSelectedQueue(queue);
                              setShowMembersDialog(true);
                            }}
                          >
                            <Users className="h-3 w-3 mr-1" />
                            Membros
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })
                )}
              </TableBody>
            </Table>
          </CardContent>
        </Card>

        {/* Members Dialog */}
        <Dialog open={showMembersDialog} onOpenChange={setShowMembersDialog}>
          <DialogContent className="max-w-lg">
            <DialogHeader>
              <DialogTitle>Membros: {selectedQueue?.name}</DialogTitle>
              <DialogDescription>
                Gerencie os agentes atribuídos a esta fila.
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              {/* Current members */}
              <div className="space-y-2">
                <Label className="text-sm font-medium">Membros Atuais ({selectedQueueMembers.length})</Label>
                {selectedQueueMembers.length === 0 ? (
                  <p className="text-sm text-muted-foreground">Nenhum membro nesta fila</p>
                ) : (
                  <div className="space-y-2 max-h-48 overflow-y-auto">
                    {selectedQueueMembers.map(member => (
                      <div key={member.id} className="flex items-center justify-between border rounded-lg p-2">
                        <div className="flex items-center gap-2">
                          <Avatar className="h-7 w-7">
                            <AvatarFallback className="text-xs">
                              {member.user?.first_name?.[0]}{member.user?.last_name?.[0]}
                            </AvatarFallback>
                          </Avatar>
                          <div>
                            <p className="text-sm font-medium">
                              {member.user?.first_name} {member.user?.last_name}
                            </p>
                            <p className="text-xs text-muted-foreground">{member.user?.email}</p>
                          </div>
                        </div>
                        <Button
                          size="icon"
                          variant="ghost"
                          className="h-7 w-7 text-destructive"
                          onClick={() => removeMemberMutation.mutate(member.id)}
                        >
                          <Trash2 className="h-3 w-3" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Add member */}
              {selectedQueue && agentsNotInQueue.length > 0 && (
                <div className="space-y-2">
                  <Label className="text-sm font-medium">Adicionar Membro</Label>
                  <div className="space-y-2 max-h-36 overflow-y-auto">
                    {agentsNotInQueue.map(agent => (
                      <div key={agent.id} className="flex items-center justify-between border rounded-lg p-2">
                        <div className="flex items-center gap-2">
                          <Avatar className="h-7 w-7">
                            <AvatarFallback className="text-xs">
                              {agent.first_name?.[0]}{agent.last_name?.[0]}
                            </AvatarFallback>
                          </Avatar>
                          <div>
                            <p className="text-sm font-medium">{agent.first_name} {agent.last_name}</p>
                            <p className="text-xs text-muted-foreground">{agent.email}</p>
                          </div>
                        </div>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => addMemberMutation.mutate({ queueId: selectedQueue.id, userId: agent.id })}
                          disabled={addMemberMutation.isPending}
                        >
                          <UserPlus className="h-3 w-3 mr-1" />
                          Adicionar
                        </Button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </DialogContent>
        </Dialog>
      </div>
    </>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Switch } from '@/components/ui/switch';
import {
  Globe, Plus, Search, Filter, MessageSquare, AtSign,
  Instagram, Facebook, Twitter, Linkedin, Youtube,
  TrendingUp, TrendingDown, Heart, Share2, MessageCircle,
  CheckCircle, AlertTriangle, Eye, EyeOff, Flag,
  Sparkles, RefreshCw, ExternalLink, Send, ThumbsUp,
  ThumbsDown, Minus
} from '@/components/icons';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { toast } from 'sonner';
import { formatDistanceToNow, format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { cn } from '@/lib/utils';

const platformIcons: Record<string, React.ReactNode> = {
  instagram: <Instagram className="h-4 w-4 text-pink-500" />,
  facebook: <Facebook className="h-4 w-4 text-blue-600" />,
  twitter: <Twitter className="h-4 w-4 text-sky-500" />,
  linkedin: <Linkedin className="h-4 w-4 text-blue-700" />,
  youtube: <Youtube className="h-4 w-4 text-red-600" />,
  tiktok: <Sparkles className="h-4 w-4 text-foreground" />,
};

const platformLabels: Record<string, string> = {
  instagram: 'Instagram',
  facebook: 'Facebook',
  twitter: 'Twitter/X',
  linkedin: 'LinkedIn',
  youtube: 'YouTube',
  tiktok: 'TikTok',
};

const sentimentIcons: Record<string, React.ReactNode> = {
  positive: <ThumbsUp className="h-4 w-4 text-green-500" />,
  negative: <ThumbsDown className="h-4 w-4 text-red-500" />,
  neutral: <Minus className="h-4 w-4 text-gray-500" />,
  mixed: <Sparkles className="h-4 w-4 text-yellow-500" />,
};

const sentimentLabels: Record<string, string> = {
  positive: 'Positivo',
  negative: 'Negativo',
  neutral: 'Neutro',
  mixed: 'Misto',
};

export default function SocialInbox() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState('messages');
  const [searchQuery, setSearchQuery] = useState('');
  const [platformFilter, setPlatformFilter] = useState('all');
  const [directionFilter, setDirectionFilter] = useState('all');
  const [sentimentFilter, setSentimentFilter] = useState('all');
  const [showConnectDialog, setShowConnectDialog] = useState(false);
  const [selectedMessage, setSelectedMessage] = useState<any>(null);
  const [replyContent, setReplyContent] = useState('');

  // New account form
  const [newAccount, setNewAccount] = useState({
    platform: 'instagram',
    account_name: '',
    account_handle: '',
    auto_import_messages: true,
    auto_import_mentions: true,
    auto_create_conversations: true,
  });

  // === QUERIES ===

  const { data: socialAccounts = [] } = useQuery({
    queryKey: ['social-accounts'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('social_accounts')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: socialMessages = [], isLoading: messagesLoading } = useQuery({
    queryKey: ['social-messages', platformFilter, directionFilter],
    queryFn: async () => {
      let query = supabase
        .from('social_messages')
        .select(`
          *,
          social_account:social_accounts(id, platform, account_name, account_handle),
          contact:contacts(id, first_name, last_name, email)
        `)
        .order('created_at', { ascending: false })
        .limit(100);

      if (platformFilter !== 'all') {
        const accountIds = socialAccounts
          .filter(a => a.platform === platformFilter)
          .map(a => a.id);
        if (accountIds.length > 0) {
          query = query.in('social_account_id', accountIds);
        }
      }

      if (directionFilter !== 'all') {
        query = query.eq('direction', directionFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const { data: socialMentions = [], isLoading: mentionsLoading } = useQuery({
    queryKey: ['social-mentions', platformFilter, sentimentFilter],
    queryFn: async () => {
      let query = supabase
        .from('social_mentions')
        .select(`
          *,
          social_account:social_accounts(id, platform, account_name, account_handle)
        `)
        .order('created_at', { ascending: false })
        .limit(100);

      if (platformFilter !== 'all') {
        query = query.eq('platform', platformFilter as any);
      }
      if (sentimentFilter !== 'all') {
        query = query.eq('sentiment', sentimentFilter as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  // === MUTATIONS ===

  const connectAccountMutation = useMutation({
    mutationFn: async (data: typeof newAccount) => {
      const { error } = await supabase.from('social_accounts').insert({
        organization_id: profile?.organization_id,
        platform: data.platform as any,
        account_name: data.account_name,
        account_handle: data.account_handle || null,
        status: 'connected',
        auto_import_messages: data.auto_import_messages,
        auto_import_mentions: data.auto_import_mentions,
        auto_create_conversations: data.auto_create_conversations,
        connected_by: profile?.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['social-accounts'] });
      setShowConnectDialog(false);
      toast.success('Conta social conectada');
      setNewAccount({
        platform: 'instagram', account_name: '', account_handle: '',
        auto_import_messages: true, auto_import_mentions: true, auto_create_conversations: true,
      });
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  const markAsReadMutation = useMutation({
    mutationFn: async (messageId: string) => {
      const { error } = await supabase.from('social_messages')
        .update({ is_read: true })
        .eq('id', messageId);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['social-messages'] }),
  });

  const reviewMentionMutation = useMutation({
    mutationFn: async ({ id, action }: { id: string; action: string }) => {
      const { error } = await supabase.from('social_mentions')
        .update({
          is_reviewed: true,
          reviewed_by: profile?.id,
          reviewed_at: new Date().toISOString(),
          action_taken: action,
        })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['social-mentions'] });
      toast.success('Menção revisada');
    },
    onError: (e: any) => toast.error('Erro: ' + e.message),
  });

  // === COMPUTED ===

  const unreadMessages = socialMessages.filter(m => !m.is_read).length;
  const unreviewedMentions = socialMentions.filter(m => !m.is_reviewed).length;
  const inboundMessages = socialMessages.filter(m => m.direction === 'inbound').length;
  const negativeMentions = socialMentions.filter(m => m.sentiment === 'negative').length;

  const filteredMessages = socialMessages.filter(m => {
    if (!searchQuery) return true;
    const s = searchQuery.toLowerCase();
    return (
      m.content?.toLowerCase().includes(s) ||
      m.sender_name?.toLowerCase().includes(s) ||
      m.sender_handle?.toLowerCase().includes(s)
    );
  });

  const filteredMentions = socialMentions.filter(m => {
    if (!searchQuery) return true;
    const s = searchQuery.toLowerCase();
    return (
      m.content?.toLowerCase().includes(s) ||
      m.author_name?.toLowerCase().includes(s) ||
      m.author_handle?.toLowerCase().includes(s)
    );
  });

  return (
    <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-3">
              <Globe className="h-8 w-8 text-primary" />
              Social Inbox
            </h1>
            <p className="text-muted-foreground mt-1">
              Gerencie mensagens e menções de todas as redes sociais em um só lugar
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => queryClient.invalidateQueries()}>
              <RefreshCw className="h-4 w-4 mr-2" /> Sincronizar
            </Button>
            <Dialog open={showConnectDialog} onOpenChange={setShowConnectDialog}>
              <DialogTrigger asChild>
                <Button>
                  <Plus className="h-4 w-4 mr-2" /> Conectar Conta
                </Button>
              </DialogTrigger>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>Conectar Conta Social</DialogTitle>
                  <DialogDescription>
                    Adicione uma conta de rede social para monitorar mensagens e menções.
                  </DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label>Plataforma</Label>
                    <Select
                      value={newAccount.platform}
                      onValueChange={v => setNewAccount(p => ({ ...p, platform: v }))}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {Object.entries(platformLabels).map(([key, label]) => (
                          <SelectItem key={key} value={key}>
                            <div className="flex items-center gap-2">
                              {platformIcons[key]}
                              {label}
                            </div>
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Nome da Conta</Label>
                    <Input
                      value={newAccount.account_name}
                      onChange={e => setNewAccount(p => ({ ...p, account_name: e.target.value }))}
                      placeholder="Ex: Fireware CRM"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Handle / @</Label>
                    <Input
                      value={newAccount.account_handle}
                      onChange={e => setNewAccount(p => ({ ...p, account_handle: e.target.value }))}
                      placeholder="@firewarecrm"
                    />
                  </div>
                  <div className="space-y-3 border rounded-lg p-3">
                    <div className="flex items-center justify-between">
                      <Label className="text-sm">Importar mensagens automaticamente</Label>
                      <Switch
                        checked={newAccount.auto_import_messages}
                        onCheckedChange={v => setNewAccount(p => ({ ...p, auto_import_messages: v }))}
                      />
                    </div>
                    <div className="flex items-center justify-between">
                      <Label className="text-sm">Importar menções automaticamente</Label>
                      <Switch
                        checked={newAccount.auto_import_mentions}
                        onCheckedChange={v => setNewAccount(p => ({ ...p, auto_import_mentions: v }))}
                      />
                    </div>
                    <div className="flex items-center justify-between">
                      <Label className="text-sm">Criar conversas automaticamente</Label>
                      <Switch
                        checked={newAccount.auto_create_conversations}
                        onCheckedChange={v => setNewAccount(p => ({ ...p, auto_create_conversations: v }))}
                      />
                    </div>
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setShowConnectDialog(false)}>Cancelar</Button>
                  <Button
                    onClick={() => connectAccountMutation.mutate(newAccount)}
                    disabled={!newAccount.account_name || connectAccountMutation.isPending}
                  >
                    {connectAccountMutation.isPending ? 'Conectando...' : 'Conectar Conta'}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* Connected Accounts Strip */}
        {socialAccounts.length > 0 && (
          <div className="flex gap-3 overflow-x-auto pb-2">
            {socialAccounts.map(account => (
              <Card key={account.id} className="min-w-[200px] flex-shrink-0">
                <CardContent className="p-3 flex items-center gap-3">
                  {platformIcons[account.platform]}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">{account.account_name}</p>
                    <p className="text-xs text-muted-foreground">{account.account_handle}</p>
                  </div>
                  <Badge variant={account.status === 'connected' ? 'default' : 'destructive'} className="text-xs">
                    {account.status === 'connected' ? 'OK' : account.status}
                  </Badge>
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Mensagens Não Lidas</p>
                  <p className="text-3xl font-bold">{unreadMessages}</p>
                </div>
                <MessageSquare className="h-8 w-8 text-blue-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Menções Pendentes</p>
                  <p className="text-3xl font-bold">{unreviewedMentions}</p>
                </div>
                <AtSign className="h-8 w-8 text-purple-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Recebidas (Inbound)</p>
                  <p className="text-3xl font-bold">{inboundMessages}</p>
                </div>
                <TrendingUp className="h-8 w-8 text-green-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Menções Negativas</p>
                  <p className="text-3xl font-bold text-red-600">{negativeMentions}</p>
                </div>
                <AlertTriangle className="h-8 w-8 text-red-500 opacity-50" />
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList>
            <TabsTrigger value="messages">
              <MessageSquare className="h-4 w-4 mr-2" />
              Mensagens
              {unreadMessages > 0 && (
                <Badge variant="destructive" className="ml-2 text-xs px-1.5">{unreadMessages}</Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="mentions">
              <AtSign className="h-4 w-4 mr-2" />
              Menções
              {unreviewedMentions > 0 && (
                <Badge variant="destructive" className="ml-2 text-xs px-1.5">{unreviewedMentions}</Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="accounts">
              <Globe className="h-4 w-4 mr-2" />
              Contas ({socialAccounts.length})
            </TabsTrigger>
          </TabsList>

          {/* Filters */}
          <div className="flex items-center gap-4 mt-4">
            <div className="relative flex-1 max-w-md">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar mensagens ou menções..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>
            <Select value={platformFilter} onValueChange={setPlatformFilter}>
              <SelectTrigger className="w-40">
                <Filter className="h-4 w-4 mr-2" />
                <SelectValue placeholder="Plataforma" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todas</SelectItem>
                {Object.entries(platformLabels).map(([key, label]) => (
                  <SelectItem key={key} value={key}>{label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
            {activeTab === 'mentions' && (
              <Select value={sentimentFilter} onValueChange={setSentimentFilter}>
                <SelectTrigger className="w-40">
                  <Sparkles className="h-4 w-4 mr-2" />
                  <SelectValue placeholder="Sentimento" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="positive">Positivo</SelectItem>
                  <SelectItem value="negative">Negativo</SelectItem>
                  <SelectItem value="neutral">Neutro</SelectItem>
                  <SelectItem value="mixed">Misto</SelectItem>
                </SelectContent>
              </Select>
            )}
          </div>

          {/* Messages Tab */}
          <TabsContent value="messages" className="space-y-4">
            <Card>
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Plataforma</TableHead>
                      <TableHead>Remetente</TableHead>
                      <TableHead>Tipo</TableHead>
                      <TableHead>Conteúdo</TableHead>
                      <TableHead>Engajamento</TableHead>
                      <TableHead>Data</TableHead>
                      <TableHead>Ações</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {messagesLoading ? (
                      <TableRow>
                        <TableCell colSpan={7} className="text-center py-8 text-muted-foreground">
                          Carregando mensagens...
                        </TableCell>
                      </TableRow>
                    ) : filteredMessages.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={7} className="text-center py-8 text-muted-foreground">
                          <MessageSquare className="h-8 w-8 mx-auto mb-2 opacity-50" />
                          Nenhuma mensagem encontrada
                        </TableCell>
                      </TableRow>
                    ) : (
                      filteredMessages.map(msg => (
                        <TableRow key={msg.id} className={cn(!msg.is_read && 'bg-accent/30')}>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              {platformIcons[msg.social_account?.platform || ''] || <Globe className="h-4 w-4" />}
                              <span className="text-xs">{msg.social_account?.account_name}</span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              <Avatar className="h-7 w-7">
                                {msg.sender_avatar_url ? (
                                  <AvatarImage src={msg.sender_avatar_url} />
                                ) : null}
                                <AvatarFallback className="text-xs">
                                  {msg.sender_name?.[0] || '?'}
                                </AvatarFallback>
                              </Avatar>
                              <div>
                                <p className="text-sm font-medium">{msg.sender_name || 'Desconhecido'}</p>
                                <p className="text-xs text-muted-foreground">{msg.sender_handle}</p>
                              </div>
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-1">
                              <Badge variant={msg.direction === 'inbound' ? 'default' : 'secondary'} className="text-xs">
                                {msg.direction === 'inbound' ? '← Entrada' : '→ Saída'}
                              </Badge>
                              <Badge variant="outline" className="text-xs capitalize">
                                {msg.message_type === 'direct_message' ? 'DM' :
                                 msg.message_type === 'comment' ? 'Comentário' :
                                 msg.message_type === 'mention' ? 'Menção' :
                                 msg.message_type === 'reply' ? 'Resposta' : msg.message_type}
                              </Badge>
                            </div>
                          </TableCell>
                          <TableCell>
                            <p className="text-sm truncate max-w-[300px]">{msg.content}</p>
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-3 text-xs text-muted-foreground">
                              <span className="flex items-center gap-1">
                                <Heart className="h-3 w-3" /> {msg.likes_count || 0}
                              </span>
                              <span className="flex items-center gap-1">
                                <Share2 className="h-3 w-3" /> {msg.shares_count || 0}
                              </span>
                              <span className="flex items-center gap-1">
                                <MessageCircle className="h-3 w-3" /> {msg.replies_count || 0}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell className="text-xs text-muted-foreground">
                            {formatDistanceToNow(new Date(msg.created_at), { addSuffix: true, locale: ptBR })}
                          </TableCell>
                          <TableCell>
                            <div className="flex gap-1">
                              {!msg.is_read && (
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-7 w-7"
                                  onClick={() => markAsReadMutation.mutate(msg.id)}
                                  title="Marcar como lida"
                                >
                                  <Eye className="h-3 w-3" />
                                </Button>
                              )}
                              {msg.original_post_url && (
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-7 w-7"
                                  onClick={() => window.open(msg.original_post_url, '_blank')}
                                  title="Ver no original"
                                >
                                  <ExternalLink className="h-3 w-3" />
                                </Button>
                              )}
                            </div>
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Mentions Tab */}
          <TabsContent value="mentions" className="space-y-4">
            <Card>
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Plataforma</TableHead>
                      <TableHead>Autor</TableHead>
                      <TableHead>Conteúdo</TableHead>
                      <TableHead>Sentimento</TableHead>
                      <TableHead>Engajamento</TableHead>
                      <TableHead>Alcance</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Ações</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {mentionsLoading ? (
                      <TableRow>
                        <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                          Carregando menções...
                        </TableCell>
                      </TableRow>
                    ) : filteredMentions.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={8} className="text-center py-8 text-muted-foreground">
                          <AtSign className="h-8 w-8 mx-auto mb-2 opacity-50" />
                          Nenhuma menção encontrada
                        </TableCell>
                      </TableRow>
                    ) : (
                      filteredMentions.map(mention => (
                        <TableRow key={mention.id} className={cn(!mention.is_reviewed && 'bg-accent/30')}>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              {platformIcons[mention.platform] || <Globe className="h-4 w-4" />}
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-2">
                              <Avatar className="h-7 w-7">
                                {mention.author_avatar_url ? (
                                  <AvatarImage src={mention.author_avatar_url} />
                                ) : null}
                                <AvatarFallback className="text-xs">
                                  {mention.author_name?.[0] || '?'}
                                </AvatarFallback>
                              </Avatar>
                              <div>
                                <p className="text-sm font-medium">{mention.author_name || 'Desconhecido'}</p>
                                <p className="text-xs text-muted-foreground">
                                  {mention.author_handle}
                                  {mention.author_followers_count > 0 && (
                                    <span className="ml-1">({mention.author_followers_count.toLocaleString()} seg.)</span>
                                  )}
                                </p>
                              </div>
                            </div>
                          </TableCell>
                          <TableCell>
                            <p className="text-sm truncate max-w-[250px]">{mention.content}</p>
                            {mention.topics && (mention.topics as string[]).length > 0 && (
                              <div className="flex gap-1 mt-1 flex-wrap">
                                {(mention.topics as string[]).slice(0, 3).map((t, i) => (
                                  <Badge key={i} variant="outline" className="text-xs">{t}</Badge>
                                ))}
                              </div>
                            )}
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-1">
                              {sentimentIcons[mention.sentiment || 'neutral']}
                              <span className="text-sm">
                                {sentimentLabels[mention.sentiment || 'neutral']}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <div className="flex items-center gap-3 text-xs text-muted-foreground">
                              <span className="flex items-center gap-1">
                                <Heart className="h-3 w-3" /> {mention.likes_count || 0}
                              </span>
                              <span className="flex items-center gap-1">
                                <Share2 className="h-3 w-3" /> {mention.shares_count || 0}
                              </span>
                            </div>
                          </TableCell>
                          <TableCell>
                            <span className="text-sm font-mono">
                              {(mention.reach_estimate || 0).toLocaleString()}
                            </span>
                          </TableCell>
                          <TableCell>
                            {mention.is_reviewed ? (
                              <Badge variant="secondary" className="text-xs">
                                <CheckCircle className="h-3 w-3 mr-1" />
                                {mention.action_taken === 'responded' ? 'Respondida' :
                                 mention.action_taken === 'escalated' ? 'Escalada' :
                                 mention.action_taken === 'flagged' ? 'Sinalizada' :
                                 mention.action_taken === 'ignored' ? 'Ignorada' : 'Revisada'}
                              </Badge>
                            ) : (
                              <Badge variant="outline" className="text-xs">Pendente</Badge>
                            )}
                          </TableCell>
                          <TableCell>
                            {!mention.is_reviewed && (
                              <div className="flex gap-1">
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-7 w-7 text-green-600"
                                  title="Marcar como respondida"
                                  onClick={() => reviewMentionMutation.mutate({ id: mention.id, action: 'responded' })}
                                >
                                  <CheckCircle className="h-3 w-3" />
                                </Button>
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-7 w-7 text-orange-600"
                                  title="Escalar"
                                  onClick={() => reviewMentionMutation.mutate({ id: mention.id, action: 'escalated' })}
                                >
                                  <AlertTriangle className="h-3 w-3" />
                                </Button>
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-7 w-7 text-muted-foreground"
                                  title="Ignorar"
                                  onClick={() => reviewMentionMutation.mutate({ id: mention.id, action: 'ignored' })}
                                >
                                  <EyeOff className="h-3 w-3" />
                                </Button>
                                {mention.content_url && (
                                  <Button
                                    size="icon"
                                    variant="ghost"
                                    className="h-7 w-7"
                                    title="Ver original"
                                    onClick={() => window.open(mention.content_url, '_blank')}
                                  >
                                    <ExternalLink className="h-3 w-3" />
                                  </Button>
                                )}
                              </div>
                            )}
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Accounts Tab */}
          <TabsContent value="accounts" className="space-y-4">
            {socialAccounts.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-12">
                  <Globe className="h-12 w-12 text-muted-foreground mb-4 opacity-50" />
                  <h3 className="text-lg font-medium mb-2">Nenhuma conta conectada</h3>
                  <p className="text-muted-foreground mb-4">Conecte suas redes sociais para começar a monitorar.</p>
                  <Button onClick={() => setShowConnectDialog(true)}>
                    <Plus className="h-4 w-4 mr-2" /> Conectar Conta
                  </Button>
                </CardContent>
              </Card>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {socialAccounts.map(account => (
                  <Card key={account.id}>
                    <CardHeader className="pb-3">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="p-2 rounded-lg bg-accent">
                            {platformIcons[account.platform]}
                          </div>
                          <div>
                            <CardTitle className="text-base">{account.account_name}</CardTitle>
                            <CardDescription>{account.account_handle}</CardDescription>
                          </div>
                        </div>
                        <Badge variant={
                          account.status === 'connected' ? 'default' :
                          account.status === 'expired' ? 'destructive' : 'secondary'
                        }>
                          {account.status === 'connected' ? 'Conectada' :
                           account.status === 'disconnected' ? 'Desconectada' :
                           account.status === 'expired' ? 'Expirada' : account.status}
                        </Badge>
                      </div>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      <div className="grid grid-cols-2 gap-3 text-sm">
                        <div>
                          <p className="text-muted-foreground text-xs">Seguidores</p>
                          <p className="font-bold">{(account.followers_count || 0).toLocaleString()}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Seguindo</p>
                          <p className="font-bold">{(account.following_count || 0).toLocaleString()}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Msgs Importadas</p>
                          <p className="font-bold">{account.total_messages_imported}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Menções Importadas</p>
                          <p className="font-bold">{account.total_mentions_imported}</p>
                        </div>
                      </div>
                      {account.last_sync_at && (
                        <p className="text-xs text-muted-foreground">
                          Última sincronização: {formatDistanceToNow(new Date(account.last_sync_at), { addSuffix: true, locale: ptBR })}
                        </p>
                      )}
                      {account.last_error && (
                        <p className="text-xs text-destructive">Erro: {account.last_error}</p>
                      )}
                      <div className="flex gap-2 text-xs">
                        {account.auto_import_messages && (
                          <Badge variant="outline">Auto Msgs</Badge>
                        )}
                        {account.auto_import_mentions && (
                          <Badge variant="outline">Auto Menções</Badge>
                        )}
                        {account.auto_create_conversations && (
                          <Badge variant="outline">Auto Conv.</Badge>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>
    </div>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Switch } from '@/components/ui/switch';
import { Skeleton } from '@/components/ui/skeleton';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Progress } from '@/components/ui/progress';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  Phone,
  PhoneCall,
  PhoneIncoming,
  PhoneOutgoing,
  PhoneMissed,
  PhoneOff,
  Plus,
  Settings,
  Mic,
  MicOff,
  Volume2,
  VolumeX,
  Play,
  Pause,
  Download,
  RefreshCw,
  Trash2,
  Edit,
  Eye,
  Users,
  TrendingUp,
  Activity,
  Clock,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Search,
  Filter,
  MoreHorizontal,
  Copy,
  FileText,
  Voicemail,
  Timer,
  BarChart3,
  Headphones,
} from '@/components/icons';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import type { Database } from '@/integrations/supabase/types';

// Use database types directly
type VoiceProvider = Database['public']['Tables']['voice_providers']['Row'];
type VoiceCall = Database['public']['Tables']['voice_calls']['Row'];
type VoiceVoicemail = Database['public']['Tables']['voice_voicemails']['Row'];
type VoiceTranscript = Database['public']['Tables']['voice_transcripts']['Row'];


export default function VoiceAdmin() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState('providers');
  const [isProviderDialogOpen, setIsProviderDialogOpen] = useState(false);
  const [selectedProvider, setSelectedProvider] = useState<VoiceProvider | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [directionFilter, setDirectionFilter] = useState<string>('all');
  const [playingAudio, setPlayingAudio] = useState<string | null>(null);

  // Form states
  const [providerForm, setProviderForm] = useState({
    name: '',
    provider_type: 'twilio',
    account_sid: '',
    auth_token: '',
    phone_number: '',
    region: 'us1',
  });

  // Queries
  const { data: providers, isLoading: providersLoading } = useQuery({
    queryKey: ['voice-providers', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('voice_providers')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as VoiceProvider[];
    },
    enabled: !!profile?.organization_id,
  });

  const { data: calls, isLoading: callsLoading } = useQuery({
    queryKey: ['voice-calls', profile?.organization_id, searchQuery, statusFilter, directionFilter],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      let query = supabase
        .from('voice_calls')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('initiated_at', { ascending: false })
        .limit(100);

      if (statusFilter !== 'all') {
        query = query.eq('status', statusFilter as Database['public']['Enums']['voice_call_status']);
      }
      if (directionFilter !== 'all') {
        query = query.eq('direction', directionFilter as Database['public']['Enums']['communication_direction']);
      }
      if (searchQuery) {
        query = query.or(`from_number.ilike.%${searchQuery}%,to_number.ilike.%${searchQuery}%,caller_name.ilike.%${searchQuery}%`);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as VoiceCall[];
    },
    enabled: !!profile?.organization_id,
  });

  const { data: voicemails, isLoading: voicemailsLoading } = useQuery({
    queryKey: ['voice-voicemails', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('voice_voicemails')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data as VoiceVoicemail[];
    },
    enabled: !!profile?.organization_id,
  });

  const { data: transcripts, isLoading: transcriptsLoading } = useQuery({
    queryKey: ['voice-transcripts', profile?.organization_id],
    queryFn: async () => {
      if (!profile?.organization_id) return [];
      const { data, error } = await supabase
        .from('voice_transcripts')
        .select('*')
        .eq('organization_id', profile.organization_id)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data as VoiceTranscript[];
    },
    enabled: !!profile?.organization_id,
  });

  // Mutations
  const createProviderMutation = useMutation({
    mutationFn: async (data: typeof providerForm) => {
      if (!profile?.organization_id || !profile?.id) throw new Error('Não autenticado');
      const { error } = await supabase.from('voice_providers').insert({
        organization_id: profile.organization_id,
        name: data.name,
        provider_type: data.provider_type,
        account_sid: data.account_sid,
        auth_token_encrypted: data.auth_token,
        phone_numbers: data.phone_number ? [data.phone_number] : null,
        health_status: 'pending',
        is_active: false,
        created_by: profile.id,
        updated_by: profile.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Provedor de voz criado com sucesso!');
      queryClient.invalidateQueries({ queryKey: ['voice-providers'] });
      setIsProviderDialogOpen(false);
      resetProviderForm();
    },
    onError: (error) => {
      toast.error('Erro ao criar provedor: ' + (error as Error).message);
    },
  });

  const updateProviderMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<VoiceProvider> }) => {
      if (!profile?.id) throw new Error('Não autenticado');
      const { error } = await supabase
        .from('voice_providers')
        .update({ ...data, updated_by: profile.id })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Provedor atualizado!');
      queryClient.invalidateQueries({ queryKey: ['voice-providers'] });
    },
    onError: (error) => {
      toast.error('Erro ao atualizar: ' + (error as Error).message);
    },
  });

  const deleteProviderMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from('voice_providers').delete().eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success('Provedor removido!');
      queryClient.invalidateQueries({ queryKey: ['voice-providers'] });
    },
    onError: (error) => {
      toast.error('Erro ao remover: ' + (error as Error).message);
    },
  });

  const markVoicemailListenedMutation = useMutation({
    mutationFn: async (id: string) => {
      if (!profile?.id) throw new Error('Não autenticado');
      const { error } = await supabase
        .from('voice_voicemails')
        .update({ is_read: true, read_by: profile.id, read_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['voice-voicemails'] });
    },
  });

  // Helpers
  const resetProviderForm = () => {
    setProviderForm({
      name: '',
      provider_type: 'twilio',
      account_sid: '',
      auth_token: '',
      phone_number: '',
      region: 'us1',
    });
    setSelectedProvider(null);
  };

  const formatDurationFromSeconds = (seconds: number | null) => {
    if (!seconds) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getCallStatusBadge = (status: string) => {
    const statusConfig: Record<string, { variant: 'default' | 'secondary' | 'destructive' | 'outline'; icon: any; label: string }> = {
      initiated: { variant: 'secondary', icon: Clock, label: 'Iniciada' },
      ringing: { variant: 'secondary', icon: PhoneCall, label: 'Tocando' },
      in_progress: { variant: 'default', icon: Phone, label: 'Em Andamento' },
      completed: { variant: 'outline', icon: CheckCircle, label: 'Completada' },
      busy: { variant: 'destructive', icon: PhoneOff, label: 'Ocupado' },
      no_answer: { variant: 'destructive', icon: PhoneMissed, label: 'Sem Resposta' },
      failed: { variant: 'destructive', icon: XCircle, label: 'Falhou' },
      canceled: { variant: 'outline', icon: PhoneOff, label: 'Cancelada' },
    };
    const config = statusConfig[status] || { variant: 'outline' as const, icon: Phone, label: status };
    const Icon = config.icon;
    return (
      <Badge variant={config.variant} className="gap-1">
        <Icon className="h-3 w-3" />
        {config.label}
      </Badge>
    );
  };

  const getDirectionIcon = (direction: string) => {
    if (direction === 'inbound') return PhoneIncoming;
    return PhoneOutgoing;
  };

  const getProviderStatusBadge = (status: string) => {
    const statusConfig: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
      connected: 'default',
      active: 'default',
      pending: 'secondary',
      disconnected: 'destructive',
      error: 'destructive',
    };
    return <Badge variant={statusConfig[status] || 'outline'}>{status}</Badge>;
  };

  // Calculate stats
  const stats = {
    totalProviders: providers?.length || 0,
    activeProviders: providers?.filter(p => p.is_active).length || 0,
    todayCalls: calls?.filter(c => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      return new Date(c.initiated_at) >= today;
    }).length || 0,
    inboundCalls: calls?.filter(c => c.direction === 'inbound').length || 0,
    outboundCalls: calls?.filter(c => c.direction === 'outbound').length || 0,
    missedCalls: calls?.filter(c => c.status === 'no_answer' || c.status === 'missed').length || 0,
    totalMinutes: calls?.filter(c => c.talk_duration_seconds).reduce((sum, c) => sum + Math.round((c.talk_duration_seconds || 0) / 60), 0) || 0,
    unheardVoicemails: voicemails?.filter(v => !v.is_read).length || 0,
    avgCallDuration: calls && calls.length > 0
      ? Math.round(calls.filter(c => c.talk_duration_seconds).reduce((sum, c) => sum + (c.talk_duration_seconds || 0), 0) / calls.filter(c => c.talk_duration_seconds).length)
      : 0,
  };

  const webhookUrl = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/voice-webhook`;

  return (
    <div className="flex flex-col gap-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight flex items-center gap-2">
              <Phone className="h-8 w-8 text-primary" />
              Telefonia / Voice
            </h1>
            <p className="text-muted-foreground">
              Gerencie provedores de telefonia, chamadas e gravações
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" onClick={() => queryClient.invalidateQueries({ queryKey: ['voice-providers'] })}>
              <RefreshCw className="h-4 w-4 mr-2" />
              Atualizar
            </Button>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-5">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Provedores Ativos</CardTitle>
              <Headphones className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.activeProviders}/{stats.totalProviders}</div>
              <p className="text-xs text-muted-foreground">configurados</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Chamadas Hoje</CardTitle>
              <PhoneCall className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.todayCalls}</div>
              <p className="text-xs text-muted-foreground">
                {stats.inboundCalls} entrada / {stats.outboundCalls} saída
              </p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Minutos Totais</CardTitle>
              <Timer className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.totalMinutes.toLocaleString()}</div>
              <p className="text-xs text-muted-foreground">acumulados</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Tempo Médio</CardTitle>
              <BarChart3 className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{formatDurationFromSeconds(stats.avgCallDuration)}</div>
              <p className="text-xs text-muted-foreground">por chamada</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Voicemails</CardTitle>
              <Voicemail className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.unheardVoicemails}</div>
              <p className="text-xs text-muted-foreground">não ouvidos</p>
            </CardContent>
          </Card>
        </div>

        {/* Main Content Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-4">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="providers" className="gap-2">
              <Settings className="h-4 w-4" />
              Provedores
            </TabsTrigger>
            <TabsTrigger value="calls" className="gap-2">
              <PhoneCall className="h-4 w-4" />
              Histórico de Chamadas
            </TabsTrigger>
            <TabsTrigger value="voicemails" className="gap-2">
              <Voicemail className="h-4 w-4" />
              Voicemails
            </TabsTrigger>
            <TabsTrigger value="transcripts" className="gap-2">
              <FileText className="h-4 w-4" />
              Transcrições
            </TabsTrigger>
          </TabsList>

          {/* Providers Tab */}
          <TabsContent value="providers" className="space-y-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <div>
                  <CardTitle>Provedores de Telefonia</CardTitle>
                  <CardDescription>
