            </Card>
          </TabsContent>

          {/* Transcripts Tab */}
          <TabsContent value="transcripts" className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle>Transcrições de Chamadas</CardTitle>
                <CardDescription>
