                </CardDescription>
              </CardHeader>
              <CardContent>
                {transcriptsLoading ? (
                  <div className="space-y-4">
                    {[1, 2, 3].map((i) => (
                      <Skeleton key={i} className="h-32 w-full" />
                    ))}
                  </div>
                ) : transcripts && transcripts.length > 0 ? (
                  <ScrollArea className="h-[600px]">
                    <div className="space-y-4">
                      {transcripts.map((transcript) => (
                        <Card key={transcript.id}>
                          <CardHeader className="pb-2">
